# --- Resolucao de caminho para compatibilidade com PyInstaller (.exe) ---
def _get_app_dir():
    """Retorna o diretorio onde o executavel/script esta localizado."""
    if getattr(sys, 'frozen', False):
        # Executando como .exe (PyInstaller)
        return os.path.dirname(sys.executable)
    else:
        # Executando como .py normal
        return os.path.dirname(os.path.abspath(__file__)) if '__file__' in dir() else os.getcwd()

APP_DIR = _get_app_dir()
