import logging
from enum import Enum

# Configurar log de erros em arquivo
_LOG_DIR = os.path.join(APP_DIR, "logs")
try:
    os.makedirs(_LOG_DIR, exist_ok=True)
except Exception:
    _LOG_DIR = APP_DIR

LOG_FILE = os.path.join(_LOG_DIR, "pdv_erros.log")

# Configuracao avancada de logging com rotacao
try:
    from logging.handlers import RotatingFileHandler
    _log_handler = RotatingFileHandler(
        LOG_FILE, maxBytes=5*1024*1024, backupCount=3, encoding="utf-8"
    )
    _log_handler.setFormatter(logging.Formatter(
        "%(asctime)s | %(levelname)s | %(name)s | %(message)s",
        datefmt="%d/%m/%Y %H:%M:%S"
    ))
    _logger = logging.getLogger("PDVPro")
    _logger.setLevel(logging.DEBUG)
    _logger.addHandler(_log_handler)
    # Tambem logar no console para debug
    _console_handler = logging.StreamHandler()
    _console_handler.setLevel(logging.WARNING)
    _console_handler.setFormatter(logging.Formatter(
        "[%(levelname)s] %(message)s"
    ))
    _logger.addHandler(_console_handler)
except Exception:
    logging.basicConfig(
        filename=LOG_FILE,
        level=logging.ERROR,
        format="%(asctime)s | %(levelname)s | %(message)s",
        datefmt="%d/%m/%Y %H:%M:%S",
        encoding="utf-8"
    )
    _logger = logging.getLogger("PDVPro")


class Severidade(Enum):
    """Niveis de severidade dos erros."""
    CRITICO = "CRITICO"    # Sistema nao funciona, precisa de acao imediata
    ALTO = "ALTO"          # Funcionalidade principal comprometida
    MEDIO = "MEDIO"        # Funcionalidade secundaria afetada
    BAIXO = "BAIXO"        # Inconveniencia menor, sistema continua
    INFO = "INFO"          # Informativo, nao e erro


