    # ================================================================
    # CONTADORES PARA MONITORAMENTO
    # ================================================================
    _erro_counter = {}  # {codigo: count}
    _ultimo_erro_time = {}  # {codigo: timestamp}

    @staticmethod
    def traduzir(erro, contexto=""):
        """Traduz um erro tecnico em mensagem amigavel para leigos.
        Retorna (mensagem_amigavel, codigo_erro, detalhes_tecnicos)."""
        detalhes = str(erro)
        tipo_erro = type(erro).__name__

        # 1. Tentar identificar erro MySQL pelo codigo numerico
        if hasattr(erro, 'errno') and erro.errno is not None:
            errno = erro.errno
            if errno in ErroAmigavel._MYSQL_ERRORS:
                msg, cod, sev = ErroAmigavel._MYSQL_ERRORS[errno]
                ErroAmigavel._registrar_ocorrencia(cod)
                return msg, cod, detalhes

        # 2. Tentar identificar pelo tipo de excecao Python
        for tipo_nome, dados in ErroAmigavel._PYTHON_ERRORS.items():
            msg, cod, sev = dados
            if tipo_erro == tipo_nome or tipo_nome in tipo_erro:
                ErroAmigavel._registrar_ocorrencia(cod)
                return msg, cod, detalhes

        # 3. Tentar identificar por palavras-chave na mensagem
        err_lower = detalhes.lower()
        for keywords, msg, cod, sev in ErroAmigavel._KEYWORD_ERRORS:
            if any(kw in err_lower for kw in keywords):
                ErroAmigavel._registrar_ocorrencia(cod)
                return msg, cod, detalhes

        # 4. Erro generico com mensagem amigavel
        ErroAmigavel._registrar_ocorrencia("ERRO-GEN-001")
        return (
            "Ocorreu um erro inesperado no sistema.\n\n"
            "O QUE ACONTECEU:\n"
            "Algo nao funcionou como esperado.\n\n"
            "COMO RESOLVER:\n"
            "1. Tente a operacao novamente\n"
            "2. Se persistir, reinicie o sistema\n"
            "3. Anote o codigo do erro abaixo\n"
            "4. Entre em contato com o suporte tecnico",
            "ERRO-GEN-001", detalhes)

    @staticmethod
    def _registrar_ocorrencia(codigo):
        """Registra ocorrencia de erro para monitoramento."""
        ErroAmigavel._erro_counter[codigo] = ErroAmigavel._erro_counter.get(codigo, 0) + 1
        ErroAmigavel._ultimo_erro_time[codigo] = time.time()

    @staticmethod
    def obter_severidade(erro):
        """Retorna a severidade do erro."""
        if hasattr(erro, 'errno') and erro.errno is not None:
            if erro.errno in ErroAmigavel._MYSQL_ERRORS:
                return ErroAmigavel._MYSQL_ERRORS[erro.errno][2]
        tipo_erro = type(erro).__name__
        for tipo_nome, dados in ErroAmigavel._PYTHON_ERRORS.items():
            if tipo_erro == tipo_nome or tipo_nome in tipo_erro:
                return dados[2]
        return Severidade.MEDIO

    @staticmethod
    def log_erro(erro, contexto="", nivel=None):
        """Registra o erro no arquivo de log com detalhes tecnicos completos."""
        try:
            msg_amigavel, codigo, detalhes = ErroAmigavel.traduzir(erro, contexto)
            severidade = nivel or ErroAmigavel.obter_severidade(erro)
            log_msg = (
                f"[{codigo}] [{severidade.value}] "
                f"Contexto: {contexto} | "
                f"Tipo: {type(erro).__name__} | "
                f"Detalhes: {detalhes} | "
                f"Ocorrencias: {ErroAmigavel._erro_counter.get(codigo, 1)} | "
                f"Traceback: {traceback.format_exc()}"
            )
            if severidade in (Severidade.CRITICO, Severidade.ALTO):
                _logger.error(log_msg)
            elif severidade == Severidade.MEDIO:
                _logger.warning(log_msg)
            else:
                _logger.info(log_msg)
        except Exception:
            try:
                _logger.error(f"Erro nao catalogado: {erro} | Contexto: {contexto}")
            except Exception:
                pass

    @staticmethod
    def mostrar_erro(erro, contexto="", parent=None):
        """Exibe mensagem amigavel ao usuario e registra no log.
        A mensagem e clara, direta e inclui passos para resolver."""
        msg_amigavel, codigo, detalhes = ErroAmigavel.traduzir(erro, contexto)
        ErroAmigavel.log_erro(erro, contexto)
        severidade = ErroAmigavel.obter_severidade(erro)

        # Titulo baseado na severidade
        titulos = {
            Severidade.CRITICO: "Erro Critico - Atencao!",
            Severidade.ALTO: "Ops! Algo deu errado",
            Severidade.MEDIO: "Aviso - Problema Detectado",
            Severidade.BAIXO: "Atencao",
            Severidade.INFO: "Informacao",
        }
        titulo = titulos.get(severidade, "Ops! Algo deu errado")

        # Montar mensagem completa
        mensagem_completa = (
            f"{msg_amigavel}\n\n"
            f"{'='*40}\n"
            f"Codigo do erro: {codigo}\n"
            f"Se precisar de ajuda, informe este codigo ao suporte."
        )

        try:
            if severidade in (Severidade.CRITICO, Severidade.ALTO):
                if parent:
                    messagebox.showerror(titulo, mensagem_completa, parent=parent)
                else:
                    messagebox.showerror(titulo, mensagem_completa)
            else:
                if parent:
                    messagebox.showwarning(titulo, mensagem_completa, parent=parent)
                else:
                    messagebox.showwarning(titulo, mensagem_completa)
        except Exception:
            print(f"[ERRO {codigo}] {msg_amigavel}")

        return codigo

    @staticmethod
    def mostrar_erro_toast(erro, contexto=""):
        """Exibe erro como toast (nao bloqueante) e registra no log."""
        msg_amigavel, codigo, detalhes = ErroAmigavel.traduzir(erro, contexto)
        ErroAmigavel.log_erro(erro, contexto)
        severidade = ErroAmigavel.obter_severidade(erro)
        try:
            primeira_linha = msg_amigavel.split(chr(10))[0]
            if severidade in (Severidade.CRITICO, Severidade.ALTO):
                ToastManager.error(f"{primeira_linha} ({codigo})", duration=6000)
            else:
                ToastManager.warning(f"{primeira_linha} ({codigo})", duration=4000)
        except Exception:
            pass
        return codigo

