    @staticmethod
    def confirmar(mensagem, titulo="Confirmar", parent=None):
        """Exibe dialogo de confirmacao e retorna True/False."""
        try:
            if parent:
                return messagebox.askyesno(titulo, mensagem, parent=parent)
            else:
                return messagebox.askyesno(titulo, mensagem)
        except Exception:
            return False

    @staticmethod
    def validar_campo_obrigatorio(valor, nome_campo, parent=None):
        """Valida se um campo obrigatorio foi preenchido.
        Retorna True se valido, False se vazio (e mostra aviso)."""
        if not valor or (isinstance(valor, str) and not valor.strip()):
            ErroAmigavel.mostrar_aviso(
                f"O campo '{nome_campo}' e obrigatorio.\n\n"
                f"Por favor, preencha o campo '{nome_campo}' para continuar.",
                "Campo Obrigatorio", parent)
            return False
        return True

    @staticmethod
    def validar_valor_numerico(valor_str, nome_campo, minimo=0, parent=None):
        """Valida se um valor e numerico e esta dentro do range.
        Retorna o valor float se valido, None se invalido."""
        try:
            valor = float(str(valor_str).replace(".", "").replace(",", ".").strip())
            if valor < minimo:
                ErroAmigavel.mostrar_aviso(
                    f"O valor do campo '{nome_campo}' deve ser maior que {minimo}.\n\n"
                    f"Valor informado: {valor_str}\n"
                    f"Por favor, informe um valor valido.",
                    "Valor Invalido", parent)
                return None
            return valor
        except (ValueError, TypeError):
            ErroAmigavel.mostrar_aviso(
                f"O campo '{nome_campo}' deve conter apenas numeros.\n\n"
                f"Valor informado: '{valor_str}'\n"
                f"Use virgula para centavos. Exemplo: 10,50",
                "Valor Invalido", parent)
            return None

    @staticmethod
    def validar_selecao(selecao, nome_item="item", parent=None):
        """Valida se um item foi selecionado na lista.
        Retorna True se selecionado, False se nao."""
        if not selecao:
            ErroAmigavel.mostrar_aviso(
                f"Nenhum {nome_item} foi selecionado.\n\n"
                f"Por favor, clique sobre o {nome_item} desejado na lista\n"
                f"e tente novamente.",
                f"Selecione um {nome_item}", parent)
            return False
        return True

    @staticmethod
    def diagnosticar_conexao(host="localhost", port=3306):
        """Realiza diagnostico da conexao com o banco de dados.
        Retorna (ok, mensagem_diagnostico)."""
        diagnostico = []
        ok = True

        # 1. Verificar se o host e acessivel
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(3)
            result = sock.connect_ex((host, port))
            sock.close()
            if result == 0:
                diagnostico.append("Servidor acessivel na porta " + str(port))
            else:
                diagnostico.append(f"PROBLEMA: Porta {port} nao esta aberta no servidor")
                diagnostico.append(f"  -> Verifique se o MySQL esta rodando")
                ok = False
        except socket.gaierror:
            diagnostico.append(f"PROBLEMA: Endereco '{host}' nao encontrado")
            diagnostico.append(f"  -> Verifique se o endereco esta correto")
            ok = False
        except Exception as e:
            diagnostico.append(f"PROBLEMA: Erro ao testar conexao: {e}")
            ok = False

        # 2. Verificar se e localhost
        if host in ("localhost", "127.0.0.1"):
            diagnostico.append("Banco de dados configurado localmente (neste PC)")
        else:
            diagnostico.append(f"Banco de dados em servidor remoto: {host}")

        return ok, "\n".join(diagnostico)

    @staticmethod
    def obter_estatisticas_erros():
        """Retorna estatisticas dos erros ocorridos na sessao."""
        if not ErroAmigavel._erro_counter:
            return "Nenhum erro registrado nesta sessao."
        stats = []
        for cod, count in sorted(ErroAmigavel._erro_counter.items(),
                                   key=lambda x: x[1], reverse=True):
            ultimo = ErroAmigavel._ultimo_erro_time.get(cod, 0)
            if ultimo:
                ultimo_str = datetime.datetime.fromtimestamp(ultimo).strftime("%H:%M:%S")
            else:
                ultimo_str = "N/A"
            stats.append(f"  {cod}: {count}x (ultimo: {ultimo_str})")
        return "Erros desta sessao:\n" + "\n".join(stats)



