# ============================================================================
# GERENCIADOR DE LICENCA (Alinhado com LicencaManager.java do Android)
# ============================================================================

class LicencaManager:
    """Gerenciador de licenca do PDV Pro Desktop.
    Replica a logica do LicencaManager.java do Android:
    - Gera contra-chave unica por maquina (MD5 do machine_id + '_PDV')
    - Valida chave de ativacao via SHA-256(contraChave + SECRET_KEY + dataExpiracao)
    - Cache local em arquivo JSON (equivalente ao SharedPreferences do Android)
    - Verificacao no banco MySQL (tabela licenca)
    - Bloqueio do sistema quando licenca invalida, faltante ou expirada
    - Aceita licencas ativadas por QUALQUER dispositivo (Android ou Desktop)
      desde que os dados (contra_chave + chave_ativacao + data_expiracao) sejam
      consistentes entre si no banco MySQL.
    """
    SECRET_KEY = "PDV_PRO_V3_2024_SECRET"
    _cache = None
    _lock = threading.Lock()
    _last_known_date = None  # Maior data ja vista (anti-fraude de relogio)
    _date_fraud_detected = False  # Flag de fraude de data detectada

    # ---- PROTECAO ANTI-FRAUDE DE DATA ----

    @staticmethod
    def _obter_hora_ntp(timeout=3):
        """Obtem a data/hora atual de um servidor NTP (sem dependencias externas).
        Usa protocolo NTP puro via socket UDP.
        Retorna datetime.date ou None se falhar."""
        NTP_SERVERS = [
            "pool.ntp.org",
            "time.google.com",
            "time.windows.com",
            "time.nist.gov",
            "a.ntp.br",
        ]
        NTP_EPOCH = datetime.datetime(1900, 1, 1)
        for server in NTP_SERVERS:
            try:
                client = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                client.settimeout(timeout)
                # Pacote NTP: 48 bytes, primeiro byte = 0x1B (LI=0, VN=3, Mode=3)
                data = b'\x1b' + 47 * b'\0'
                client.sendto(data, (server, 123))
                resp, _ = client.recvfrom(1024)
                client.close()
                if len(resp) >= 48:
                    # Transmit Timestamp esta nos bytes 40-47
                    t = struct.unpack('!12I', resp)[10]
                    # Converter NTP timestamp para datetime
                    ntp_time = NTP_EPOCH + datetime.timedelta(seconds=t)
                    print(f"[LICENCA] Hora NTP obtida de {server}: {ntp_time.date()}")
                    return ntp_time.date()
            except Exception as e:
                print(f"[LICENCA] Falha NTP ({server}): {e}")
                continue
        print("[LICENCA] Nao foi possivel obter hora de nenhum servidor NTP")
        return None

    @staticmethod
    def _obter_hora_mysql():
        """Obtem a data atual do servidor MySQL via SELECT CURDATE().
        Retorna datetime.date ou None se falhar."""
        try:
            db = DatabaseHelper.get_instance()
            rows = db.execute_query("SELECT CURDATE() AS hoje")
            if rows:
                hoje_db = rows[0].get("hoje")
                if hoje_db:
                    if isinstance(hoje_db, datetime.date):
                        print(f"[LICENCA] Hora MySQL: {hoje_db}")
                        return hoje_db
                    # Se vier como string
                    dt = datetime.datetime.strptime(str(hoje_db)[:10], "%Y-%m-%d").date()
                    print(f"[LICENCA] Hora MySQL (str): {dt}")
                    return dt
        except Exception as e:
            print(f"[LICENCA] Falha ao obter hora do MySQL: {e}")
        return None

    @staticmethod
    def _carregar_date_control():
        """Carrega o arquivo de controle de data (maior data ja vista)."""
        try:
            if os.path.exists(LICENCA_DATE_CONTROL_FILE):
                with open(LICENCA_DATE_CONTROL_FILE, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if isinstance(data, dict):
                    last_str = data.get("last_known_date")
                    if last_str:
                        return datetime.datetime.strptime(last_str, "%Y-%m-%d").date()
        except Exception as e:
            print(f"[LICENCA] Erro ao carregar date_control: {e}")
        return None

    @staticmethod
    def _salvar_date_control(data_atual):
        """Salva a maior data ja vista no arquivo de controle."""
        try:
            data_str = data_atual.strftime("%Y-%m-%d") if isinstance(data_atual, datetime.date) else str(data_atual)
            control = {
                "last_known_date": data_str,
                "last_update_ts": time.time()
            }
            tmp_file = LICENCA_DATE_CONTROL_FILE + ".tmp"
            with open(tmp_file, "w", encoding="utf-8") as f:
                json.dump(control, f, indent=2)
                f.flush()
                os.fsync(f.fileno())
            if os.path.exists(LICENCA_DATE_CONTROL_FILE):
                try:
                    os.remove(LICENCA_DATE_CONTROL_FILE)
                except Exception:
                    pass
            os.rename(tmp_file, LICENCA_DATE_CONTROL_FILE)
            LicencaManager._last_known_date = data_atual
            print(f"[LICENCA] Date control salvo: {data_str}")
        except Exception as e:
            print(f"[LICENCA] Erro ao salvar date_control: {e}")

    @staticmethod
    def _obter_data_confiavel():
        """Obtem a data atual de forma confiavel, detectando manipulacao de relogio.
        Estrategia:
        1. Tenta obter data do MySQL (fonte mais confiavel, servidor externo)
        2. Tenta obter data via NTP (fonte online)
        3. Compara com last_known_date (maior data ja vista)
        4. Se data local < last_known_date e nao ha fonte externa, BLOQUEIA
        Retorna (datetime.date, bool_fraude_detectada)"""
        data_local = datetime.date.today()
        fraude = False

        # Carregar last_known_date do disco se ainda nao carregou
        if LicencaManager._last_known_date is None:
            LicencaManager._last_known_date = LicencaManager._carregar_date_control()

        last_known = LicencaManager._last_known_date

        # Tentar obter data de fonte externa confiavel
        data_externa = None
        # 1) MySQL
        data_externa = LicencaManager._obter_hora_mysql()
        # 2) NTP (se MySQL falhou)
        if data_externa is None:
            data_externa = LicencaManager._obter_hora_ntp()

        if data_externa is not None:
            # Temos data externa confiavel
            # Verificar se data local esta muito diferente (tolerancia de 1 dia)
            diff = abs((data_local - data_externa).days)
            if diff > 1:
                print(f"[LICENCA] ALERTA: Data local ({data_local}) difere da "
                      f"data externa ({data_externa}) em {diff} dias!")
                fraude = True
            # Usar a data externa como referencia
            data_confiavel = data_externa
        else:
            # Sem fonte externa - usar data local mas verificar contra last_known
            data_confiavel = data_local

        # Verificar contra last_known_date (anti-retrocesso)
        if last_known is not None:
            if data_confiavel < last_known:
                print(f"[LICENCA] FRAUDE DETECTADA: Data confiavel ({data_confiavel}) "
                      f"e ANTERIOR a ultima data conhecida ({last_known})!")
                fraude = True
                # Usar a last_known_date como data real (nao deixar voltar)
                data_confiavel = last_known

        # Atualizar last_known_date se a data atual e maior
        if last_known is None or data_confiavel > last_known:
            LicencaManager._salvar_date_control(data_confiavel)

        if fraude:
            LicencaManager._date_fraud_detected = True
            print(f"[LICENCA] Data confiavel final: {data_confiavel} (FRAUDE DETECTADA)")
        else:
            LicencaManager._date_fraud_detected = False
            print(f"[LICENCA] Data confiavel final: {data_confiavel}")

        return data_confiavel, fraude

    @staticmethod
    def _get_machine_id():
        """Gera um identificador unico da maquina (equivalente ao ANDROID_ID).
        Usa combinacao de hostname + MAC address para unicidade."""
        try:
            import uuid
            mac = uuid.getnode()
            hostname = _platform.node()
            machine_id = f"{hostname}_{mac}"
        except Exception:
            machine_id = "DEFAULT_DEVICE"
        return machine_id

    @staticmethod
    def gerar_contra_chave():
        """Gera a contra-chave unica desta maquina.
        Equivalente a LicencaManager.gerarContraChave() do Android.
        Retorna 16 caracteres hexadecimais maiusculos."""
        try:
            machine_id = LicencaManager._get_machine_id()
            raw = machine_id + "_PDV"
            md = hashlib.md5(raw.encode("utf-8")).digest()
            return "".join(f"{b:02X}" for b in md[:8])
        except Exception:
            return "0000000000000000"

    @staticmethod
    def gerar_chave_ativacao(contra_chave, data_expiracao):
        """Gera a chave de ativacao esperada.
        Equivalente a LicencaManager.gerarChaveAtivacao() do Android.
        Formato: XXXX-XXXX-XXXX-XXXX-XXXX-XXXX-XXXX-XXXX"""
        try:
            raw = contra_chave.strip() + LicencaManager.SECRET_KEY + data_expiracao.strip()
            digest = hashlib.sha256(raw.encode("utf-8")).digest()
            hex_str = "".join(f"{b:02X}" for b in digest[:16])
            # Formato: XXXX-XXXX-XXXX-XXXX-XXXX-XXXX-XXXX-XXXX
            parts = [hex_str[i:i+4] for i in range(0, 32, 4)]
            return "-".join(parts)
        except Exception:
            return ""

    @staticmethod
    def validar_chave(contra_chave, chave_ativacao, data_expiracao):
        """Valida se a chave de ativacao corresponde a contra-chave e data.
        Equivalente a LicencaManager.validarChave() do Android.
        Aplica strip() e upper() para evitar falhas por espacos ou case."""
        if not contra_chave or not chave_ativacao or not data_expiracao:
            return False
        ck = contra_chave.strip()
        ca = chave_ativacao.strip()
        de = data_expiracao.strip()
        chave_esperada = LicencaManager.gerar_chave_ativacao(ck, de)
        return chave_esperada.upper() == ca.upper()

    @staticmethod
    def _normalizar_data_exp(data_exp):
        """Normaliza a data de expiracao para o formato yyyy-MM-dd.
        Aceita formatos: 'yyyy-MM-dd', 'yyyy-MM-dd HH:mm:ss', etc.
        Retorna string no formato 'yyyy-MM-dd' ou None se invalida."""
        if not data_exp:
            return None
        data_exp = str(data_exp).strip()
        # Se ja esta no formato correto
        if len(data_exp) == 10:
            try:
                datetime.datetime.strptime(data_exp, "%Y-%m-%d")
                return data_exp
            except ValueError:
                pass
        # Tentar extrair apenas a parte da data (primeiros 10 chars)
        if len(data_exp) >= 10:
            parte_data = data_exp[:10]
            try:
                datetime.datetime.strptime(parte_data, "%Y-%m-%d")
                return parte_data
            except ValueError:
                pass
        # Tentar parse completo com hora
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S", "%d/%m/%Y", "%Y-%m-%d"):
            try:
                dt = datetime.datetime.strptime(data_exp, fmt)
                return dt.strftime("%Y-%m-%d")
            except ValueError:
                continue
        return None

    @staticmethod
    def _salvar_cache_local(contra_chave, chave_ativacao, data_expiracao, valida):
        """Salva dados da licenca no cache local (arquivo JSON).
        Equivalente a salvarCacheLocal() do Android (SharedPreferences).
        Usa escrita atomica (temp + rename) para evitar corrupcao."""
        try:
            # Normalizar data para garantir formato consistente yyyy-MM-dd
            data_norm = LicencaManager._normalizar_data_exp(data_expiracao) if data_expiracao else data_expiracao
            cache = {
                "contra_chave": contra_chave.strip() if contra_chave else contra_chave,
                "chave_ativacao": chave_ativacao.strip() if chave_ativacao else chave_ativacao,
                "data_expiracao": (data_norm or data_expiracao).strip() if data_expiracao else data_expiracao,
                "licenca_valida": valida,
                "last_check_time": time.time()
            }
            # Escrita atomica: grava em arquivo temporario e renomeia
            tmp_file = LICENCA_CACHE_FILE + ".tmp"
            with open(tmp_file, "w", encoding="utf-8") as f:
                json.dump(cache, f, indent=2)
                f.flush()
                os.fsync(f.fileno())
            # Rename atomico (substitui o arquivo original)
            if os.path.exists(LICENCA_CACHE_FILE):
                try:
                    os.remove(LICENCA_CACHE_FILE)
                except Exception:
                    pass
            os.rename(tmp_file, LICENCA_CACHE_FILE)
            LicencaManager._cache = cache
            print(f"[LICENCA] Cache local salvo: {LICENCA_CACHE_FILE}")
        except Exception as e:
            print(f"[LICENCA] Erro ao salvar cache de licenca: {e}")
            # Fallback: tentar escrita direta se atomica falhou
            try:
                with open(LICENCA_CACHE_FILE, "w", encoding="utf-8") as f:
                    json.dump(cache, f, indent=2)
                LicencaManager._cache = cache
                print(f"[LICENCA] Cache local salvo (fallback direto): {LICENCA_CACHE_FILE}")
            except Exception as e2:
                print(f"[LICENCA] ERRO CRITICO ao salvar cache (fallback): {e2}")

    @staticmethod
    def _carregar_cache_local():
        """Carrega dados da licenca do cache local."""
        if LicencaManager._cache is not None:
            return LicencaManager._cache
        try:
            if os.path.exists(LICENCA_CACHE_FILE):
                print(f"[LICENCA] Carregando cache de: {LICENCA_CACHE_FILE}")
                with open(LICENCA_CACHE_FILE, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if isinstance(data, dict) and data.get("contra_chave"):
                    LicencaManager._cache = data
                    print(f"[LICENCA] Cache carregado com sucesso "
                          f"(ck={data.get('contra_chave', '')[:8]}..., "
                          f"valida={data.get('licenca_valida')}, "
                          f"data_exp={data.get('data_expiracao')})")
                    return LicencaManager._cache
                else:
                    print(f"[LICENCA] Cache local existe mas esta vazio ou invalido")
            else:
                print(f"[LICENCA] Arquivo de cache nao encontrado: {LICENCA_CACHE_FILE}")
        except json.JSONDecodeError as e:
            print(f"[LICENCA] Cache local corrompido (JSON invalido): {e}")
            # Tentar remover cache corrompido
            try:
                os.remove(LICENCA_CACHE_FILE)
            except Exception:
                pass
        except Exception as e:
            print(f"[LICENCA] Erro ao carregar cache de licenca: {e}")
        return None

    @staticmethod
    def _limpar_cache_local():
        """Limpa o cache local da licenca."""
        print(f"[LICENCA] Limpando cache local (memoria e disco)...")
        LicencaManager._cache = None
        try:
            if os.path.exists(LICENCA_CACHE_FILE):
                os.remove(LICENCA_CACHE_FILE)
                print(f"[LICENCA] Arquivo de cache removido: {LICENCA_CACHE_FILE}")
            else:
                print(f"[LICENCA] Arquivo de cache nao existia: {LICENCA_CACHE_FILE}")
        except Exception as e:
            print(f"[LICENCA] Erro ao remover cache: {e}")

    @staticmethod
    def _verificar_cache_local():
        """Verifica a licenca usando o cache local.
        Equivalente a verificarCacheLocal() do Android."""
        try:
            cache = LicencaManager._carregar_cache_local()
            if not cache:
                print("[LICENCA] Cache local: nenhum cache disponivel")
                return False
            if not cache.get("licenca_valida", False):
                print("[LICENCA] Cache local: flag licenca_valida=False")
                return False
            contra_chave = cache.get("contra_chave")
            chave_ativacao = cache.get("chave_ativacao")
            data_exp = cache.get("data_expiracao")
            if not contra_chave or not chave_ativacao or not data_exp:
                print(f"[LICENCA] Cache local: campos vazios "
                      f"(ck={'OK' if contra_chave else 'VAZIO'}, "
                      f"ca={'OK' if chave_ativacao else 'VAZIO'}, "
                      f"de={'OK' if data_exp else 'VAZIO'})")
                return False
            # Normalizar data
            data_exp_original = data_exp
            data_exp = LicencaManager._normalizar_data_exp(data_exp)
            if not data_exp:
                print(f"[LICENCA] Cache local: data invalida '{data_exp_original}'")
                return False
            # Validar a chave localmente
            if not LicencaManager.validar_chave(contra_chave, chave_ativacao, data_exp):
                print(f"[LICENCA] Cache local: chave INVALIDA "
                      f"(ck={contra_chave[:8]}..., de={data_exp})")
                # Tentar validar com data original (caso normalização tenha alterado)
                if data_exp != data_exp_original:
                    if LicencaManager.validar_chave(contra_chave, chave_ativacao, data_exp_original):
                        print(f"[LICENCA] Cache local: chave VALIDA com data original '{data_exp_original}'")
                        # Atualizar cache com data normalizada e chave correta
                        chave_correta = LicencaManager.gerar_chave_ativacao(contra_chave, data_exp)
                        LicencaManager._salvar_cache_local(contra_chave, chave_correta, data_exp, True)
                        exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
                        hoje_confiavel, fraude = LicencaManager._obter_data_confiavel()
                        if fraude:
                            print("[LICENCA] Cache local: FRAUDE DE DATA detectada - licenca BLOQUEADA")
                            return False
                        return hoje_confiavel <= exp_date
                return False
            # Verificar se nao expirou (usando data confiavel anti-fraude)
            exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
            hoje, fraude = LicencaManager._obter_data_confiavel()
            if fraude:
                print("[LICENCA] Cache local: FRAUDE DE DATA detectada - licenca BLOQUEADA")
                return False
            valida = hoje <= exp_date
            if valida:
                print(f"[LICENCA] Cache local: licenca VALIDA ate {data_exp} "
                      f"({(exp_date - hoje).days} dias restantes)")
            else:
                print(f"[LICENCA] Cache local: licenca EXPIRADA em {data_exp}")
            return valida
        except Exception as e:
            print(f"[LICENCA] Erro ao verificar cache local de licenca: {e}")
            import traceback
            traceback.print_exc()
            return False

    @staticmethod
    def _verificar_licenca_banco():
        """Verifica a licenca diretamente no banco MySQL.
        Equivalente a verificarLicencaBanco() do Android.
        Aceita licencas ativadas por qualquer dispositivo (Android ou Desktop)
        desde que contra_chave + chave_ativacao + data_expiracao sejam consistentes."""
        try:
            from mysql.connector import Error as MySQLError
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT contra_chave, chave_ativacao, "
                "DATE_FORMAT(data_expiracao, '%%Y-%%m-%%d') AS data_exp "
                "FROM licenca ORDER BY id DESC LIMIT 1"
            )
            if rows:
                row = rows[0]
                contra_chave = (row.get("contra_chave") or "").strip()
                chave_ativacao = (row.get("chave_ativacao") or "").strip()
                data_exp = (row.get("data_exp") or "").strip()
                print(f"[LICENCA] Banco: encontrada licenca "
                      f"(ck={contra_chave[:8] if contra_chave else 'VAZIO'}..., "
                      f"data_exp={data_exp or 'VAZIO'})")
                if not contra_chave or not chave_ativacao or not data_exp:
                    print("[LICENCA] Banco: campos vazios na licenca")
                    return False
                # Normalizar data
                data_exp = LicencaManager._normalizar_data_exp(data_exp)
                if not data_exp:
                    print(f"[LICENCA] Banco: data de expiracao invalida")
                    return False
                # Validar chave - a contra_chave pode ser de qualquer dispositivo
                # (Android ou Desktop). A validacao verifica se os 3 campos sao
                # consistentes entre si, independente de quem gerou.
                if not LicencaManager.validar_chave(contra_chave, chave_ativacao, data_exp):
                    print(f"[LICENCA] Banco: chave de ativacao INVALIDA "
                          f"(contra_chave={contra_chave[:8]}..., "
                          f"data_exp={data_exp})")
                    return False
                # Verificar expiracao (usando data confiavel anti-fraude)
                exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
                hoje, fraude = LicencaManager._obter_data_confiavel()
                if fraude:
                    print("[LICENCA] Banco: FRAUDE DE DATA detectada - licenca BLOQUEADA")
                    LicencaManager._limpar_cache_local()
                    return False
                valida = hoje <= exp_date
                # Atualizar cache local com dados do banco
                # (inclui contra_chave do dispositivo que ativou, nao a local)
                if valida:
                    LicencaManager._salvar_cache_local(
                        contra_chave, chave_ativacao, data_exp, True)
                    print(f"[LICENCA] Banco: licenca VALIDA ate {data_exp} "
                          f"({(exp_date - hoje).days} dias restantes)")
                else:
                    LicencaManager._limpar_cache_local()
                    print(f"[LICENCA] Banco: licenca EXPIRADA em {data_exp}")
                return valida
            print("[LICENCA] Banco: nenhuma licenca encontrada")
            return False
        except Exception as e:
            print(f"[LICENCA] Erro ao verificar licenca no banco: {e}")
            raise

    @staticmethod
    def verificar_licenca():
        """Verifica se a licenca e valida.
        Estrategia robusta com fallback:
        1. Verifica cache local primeiro (rapido, offline)
        2. Tenta verificar no banco remoto
        3. Se banco responde com licenca valida, usa banco e atualiza cache
        4. Se banco responde sem licenca mas cache e valido, confia no cache
           (protege contra tabela vazia/recriada no banco)
        5. Se banco falha na conexao, confia no cache local
        Retorna True se licenca valida, False caso contrario."""
        with LicencaManager._lock:
            print("[LICENCA] Iniciando verificacao de licenca...")
            print(f"[LICENCA] APP_DIR: {APP_DIR}")
            print(f"[LICENCA] Cache file: {LICENCA_CACHE_FILE}")
            print(f"[LICENCA] Cache file existe: {os.path.exists(LICENCA_CACHE_FILE)}")

            # PASSO 1: Verificar cache local
            cache_valido = LicencaManager._verificar_cache_local()
            print(f"[LICENCA] Cache local: {'VALIDO' if cache_valido else 'INVALIDO/AUSENTE'}")

            # PASSO 2: Tentar verificar no banco remoto
            banco_verificado = False
            banco_resultado = False
            try:
                banco_resultado = LicencaManager._verificar_licenca_banco()
                banco_verificado = True
                print(f"[LICENCA] Banco: {'VALIDA' if banco_resultado else 'INVALIDA/AUSENTE'}")
            except Exception as e:
                print(f"[LICENCA] Banco: FALHA na conexao ({e})")

            # PASSO 3: Decidir resultado com logica robusta
            if banco_verificado and banco_resultado:
                # Banco confirmou licenca valida - melhor cenario
                print("[LICENCA] Decisao: BANCO confirmou licenca VALIDA")
                return True

            if banco_verificado and not banco_resultado:
                # Banco respondeu mas nao encontrou licenca valida
                if cache_valido:
                    # Cache local tem licenca valida - pode ser que o banco
                    # perdeu os dados (tabela recriada, migração, etc.)
                    # Restaurar a licenca do cache para o banco
                    print("[LICENCA] Banco sem licenca mas CACHE VALIDO - "
                          "restaurando licenca do cache para o banco...")
                    try:
                        cache = LicencaManager._carregar_cache_local()
                        if cache:
                            ck = cache.get("contra_chave", "").strip()
                            ca = cache.get("chave_ativacao", "").strip()
                            de = cache.get("data_expiracao", "").strip()
                            de = LicencaManager._normalizar_data_exp(de) or de
                            if ck and ca and de:
                                db = DatabaseHelper.get_instance()
                                db.execute_update("DELETE FROM licenca")
                                db.execute_update(
                                    "INSERT INTO licenca (contra_chave, chave_ativacao, "
                                    "data_ativacao, data_expiracao) "
                                    "VALUES (%s, %s, NOW(), %s)",
                                    (ck, ca, de)
                                )
                                print("[LICENCA] Licenca restaurada do cache para o banco")
                    except Exception as e:
                        print(f"[LICENCA] Nao foi possivel restaurar licenca no banco: {e}")
                    print("[LICENCA] Decisao: usando CACHE LOCAL valido -> LICENCA VALIDA")
                    return True
                else:
                    # Banco sem licenca e cache tambem invalido
                    print("[LICENCA] Decisao: banco sem licenca e cache invalido -> BLOQUEADO")
                    return False

            if not banco_verificado:
                # Banco indisponivel - usar cache como fallback
                if cache_valido:
                    print("[LICENCA] Decisao: banco indisponivel, usando CACHE LOCAL -> LICENCA VALIDA")
                    return True

            print("[LICENCA] Decisao: sem licenca valida em nenhuma fonte -> BLOQUEADO")
            return False

    @staticmethod
    def is_licenca_expirada():
        """Verifica se existe licenca cadastrada mas VENCIDA.
        Equivalente a isLicencaExpirada() do Android.
        Usa data confiavel anti-fraude."""
        try:
            hoje, _ = LicencaManager._obter_data_confiavel()
        except Exception:
            hoje = datetime.date.today()
        # Verificar cache local
        try:
            cache = LicencaManager._carregar_cache_local()
            if cache:
                data_exp = cache.get("data_expiracao")
                chave = cache.get("chave_ativacao")
                if data_exp and chave:
                    data_exp = LicencaManager._normalizar_data_exp(data_exp)
                    if data_exp:
                        exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
                        if exp_date < hoje:
                            return True
        except Exception:
            pass
        # Verificar banco
        try:
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT DATE_FORMAT(data_expiracao, '%%Y-%%m-%%d') AS data_exp "
                "FROM licenca ORDER BY id DESC LIMIT 1"
            )
            if rows:
                data_exp = (rows[0].get("data_exp") or "").strip()
                data_exp = LicencaManager._normalizar_data_exp(data_exp)
                if data_exp:
                    exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
                    if exp_date < hoje:
                        return True
        except Exception:
            pass
        return False

    @staticmethod
    def get_data_expiracao():
        """Retorna a data de expiracao da licenca (yyyy-MM-dd) ou None."""
        # Cache local primeiro
        try:
            cache = LicencaManager._carregar_cache_local()
            if cache:
                data_exp = cache.get("data_expiracao")
                if data_exp:
                    norm = LicencaManager._normalizar_data_exp(data_exp)
                    if norm:
                        return norm
        except Exception:
            pass
        # Banco
        try:
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT DATE_FORMAT(data_expiracao, '%%Y-%%m-%%d') AS data_exp "
                "FROM licenca ORDER BY id DESC LIMIT 1"
            )
            if rows:
                data_exp = (rows[0].get("data_exp") or "").strip()
                return LicencaManager._normalizar_data_exp(data_exp)
        except Exception:
            pass
        return None

    @staticmethod
    def get_dias_para_vencimento():
        """Retorna dias restantes ate o vencimento. Negativo se vencida.
        Usa data confiavel anti-fraude."""
        data_exp = LicencaManager.get_data_expiracao()
        if not data_exp:
            return -1
        try:
            exp_date = datetime.datetime.strptime(data_exp, "%Y-%m-%d").date()
            try:
                hoje, _ = LicencaManager._obter_data_confiavel()
            except Exception:
                hoje = datetime.date.today()
            return (exp_date - hoje).days
        except Exception:
            return -1

    @staticmethod
    def ativar_licenca(contra_chave, chave_ativacao, data_expiracao):
        """Ativa a licenca (salva no cache local e no banco).
        Equivalente a ativarLicenca() do Android.
        data_expiracao no formato yyyy-MM-dd.
        
        Fluxo:
        1. Normaliza e valida os inputs
        2. Valida a chave de ativacao criptograficamente
        3. Salva no cache local (JSON) para acesso rapido
        4. Salva no banco MySQL para persistencia e sincronizacao
        5. Verifica se o salvamento no banco foi bem-sucedido
        6. Atualiza o cache interno em memoria
        """
        # Normalizar inputs
        contra_chave = (contra_chave or "").strip()
        chave_ativacao = (chave_ativacao or "").strip()
        data_expiracao = (data_expiracao or "").strip()
        data_expiracao = LicencaManager._normalizar_data_exp(data_expiracao) or data_expiracao

        print(f"[LICENCA] Tentando ativar licenca...")
        print(f"[LICENCA] Contra-chave: {contra_chave}")
        print(f"[LICENCA] Data expiracao: {data_expiracao}")

        # Validar campos obrigatorios
        if not contra_chave or not chave_ativacao or not data_expiracao:
            print("[LICENCA] ERRO: Campos obrigatorios vazios")
            return False

        # Validar data nao retroativa (usando data confiavel)
        try:
            exp_date = datetime.datetime.strptime(data_expiracao, "%Y-%m-%d").date()
            try:
                hoje_confiavel, _ = LicencaManager._obter_data_confiavel()
            except Exception:
                hoje_confiavel = datetime.date.today()
            if exp_date < hoje_confiavel:
                print(f"[LICENCA] ERRO: Data expirada ({data_expiracao})")
                return False
        except Exception:
            print(f"[LICENCA] ERRO: Data invalida ({data_expiracao})")
            return False

        # Validar chave criptograficamente
        if not LicencaManager.validar_chave(contra_chave, chave_ativacao, data_expiracao):
            print("[LICENCA] ERRO: Chave de ativacao invalida")
            return False

        print("[LICENCA] Chave validada com sucesso!")

        # Salvar no cache local PRIMEIRO (garante acesso imediato)
        LicencaManager._salvar_cache_local(
            contra_chave, chave_ativacao, data_expiracao, True)
        print("[LICENCA] Cache local salvo com sucesso")

        # Verificar se o cache foi realmente persistido no disco
        try:
            if os.path.exists(LICENCA_CACHE_FILE):
                with open(LICENCA_CACHE_FILE, "r", encoding="utf-8") as f:
                    cache_verificado = json.load(f)
                if cache_verificado.get("licenca_valida") and cache_verificado.get("contra_chave"):
                    print(f"[LICENCA] Cache verificado no disco: OK "
                          f"(ck={cache_verificado.get('contra_chave', '')[:8]}...)")
                else:
                    print("[LICENCA] AVISO: Cache no disco parece incompleto")
            else:
                print(f"[LICENCA] AVISO: Arquivo de cache NAO encontrado apos salvamento: {LICENCA_CACHE_FILE}")
        except Exception as e:
            print(f"[LICENCA] AVISO: Erro ao verificar cache no disco: {e}")

        # Salvar no banco MySQL
        banco_salvo = False
        try:
            db = DatabaseHelper.get_instance()
            # Limpar licencas anteriores
            db.execute_update("DELETE FROM licenca")
            # Inserir nova licenca
            db.execute_update(
                "INSERT INTO licenca (contra_chave, chave_ativacao, data_ativacao, data_expiracao) "
                "VALUES (%s, %s, NOW(), %s)",
                (contra_chave, chave_ativacao, data_expiracao)
            )
            # Verificar se foi salvo corretamente no banco
            rows = db.execute_query(
                "SELECT contra_chave, chave_ativacao, "
                "DATE_FORMAT(data_expiracao, '%%Y-%%m-%%d') AS data_exp "
                "FROM licenca ORDER BY id DESC LIMIT 1"
            )
            if rows:
                row = rows[0]
                ck_banco = (row.get("contra_chave") or "").strip()
                ca_banco = (row.get("chave_ativacao") or "").strip()
                de_banco = (row.get("data_exp") or "").strip()
                if (ck_banco.upper() == contra_chave.upper() and
                    ca_banco.upper() == chave_ativacao.upper() and
                    de_banco == data_expiracao):
                    banco_salvo = True
                    print("[LICENCA] Licenca salva e verificada no banco com sucesso!")
                else:
                    print(f"[LICENCA] AVISO: Dados no banco divergem do esperado")
                    print(f"[LICENCA]   Banco: ck={ck_banco}, ca={ca_banco[:12]}..., de={de_banco}")
                    print(f"[LICENCA]   Local: ck={contra_chave}, ca={chave_ativacao[:12]}..., de={data_expiracao}")
                    # Mesmo com divergencia, se o banco tem dados, considerar salvo
                    if ck_banco and ca_banco and de_banco:
                        banco_salvo = True
                        print("[LICENCA] Banco tem dados - considerando salvo")
            else:
                print("[LICENCA] AVISO: Nenhum registro encontrado no banco apos INSERT")
        except Exception as e:
            print(f"[LICENCA] AVISO: Erro ao salvar licenca no banco: {e}")
            print(f"[LICENCA] Cache local ja foi salvo - sistema funcionara offline")

        if banco_salvo:
            print("[LICENCA] Ativacao completa (cache + banco)")
        else:
            print("[LICENCA] Ativacao parcial (apenas cache local)")

        # Forcar atualizacao do cache em memoria para garantir consistencia
        LicencaManager._cache = {
            "contra_chave": contra_chave,
            "chave_ativacao": chave_ativacao,
            "data_expiracao": data_expiracao,
            "licenca_valida": True,
            "last_check_time": time.time()
        }
        print("[LICENCA] Cache em memoria atualizado")

        return True

    @staticmethod
    def limpar_licenca(senha):
        """Limpa a licenca (requer senha de confirmacao)."""
        if senha != "2394":
            return False
        LicencaManager._limpar_cache_local()
        try:
            db = DatabaseHelper.get_instance()
            db.execute_update("DELETE FROM licenca")
        except Exception:
            pass
        return True


# ============================================================================
# LOGGER DE AUDITORIA
# ============================================================================

class AuditLogger:
    """Registra acoes criticas do sistema em arquivo de log para auditoria."""
    _lock = threading.Lock()

    @staticmethod
    def log(acao, detalhes="", usuario=""):
        """Grava uma entrada no log de auditoria."""
        try:
            with AuditLogger._lock:
                ts = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                user_info = usuario or "Sistema"
                linha = f"[{ts}] [{user_info}] {acao}"
                if detalhes:
                    linha += f" | {detalhes}"
                with open(AUDIT_LOG_FILE, "a", encoding="utf-8", errors="replace") as f:
                    f.write(linha + "\n")
        except Exception:
            pass

    @staticmethod
    def get_entries(limit=200):
        """Retorna as ultimas N entradas do log."""
        try:
            if not os.path.exists(AUDIT_LOG_FILE):
                return []
            with open(AUDIT_LOG_FILE, "r", encoding="utf-8", errors="replace") as f:
                linhas = f.readlines()
            return [l.strip() for l in linhas[-limit:] if l.strip()]
        except Exception:
            return []


# ============================================================================
# MOTOR DE ANIMACOES E EFEITOS VISUAIS
# ============================================================================

class AnimationEngine:
    """Motor de animacoes centralizado para efeitos visuais futuristicos."""

    @staticmethod
    def fade_in(widget, duration=400, steps=20, callback=None):
        """Efeito de fade-in suave usando opacidade simulada."""
        if not widget.winfo_exists():
            return
        step_time = max(1, duration // steps)
        current_step = [0]

        def _step():
            if not widget.winfo_exists():
                return
            current_step[0] += 1
            alpha = current_step[0] / steps
            try:
                # Simular fade alterando a cor de fundo gradualmente
                r = int(10 + alpha * (int(widget.cget("bg")[1:3], 16) - 10))
                g = int(14 + alpha * (int(widget.cget("bg")[3:5], 16) - 14))
                b = int(26 + alpha * (int(widget.cget("bg")[5:7], 16) - 26))
            except Exception:
                pass
            if current_step[0] < steps:
                widget.after(step_time, _step)
            elif callback:
                callback()

        _step()

    @staticmethod
    def pulse_glow(canvas, item_id, color1, color2, duration=2000, root=None):
        """Efeito de pulso/glow continuo em um item do canvas."""
        if root is None:
            return
        steps = 60
        step_time = max(1, duration // steps)
        current = [0]
        direction = [1]

        def _parse_color(c):
            return (int(c[1:3], 16), int(c[3:5], 16), int(c[5:7], 16))

        def _to_hex(r, g, b):
            return f"#{max(0,min(255,r)):02x}{max(0,min(255,g)):02x}{max(0,min(255,b)):02x}"

        r1, g1, b1 = _parse_color(color1)
        r2, g2, b2 = _parse_color(color2)

        def _step():
            try:
                if not canvas.winfo_exists():
                    return
                t = current[0] / steps
                # Suavizar com seno
                t = (math.sin(t * math.pi * 2 - math.pi / 2) + 1) / 2
                r = int(r1 + (r2 - r1) * t)
                g = int(g1 + (g2 - g1) * t)
                b = int(b1 + (b2 - b1) * t)
                canvas.itemconfig(item_id, fill=_to_hex(r, g, b))
                current[0] += direction[0]
                if current[0] >= steps:
                    direction[0] = -1
                elif current[0] <= 0:
                    direction[0] = 1
                root.after(step_time, _step)
            except Exception:
                pass

        _step()

    @staticmethod
    def slide_in(widget, direction="left", distance=50, duration=300, steps=15):
        """Efeito de slide-in suave."""
        if not widget.winfo_exists():
            return
        step_time = max(1, duration // steps)
        current_step = [0]

        def _step():
            if not widget.winfo_exists():
                return
            current_step[0] += 1
            progress = current_step[0] / steps
            # Easing: ease-out cubic
            progress = 1 - (1 - progress) ** 3
            if current_step[0] < steps:
                widget.after(step_time, _step)

        _step()

    @staticmethod
    def typewriter(label, text, speed=30, callback=None):
        """Efeito de digitacao (typewriter) em um label."""
        current = [0]

        def _type():
            if not label.winfo_exists():
                return
            current[0] += 1
            label.config(text=text[:current[0]])
            if current[0] < len(text):
                label.after(speed, _type)
            elif callback:
                callback()

        label.config(text="")
        label.after(speed, _type)


class ParticleSystem:
    """Sistema de particulas flutuantes para fundo animado."""

    def __init__(self, canvas, width, height, num_particles=40, root=None):
        self.canvas = canvas
        self.width = width
        self.height = height
        self.root = root
        self.particles = []
        self.running = True
        self._create_particles(num_particles)

    def _create_particles(self, num):
        colors = ["#00d4ff", "#7c3aed", "#f72585", "#4cc9f0", "#00f5a0",
                  "#1a3a5c", "#2a4a6c", "#0a2a4c"]
        for _ in range(num):
            x = random.randint(0, self.width)
            y = random.randint(0, self.height)
            size = random.uniform(1, 3.5)
            speed_x = random.uniform(-0.3, 0.3)
            speed_y = random.uniform(-0.5, -0.1)
            color = random.choice(colors)
            alpha = random.uniform(0.15, 0.6)
            # Ajustar cor com base na alpha simulada
            r, g, b = int(color[1:3], 16), int(color[3:5], 16), int(color[5:7], 16)
            r = int(r * alpha + 10 * (1 - alpha))
            g = int(g * alpha + 14 * (1 - alpha))
            b = int(b * alpha + 26 * (1 - alpha))
            actual_color = f"#{max(0,min(255,r)):02x}{max(0,min(255,g)):02x}{max(0,min(255,b)):02x}"

            particle_id = self.canvas.create_oval(
                x - size, y - size, x + size, y + size,
                fill=actual_color, outline=""
            )
            self.particles.append({
                "id": particle_id, "x": x, "y": y,
                "speed_x": speed_x, "speed_y": speed_y,
                "size": size, "base_color": color, "alpha": alpha
            })

    def animate(self):
        if not self.running:
            return
        try:
            if not self.canvas.winfo_exists():
                return
        except Exception:
            return

        for p in self.particles:
            p["x"] += p["speed_x"]
            p["y"] += p["speed_y"]

            # Wrap around
            if p["y"] < -10:
                p["y"] = self.height + 10
                p["x"] = random.randint(0, self.width)
            if p["x"] < -10:
                p["x"] = self.width + 10
            elif p["x"] > self.width + 10:
                p["x"] = -10

            try:
                self.canvas.coords(
                    p["id"],
                    p["x"] - p["size"], p["y"] - p["size"],
                    p["x"] + p["size"], p["y"] + p["size"]
                )
            except Exception:
                pass

        if self.root:
            self.root.after(50, self.animate)

    def stop(self):
        self.running = False

    def update_size(self, width, height):
        self.width = width
        self.height = height


class NeonBorderEffect:
    """Cria bordas neon brilhantes ao redor de widgets."""

    @staticmethod
    def apply(widget, color=COR_PRIMARIA, width=2):
        """Aplica borda neon a um widget."""
        widget.configure(
            highlightthickness=width,
            highlightcolor=color,
            highlightbackground=COR_CARD_BORDER
        )

    @staticmethod
    def apply_hover(widget, color_normal=COR_CARD_BORDER, color_hover=COR_PRIMARIA, width=2):
        """Aplica borda neon com efeito hover."""
        widget.configure(
            highlightthickness=width,
            highlightcolor=color_normal,
            highlightbackground=color_normal
        )
        widget.bind("<Enter>", lambda e: widget.configure(
            highlightcolor=color_hover, highlightbackground=color_hover))
        widget.bind("<Leave>", lambda e: widget.configure(
            highlightcolor=color_normal, highlightbackground=color_normal))


