# ============================================================================
# SISTEMA DE TOAST NOTIFICATIONS (nao bloqueia o fluxo)
# ============================================================================

class ToastManager:
    """Gerenciador de notificacoes toast nao-bloqueantes."""
    _toasts = []
    _root = None

    @classmethod
    def set_root(cls, root):
        cls._root = root

    @classmethod
    def show(cls, message, toast_type="info", duration=3000):
        """
        Exibe uma notificacao toast.
        toast_type: 'info' | 'success' | 'warning' | 'error'
        """
        if cls._root is None:
            return
        try:
            colors = {
                "info":    (COR_BOTAO_AZUL, "#ffffff"),
                "success": (COR_BOTAO_VERDE, "#ffffff"),
                "warning": (COR_ALERTA, "#000000"),
                "error":   (COR_ERRO, "#ffffff"),
            }
            icons_map = {
                "info": Icons.INFO,
                "success": Icons.CHECK,
                "warning": Icons.ALERT,
                "error": Icons.CROSS,
            }
            bg, fg = colors.get(toast_type, colors["info"])
            icon = icons_map.get(toast_type, Icons.INFO)

            toast = tk.Toplevel(cls._root)
            toast.overrideredirect(True)
            toast.attributes("-topmost", True)
            toast.configure(bg=bg)

            # Borda
            outer = tk.Frame(toast, bg=bg, padx=2, pady=2)
            outer.pack(fill="both", expand=True)
            inner = tk.Frame(outer, bg=bg, padx=14, pady=10)
            inner.pack(fill="both", expand=True)

            tk.Label(inner, text=f"{icon}  {message}", bg=bg, fg=fg,
                     font=("Segoe UI", 10, "bold"),
                     wraplength=340, justify="left").pack()

            # Posicionar no canto inferior direito
            cls._root.update_idletasks()
            sw = cls._root.winfo_screenwidth()
            sh = cls._root.winfo_screenheight()
            toast.update_idletasks()
            tw = toast.winfo_reqwidth()
            th = toast.winfo_reqheight()

            # Empilhar toasts
            offset_y = 20 + sum(getattr(t, '_toast_h', 50) + 8 for t in cls._toasts if t.winfo_exists())
            x = sw - tw - 20
            y = sh - offset_y - th - 50
            toast.geometry(f"+{max(0, x)}+{max(0, y)}")
            toast._toast_h = th

            cls._toasts.append(toast)

            def _destroy():
                try:
                    toast.destroy()
                    if toast in cls._toasts:
                        cls._toasts.remove(toast)
                except Exception:
                    pass

            # Auto-destruir apos duration ms
            toast.after(duration, _destroy)

            # Fechar ao clicar
            toast.bind("<Button-1>", lambda e: _destroy())

        except Exception as e:
            pass

    @classmethod
    def success(cls, msg, duration=3000):
        cls.show(msg, "success", duration)

    @classmethod
    def error(cls, msg, duration=4000):
        cls.show(msg, "error", duration)

    @classmethod
    def warning(cls, msg, duration=3500):
        cls.show(msg, "warning", duration)

    @classmethod
    def info(cls, msg, duration=3000):
        cls.show(msg, "info", duration)


# ============================================================================
# SISTEMA DE TOOLTIPS
# ============================================================================

class Tooltip:
    """Tooltip elegante que aparece ao passar o mouse sobre um widget."""

    def __init__(self, widget, text, delay=600):
        self.widget = widget
        self.text = text
        self.delay = delay
        self._tip_window = None
        self._id = None
        widget.bind("<Enter>", self._schedule, add="+")
        widget.bind("<Leave>", self._cancel, add="+")
        widget.bind("<ButtonPress>", self._cancel, add="+")

    def _schedule(self, event=None):
        self._cancel()
        self._id = self.widget.after(self.delay, self._show)

    def _cancel(self, event=None):
        if self._id:
            self.widget.after_cancel(self._id)
            self._id = None
        self._hide()

    def _show(self):
        if self._tip_window or not self.text:
            return
        try:
            x = self.widget.winfo_rootx() + 20
            y = self.widget.winfo_rooty() + self.widget.winfo_height() + 4
            self._tip_window = tw = tk.Toplevel(self.widget)
            tw.overrideredirect(True)
            tw.attributes("-topmost", True)
            tw.configure(bg=COR_CARD_BORDER)
            outer = tk.Frame(tw, bg=COR_CARD_BORDER, padx=1, pady=1)
            outer.pack()
            lbl = tk.Label(outer, text=self.text, bg=COR_GLASS, fg=COR_TEXTO2,
                           font=("Segoe UI", 9), padx=8, pady=5,
                           wraplength=280, justify="left")
            lbl.pack()
            tw.geometry(f"+{x}+{y}")
        except Exception:
            pass

    def _hide(self):
        if self._tip_window:
            try:
                self._tip_window.destroy()
            except Exception:
                pass
            self._tip_window = None


def add_tooltip(widget, text):
    """Helper para adicionar tooltip a qualquer widget."""
    if text:
        Tooltip(widget, text)
    return widget


class RichTooltipArmario:
    """Tooltip rico e detalhado para cards de armario, com layout formatado.
    Exibe numero, status, cliente, data/hora entrada, localizacao, descricao,
    observacao, total de consumo e lista de produtos/itens."""

    def __init__(self, widget, arm_data, status, delay=400):
        self.widget = widget
        self.arm = arm_data
        self.status = status
        self.delay = delay
        self._tip_window = None
        self._id = None
        self._itens_cache = None
        widget.bind("<Enter>", self._schedule, add="+")
        widget.bind("<Leave>", self._cancel, add="+")
        widget.bind("<ButtonPress>", self._cancel, add="+")

    def _schedule(self, event=None):
        self._cancel()
        self._id = self.widget.after(self.delay, self._show)

    def _cancel(self, event=None):
        if self._id:
            self.widget.after_cancel(self._id)
            self._id = None
        self._hide()

    def _show(self):
        if self._tip_window:
            return
        try:
            x = self.widget.winfo_rootx() + self.widget.winfo_width() + 5
            y = self.widget.winfo_rooty()

            self._tip_window = tw = tk.Toplevel(self.widget)
            tw.overrideredirect(True)
            tw.attributes("-topmost", True)
            tw.configure(bg="#1e2d4a")

            outer = tk.Frame(tw, bg="#1e2d4a", padx=2, pady=2)
            outer.pack()
            inner = tk.Frame(outer, bg="#0f1629", padx=12, pady=10)
            inner.pack(fill="both", expand=True)

            arm = self.arm
            status = self.status
            numero = arm.get("numero", "?")

            # Titulo
            status_cores = {"livre": "#00c853", "ocupado": "#9C27B0", "manutencao": "#fbbf24"}
            status_nomes = {"livre": "LIVRE", "ocupado": "OCUPADO", "manutencao": "MANUTENCAO"}
            cor_status = status_cores.get(status, "#e8eaed")

            titulo_frame = tk.Frame(inner, bg="#0f1629")
            titulo_frame.pack(fill="x", pady=(0, 6))
            tk.Label(titulo_frame, text=f"Armario {numero}",
                     bg="#0f1629", fg="#00d4ff",
                     font=("Segoe UI", 12, "bold")).pack(side="left")
            tk.Label(titulo_frame, text=f"  [{status_nomes.get(status, status.upper())}]",
                     bg="#0f1629", fg=cor_status,
                     font=("Segoe UI", 10, "bold")).pack(side="left")

            # Separador
            tk.Frame(inner, bg="#2a3a5c", height=1).pack(fill="x", pady=4)

            # Dados
            def _add_line(label, value, fg_val="#e8eaed"):
                if not value:
                    return
                f = tk.Frame(inner, bg="#0f1629")
                f.pack(fill="x", pady=1)
                tk.Label(f, text=f"{label}: ", bg="#0f1629", fg="#8892a4",
                         font=("Segoe UI", 9)).pack(side="left")
                tk.Label(f, text=str(value), bg="#0f1629", fg=fg_val,
                         font=("Segoe UI", 9, "bold")).pack(side="left")

            desc = arm.get("descricao") or ""
            loc = arm.get("localizacao") or ""
            cliente = arm.get("cliente_nome") or ""
            obs = arm.get("observacao") or ""
            data_entrada = arm.get("data_entrada")
            total_consumo = float(arm.get("total_consumo", 0))

            if desc:
                _add_line("Descricao", desc)
            if loc:
                _add_line("Localizacao", loc)

            if status == "ocupado":
                if cliente:
                    _add_line("Cliente", cliente, "#00f5a0")
                else:
                    _add_line("Cliente", "Nao informado", "#8892a4")
                if data_entrada:
                    _add_line("Entrada", FormatUtils.format_date(data_entrada), "#fbbf24")
                _add_line("Total Consumo", f"R$ {FormatUtils.format_money(total_consumo)}", "#00f5a0")
                if obs:
                    _add_line("Observacao", obs)

                # Itens/Produtos
                uso_id = arm.get("uso_id") or 0
                itens = arm.get("_itens_tooltip") or []
                if itens:
                    tk.Frame(inner, bg="#2a3a5c", height=1).pack(fill="x", pady=4)
                    tk.Label(inner, text=f"Produtos/Itens ({len(itens)}):",
                             bg="#0f1629", fg="#00d4ff",
                             font=("Segoe UI", 9, "bold")).pack(anchor="w", pady=(2, 2))
                    for idx, item in enumerate(itens[:15]):
                        qtd = item.get("quantidade", 1)
                        nome_prod = item.get("descricao_produto", "?")
                        preco = float(item.get("total", 0)) + float(item.get("adicionais_total", 0))
                        ad_desc = item.get("adicionais_descricao") or ""
                        item_text = f"  {idx+1}. {nome_prod} x{qtd} = R$ {FormatUtils.format_money(preco)}"
                        if ad_desc:
                            item_text += f" (+{ad_desc})"
                        tk.Label(inner, text=item_text,
                                 bg="#0f1629", fg="#e8eaed",
                                 font=("Consolas", 8), anchor="w").pack(anchor="w")
                    if len(itens) > 15:
                        tk.Label(inner, text=f"  ... e mais {len(itens) - 15} item(ns)",
                                 bg="#0f1629", fg="#8892a4",
                                 font=("Segoe UI", 8)).pack(anchor="w")
                elif uso_id and uso_id > 0:
                    tk.Frame(inner, bg="#2a3a5c", height=1).pack(fill="x", pady=4)
                    tk.Label(inner, text="Nenhum produto adicionado",
                             bg="#0f1629", fg="#8892a4",
                             font=("Segoe UI", 8, "italic")).pack(anchor="w")

            elif status == "manutencao":
                if obs:
                    _add_line("Motivo", obs, "#fbbf24")
                if data_entrada:
                    _add_line("Desde", FormatUtils.format_date(data_entrada))

            elif status == "livre":
                tk.Label(inner, text="Armario disponivel para uso",
                         bg="#0f1629", fg="#00c853",
                         font=("Segoe UI", 9, "italic")).pack(anchor="w", pady=2)

            # Rodape
            tk.Frame(inner, bg="#2a3a5c", height=1).pack(fill="x", pady=(6, 2))
            tk.Label(inner, text="Clique para gerenciar",
                     bg="#0f1629", fg="#8892a4",
                     font=("Segoe UI", 8, "italic")).pack(anchor="center")

            tw.update_idletasks()
            tw_width = tw.winfo_reqwidth()
            tw_height = tw.winfo_reqheight()
            screen_width = self.widget.winfo_screenwidth()
            screen_height = self.widget.winfo_screenheight()
            if x + tw_width > screen_width:
                x = self.widget.winfo_rootx() - tw_width - 5
            if y + tw_height > screen_height:
                y = screen_height - tw_height - 10
            tw.geometry(f"+{x}+{y}")
        except Exception:
            pass

    def _hide(self):
        if self._tip_window:
            try:
                self._tip_window.destroy()
            except Exception:
                pass
            self._tip_window = None


# ============================================================================
# BARRA DE STATUS INFERIOR
# ============================================================================

class StatusBar(tk.Frame):
    """Barra de status inferior com info de sessao, conexao e relogio."""

    def __init__(self, master, **kwargs):
        super().__init__(master, bg=COR_FUNDO3, height=24, **kwargs)
        self.pack_propagate(False)

        # Linha divisora superior
        div = tk.Frame(self, bg=COR_GLASS_BORDER, height=1)
        div.pack(fill="x", side="top")

        # Status de conexao
        self._conn_dot = tk.Label(self, text=Icons.ONLINE, bg=COR_FUNDO3,
                                   fg=COR_SUCESSO, font=("Segoe UI", 9))
        self._conn_dot.pack(side="left", padx=(8, 0))
        self._conn_lbl = tk.Label(self, text="BD: Conectado", bg=COR_FUNDO3,
                                   fg=COR_TEXTO2, font=("Segoe UI", 8))
        self._conn_lbl.pack(side="left", padx=(2, 12))
        add_tooltip(self._conn_lbl, "Status da conexao com o banco de dados")

        # Versao
        tk.Label(self, text=f"PDV Pro v{APP_VERSION}", bg=COR_FUNDO3,
                 fg=COR_TEXTO2, font=("Segoe UI", 8)).pack(side="left", padx=8)

        # Tema ativo
        self._theme_lbl = tk.Label(self, text=f"{Icons.THEME} {_ACTIVE_THEME}",
                                    bg=COR_FUNDO3, fg=COR_TEXTO2, font=("Segoe UI", 8),
                                    cursor="hand2")
        self._theme_lbl.pack(side="left", padx=8)

        # Separador
        tk.Label(self, text="|", bg=COR_FUNDO3, fg=COR_GLASS_BORDER,
                 font=("Segoe UI", 8)).pack(side="left")

        # Usuario logado
        self._user_lbl = tk.Label(self, text="", bg=COR_FUNDO3,
                                   fg=COR_PRIMARIA, font=("Segoe UI", 8, "bold"))
        self._user_lbl.pack(side="left", padx=8)

        # Caixa status
        self._caixa_lbl = tk.Label(self, text="", bg=COR_FUNDO3,
                                    fg=COR_TEXTO2, font=("Segoe UI", 8))
        self._caixa_lbl.pack(side="left", padx=4)

        # Relogio (direita)
        self._clock_lbl = tk.Label(self, text="", bg=COR_FUNDO3,
                                    fg=COR_TEXTO2, font=("Consolas", 8))
        self._clock_lbl.pack(side="right", padx=8)

        # F1 hint
        tk.Label(self, text="F1=Ajuda  F11=Tela Cheia  Ctrl+F=Busca",
                 bg=COR_FUNDO3, fg=COR_GLASS_BORDER,
                 font=("Segoe UI", 8)).pack(side="right", padx=8)

        self._update_clock()

    def _update_clock(self):
        try:
            if self.winfo_exists():
                now = datetime.datetime.now().strftime("%d/%m/%Y  %H:%M:%S")
                self._clock_lbl.config(text=now)
                self.after(1000, self._update_clock)
        except Exception:
            pass

    def set_connection(self, ok, host=""):
        try:
            if ok:
                self._conn_dot.config(fg=COR_SUCESSO, text=Icons.ONLINE)
                self._conn_lbl.config(text=f"BD: {host}" if host else "BD: Conectado")
            else:
                self._conn_dot.config(fg=COR_ERRO, text=Icons.OFFLINE)
                self._conn_lbl.config(text="BD: Desconectado")
        except Exception:
            pass

    def set_user(self, nome, nivel=""):
        try:
            info = f"{Icons.USER} {nome}"
            if nivel:
                info += f" [{nivel}]"
            self._user_lbl.config(text=info)
        except Exception:
            pass

    def set_caixa(self, aberto, caixa_id=0):
        try:
            if aberto:
                self._caixa_lbl.config(
                    text=f"{Icons.CAIXA} Caixa #{caixa_id} Aberto",
                    fg=COR_SUCESSO)
            else:
                self._caixa_lbl.config(text=f"{Icons.CAIXA} Caixa Fechado",
                                        fg=COR_ALERTA)
        except Exception:
            pass

    def update_theme_label(self):
        try:
            self._theme_lbl.config(text=f"{Icons.THEME} {_ACTIVE_THEME}")
        except Exception:
            pass

    def bind_theme_click(self, callback):
        self._theme_lbl.bind("<Button-1>", lambda e: callback())


# ============================================================================
# ATALHOS DE TECLADO GLOBAIS
# ============================================================================

class KeyboardShortcuts:
    """Gerencia atalhos de teclado globais para a aplicacao."""

    def __init__(self, root, app):
        self.root = root
        self.app = app
        self._register()

    def _register(self):
        r = self.root
        # F1 - Ajuda / atalhos
        r.bind_all("<F1>", lambda e: self._show_help())
        # F2 - Nova Venda rapida
        r.bind_all("<F2>", lambda e: self._safe_call(self.app.show_venda,
            "vendas.acessar"))
        # F3 - Caixa
        r.bind_all("<F3>", lambda e: self._safe_call(self.app.show_caixa,
            "caixa.acessar"))
        # F4 - Comandas
        r.bind_all("<F4>", lambda e: self._safe_call(self.app.show_comandas,
            "comandas.acessar"))
        # F5 - Historico
        r.bind_all("<F5>", lambda e: self._safe_call(self.app.show_historico,
            "historico.acessar"))
        # F6 - Produtos
        r.bind_all("<F6>", lambda e: self._safe_call(
            self.app.show_cadastro_produto, "produtos.acessar"))
        # F7 - Relatorios
        r.bind_all("<F7>", lambda e: self._safe_call(self.app.show_relatorios,
            "relatorios.acessar"))
        # F8 - Clientes
        r.bind_all("<F8>", lambda e: self._safe_call(
            self.app.show_cadastro_cliente, "clientes.acessar"))
        # F9 - Mesas
        r.bind_all("<F9>", lambda e: self._safe_call(
            self.app.show_gerenciar_mesas, "gerenciar_mesas.acessar"))
        # F10 - Dashboard / Menu principal
        r.bind_all("<F10>", lambda e: self.app.show_main_menu())
        # F11 - Tela cheia
        r.bind_all("<F11>", lambda e: self._toggle_fullscreen())
        # F12 - Configuracoes de impressora
        r.bind_all("<F12>", lambda e: self._safe_call(
            self.app.show_config_impressora, "config_impressora.acessar"))
        # Ctrl+L - Logoff
        r.bind_all("<Control-l>", lambda e: self.app.do_logoff())
        # Ctrl+Z - Desfazer ultimo item do carrinho (na tela de venda)
        r.bind_all("<Control-z>", lambda e: self._undo_carrinho())
        # Ctrl+P - Impressao rapida (na tela de venda)
        r.bind_all("<Control-p>", lambda e: self._imprimir_rapido())
        # Escape - Fechar dialogs
        r.bind_all("<Escape>", lambda e: self._fechar_dialog_ativo())

    def _safe_call(self, func, perm_chave=None):
        """Chama funcao apenas se o usuario tiver permissao."""
        try:
            from __main__ import Session
        except Exception:
            pass
        try:
            if perm_chave and not Session.is_admin():
                if not Session.has_permission(perm_chave):
                    ToastManager.warning("Sem permissao para esta acao.")
                    return
            func()
        except Exception:
            pass

    def _toggle_fullscreen(self):
        try:
            estado = self.root.attributes("-fullscreen")
            self.root.attributes("-fullscreen", not estado)
            if not estado:
                ToastManager.info("Tela cheia ativada. Pressione F11 para sair.")
        except Exception:
            try:
                estado = self.root.state()
                if estado == "zoomed":
                    self.root.state("normal")
                else:
                    self.root.state("zoomed")
            except Exception:
                pass

    def _undo_carrinho(self):
        try:
            if hasattr(self.app, "carrinho") and self.app.carrinho:
                removido = self.app.carrinho.pop()
                self.app.atualizar_tree_carrinho()
                ToastManager.info(f"Item removido: {removido.descricao_produto}")
        except Exception:
            pass

    def _imprimir_rapido(self):
        try:
            if hasattr(self.app, "_ultimo_cupom") and self.app._ultimo_cupom:
                def _do():
                    return self.app._imprimir_texto(self.app._ultimo_cupom)
                def _ok(r):
                    ok, msg = r
                    if ok:
                        ToastManager.success("Impresso com sucesso!")
                    else:
                        ToastManager.error(
                            f"Nao foi possivel imprimir. Verifique se a impressora esta ligada. ({msg})",
                            duration=5000)
                self.app.run_async(_do, _ok)
            else:
                ToastManager.warning("Nenhum cupom disponivel para impressao rapida.")
        except Exception:
            pass

    def _fechar_dialog_ativo(self):
        try:
            focused = self.root.focus_get()
            if focused:
                top = focused.winfo_toplevel()
                if top != self.root:
                    top.destroy()
        except Exception:
            pass

    def _show_help(self):
        """Exibe janela de ajuda com todos os atalhos."""
        try:
            dialog = tk.Toplevel(self.root)
            dialog.title("Atalhos de Teclado - PDV Pro")
            dialog.geometry("520x480")
            dialog.configure(bg=COR_FUNDO)
            dialog.transient(self.root)
            dialog.grab_set()

            tk.Label(dialog, text=f"{Icons.SHORTCUT} Atalhos de Teclado",
                     bg=COR_FUNDO, fg=COR_PRIMARIA,
                     font=("Segoe UI", 15, "bold")).pack(pady=(18, 5))

            from tkinter import ttk as _ttk
            tree = _ttk.Treeview(dialog, columns=("atalho", "acao"),
                                  show="headings", height=16)
            tree.heading("atalho", text="Atalho")
            tree.heading("acao", text="Acao")
            tree.column("atalho", width=130, anchor="center")
            tree.column("acao", width=330)

            atalhos = [
                ("F1", "Exibir esta janela de ajuda"),
                ("F2", "Nova Venda"),
                ("F3", "Caixa"),
                ("F4", "Comandas"),
                ("F5", "Historico de Vendas"),
                ("F6", "Cadastro de Produtos"),
                ("F7", "Relatorios"),
                ("F8", "Clientes"),
                ("F9", "Gerenciar Mesas"),
                ("F10", "Dashboard / Menu Principal"),
                ("F11", "Alternar Tela Cheia"),
                ("F12", "Configuracoes de Impressora"),
                ("Ctrl+Z", "Desfazer ultimo item do carrinho"),
                ("Ctrl+P", "Impressao rapida (ultimo cupom)"),
                ("Ctrl+L", "Logoff / Trocar usuario"),
                ("ESC", "Fechar dialog ativo"),
            ]
            for a, d in atalhos:
                tree.insert("", "end", values=(a, d))

            tree.pack(fill="both", expand=True, padx=20, pady=10)

            StyledButton(dialog, text=f"{Icons.CROSS} Fechar",
                         command=dialog.destroy, color="#2a3a5c",
                         width=10).pack(pady=10)
        except Exception as e:
            ToastManager.error(f"Erro ao abrir ajuda: {e}")


# ============================================================================
# EXPORTADOR CSV / TXT
# ============================================================================

class DataExporter:
    """Utilitario para exportar dados de Treeview ou lista para CSV/TXT."""

    @staticmethod
    def export_treeview_csv(tree, filename_hint="export", parent=None):
        """Exporta dados de um Treeview para CSV."""
        try:
            cols = tree["columns"]
            rows = []
            for child in tree.get_children():
                rows.append(tree.item(child)["values"])
            if not rows:
                ToastManager.warning("Nenhum dado para exportar.")
                return None

            ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            default_name = f"{filename_hint}_{ts}.csv"
            filepath = filedialog.asksaveasfilename(
                parent=parent,
                initialdir=EXPORT_DIR,
                initialfile=default_name,
                defaultextension=".csv",
                filetypes=[("CSV", "*.csv"), ("Todos", "*.*")]
            )
            if not filepath:
                return None

            with open(filepath, "w", newline="", encoding="utf-8-sig") as f:
                writer = csv.writer(f, delimiter=";")
                # Cabecalho
                headers = [tree.heading(c)["text"] for c in cols]
                writer.writerow(headers)
                writer.writerows(rows)

            ToastManager.success(f"Exportado: {os.path.basename(filepath)}")
            AuditLogger.log("EXPORT_CSV", f"Arquivo: {filepath}")
            return filepath
        except Exception as e:
            ToastManager.error(f"Erro ao exportar: {e}")
            return None

    @staticmethod
    def export_text(content, filename_hint="relatorio", parent=None):
        """Exporta texto para arquivo TXT."""
        try:
            ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            default_name = f"{filename_hint}_{ts}.txt"
            filepath = filedialog.asksaveasfilename(
                parent=parent,
                initialdir=EXPORT_DIR,
                initialfile=default_name,
                defaultextension=".txt",
                filetypes=[("Texto", "*.txt"), ("Todos", "*.*")]
            )
            if not filepath:
                return None
            with open(filepath, "w", encoding="utf-8", errors="replace") as f:
                f.write(content)
            ToastManager.success(f"Salvo: {os.path.basename(filepath)}")
            AuditLogger.log("EXPORT_TXT", f"Arquivo: {filepath}")
            return filepath
        except Exception as e:
            ToastManager.error(f"Erro ao salvar: {e}")
            return None



