# ============================================================================
# UTILITARIOS DE FORMATACAO
# ============================================================================

class FormatUtils:
    @staticmethod
    def format_money(value):
        try:
            return f"{float(value):,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
        except (ValueError, TypeError):
            return "0,00"

    @staticmethod
    def format_date(date_str):
        if not date_str:
            return ""
        try:
            if isinstance(date_str, datetime.datetime):
                return date_str.strftime("%d/%m/%Y %H:%M")
            dt = datetime.datetime.strptime(str(date_str)[:19], "%Y-%m-%d %H:%M:%S")
            return dt.strftime("%d/%m/%Y %H:%M")
        except Exception:
            return str(date_str) if date_str else ""

    @staticmethod
    def safe_string(s):
        return s if s else ""

    @staticmethod
    def parse_money(text):
        try:
            clean = text.replace(".", "").replace(",", ".").strip()
            return float(clean)
        except (ValueError, TypeError):
            return 0.0

    @staticmethod
    def format_quantidade(value):
        """Formata quantidade (3 casas decimais, remove zeros a direita)."""
        try:
            v = float(value)
            s = f"{v:.3f}"
            # Remove zeros a direita, mas mantem pelo menos uma casa decimal
            if '.' in s:
                s = s.rstrip('0').rstrip('.')
            return s
        except (ValueError, TypeError):
            return "0"


class EanUtils:
    """Utilitario para geracao e validacao de codigos de barras EAN-13.
    Alinhado com EanUtils.java do Android.
    Estrutura EAN-13:
    - Digitos 1-3: Prefixo do pais (789 = Brasil)
    - Digitos 4-7: Codigo da empresa (gerado aleatoriamente para uso interno)
    - Digitos 8-12: Codigo do produto (gerado aleatoriamente)
    - Digito 13: Digito verificador (calculado pelo algoritmo padrao EAN)
    """

    @staticmethod
    def gerar_ean13():
        """Gera um codigo EAN-13 valido com prefixo Brasil (789)."""
        sb = "789"
        for _ in range(9):
            sb += str(random.randint(0, 9))
        digito = EanUtils.calcular_digito_verificador(sb)
        sb += str(digito)
        return sb

    @staticmethod
    def calcular_digito_verificador(doze_digitos):
        """Calcula o digito verificador EAN-13 a partir dos 12 primeiros digitos."""
        if not doze_digitos or len(doze_digitos) != 12:
            raise ValueError("Sao necessarios exatamente 12 digitos")
        soma = 0
        for i in range(12):
            digito = int(doze_digitos[i])
            if i % 2 == 0:
                soma += digito
            else:
                soma += digito * 3
        resto = soma % 10
        return 0 if resto == 0 else (10 - resto)

    @staticmethod
    def validar_ean13(ean13):
        """Valida se um codigo EAN-13 e valido verificando o digito verificador."""
        if not ean13 or len(ean13) != 13:
            return False
        if not ean13.isdigit():
            return False
        digito_esperado = EanUtils.calcular_digito_verificador(ean13[:12])
        digito_atual = int(ean13[12])
        return digito_esperado == digito_atual


