    def _parse_columns_from_create_sql(self, create_sql):
        """Extrai nome e definicao das colunas a partir de um CREATE TABLE SQL.
        Retorna dict {nome_coluna: definicao_completa}."""
        columns = {}
        try:
            # Encontrar conteudo entre os parenteses do CREATE TABLE
            match = re.search(r'\((.+)\)\s*ENGINE', create_sql, re.DOTALL)
            if not match:
                return columns
            body = match.group(1)
            # Separar por linhas e processar cada uma
            for line in body.split('\n'):
                line = line.strip().rstrip(',')
                if not line:
                    continue
                # Ignorar linhas de constraint/index
                upper = line.upper()
                if any(upper.startswith(kw) for kw in [
                    'PRIMARY', 'UNIQUE', 'KEY', 'INDEX', 'CONSTRAINT',
                    'FOREIGN', 'CHECK'
                ]):
                    continue
                # Extrair nome da coluna (primeira palavra)
                parts = line.split()
                if len(parts) >= 2:
                    col_name = parts[0].strip('`').lower()
                    # Ignorar se parece keyword
                    if col_name.upper() in ('PRIMARY', 'UNIQUE', 'KEY', 'INDEX',
                                             'CONSTRAINT', 'FOREIGN', 'CHECK', 'ENGINE'):
                        continue
                    col_def = ' '.join(parts[1:])
                    # Remover trailing comma
                    col_def = col_def.rstrip(',')
                    columns[col_name] = col_def
        except Exception as e:
            print(f"[AUTO-MIGRACAO] Erro ao parsear SQL: {e}")
        return columns

    def auto_migrate_database(self):
        """Verificacao e auto-migracao do banco de dados.
        Executada ANTES de qualquer operacao do sistema.
        Verifica se todas as tabelas e colunas necessarias existem
        e cria/adiciona as faltantes automaticamente.
        Isso permite restaurar bancos de dados antigos e o sistema
        atualiza a estrutura automaticamente antes de iniciar."""
        print("[AUTO-MIGRACAO] Iniciando verificacao e atualizacao do banco de dados...")
        _logger.info("Auto-migracao: iniciando verificacao do banco de dados")

        try:
            # 1. Garantir que o banco de dados existe
            if not self.ensure_database_exists():
                _logger.error("Auto-migracao: nao foi possivel garantir a existencia do banco")
                print("[AUTO-MIGRACAO] ERRO: Nao foi possivel acessar/criar o banco de dados")
                return False

            # 2. Obter definicoes de todas as tabelas necessarias
            tables = self.get_table_definitions()

            # 3. Obter lista de tabelas existentes no banco
            with self._conn_lock:
                conn = self.get_connection()
                cursor = conn.cursor(dictionary=True)

                cursor.execute("SHOW TABLES")
                existing_tables_rows = cursor.fetchall()
                existing_tables = set()
                if existing_tables_rows:
                    key = list(existing_tables_rows[0].keys())[0]
                    existing_tables = {r[key].lower() for r in existing_tables_rows}

                tabelas_criadas = 0
                colunas_adicionadas = 0
                erros = 0
                
                # Log de diagnostico inicial
                print(f"[AUTO-MIGRACAO] Tabelas encontradas: {len(existing_tables)}")

                # 4. Para cada tabela necessaria, verificar e criar/atualizar
                for table_name, create_sql in tables.items():
                    try:
                        if table_name.lower() not in existing_tables:
                            # Tabela nao existe - criar
                            cursor.execute(create_sql)
                            tabelas_criadas += 1
                            print(f"[AUTO-MIGRACAO] Tabela '{table_name}' criada com sucesso")
                            _logger.info(f"Auto-migracao: tabela '{table_name}' criada")
                        else:
                            # Tabela existe - verificar colunas faltantes
                            expected_columns = self._parse_columns_from_create_sql(create_sql)
                            if not expected_columns:
                                continue

                            # Obter colunas existentes na tabela
                            cursor.execute(f"SHOW COLUMNS FROM `{table_name}`")
                            existing_cols_rows = cursor.fetchall()
                            existing_cols = {r['Field'].lower() for r in existing_cols_rows}

                            # Adicionar colunas faltantes ou corrigir 'id' sem AUTO_INCREMENT
                            for col_name, col_def in expected_columns.items():
                                col_name_lower = col_name.lower()
                                if col_name_lower not in existing_cols:
                                    try:
                                        alter_sql = f"ALTER TABLE `{table_name}` ADD COLUMN `{col_name}` {col_def}"
                                        cursor.execute(alter_sql)
                                        colunas_adicionadas += 1
                                        print(f"[AUTO-MIGRACAO] Coluna '{col_name}' adicionada na tabela '{table_name}'")
                                        _logger.info(f"Auto-migracao: coluna '{col_name}' adicionada em '{table_name}'")
                                    except Exception as e_col:
                                        print(f"[AUTO-MIGRACAO] Aviso ao adicionar coluna '{col_name}' em '{table_name}': {e_col}")
                                        _logger.warning(f"Auto-migracao: aviso coluna '{col_name}' em '{table_name}': {e_col}")
                                elif col_name_lower == 'id':
                                    # Verificar se o 'id' existente tem AUTO_INCREMENT
                                    has_auto_inc = False
                                    for row in existing_cols_rows:
                                        if row['Field'].lower() == 'id' and 'auto_increment' in row.get('Extra', '').lower():
                                            has_auto_inc = True
                                            break
                                    
                                    if not has_auto_inc:
                                        try:
                                            print(f"[AUTO-MIGRACAO] Corrigindo 'id' sem AUTO_INCREMENT na tabela '{table_name}'...")
                                            # Limpar a definicao da coluna para o MODIFY (remover PRIMARY KEY se ja existir)
                                            clean_def = col_def.upper().replace("PRIMARY KEY", "").strip()
                                            # Garantir que tenha AUTO_INCREMENT na definicao
                                            if "AUTO_INCREMENT" not in clean_def:
                                                clean_def += " AUTO_INCREMENT"
                                            
                                            alter_sql = f"ALTER TABLE `{table_name}` MODIFY COLUMN `{col_name}` {clean_def}"
                                            cursor.execute(alter_sql)
                                            print(f"[AUTO-MIGRACAO] Coluna 'id' corrigida com sucesso em '{table_name}'")
                                            _logger.info(f"Auto-migracao: coluna 'id' corrigida (AUTO_INCREMENT) em '{table_name}'")
                                        except Exception as e_id:
                                            # Se falhar o MODIFY, tenta uma abordagem mais drastica: adicionar PK se nao tiver
                                            try:
                                                cursor.execute(f"ALTER TABLE `{table_name}` ADD PRIMARY KEY (`{col_name}`)")
                                                cursor.execute(f"ALTER TABLE `{table_name}` MODIFY COLUMN `{col_name}` {clean_def}")
                                                print(f"[AUTO-MIGRACAO] Coluna 'id' corrigida (tentativa 2) em '{table_name}'")
                                            except Exception:
                                                print(f"[AUTO-MIGRACAO] Erro critico ao corrigir 'id' em '{table_name}': {e_id}")
                                                _logger.error(f"Auto-migracao: erro ao corrigir 'id' em '{table_name}': {e_id}")
                    except Exception as e_table:
                        erros += 1
                        print(f"[AUTO-MIGRACAO] Erro ao processar tabela '{table_name}': {e_table}")
                        _logger.error(f"Auto-migracao: erro tabela '{table_name}': {e_table}")

                # 5. Executar migracoes especificas (ALTER TABLE de alinhamento)
                migracoes_especificas = [
                    # Adicionar coluna data_abertura em armarios
                    ("ALTER TABLE armarios ADD COLUMN data_abertura DATETIME DEFAULT NULL",
                     "armarios.data_abertura"),
                    # Adicionar coluna uso_armario_id em vendas
                    ("ALTER TABLE vendas ADD COLUMN uso_armario_id INT DEFAULT 0",
                     "vendas.uso_armario_id"),
                    # Adicionar coluna cliente_nome em vendas
                    ("ALTER TABLE vendas ADD COLUMN cliente_nome VARCHAR(200) DEFAULT NULL",
                     "vendas.cliente_nome"),
                    # Adicionar coluna personalizavel em perfis
                    ("ALTER TABLE perfis ADD COLUMN personalizavel TINYINT(1) DEFAULT 0",
                     "perfis.personalizavel"),
                    # Adicionar coluna perfil_id em usuarios
                    ("ALTER TABLE usuarios ADD COLUMN perfil_id INT DEFAULT NULL",
                     "usuarios.perfil_id"),
                ]

                for mig_sql, mig_desc in migracoes_especificas:
                    try:
                        cursor.execute(mig_sql)
                        print(f"[AUTO-MIGRACAO] Migracao aplicada: {mig_desc}")
                    except Exception:
                        pass  # Coluna/tabela ja existe ou tabela nao existe ainda

                # 6. Migracoes de remocao/modificacao (seguras com try/except)
                migracoes_remocao = [
                    # Remover coluna mesa_id de itens_mesa (alinhamento Android)
                    ("ALTER TABLE itens_mesa DROP COLUMN mesa_id",
                     "remover itens_mesa.mesa_id"),
                    # Garantir ocupacao_id NOT NULL em itens_mesa
                    ("ALTER TABLE itens_mesa MODIFY COLUMN ocupacao_id INT NOT NULL",
                     "itens_mesa.ocupacao_id NOT NULL"),
                    # Remover coluna status de mesas (status fica em ocupacao_mesa)
                    ("ALTER TABLE mesas DROP COLUMN status",
                     "remover mesas.status"),
                    # Remover UNIQUE de permissoes.chave
                    ("ALTER TABLE permissoes DROP INDEX chave",
                     "remover UNIQUE permissoes.chave"),
                ]

                for mig_sql, mig_desc in migracoes_remocao:
                    try:
                        cursor.execute(mig_sql)
                        print(f"[AUTO-MIGRACAO] Migracao aplicada: {mig_desc}")
                    except Exception:
                        pass  # Ja aplicada ou nao aplicavel

                # 7. Migracao corretiva de dados
                try:
                    cursor.execute(
                        "UPDATE vendas v "
                        "LEFT JOIN uso_armario_sauna u ON u.id = v.uso_armario_id "
                        "SET v.cliente_nome = u.cliente_nome "
                        "WHERE (v.cliente_nome IS NULL OR TRIM(v.cliente_nome) = '') "
                        "AND v.uso_armario_id > 0 "
                        "AND u.cliente_nome IS NOT NULL AND TRIM(u.cliente_nome) <> ''"
                    )
                except Exception:
                    pass  # Tabelas podem nao existir ainda

                cursor.close()

            # Resumo
            resumo = (f"[AUTO-MIGRACAO] Concluido: "
                      f"{tabelas_criadas} tabela(s) criada(s), "
                      f"{colunas_adicionadas} coluna(s) adicionada(s), "
                      f"{erros} erro(s)")
            print(resumo)
            _logger.info(resumo)

            if erros == 0:
                print("[AUTO-MIGRACAO] Banco de dados verificado e atualizado com sucesso!")
            else:
                print(f"[AUTO-MIGRACAO] Banco atualizado com {erros} aviso(s). Verifique o log.")

            return True

        except MySQLError as e:
            ErroAmigavel.log_erro(e, "auto_migrate_database_mysql")
            _logger.error(f"Auto-migracao: erro MySQL: {e}")
            print(f"[AUTO-MIGRACAO] Erro MySQL: {e}")
            return False
        except Exception as e:
            ErroAmigavel.log_erro(e, "auto_migrate_database_geral")
            _logger.error(f"Auto-migracao: erro geral: {e}")
            print(f"[AUTO-MIGRACAO] Erro geral: {e}")
            return False

    def create_tables(self):
        """Cria todas as tabelas do sistema no banco de dados.
        Inclui tratamento individual por tabela para nao interromper
        a criacao em caso de erro em uma tabela especifica.
        NOTA: Agora chama auto_migrate_database() primeiro para garantir
        que bancos antigos/restaurados sejam atualizados automaticamente."""
        if self.initialized:
            return
        try:
            # ============================================================
            # AUTO-MIGRACAO: Verificar e atualizar banco ANTES de tudo
            # Isso garante que bancos antigos restaurados sejam
            # atualizados automaticamente com tabelas/colunas faltantes
            # ============================================================
            self.auto_migrate_database()

            # Executar CREATE TABLE IF NOT EXISTS para garantia extra
            tabelas_ok = 0
            tabelas_erro = 0
            with self._conn_lock:
                conn = self.get_connection()
                cursor = conn.cursor()
                tables = self.get_table_definitions()
                for table_name, create_sql in tables.items():
                    try:
                        cursor.execute(create_sql)
                        tabelas_ok += 1
                    except Exception as e:
                        tabelas_erro += 1
                        ErroAmigavel.log_erro(e, f"create_table_{table_name}")
                        _logger.warning(f"Aviso ao criar tabela '{table_name}': {e}")
                # As migracoes abaixo sao mantidas por seguranca redundante
                # (ja executadas pelo auto_migrate_database acima)
                # Migracao: adicionar coluna data_abertura em armarios existentes
                try:
                    cursor.execute(
                        "ALTER TABLE armarios ADD COLUMN data_abertura DATETIME DEFAULT NULL"
                    )
                except Exception:
                    pass  # Coluna ja existe
                # Migracao: remover coluna mesa_id de itens_mesa (alinhamento com Android)
                try:
                    cursor.execute(
                        "ALTER TABLE itens_mesa DROP COLUMN mesa_id"
                    )
                except Exception:
                    pass  # Coluna nao existe
                # Migracao: garantir que ocupacao_id seja NOT NULL em itens_mesa (alinhamento com Android)
                try:
                    cursor.execute(
                        "ALTER TABLE itens_mesa MODIFY COLUMN ocupacao_id INT NOT NULL"
                    )
                except Exception:
                    pass  # Coluna ja esta correta
                # Migracao: remover coluna status de mesas (alinhamento com Android - status fica em ocupacao_mesa)
                try:
                    cursor.execute(
                        "ALTER TABLE mesas DROP COLUMN status"
                    )
                except Exception:
                    pass  # Coluna nao existe
                # Migracao: adicionar coluna uso_armario_id em vendas (alinhamento com Android)
                try:
                    cursor.execute(
                        "ALTER TABLE vendas ADD COLUMN uso_armario_id INT DEFAULT 0"
                    )
                except Exception:
                    pass  # Coluna ja existe
                # Migracao: adicionar coluna cliente_nome em vendas para preservar nome avulso do cliente
                try:
                    cursor.execute(
                        "ALTER TABLE vendas ADD COLUMN cliente_nome VARCHAR(200) DEFAULT NULL"
                    )
                except Exception:
                    pass  # Coluna ja existe
                # Migracao: colunas do MODULO DE ENTREGA em vendas (garantia para bancos antigos)
                for _alter_entrega in (
                    "ALTER TABLE vendas ADD COLUMN para_entrega TINYINT(1) DEFAULT 0",
                    "ALTER TABLE vendas ADD COLUMN taxa_entrega DECIMAL(10,2) DEFAULT 0",
                    "ALTER TABLE vendas ADD COLUMN bairro_entrega VARCHAR(150) DEFAULT NULL",
                    "ALTER TABLE vendas ADD COLUMN endereco_entrega VARCHAR(500) DEFAULT NULL",
                    "ALTER TABLE vendas ADD COLUMN celular_whatsapp VARCHAR(30) DEFAULT NULL",
                    "ALTER TABLE vendas ADD COLUMN status_entrega VARCHAR(20) DEFAULT NULL",
                ):
                    try:
                        cursor.execute(_alter_entrega)
                    except Exception:
                        pass  # Coluna ja existe
                # Migracao corretiva: preencher cliente_nome em vendas de armario ja vinculadas
                try:
                    cursor.execute(
                        "UPDATE vendas v "
                        "LEFT JOIN uso_armario_sauna u ON u.id = v.uso_armario_id "
                        "SET v.cliente_nome = u.cliente_nome "
                        "WHERE (v.cliente_nome IS NULL OR TRIM(v.cliente_nome) = '') "
                        "AND v.uso_armario_id > 0 "
                        "AND u.cliente_nome IS NOT NULL AND TRIM(u.cliente_nome) <> ''"
                    )
                except Exception:
                    pass

                # Migracao: remover UNIQUE de permissoes.chave (alinhamento com Android)
                try:
                    cursor.execute(
                        "ALTER TABLE permissoes DROP INDEX chave"
                    )
                except Exception:
                    pass  # Index nao existe
                cursor.close()
            _logger.info(f"Tabelas criadas: {tabelas_ok} OK, {tabelas_erro} com aviso")
            # Inserir dados padrao (usa execute_query/execute_update que ja tem lock)
            self.insert_default_data()
            # Sincronizar armarios cadastrados pelo app APK
            self.sync_armarios_from_apk()
            # Setup do sistema de permissoes (alinhado com Android)
            PermissionDatabaseSetup.setup(self)
            self.initialized = True
        except MySQLError as e:
            ErroAmigavel.log_erro(e, "create_tables_mysql")
            _logger.error(f"Erro MySQL ao criar tabelas: {e}")
        except Exception as e:
            ErroAmigavel.log_erro(e, "create_tables_geral")
            _logger.error(f"Erro geral ao criar tabelas: {e}")

    def insert_default_data(self):
        """Insere dados padrao usando execute_query/execute_update (thread-safe)."""
        try:
            rows = self.execute_query("SELECT COUNT(*) as cnt FROM usuarios")
            count = rows[0].get("cnt", 0) if rows else 0
            if count == 0:
                self.execute_update(
                    "INSERT INTO usuarios (nome, login, senha, nivel, ativo) "
                    "VALUES ('Administrador', 'admin', 'admin', 'admin', 1)"
                )

            rows = self.execute_query("SELECT COUNT(*) as cnt FROM formas_pagamento")
            count = rows[0].get("cnt", 0) if rows else 0
            if count == 0:
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('Dinheiro', 'dinheiro', 0, 1)"
                )
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('Cartao de Credito', 'credito', 1, 1)"
                )
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('Cartao de Debito', 'debito', 0, 1)"
                )
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('PIX', 'pix', 0, 1)"
                )
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('Contas a Receber', 'conta_receber', 0, 1)"
                )

            # Garantir forma de pagamento Contas a Receber
            rows = self.execute_query("SELECT COUNT(*) as cnt FROM formas_pagamento WHERE tipo = 'conta_receber'")
            count = rows[0].get("cnt", 0) if rows else 0
            if count == 0:
                self.execute_update(
                    "INSERT INTO formas_pagamento (descricao, tipo, permite_parcelamento, ativo) "
                    "VALUES ('Contas a Receber', 'conta_receber', 0, 1)"
                )

            # === Cardapio do restaurante DELICIAS FOOD (itens cadastrados SEM preco) ===
            try:
                self.seed_cardapio_delicias_food()
            except Exception as _e_card:
                print(f"Aviso ao semear cardapio Delicias Food: {_e_card}")

            # Perfis padrao agora sao criados pelo PermissionDatabaseSetup.setup()
        except Exception as e:
            print(f"Aviso ao inserir dados padrao: {e}")

    # ========================================================================
    # CARDAPIO DELICIAS FOOD  -  cadastro automatico do cardapio (sem precos)
    # ========================================================================
    # Nomes das categorias (tipos_produto). Usados tambem pelo assistente
    # "MONTE SEU PRATO". Mantidos SEM acento para evitar qualquer divergencia
    # entre o cadastro e as consultas do assistente.
    CAT_MONTE_PRATO = "MONTE SEU PRATO"
    CAT_PROTEINAS = "Proteinas"
    CAT_ACOMPANHAMENTOS = "Acompanhamentos"
    CAT_SUCOS = "Sucos"
    CAT_REFRI_200 = "Refrigerantes 200ml"
    CAT_REFRI_350 = "Refrigerantes 350ml (Lata)"
    CAT_AGUAS = "Aguas"
    CAT_SOBREMESAS = "Sobremesas"

    def seed_cardapio_delicias_food(self):
        """Cadastra o cardapio do restaurante DELICIAS FOOD.

        - Todos os itens sao cadastrados SEM preco (preco_venda = 0). O preco
          deve ser definido depois pelo cliente no cadastro de produtos.
        - Idempotente: so insere o que ainda nao existe (pode rodar a cada
          inicializacao sem duplicar).
        - Se a categoria "MONTE SEU PRATO" ja existir, assume-se que o
          cardapio ja foi cadastrado e o seed e ignorado (evita overhead).
        """
        # Se ja existe a categoria principal, considera o cardapio cadastrado.
        ja_existe = self.execute_query(
            "SELECT id FROM tipos_produto WHERE descricao = %s LIMIT 1",
            (self.CAT_MONTE_PRATO,)
        )
        if ja_existe:
            return

        def _get_or_create_tipo(descricao):
            rows = self.execute_query(
                "SELECT id FROM tipos_produto WHERE descricao = %s LIMIT 1",
                (descricao,)
            )
            if rows:
                return rows[0]["id"]
            return self.execute_update(
                "INSERT INTO tipos_produto (descricao, ativo) VALUES (%s, 1)",
                (descricao,)
            )

        def _ensure_produto(descricao, tipo_id, codigo=None):
            rows = self.execute_query(
                "SELECT id FROM produtos WHERE descricao = %s AND tipo_produto_id = %s LIMIT 1",
                (descricao, tipo_id)
            )
            if rows:
                return rows[0]["id"]
            # preco_custo / preco_venda = 0 (cliente define depois). Estoque alto
            # para itens de restaurante (feitos na hora) nao bloquearem a venda.
            return self.execute_update(
                "INSERT INTO produtos (codigo, descricao, unidade, tipo_produto_id, "
                "preco_custo, preco_venda, estoque, estoque_minimo, ativo) "
                "VALUES (%s, %s, 'UN', %s, 0, 0, 99999, 0, 1)",
                (codigo, descricao, tipo_id)
            )

        # ---- MONTE SEU PRATO (tamanhos) ----
        # O codigo guarda o numero de proteinas que o tamanho permite escolher
        # (ultimo digito do codigo). Ex.: MSP-G2 = tamanho G com 2 proteinas.
        tipo_monte = _get_or_create_tipo(self.CAT_MONTE_PRATO)
        for desc, cod in [
            ("Tamanho P - 1 Proteina", "MSP-P1"),
            ("Tamanho P - 2 Proteinas", "MSP-P2"),
            ("Tamanho G - 1 Proteina", "MSP-G1"),
            ("Tamanho G - 2 Proteinas", "MSP-G2"),
        ]:
            _ensure_produto(desc, tipo_monte, cod)

        # ---- PROTEINAS ----
        tipo_prot = _get_or_create_tipo(self.CAT_PROTEINAS)
        proteinas = [
            "Lasanha bolonhesa", "Lasanha de frango", "Panqueca de carne do sol",
            "Panqueca de carne", "Panqueca de frango", "Escondidinho de frango",
            "Escondidinho de carne", "Escondidinho de carne do sol", "Peixada",
            "Peixe tilapia frita em postas", "Frango assado no forno",
            "Porco assado na brasa", "Porco ao molho", "Cozido com pirao",
            "Mao de vaca com pirao", "Frango a milanesa", "Frango parmegiana",
            "Filezinho grelhado", "Carne trinchada", "Porco trinchado",
            "Porco frito", "Porco frito no molho barbecue", "File de peixe frito",
            "Creme de galinha", "Vatapa de frango", "Vatapa de camarao",
            "Fricasse de frango", "Maninha assada", "Picanha assada",
            "Picanha de porco assada", "Costelinha suina assada",
            "Calabresa acebolada", "Escondidinho de calabresa",
            "Linguica Toscana assada", "Linguica Toscana no forno",
            "Linguica Toscana no molho barbecue", "Almondega", "Omelete de frango",
            "Omelete de carne", "Omelete de carne do sol", "Ovo cozido",
            "Ovo frito", "Feijoada", "Bobo de Camarao",
        ]
        for nome in proteinas:
            _ensure_produto(nome, tipo_prot)

        # ---- ACOMPANHAMENTOS (o codigo guarda o grupo) ----
        tipo_acomp = _get_or_create_tipo(self.CAT_ACOMPANHAMENTOS)
        acompanhamentos = [
            # (descricao, grupo)
            ("Arroz branco", "ARROZ"), ("Arroz temperado", "ARROZ"),
            ("Baiao de dois", "ARROZ"), ("Macarrao espaguete", "ARROZ"),
            ("Macarrao ninho", "ARROZ"),
            ("Feijao carioca", "FEIJAO"), ("Feijao de corda", "FEIJAO"),
            ("Feijao preto", "FEIJAO"),
            ("Salada verde", "SALADA"), ("Salada de legumes", "SALADA"),
            ("Salada de maionese", "SALADA"), ("Salada acelga com manga", "SALADA"),
            ("Salada tropical", "SALADA"), ("Salada de repolho refogado", "SALADA"),
            ("Salada de repolho cremoso", "SALADA"), ("Salada de repolho crua", "SALADA"),
            ("Beterraba", "SALADA"), ("Batata doce", "SALADA"),
            ("Abobora refogado", "SALADA"),
        ]
        for nome, grupo in acompanhamentos:
            _ensure_produto(nome, tipo_acomp, f"ACOMP-{grupo}")

        # ---- SUCOS (todos 400ml) ----
        tipo_sucos = _get_or_create_tipo(self.CAT_SUCOS)
        sucos = [
            "Suco de Caja 400ml", "Suco de Caju 400ml", "Suco de Manga 400ml",
            "Suco de Acerola 400ml", "Suco de Abacaxi 400ml", "Suco de Maracuja 400ml",
            "Suco de Goiaba 400ml", "Suco de Graviola 400ml", "Suco de Siriguela 400ml",
            "Suco de Tamarindo 400ml", "Suco de Sapoti 400ml",
            "Suco de Abacaxi com Hortela 400ml",
        ]
        for nome in sucos:
            _ensure_produto(nome, tipo_sucos)

        # ---- REFRIGERANTES 200ml ----
        tipo_r200 = _get_or_create_tipo(self.CAT_REFRI_200)
        refri_200 = [
            "Coca-Cola 200ml", "Coca-Cola Zero 200ml", "Sao Geraldo 200ml",
            "Fanta Uva 200ml", "Fanta Laranja 200ml", "Guarana 200ml",
        ]
        for nome in refri_200:
            _ensure_produto(nome, tipo_r200)

        # ---- REFRIGERANTES 350ml (LATA) ----
        tipo_r350 = _get_or_create_tipo(self.CAT_REFRI_350)
        refri_350 = [
            "Coca-Cola Lata 350ml", "Coca-Cola Lata Zero 350ml", "Fanta Uva Lata 350ml",
            "Fanta Laranja Lata 350ml", "Sao Geraldo Zero 350ml", "Sao Geraldo 350ml",
            "Guarana Lata 350ml",
        ]
        for nome in refri_350:
            _ensure_produto(nome, tipo_r350)

        # ---- AGUAS ----
        tipo_aguas = _get_or_create_tipo(self.CAT_AGUAS)
        for nome in ["Agua com gas 500ml", "Agua sem gas 500ml"]:
            _ensure_produto(nome, tipo_aguas)

        # ---- SOBREMESAS ----
        tipo_sobr = _get_or_create_tipo(self.CAT_SOBREMESAS)
        sobremesas = [
            "Delicia de abacaxi", "Musse de abacaxi c/ abacaxi caramelizado",
            "Palha italiana no pote", "Pudim", "Trufas", "Alfajor",
            "Escondidinho de morango", "Escondidinho de chocolate",
            "Musse de morango", "Bombom de uva", "Bombom de morango", "Brownie",
            "Musse de limao", "Musse de maracuja", "Musse de chocolate",
        ]
        for nome in sobremesas:
            _ensure_produto(nome, tipo_sobr)

        try:
            _logger.info("Cardapio Delicias Food cadastrado (itens sem preco).")
        except Exception:
            pass

    def _safe_reconnect(self):
        """Forca reconexao descartando a conexao atual (possivelmente corrompida)."""
        try:
            if self.connection:
                try:
                    self.connection.close()
                except Exception:
                    pass
                self.connection = None
        except Exception:
            self.connection = None
        return self.get_connection()

    def execute_query(self, sql, params=None):
        with self._conn_lock:
            for attempt in range(2):
                try:
                    conn = self.get_connection()
                    cursor = conn.cursor(dictionary=True)
                    cursor.execute(sql, params or ())
                    results = cursor.fetchall()
                    cursor.close()
                    return results
                except (MySQLError, IndexError, ValueError) as e:
                    err_msg = str(e).lower()
                    if attempt == 0 and ('bytearray' in err_msg or 'index out of range' in err_msg
                                         or 'not connected' in err_msg or 'connection' in err_msg
                                         or isinstance(e, (IndexError, ValueError))):
                        self._safe_reconnect()
                    else:
                        ErroAmigavel.log_erro(e, f"execute_query: {sql[:80]}")
                        raise
            return []

    def execute_update(self, sql, params=None):
        with self._conn_lock:
            for attempt in range(2):
                try:
                    conn = self.get_connection()
                    cursor = conn.cursor()
                    cursor.execute(sql, params or ())
                    conn.commit()
                    last_id = cursor.lastrowid
                    cursor.close()
                    return last_id
                except (MySQLError, IndexError, ValueError) as e:
                    err_msg = str(e).lower()
                    if attempt == 0 and ('bytearray' in err_msg or 'index out of range' in err_msg
                                         or 'not connected' in err_msg or 'connection' in err_msg
                                         or isinstance(e, (IndexError, ValueError))):
                        self._safe_reconnect()
                    else:
                        ErroAmigavel.log_erro(e, f"execute_update: {sql[:80]}")
                        raise
            return 0

    def execute_scalar(self, sql, params=None):
        with self._conn_lock:
            for attempt in range(2):
                try:
                    conn = self.get_connection()
                    cursor = conn.cursor()
                    cursor.execute(sql, params or ())
                    result = cursor.fetchone()
                    cursor.close()
                    return result[0] if result else None
                except (MySQLError, IndexError, ValueError) as e:
                    err_msg = str(e).lower()
                    if attempt == 0 and ('bytearray' in err_msg or 'index out of range' in err_msg
                                         or 'not connected' in err_msg or 'connection' in err_msg
                                         or isinstance(e, (IndexError, ValueError))):
                        self._safe_reconnect()
                    else:
                        ErroAmigavel.log_erro(e, f"execute_scalar: {sql[:80]}")
                        raise
            return None

