# ============================================================================
# SESSAO DO USUARIO
# ============================================================================

class Session:
    """Sessao do usuario logado. Alinhada com PermissionManager.java do Android.
    Carrega permissoes do perfil + overrides individuais (adicionar/remover)."""
    user_id = 0
    user_nome = ""
    user_nivel = ""
    user_login = ""
    user_perfil_id = 0
    caixa_id = 0
    permissoes = set()

    @classmethod
    def clear(cls):
        cls.user_id = 0
        cls.user_nome = ""
        cls.user_nivel = ""
        cls.user_login = ""
        cls.user_perfil_id = 0
        cls.caixa_id = 0
        cls.permissoes = set()

    @classmethod
    def is_admin(cls):
        return cls.user_nivel == "admin"

    @classmethod
    def has_permission(cls, chave):
        if cls.is_admin():
            return True
        return chave in cls.permissoes

    @classmethod
    def load_permissions(cls):
        """Carrega permissoes do perfil + overrides individuais do usuario.
        Alinhado com PermissionManager.loadPermissions() do Android."""
        if cls.is_admin():
            cls.permissoes = set(PermissionConstants.get_todas_chaves())
            return
        try:
            db = DatabaseHelper.get_instance()
            # 1. Obter perfil_id do usuario
            rows = db.execute_query(
                "SELECT u.perfil_id FROM usuarios u WHERE u.id = %s", (cls.user_id,)
            )
            perfil_id = 0
            if rows and rows[0].get("perfil_id"):
                perfil_id = rows[0]["perfil_id"]
                cls.user_perfil_id = perfil_id

            # 2. Carregar permissoes do perfil
            perms_perfil = set()
            if perfil_id > 0:
                perms = db.execute_query(
                    "SELECT p.chave FROM permissoes p "
                    "JOIN perfil_permissoes pp ON pp.permissao_id = p.id "
                    "WHERE pp.perfil_id = %s", (perfil_id,)
                )
                perms_perfil = {r["chave"] for r in perms}

            # 3. Carregar overrides individuais do usuario (usuario_permissoes)
            overrides = db.execute_query(
                "SELECT p.chave, up.tipo FROM usuario_permissoes up "
                "JOIN permissoes p ON p.id = up.permissao_id "
                "WHERE up.usuario_id = %s", (cls.user_id,)
            )
            for ov in overrides:
                if ov["tipo"] == "adicionar":
                    perms_perfil.add(ov["chave"])
                elif ov["tipo"] == "remover":
                    perms_perfil.discard(ov["chave"])

            cls.permissoes = perms_perfil
        except Exception as e:
            ErroAmigavel.log_erro(e, "Session.load_permissions")
            print(f"[AVISO] Nao foi possivel carregar as permissoes do usuario: {e}")


# ============================================================================
# GERADOR DE CUPOM
# ============================================================================

class CupomGenerator:
    @staticmethod
    def gerar_cupom(venda, itens, pagamentos, empresa=None, obs_cupom="",
                    colunas=48, margem_esq=0, margem_dir=0, espacamento=1):
        """Gera o texto do cupom nao fiscal com layout dinamico.
        - colunas: largura total do papel em caracteres
        - margem_esq / margem_dir: caracteres de margem (espacos) em cada lado
        - espacamento: 1 = normal, 2 = linha extra entre cada linha
        O texto e formatado para caber exatamente na largura util,
        com word-wrap automatico para textos longos.
        """
        try:
            # Largura util = total - margens
            largura_util = max(20, colunas - margem_esq - margem_dir)
            prefixo = " " * margem_esq  # espacos de margem esquerda

            line_sep = prefixo + "-" * largura_util
            line_eq = prefixo + "=" * largura_util

            sb = []

            def _add(texto):
                """Adiciona uma linha ao cupom com margem esquerda, truncada na largura util."""
                sb.append(prefixo + texto[:largura_util])

            def _add_center(texto):
                """Adiciona texto centralizado na largura util."""
                for ln in CupomGenerator._wrap_text(texto, largura_util):
                    sb.append(prefixo + CupomGenerator._center(ln, largura_util))

            def _add_right(texto):
                """Adiciona texto alinhado a direita na largura util."""
                sb.append(prefixo + CupomGenerator._right_align(texto, largura_util))

            def _add_wrap(texto):
                """Adiciona texto com word-wrap automatico."""
                for ln in CupomGenerator._wrap_text(texto, largura_util):
                    _add(ln)

            # === CABECALHO ===
            sb.append(line_eq)

            if empresa:
                # Helper para acessar dados da empresa (suporta objeto ou dict)
                def _get_emp(attr):
                    try:
                        if isinstance(empresa, dict):
                            return empresa.get(attr)
                        return getattr(empresa, attr, None)
                    except Exception:
                        return None

                nome_f = _get_emp("nome_fantasia")
                razao = _get_emp("razao_social")
                cnpj = _get_emp("cnpj")
                end = _get_emp("endereco")
                num = _get_emp("numero")
                bairro = _get_emp("bairro")
                cidade = _get_emp("cidade")
                uf = _get_emp("uf")
                fone = _get_emp("telefone")

                if nome_f:
                    _add_center(str(nome_f))
                if razao:
                    _add_center(str(razao))
                if cnpj:
                    _add_center(f"CNPJ: {cnpj}")
                
                endereco_parts = []
                if end: endereco_parts.append(str(end))
                if num: endereco_parts.append(f"N {num}")
                if bairro: endereco_parts.append(str(bairro))
                if endereco_parts:
                    _add_center(", ".join(endereco_parts))
                
                cidade_parts = []
                if cidade: cidade_parts.append(str(cidade))
                if uf: cidade_parts.append(str(uf))
                if cidade_parts:
                    _add_center(" - ".join(cidade_parts))
                
                if fone:
                    _add_center(f"Fone: {fone}")

            sb.append(line_sep)
            _add_center("CUPOM NAO FISCAL")
            sb.append(line_sep)

            # === DADOS DA VENDA ===
            _add_wrap(f"Venda: #{venda.id}")
            _add_wrap(f"Data: {FormatUtils.format_date(venda.data_venda)}")
            if venda.cliente_nome:
                _add_wrap(f"Cliente: {venda.cliente_nome}")
            if venda.vendedor_nome:
                _add_wrap(f"Vendedor: {venda.vendedor_nome}")
            sb.append(line_sep)

            # === ITENS ===
            def _item_nome_extras(item):
                """Separa o nome principal do item dos detalhes (proteinas e
                acompanhamentos do MONTE SEU PRATO), para impressao no cupom."""
                raw = (item.descricao_produto or "").strip()
                if " | " in raw:
                    partes = [p.strip() for p in raw.split(" | ") if p.strip()]
                    return partes[0], partes[1:]
                ad = getattr(item, "adicionais", None) or []
                extras = [a if isinstance(a, str) else str(a) for a in ad]
                return raw, extras

            def _print_extras(extras):
                """Imprime as proteinas/acompanhamentos indentados, com fonte
                visivel e quebra de linha automatica (abaixo do prato)."""
                for ex in extras:
                    for ln in CupomGenerator._wrap_text(ex, largura_util - 3):
                        _add("   " + ln)

            # Layout adaptativo conforme largura
            if largura_util >= 46:
                # Layout padrao: ITEM DESCRICAO QTD UNIT TOTAL em 1 linha
                col_item = 4
                col_total_val = 9  # espaco para TOTAL (ex: 1.234,56)
                col_unit = 9
                col_qty = 5
                col_desc = largura_util - col_item - col_qty - col_unit - col_total_val - 4  # 4 espacos separadores
                if col_desc < 8:
                    col_desc = 8

                header = (f"{'ITEM':<{col_item}} "
                          f"{'DESCRICAO':<{col_desc}} "
                          f"{'QTD':>{col_qty}} "
                          f"{'UNIT':>{col_unit}} "
                          f"{'TOTAL':>{col_total_val}}")
                _add(header[:largura_util])
                sb.append(line_sep)

                for i, item in enumerate(itens, 1):
                    nome, extras = _item_nome_extras(item)
                    qty = f"{item.quantidade:.0f}" if item.quantidade == int(item.quantidade) else f"{item.quantidade:.3f}"
                    unit = FormatUtils.format_money(item.preco_unitario)
                    total = FormatUtils.format_money(item.total)
                    if extras or len(nome) > col_desc:
                        # Prato montado (ou nome longo): nome em linha propria,
                        # detalhes indentados e valores alinhados a direita
                        _add_wrap(f"{i}. {nome}")
                        _print_extras(extras)
                        _add_right(f"{qty} x {unit} = R$ {total}")
                    else:
                        desc = nome[:col_desc]
                        linha = (f"{i:<{col_item}} "
                                 f"{desc:<{col_desc}} "
                                 f"{qty:>{col_qty}} "
                                 f"{unit:>{col_unit}} "
                                 f"{total:>{col_total_val}}")
                        _add(linha[:largura_util])

            elif largura_util >= 32:
                # Layout compacto: 2 linhas por item
                # Linha 1: NUM. DESCRICAO
                # Linha 2:          QTD x UNIT = TOTAL
                _add("ITEM DESCRICAO")
                sb.append(line_sep)

                for i, item in enumerate(itens, 1):
                    nome, extras = _item_nome_extras(item)
                    qty = f"{item.quantidade:.0f}" if item.quantidade == int(item.quantidade) else f"{item.quantidade:.3f}"
                    unit = FormatUtils.format_money(item.preco_unitario)
                    total = FormatUtils.format_money(item.total)
                    _add_wrap(f"{i:>3}. {nome}")
                    _print_extras(extras)
                    _add_right(f"{qty} x {unit} = R$ {total}")

            else:
                # Layout ultra-compacto (< 32 colunas)
                _add("ITENS:")
                sb.append(line_sep)
                for i, item in enumerate(itens, 1):
                    nome, extras = _item_nome_extras(item)
                    qty = f"{item.quantidade:.0f}" if item.quantidade == int(item.quantidade) else f"{item.quantidade:.3f}"
                    total = FormatUtils.format_money(item.total)
                    _add_wrap(f"{i}. {nome}")
                    _print_extras(extras)
                    _add_right(f"{qty} R$ {total}")

            sb.append(line_sep)

            # === DADOS DE ENTREGA ===
            if getattr(venda, "para_entrega", False):
                _add("** ENTREGA **")
                if getattr(venda, "bairro_entrega", ""):
                    _add_wrap(f"Bairro: {venda.bairro_entrega}")
                if getattr(venda, "endereco_entrega", ""):
                    _add_wrap(f"Endereco: {venda.endereco_entrega}")
                if getattr(venda, "celular_whatsapp", ""):
                    _add_wrap(f"WhatsApp: {venda.celular_whatsapp}")
                if getattr(venda, "entregador_nome", ""):
                    _add_wrap(f"Entregador: {venda.entregador_nome}")
                sb.append(line_sep)

            # === TOTAIS ===
            if venda.desconto_valor > 0:
                _add_right(f"SUBTOTAL: R$ {FormatUtils.format_money(venda.total_bruto)}")
                _add_right(f"DESCONTO: -R$ {FormatUtils.format_money(venda.desconto_valor)}")
            if venda.acrescimo_valor > 0:
                if venda.desconto_valor <= 0:
                    _add_right(f"SUBTOTAL: R$ {FormatUtils.format_money(venda.total_bruto)}")
                _add_right(f"ACRESCIMO: +R$ {FormatUtils.format_money(venda.acrescimo_valor)}")
            if venda.para_entrega and venda.taxa_entrega > 0:
                _add_right(f"TAXA ENTREGA: +R$ {FormatUtils.format_money(venda.taxa_entrega)}")

            _add_right(f"TOTAL: R$ {FormatUtils.format_money(venda.total_liquido)}")
            sb.append(line_sep)

            # === PAGAMENTO ===
            if venda.valor_recebido > 0:
                _add_right(f"RECEBIDO: R$ {FormatUtils.format_money(venda.valor_recebido)}")
            if venda.troco > 0:
                _add_right(f"TROCO: R$ {FormatUtils.format_money(venda.troco)}")

            if pagamentos:
                sb.append(line_sep)
                _add("FORMAS DE PAGAMENTO:")
                for pag in pagamentos:
                    forma = pag.forma_descricao or "N/A"
                    parcela = f" ({pag.parcelas}x)" if pag.parcelas > 1 else ""
                    pag_text = f"  {forma}{parcela}: R$ {FormatUtils.format_money(pag.valor)}"
                    _add_wrap(pag_text)

            sb.append(line_sep)

            # === OBSERVACAO ===
            if venda.observacao:
                _add("OBSERVACAO:")
                _add_wrap(f"  {venda.observacao}")
                sb.append(line_sep)

            # === OBS CUPOM ===
            if obs_cupom:
                for obs_line in CupomGenerator._wrap_text(obs_cupom, largura_util):
                    _add_center(obs_line)
                sb.append(line_sep)

            # === RODAPE ===
            _add_center(f"PDV Pro v{APP_VERSION}")
            _add_center("Obrigado pela preferencia!")
            _add_center("Contato sistema: (85) 98123-7727")
            sb.append(line_eq)

            # Aplicar espacamento entre linhas
            if espacamento and espacamento > 1:
                spaced = []
                for ln in sb:
                    spaced.append(ln)
                    for _ in range(espacamento - 1):
                        spaced.append("")  # linha em branco extra
                sb = spaced

            return "\n".join(sb)
        except Exception as e:
            return f"Erro ao gerar cupom: {e}"

    @staticmethod
    def _wrap_text(text, width):
        """Quebra texto longo em multiplas linhas respeitando a largura.
        Tenta quebrar em espacos; se nao couber, corta no limite."""
        if not text:
            return [""]
        text = str(text)
        if len(text) <= width:
            return [text]

        lines = []
        while len(text) > width:
            # Procurar ultimo espaco dentro da largura
            pos = text.rfind(" ", 0, width)
            if pos <= 0:
                # Sem espaco, cortar no limite
                pos = width
            lines.append(text[:pos])
            text = text[pos:].lstrip()
        if text:
            lines.append(text)
        return lines

    @staticmethod
    def _center(text, width):
        if not text:
            text = ""
        if len(text) >= width:
            return text[:width]
        pad = (width - len(text)) // 2
        return " " * pad + text

    @staticmethod
    def _right_align(text, width):
        if not text:
            text = ""
        if len(text) >= width:
            return text[:width]
        return " " * (width - len(text)) + text

    @staticmethod
    def gerar_cupom_parcial(venda, itens, nome_impressora="", nome_setor="",
                            empresa=None, colunas=48, margem_esq=0, margem_dir=0,
                            espacamento=1):
        """Gera cupom parcial contendo apenas os itens filtrados para uma impressora/setor.
        Usado no sistema de multiplas impressoras por categoria.
        Exibe: cabecalho da empresa, dados da venda, apenas os itens filtrados e o setor destino."""
        try:
            largura_util = max(20, colunas - margem_esq - margem_dir)
            prefixo = " " * margem_esq

            line_sep = prefixo + "-" * largura_util
            line_eq = prefixo + "=" * largura_util

            sb = []

            def _add(texto):
                sb.append(prefixo + texto[:largura_util])

            def _add_center(texto):
                for ln in CupomGenerator._wrap_text(texto, largura_util):
                    sb.append(prefixo + CupomGenerator._center(ln, largura_util))

            def _add_right(texto):
                sb.append(prefixo + CupomGenerator._right_align(texto, largura_util))

            def _add_wrap(texto):
                for ln in CupomGenerator._wrap_text(texto, largura_util):
                    _add(ln)

            # === CABECALHO ===
            sb.append(line_eq)
            if empresa:
                # Helper para acessar dados da empresa (suporta objeto ou dict)
                def _get_emp(attr):
                    try:
                        if isinstance(empresa, dict):
                            return empresa.get(attr)
                        return getattr(empresa, attr, None)
                    except Exception:
                        return None
                
                nome_f = _get_emp("nome_fantasia") or _get_emp("razao_social")
                if nome_f:
                    _add_center(str(nome_f))
            sb.append(line_sep)

            # Titulo do setor/impressora
            titulo_setor = nome_setor or nome_impressora or "PRODUCAO"
            _add_center(f"*** {titulo_setor.upper()} ***")
            sb.append(line_sep)

            # Dados da venda
            _add_wrap(f"Venda: #{venda.id}")
            _add_wrap(f"Data: {FormatUtils.format_date(venda.data_venda)}")
            if venda.cliente_nome:
                _add_wrap(f"Cliente: {venda.cliente_nome}")
            if venda.observacao:
                _add_wrap(f"Obs: {venda.observacao}")
            sb.append(line_sep)

            # === ITENS ===
            _add("ITENS:")
            sb.append(line_sep)

            for i, item in enumerate(itens, 1):
                desc = (item.descricao_produto or "")[:largura_util - 5]
                qty = f"{item.quantidade:.0f}" if item.quantidade == int(item.quantidade) else f"{item.quantidade:.3f}"
                _add(f"{i:>3}. {desc}")
                _add(f"     Qtd: {qty}")
                if item.adicionais:
                    for ad in item.adicionais:
                        ad_desc = ad if isinstance(ad, str) else str(ad)
                        _add(f"     + {ad_desc}")

            sb.append(line_sep)
            _add(f"Total de itens: {len(itens)}")
            sb.append(line_eq)
            data_hora = datetime.datetime.now().strftime("%d/%m/%Y %H:%M:%S")
            _add_center(f"Impresso: {data_hora}")
            sb.append(line_eq)

            # Espacamento
            if espacamento and espacamento > 1:
                spaced = []
                for ln in sb:
                    spaced.append(ln)
                    for _ in range(espacamento - 1):
                        spaced.append("")
                sb = spaced

            return "\n".join(sb)
        except Exception as e:
            return f"Erro ao gerar cupom parcial: {e}"

