# WIDGETS PERSONALIZADOS FUTURISTICOS
# ============================================================================

class StyledButton(tk.Canvas):
    """Botao futuristico com efeito neon glow, gradiente e animacao de hover."""
    def __init__(self, master, text="", command=None, color=COR_BOTAO,
                 hover_color=None, width=20, **kwargs):
        # Calcular dimensoes
        char_w = 9
        btn_w = max(width * char_w + 24, 100)
        btn_h = 38
        super().__init__(master, width=btn_w, height=btn_h,
                         bg=self._get_parent_bg(master), highlightthickness=0,
                         bd=0, **kwargs)

        self._color = color
        self._hover_color = hover_color or self._lighten(color, 30)
        self._text = text
        self._command = command
        self._btn_w = btn_w
        self._btn_h = btn_h
        self._pressed = False
        self._hovered = False

        self._draw()

        self.bind("<Enter>", self._on_enter)
        self.bind("<Leave>", self._on_leave)
        self.bind("<ButtonPress-1>", self._on_press)
        self.bind("<ButtonRelease-1>", self._on_release)

    def _get_parent_bg(self, master):
        try:
            return master.cget("bg")
        except Exception:
            return COR_FUNDO

    def _lighten(self, color, amount):
        try:
            r = min(255, int(color[1:3], 16) + amount)
            g = min(255, int(color[3:5], 16) + amount)
            b = min(255, int(color[5:7], 16) + amount)
            return f"#{r:02x}{g:02x}{b:02x}"
        except Exception:
            return color

    def _darken(self, color, amount):
        try:
            r = max(0, int(color[1:3], 16) - amount)
            g = max(0, int(color[3:5], 16) - amount)
            b = max(0, int(color[5:7], 16) - amount)
            return f"#{r:02x}{g:02x}{b:02x}"
        except Exception:
            return color

    def _draw(self):
        self.delete("all")
        w, h = self._btn_w, self._btn_h
        r = 8  # border radius

        if self._hovered:
            fill = self._hover_color
            outline = self._lighten(self._color, 50)
        elif self._pressed:
            fill = self._darken(self._color, 30)
            outline = self._color
        else:
            fill = self._color
            outline = self._darken(self._color, 20)

        # Sombra glow
        if self._hovered:
            glow_color = self._darken(self._color, 60)
            self.create_oval(4, h - 6, w - 4, h + 4, fill=glow_color, outline="")

        # Corpo do botao com cantos arredondados
        self._round_rect(2, 2, w - 2, h - 2, r, fill=fill, outline=outline, width=1)

        # Linha de brilho superior (highlight)
        highlight = self._lighten(fill, 40)
        self.create_line(r + 2, 4, w - r - 2, 4, fill=highlight, width=1)

        # Texto
        text_color = "#ffffff" if not self._is_light(fill) else "#0a0e1a"
        self.create_text(w // 2, h // 2, text=self._text,
                        fill=text_color, font=("Segoe UI", 10, "bold"))

    def _round_rect(self, x1, y1, x2, y2, r, **kwargs):
        """Desenha retangulo com cantos arredondados."""
        points = [
            x1 + r, y1,
            x2 - r, y1,
            x2, y1,
            x2, y1 + r,
            x2, y2 - r,
            x2, y2,
            x2 - r, y2,
            x1 + r, y2,
            x1, y2,
            x1, y2 - r,
            x1, y1 + r,
            x1, y1,
            x1 + r, y1,
        ]
        return self.create_polygon(points, smooth=True, **kwargs)

    def _is_light(self, color):
        try:
            r = int(color[1:3], 16)
            g = int(color[3:5], 16)
            b = int(color[5:7], 16)
            return (r * 299 + g * 587 + b * 114) / 1000 > 186
        except Exception:
            return False

    def _on_enter(self, event):
        self._hovered = True
        self.config(cursor="hand2")
        self._draw()

    def _on_leave(self, event):
        self._hovered = False
        self._pressed = False
        self.config(cursor="")
        self._draw()

    def _on_press(self, event):
        self._pressed = True
        self._draw()

    def _on_release(self, event):
        self._pressed = False
        self._draw()
        if self._hovered and self._command:
            self._command()

    def config(self, **kwargs):
        if "text" in kwargs:
            self._text = kwargs.pop("text")
            self._draw()
        if "command" in kwargs:
            self._command = kwargs.pop("command")
        if "state" in kwargs:
            state = kwargs.pop("state")
            if state == "disabled":
                self._command = None
                self._color = "#2a3a5c"
                self._hover_color = "#2a3a5c"
                self._draw()
        if "bg" in kwargs:
            self._color = kwargs.pop("bg")
            self._hover_color = self._lighten(self._color, 30)
            self._draw()
        super().config(**{k: v for k, v in kwargs.items() if k in ("cursor",)})

    configure = config


class StyledEntry(tk.Entry):
    """Campo de entrada futuristico com borda neon e efeito de foco."""
    def __init__(self, master, **kwargs):
        super().__init__(master, bg=COR_ENTRADA, fg=COR_TEXTO,
                         insertbackground=COR_PRIMARIA, font=("Segoe UI", 11),
                         relief="flat", bd=0, highlightthickness=2,
                         highlightcolor=COR_PRIMARIA,
                         highlightbackground=COR_ENTRADA_BORDER,
                         selectbackground=COR_PRIMARIA,
                         selectforeground="#ffffff",
                         **kwargs)
        # Efeito de foco neon
        self.bind("<FocusIn>", self._on_focus_in)
        self.bind("<FocusOut>", self._on_focus_out)

    def _on_focus_in(self, event):
        self.configure(highlightcolor=COR_PRIMARIA,
                      highlightbackground=COR_PRIMARIA)

    def _on_focus_out(self, event):
        self.configure(highlightcolor=COR_ENTRADA_BORDER,
                      highlightbackground=COR_ENTRADA_BORDER)


class DatePickerEntry(tk.Frame):
    """Campo de data com calendario popup futuristico.
    Exibe um Entry readonly + botao de calendario.
    Ao clicar, abre um popup com calendario visual para selecionar a data.
    Formato exibido: DD/MM/AAAA. Metodo get() retorna DD/MM/AAAA."""

    def __init__(self, master, width=15, **kwargs):
        bg = COR_GLASS
        try:
            bg = master.cget("bg")
        except Exception:
            pass
        super().__init__(master, bg=bg, **kwargs)

        self._selected_date = None  # datetime.date ou None
        self._popup = None

        # Frame interno para entry + botao
        inner = tk.Frame(self, bg=bg)
        inner.pack(anchor="w")

        self._entry = StyledEntry(inner, width=width)
        self._entry.pack(side="left")
        self._entry.config(state="readonly", readonlybackground=COR_ENTRADA,
                           cursor="hand2")
        self._entry.bind("<Button-1>", lambda e: self._toggle_popup())

        self._btn = tk.Button(inner, text=Icons.CALENDAR, bg=COR_ENTRADA,
                              fg=COR_PRIMARIA, relief="flat",
                              font=("Segoe UI", 12), cursor="hand2",
                              activebackground=COR_ENTRADA,
                              activeforeground=COR_ACCENT, bd=0,
                              command=self._toggle_popup)
        self._btn.pack(side="left", padx=(5, 0))

    def get(self):
        """Retorna a data selecionada no formato DD/MM/AAAA ou string vazia."""
        if self._selected_date:
            return self._selected_date.strftime("%d/%m/%Y")
        return ""

    def set_date(self, date_obj):
        """Define a data programaticamente (datetime.date)."""
        self._selected_date = date_obj
        self._update_entry()

    def _update_entry(self):
        self._entry.config(state="normal")
        self._entry.delete(0, "end")
        if self._selected_date:
            self._entry.insert(0, self._selected_date.strftime("%d/%m/%Y"))
        self._entry.config(state="readonly", readonlybackground=COR_ENTRADA)

    def _toggle_popup(self):
        if self._popup and self._popup.winfo_exists():
            self._popup.destroy()
            self._popup = None
            return
        self._show_popup()

    def _show_popup(self):
        """Abre o popup do calendario."""
        if self._popup and self._popup.winfo_exists():
            self._popup.destroy()

        self._popup = tk.Toplevel(self.winfo_toplevel())
        self._popup.overrideredirect(True)
        self._popup.configure(bg=COR_GLASS_BORDER)
        self._popup.attributes("-topmost", True)

        # Posicionar abaixo do entry
        x = self._entry.winfo_rootx()
        y = self._entry.winfo_rooty() + self._entry.winfo_height() + 4
        self._popup.geometry(f"+{x}+{y}")

        # Container principal
        container = tk.Frame(self._popup, bg=COR_GLASS, bd=0,
                             highlightthickness=2,
                             highlightbackground=COR_PRIMARIA)
        container.pack(fill="both", expand=True, padx=1, pady=1)

        # Data inicial para exibir
        if self._selected_date:
            self._cal_year = self._selected_date.year
            self._cal_month = self._selected_date.month
        else:
            today = datetime.date.today()
            self._cal_year = today.year
            self._cal_month = today.month

        self._cal_container = container
        self._draw_calendar()

        # Fechar ao clicar fora
        self._popup.bind("<FocusOut>", self._on_popup_focus_out)
        self._popup.focus_set()

    def _on_popup_focus_out(self, event):
        """Fecha o popup quando perde o foco (clicou fora)."""
        try:
            if self._popup and self._popup.winfo_exists():
                # Verificar se o foco foi para um widget filho do popup
                focused = self._popup.focus_get()
                if focused and str(focused).startswith(str(self._popup)):
                    return
                self._popup.after(150, self._close_popup_if_not_focused)
        except Exception:
            pass

    def _close_popup_if_not_focused(self):
        try:
            if self._popup and self._popup.winfo_exists():
                focused = self._popup.focus_get()
                if focused and str(focused).startswith(str(self._popup)):
                    return
                self._popup.destroy()
                self._popup = None
        except Exception:
            pass

    def _draw_calendar(self):
        """Desenha o calendario no popup."""
        # Limpar container
        for w in self._cal_container.winfo_children():
            w.destroy()

        container = self._cal_container

        # ---- Header: navegacao de mes/ano ----
        header = tk.Frame(container, bg=COR_GLASS)
        header.pack(fill="x", padx=8, pady=(8, 4))

        MESES_PT = ["", "Janeiro", "Fevereiro", "Marco", "Abril", "Maio",
                    "Junho", "Julho", "Agosto", "Setembro", "Outubro",
                    "Novembro", "Dezembro"]

        btn_prev_year = tk.Button(header, text="\u00AB", bg=COR_GLASS,
                                  fg=COR_PRIMARIA, relief="flat",
                                  font=("Segoe UI", 11, "bold"),
                                  cursor="hand2", bd=0,
                                  activebackground=COR_CARD_HOVER,
                                  activeforeground=COR_ACCENT,
                                  command=lambda: self._nav_calendar(-12))
        btn_prev_year.pack(side="left", padx=(0, 2))

        btn_prev = tk.Button(header, text="\u2039", bg=COR_GLASS,
                             fg=COR_PRIMARIA, relief="flat",
                             font=("Segoe UI", 14, "bold"),
                             cursor="hand2", bd=0,
                             activebackground=COR_CARD_HOVER,
                             activeforeground=COR_ACCENT,
                             command=lambda: self._nav_calendar(-1))
        btn_prev.pack(side="left", padx=(0, 4))

        month_year_text = f"{MESES_PT[self._cal_month]} {self._cal_year}"
        lbl_month = tk.Label(header, text=month_year_text, bg=COR_GLASS,
                             fg=COR_TEXTO, font=("Segoe UI", 11, "bold"))
        lbl_month.pack(side="left", expand=True)

        btn_next = tk.Button(header, text="\u203A", bg=COR_GLASS,
                             fg=COR_PRIMARIA, relief="flat",
                             font=("Segoe UI", 14, "bold"),
                             cursor="hand2", bd=0,
                             activebackground=COR_CARD_HOVER,
                             activeforeground=COR_ACCENT,
                             command=lambda: self._nav_calendar(1))
        btn_next.pack(side="right", padx=(4, 0))

        btn_next_year = tk.Button(header, text="\u00BB", bg=COR_GLASS,
                                  fg=COR_PRIMARIA, relief="flat",
                                  font=("Segoe UI", 11, "bold"),
                                  cursor="hand2", bd=0,
                                  activebackground=COR_CARD_HOVER,
                                  activeforeground=COR_ACCENT,
                                  command=lambda: self._nav_calendar(12))
        btn_next_year.pack(side="right", padx=(0, 2))

        # ---- Dias da semana ----
        days_frame = tk.Frame(container, bg=COR_GLASS)
        days_frame.pack(fill="x", padx=8, pady=(2, 0))

        dias_semana = ["Seg", "Ter", "Qua", "Qui", "Sex", "Sab", "Dom"]
        for d in dias_semana:
            cor_dia = COR_ERRO if d in ("Sab", "Dom") else COR_TEXTO2
            tk.Label(days_frame, text=d, bg=COR_GLASS, fg=cor_dia,
                     font=("Segoe UI", 9, "bold"), width=4).pack(side="left", padx=1)

        # ---- Grid de dias ----
        import calendar as _cal_mod
        cal = _cal_mod.Calendar(firstweekday=0)  # Segunda = 0
        weeks = cal.monthdayscalendar(self._cal_year, self._cal_month)

        today = datetime.date.today()

        for week in weeks:
            week_frame = tk.Frame(container, bg=COR_GLASS)
            week_frame.pack(fill="x", padx=8, pady=1)

            for i, day in enumerate(week):
                if day == 0:
                    # Dia vazio
                    tk.Label(week_frame, text="", bg=COR_GLASS,
                             width=4, height=1,
                             font=("Segoe UI", 10)).pack(side="left", padx=1)
                else:
                    d = datetime.date(self._cal_year, self._cal_month, day)
                    is_today = (d == today)
                    is_selected = (d == self._selected_date)
                    is_weekend = (i >= 5)  # Sab=5, Dom=6

                    if is_selected:
                        bg_cor = COR_PRIMARIA
                        fg_cor = "#000000"
                        font_w = "bold"
                    elif is_today:
                        bg_cor = COR_CARD_HOVER
                        fg_cor = COR_ACCENT
                        font_w = "bold"
                    else:
                        bg_cor = COR_GLASS
                        fg_cor = COR_ERRO if is_weekend else COR_TEXTO
                        font_w = "normal"

                    btn_day = tk.Label(week_frame, text=str(day), bg=bg_cor,
                                       fg=fg_cor, width=4, height=1,
                                       font=("Segoe UI", 10, font_w),
                                       cursor="hand2", relief="flat")
                    btn_day.pack(side="left", padx=1)

                    # Bind de clique
                    btn_day.bind("<Button-1>",
                                 lambda e, dt=d: self._select_date(dt))

                    # Hover
                    def _enter(e, w=btn_day, sel=is_selected):
                        if not sel:
                            w.config(bg=COR_CARD_HOVER)
                    def _leave(e, w=btn_day, sel=is_selected, orig_bg=bg_cor):
                        if not sel:
                            w.config(bg=orig_bg)
                    btn_day.bind("<Enter>", _enter)
                    btn_day.bind("<Leave>", _leave)

        # ---- Botao Hoje ----
        btn_hoje_frame = tk.Frame(container, bg=COR_GLASS)
        btn_hoje_frame.pack(fill="x", padx=8, pady=(6, 8))

        btn_hoje = tk.Button(btn_hoje_frame, text="Hoje", bg=COR_CARD_HOVER,
                             fg=COR_PRIMARIA, relief="flat",
                             font=("Segoe UI", 9, "bold"),
                             cursor="hand2", bd=0,
                             activebackground=COR_PRIMARIA,
                             activeforeground="#000000",
                             command=lambda: self._select_date(today))
        btn_hoje.pack(expand=True)

    def _nav_calendar(self, delta_months):
        """Navega o calendario por delta meses."""
        m = self._cal_month + delta_months
        y = self._cal_year
        while m > 12:
            m -= 12
            y += 1
        while m < 1:
            m += 12
            y -= 1
        self._cal_month = m
        self._cal_year = y
        self._draw_calendar()

    def _select_date(self, date_obj):
        """Seleciona uma data e fecha o popup."""
        self._selected_date = date_obj
        self._update_entry()
        if self._popup and self._popup.winfo_exists():
            self._popup.destroy()
            self._popup = None


