class ScrollableFrame(tk.Frame):
    """Frame com scroll e visual futuristico."""
    def __init__(self, master, **kwargs):
        super().__init__(master, bg=COR_FUNDO, **kwargs)
        self.canvas = tk.Canvas(self, bg=COR_FUNDO, highlightthickness=0)
        self.scrollbar = ttk.Scrollbar(self, orient="vertical", command=self.canvas.yview)
        self.scrollable_frame = tk.Frame(self.canvas, bg=COR_FUNDO)
        self.scrollable_frame.bind("<Configure>",
            lambda e: self.canvas.configure(scrollregion=self.canvas.bbox("all")))
        self.canvas.create_window((0, 0), window=self.scrollable_frame, anchor="nw")
        self.canvas.configure(yscrollcommand=self.scrollbar.set)
        self.canvas.pack(side="left", fill="both", expand=True)
        self.scrollbar.pack(side="right", fill="y")

        def _on_mousewheel(event):
            try:
                if not self.winfo_exists() or not self.canvas.winfo_exists():
                    return "break"
                bbox = self.canvas.bbox("all")
                if not bbox:
                    return "break"
                content_height = max(0, bbox[3] - bbox[1])
                canvas_height = max(1, self.canvas.winfo_height())
                if content_height <= canvas_height:
                    return "break"
                if getattr(event, "num", None) == 4:
                    self.canvas.yview_scroll(-3, "units")
                elif getattr(event, "num", None) == 5:
                    self.canvas.yview_scroll(3, "units")
                else:
                    delta = getattr(event, "delta", 0)
                    if delta:
                        self.canvas.yview_scroll(int(-1 * (delta / 120)), "units")
                return "break"
            except Exception:
                return "break"

        def _bind_mousewheel(event=None):
            try:
                if self.canvas.winfo_exists():
                    self.canvas.bind_all("<MouseWheel>", _on_mousewheel)
                    self.canvas.bind_all("<Button-4>", _on_mousewheel)
                    self.canvas.bind_all("<Button-5>", _on_mousewheel)
            except Exception:
                pass

        def _unbind_mousewheel(event=None):
            try:
                if self.canvas.winfo_exists():
                    self.canvas.unbind_all("<MouseWheel>")
                    self.canvas.unbind_all("<Button-4>")
                    self.canvas.unbind_all("<Button-5>")
            except Exception:
                pass

        self.canvas.bind("<Enter>", _bind_mousewheel)
        self.canvas.bind("<Leave>", _unbind_mousewheel)
        self.scrollable_frame.bind("<Enter>", _bind_mousewheel)
        self.scrollable_frame.bind("<Leave>", _unbind_mousewheel)
        self.bind("<Destroy>", lambda e: _unbind_mousewheel() if e.widget is self else None)


class NeonDivider(tk.Canvas):
    """Linha divisoria com efeito neon."""
    def __init__(self, master, color=COR_PRIMARIA, width_pct=0.8, **kwargs):
        super().__init__(master, height=3, bg=self._get_bg(master),
                         highlightthickness=0, **kwargs)
        self._color = color
        self._width_pct = width_pct
        self.bind("<Configure>", self._draw)

    def _get_bg(self, master):
        try:
            return master.cget("bg")
        except Exception:
            return COR_FUNDO

    def _draw(self, event=None):
        self.delete("all")
        w = self.winfo_width()
        margin = int(w * (1 - self._width_pct) / 2)
        # Linha central brilhante
        self.create_line(margin, 1, w - margin, 1, fill=self._color, width=1)
        # Glow sutil
        glow = self._darken(self._color, 80)
        self.create_line(margin + 20, 2, w - margin - 20, 2, fill=glow, width=1)

    def _darken(self, color, amount):
        try:
            r = max(0, int(color[1:3], 16) - amount)
            g = max(0, int(color[3:5], 16) - amount)
            b = max(0, int(color[5:7], 16) - amount)
            return f"#{r:02x}{g:02x}{b:02x}"
        except Exception:
            return color


class DigitalClock(tk.Label):
    """Relogio digital animado futuristico."""
    def __init__(self, master, **kwargs):
        super().__init__(master, text="", bg=COR_FUNDO2, fg=COR_PRIMARIA,
                         font=("Consolas", 12, "bold"), **kwargs)
        self._update()

    def _update(self):
        try:
            if self.winfo_exists():
                now = datetime.datetime.now()
                time_str = now.strftime("%H:%M:%S")
                date_str = now.strftime("%d/%m/%Y")
                self.config(text=f"{Icons.CLOCK} {time_str}  {date_str}")
                self.after(1000, self._update)
        except Exception:
            pass


class StatusIndicator(tk.Canvas):
    """Indicador de status com LED animado."""
    def __init__(self, master, color=COR_SUCESSO, size=10, **kwargs):
        bg = COR_FUNDO2
        try:
            bg = master.cget("bg")
        except Exception:
            pass
        super().__init__(master, width=size + 6, height=size + 6,
                         bg=bg, highlightthickness=0, **kwargs)
        self._color = color
        self._size = size
        # Glow
        glow_r = max(0, int(color[1:3], 16) // 3)
        glow_g = max(0, int(color[3:5], 16) // 3)
        glow_b = max(0, int(color[5:7], 16) // 3)
        glow_color = f"#{glow_r:02x}{glow_g:02x}{glow_b:02x}"
        self.create_oval(1, 1, size + 5, size + 5, fill=glow_color, outline="")
        self.create_oval(3, 3, size + 3, size + 3, fill=color, outline="")


