class PDVApp:
    def __init__(self, root):
        self.root = root
        self.root.title(APP_TITLE)
        self.root.configure(bg=COR_FUNDO)

        # Iniciar maximizado
        try:
            self.root.state("zoomed")
        except tk.TclError:
            try:
                self.root.attributes("-zoomed", True)
            except tk.TclError:
                sw = self.root.winfo_screenwidth()
                sh = self.root.winfo_screenheight()
                self.root.geometry(f"{sw}x{sh}+0+0")

        # Forcar maximizado
        def _forcar_maximizado(event=None):
            try:
                estado = self.root.state()
                if estado != "zoomed":
                    self.root.state("zoomed")
            except tk.TclError:
                try:
                    if not self.root.attributes("-zoomed"):
                        self.root.attributes("-zoomed", True)
                except tk.TclError:
                    pass
        self.root.bind("<Map>", _forcar_maximizado)

        # Estilo ttk FUTURISTICO
