    def show_error(self, message):
        """Exibe erro via toast (nao-bloqueante) e messagebox com mensagem amigavel.
        A mensagem e exibida de forma clara e profissional."""
        primeira_linha = message.split(chr(10))[0] if message else "Erro desconhecido"
        self.root.after(0, lambda: ToastManager.error(primeira_linha, duration=5000))
        self.root.after(0, lambda: messagebox.showerror("Ops! Algo deu errado", message))

    def show_success(self, message):
        """Exibe sucesso via toast (nao-bloqueante)."""
        self.root.after(0, lambda: ToastManager.success(message))

    def show_info_dialog(self, title, message):
        self.root.after(0, lambda: messagebox.showinfo(title, message))

    def show_toast(self, message, toast_type="info", duration=3000):
        """Exibe apenas toast, sem messagebox (para operacoes silenciosas)."""
        self.root.after(0, lambda: ToastManager.show(message, toast_type, duration))

    def run_async(self, func, callback=None, error_callback=None, retry_on_connection=True):
        """Executa funcao em thread separada com tratamento de erros robusto.
        - callback: chamado com o resultado em caso de sucesso
        - error_callback: chamado com a excecao em caso de erro
        - retry_on_connection: se True, tenta novamente em erros de conexao (1x)
        """
        func_name = func.__name__ if hasattr(func, '__name__') else 'operacao'
        def wrapper():
            tentativas = 2 if retry_on_connection else 1
            ultima_excecao = None
            for tentativa in range(tentativas):
                try:
                    result = func()
                    if callback:
                        def _safe_callback():
                            try:
                                callback(result)
                            except tk.TclError:
                                pass  # Widget destruido antes do callback executar
                            except Exception as cb_err:
                                ErroAmigavel.log_erro(cb_err, f"callback de {func_name}")
                        self.root.after(0, _safe_callback)
                    return  # Sucesso - sair do loop
                except Exception as e:
                    ultima_excecao = e
                    ErroAmigavel.log_erro(e, f"run_async({func_name}) tentativa {tentativa+1}/{tentativas}")
                    # Verificar se e erro de conexao e pode tentar novamente
                    is_conn_error = False
                    if hasattr(e, 'errno') and e.errno in (2002, 2003, 2006, 2013):
                        is_conn_error = True
                    elif type(e).__name__ in ('ConnectionRefusedError', 'ConnectionResetError',
                                               'ConnectionAbortedError', 'BrokenPipeError', 'TimeoutError'):
                        is_conn_error = True
                    elif any(kw in str(e).lower() for kw in ('connection', 'timeout', 'not connected')):
                        is_conn_error = True

                    if is_conn_error and tentativa < tentativas - 1:
                        # Tentar reconectar antes de retry
                        try:
                            db = DatabaseHelper.get_instance()
                            db._safe_reconnect()
                        except Exception:
                            pass
                        time.sleep(1)  # Aguardar 1 segundo antes de tentar novamente
                        continue  # Tentar novamente
                    break  # Nao e erro de conexao ou ultima tentativa

            # Se chegou aqui, todas as tentativas falharam
            e = ultima_excecao
            if error_callback:
                def _safe_error():
                    try:
                        error_callback(e)
                    except tk.TclError:
                        pass
                self.root.after(0, _safe_error)
            else:
                def _show_friendly_error():
                    msg, cod, det = ErroAmigavel.traduzir(e)
                    severidade = ErroAmigavel.obter_severidade(e)
                    # Toast com primeira linha
                    primeira_linha = msg.split(chr(10))[0]
                    try:
                        if severidade in (Severidade.CRITICO, Severidade.ALTO):
                            ToastManager.error(f"{primeira_linha} ({cod})", duration=5000)
                        else:
                            ToastManager.warning(f"{primeira_linha} ({cod})", duration=4000)
                    except Exception:
                        pass
                    # Messagebox com mensagem completa
                    self.show_error(
                        f"{msg}\n\n"
                        f"{'='*40}\n"
                        f"Codigo do erro: {cod}\n"
                        f"Informe este codigo ao suporte se precisar de ajuda.")
                self.root.after(0, _show_friendly_error)
        threading.Thread(target=wrapper, daemon=True).start()

    def _sort_tree(self, tree, col, reverse):
        """Ordena Treeview pelo coluna clicada. Alterna asc/desc."""
        try:
            data = [(tree.set(child, col), child)
                    for child in tree.get_children("")]
            try:
                data.sort(key=lambda x: float(
                    x[0].replace("R$", "").replace(".", "").replace(",", ".").strip()),
                    reverse=reverse)
            except (ValueError, AttributeError):
                data.sort(key=lambda x: x[0].lower(), reverse=reverse)
            for idx, (_, child) in enumerate(data):
                tree.move(child, "", idx)
                tag = "even" if idx % 2 == 0 else "odd"
                tree.item(child, tags=(tag,))
            tree.tag_configure("even", background=COR_GLASS)
            tree.tag_configure("odd", background=COR_CARD)
            tree.heading(col,
                command=lambda c=col: self._sort_tree(tree, c, not reverse))
        except Exception:
            pass

    def _apply_zebra(self, tree):
        """Aplica listras zebra em qualquer Treeview."""
        try:
            for i, child in enumerate(tree.get_children()):
                tag = "even" if i % 2 == 0 else "odd"
                current = list(tree.item(child, "tags"))
                if "even" in current:
                    current.remove("even")
                if "odd" in current:
                    current.remove("odd")
                current.append(tag)
                tree.item(child, tags=current)
            tree.tag_configure("even", background=COR_GLASS)
            tree.tag_configure("odd", background=COR_CARD)
        except Exception:
            pass

    def _create_top_bar(self, title, show_back=True, back_command=None):
        """Cria barra superior futuristica padrao."""
