        top.pack(fill="x")
        top.pack_propagate(False)
        # Linha neon superior
        _neon = tk.Canvas(top, height=2, bg=COR_FUNDO2, highlightthickness=0)
        _neon.pack(fill="x", side="top")
        _neon.bind("<Configure>", lambda e: (
            _neon.delete("all"),
            _neon.create_line(0, 1, e.width, 1, fill=COR_PRIMARIA, width=1)))

        # Linha neon superior
        neon_line = tk.Canvas(top, height=2, bg=COR_FUNDO2, highlightthickness=0)
        neon_line.pack(fill="x", side="top")
        neon_line.bind("<Configure>", lambda e: (
            neon_line.delete("all"),
            neon_line.create_line(0, 1, e.width, 1, fill=COR_PRIMARIA, width=1)
        ))

