    def _solicitar_senha_admin(self, callback, parent_window=None):
        """Exibe um dialog solicitando a senha de um administrador."""
        if Session.is_admin():
            callback()
            return

        parent = parent_window or self.root
        dialog = tk.Toplevel(parent)
        dialog.title("Autorizacao de Administrador")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(parent)
        dialog.grab_set()
        dialog.resizable(False, False)

        dlg_w = 420
        dlg_h = 340
        screen_w = dialog.winfo_screenwidth()
        screen_h = dialog.winfo_screenheight()
        pos_x = screen_w - dlg_w - 30
        pos_y = (screen_h - dlg_h) // 2
        dialog.geometry(f"{dlg_w}x{dlg_h}+{pos_x}+{pos_y}")

        tk.Label(dialog, text=f"{Icons.LOCK} Autorizacao Necessaria", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=(15, 5))
        tk.Label(dialog, text="Esta acao requer permissao de administrador.\n"
                              "Digite a senha de um administrador para continuar.",
                 bg=COR_FUNDO, fg=COR_TEXTO2, font=("Segoe UI", 10),
                 justify="center").pack(pady=(0, 10))

        card = GlassCard(dialog, glow_color=COR_ACCENT)
        card.pack(padx=25, pady=5, fill="x")

        tk.Label(card, text="Senha do Administrador:", bg=COR_GLASS, fg=COR_TEXTO,
                 font=("Segoe UI", 11)).pack(anchor="w", pady=(8, 2))
        et_senha = StyledEntry(card, show="*")
        et_senha.pack(fill="x", pady=(0, 10))
        et_senha.focus_set()

        lbl_erro = tk.Label(dialog, text="", bg=COR_FUNDO, fg=COR_ERRO,
                             font=("Segoe UI", 9, "italic"))
        lbl_erro.pack(pady=(0, 5))

        def validar(event=None):
            senha = et_senha.get().strip()
            if not senha:
                lbl_erro.config(text="Digite a senha.")
                return
            def verificar():
                db = DatabaseHelper.get_instance()
                rows = db.execute_query(
                    "SELECT id, nome FROM usuarios WHERE senha = %s AND nivel = 'admin' AND ativo = 1",
                    (senha,)
                )
                return rows
            def on_result(rows):
                if rows:
                    dialog.destroy()
                    callback()
                else:
                    lbl_erro.config(text="Senha invalida ou nao pertence a um administrador.")
