        StyledButton(btn_frame, text=f"{Icons.CROSS} Cancelar", command=dialog.destroy,
                     color="#2a3a5c", width=12).pack(side="right", padx=5)

        def trocar_usuario():
            dialog.destroy()
            self.do_logoff()

        StyledButton(btn_frame, text=f"{Icons.TROCAR} Trocar", command=trocar_usuario,
                     color=COR_BOTAO_LARANJA, width=12).pack(side="right", padx=5)

