    def toggle_senha(self):
        self.senha_visivel = not self.senha_visivel
        self.login_senha.config(show="" if self.senha_visivel else "\u2022")

    def carregar_usuarios_login(self):
        def load():
            try:
                db = DatabaseHelper.get_instance()
                db.create_tables()
                return db.execute_query(
                    "SELECT login, nome FROM usuarios WHERE ativo = 1 ORDER BY nome ASC"
                )
            except Exception as e:
                ErroAmigavel.log_erro(e, "carregar_usuarios_login")
                return []

        def on_loaded(users):
            # Verificar se o widget ainda existe (pode ter sido destruido
            # se o usuario navegou para outra tela durante o carregamento)
            try:
                if not hasattr(self, 'login_combo') or not self.login_combo.winfo_exists():
                    return
            except Exception:
                return
            if users:
                items = []
                self._login_map = {}
                for u in users:
                    nome = u.get("nome", "")
                    login = u.get("login", "")
                    if nome and nome.lower() != login.lower():
                        display = f"{nome} ({login})"
                    else:
                        display = login
                    items.append(display)
                    self._login_map[display] = login
                try:
                    self.login_combo["values"] = items
                    if items:
                        self.login_combo.current(0)
                except Exception:
                    pass  # Widget destruido durante a atribuicao
            else:
                try:
                    self.login_combo["values"] = ["Nenhum usuario encontrado"]
                except Exception:
                    pass
                self._login_map = {}

        self.run_async(load, on_loaded)

    def do_login(self):
        sel = self.login_combo.get()
        login = self._login_map.get(sel, "")
        senha = self.login_senha.get().strip()

        if not login:
            self.show_error(
                "Nenhum usuario foi encontrado no sistema.\n\n"
                "Possiveis causas:\n"
                "- O banco de dados nao esta conectado\n"
                "- O banco de dados esta vazio (primeiro uso)\n"
                "- As configuracoes do banco estao incorretas\n\n"
                "Clique em 'Configurar Banco' para verificar a conexao.")
            return
        if not senha:
            ToastManager.warning("Por favor, digite a senha.")
            return

        # Rate-limit: max 5 tentativas em 60 segundos por login
        now = time.time()
        attempts = self._login_attempts.get(login, [])
        attempts = [t for t in attempts if now - t < 60]
        if len(attempts) >= 5:
            msg = ("Voce fez muitas tentativas de login seguidas.\n"
                   "Por seguranca, aguarde 1 minuto antes de tentar novamente.\n\n"
                   "Se esqueceu sua senha, peca ajuda ao administrador do sistema.")
            ToastManager.error(msg, duration=6000)
            AuditLogger.log("LOGIN_BLOQUEADO", f"Login: {login} - rate limit atingido")
            return
        attempts.append(now)
        self._login_attempts[login] = attempts

        def authenticate():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT id, nome, nivel, perfil_id FROM usuarios "
                "WHERE login = %s AND senha = %s AND ativo = 1",
                (login, senha)
            )
            return rows

        def on_success(rows):
            if rows:
                user = rows[0]
                Session.user_id = user["id"]
                Session.user_nome = user["nome"]
                Session.user_nivel = user["nivel"]
                Session.user_login = login
                Session.user_perfil_id = user.get("perfil_id") or 0
                Session.load_permissions()
                # Limpar tentativas apos login bem-sucedido
                self._login_attempts.pop(login, None)
                # Atualizar barra de status
                self.status_bar.set_user(user["nome"], user["nivel"])
                self.status_bar.set_caixa(False)
                AuditLogger.log("LOGIN_OK", f"Usuario: {user['nome']} ({user['nivel']})",
                                usuario=login)
                ToastManager.success(f"Bem-vindo, {user['nome']}!")
                # === VERIFICACAO DE LICENCA APOS LOGIN (igual ao Android) ===
                self._verificar_licenca_pos_login()
            else:
                AuditLogger.log("LOGIN_FALHA", f"Login: {login} - senha incorreta")
                ToastManager.error("Senha incorreta. Verifique e tente novamente.", duration=4000)
                messagebox.showerror(
                    "Senha Incorreta",
                    "A senha digitada esta incorreta.\n\n"
                    "POSSIVEIS CAUSAS:\n"
                    "- O Caps Lock (letras maiusculas) pode estar ativado\n"
                    "- A tecla Num Lock pode estar desativada\n"
                    "- A senha pode ter sido digitada com espacos extras\n\n"
                    "COMO RESOLVER:\n"
                    "1. Verifique se o Caps Lock esta DESLIGADO\n"
                    "2. Digite a senha com cuidado, letra por letra\n"
                    "3. Se esqueceu a senha, peca ao administrador para redefinir\n"
                    "4. O administrador pode trocar sua senha no menu de usuarios")

        self.run_async(authenticate, on_success)

    def show_trocar_senha_dialog(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Trocar Senha")
        dialog.geometry("440x340")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        tk.Label(dialog, text=f"{Icons.LOCK} Trocar Senha", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=15)

        card = GlassCard(dialog)
        card.pack(padx=20, pady=10, fill="x")

        tk.Label(card, text="Login:", bg=COR_GLASS, fg=COR_TEXTO).pack(anchor="w")
        et_login = StyledEntry(card)
        et_login.pack(fill="x", pady=(0, 8))

        tk.Label(card, text="Senha Atual:", bg=COR_GLASS, fg=COR_TEXTO).pack(anchor="w")
        et_atual = StyledEntry(card, show="\u2022")
        et_atual.pack(fill="x", pady=(0, 8))

        tk.Label(card, text="Nova Senha:", bg=COR_GLASS, fg=COR_TEXTO).pack(anchor="w")
        et_nova = StyledEntry(card, show="\u2022")
        et_nova.pack(fill="x", pady=(0, 10))

        def trocar():
            lg = et_login.get().strip()
            atual = et_atual.get().strip()
            nova = et_nova.get().strip()
            if not lg or not atual or not nova:
                messagebox.showwarning(
                    "Campos Obrigatorios",
                    "Todos os campos precisam ser preenchidos para trocar a senha.\n\n"
                    "PREENCHA:\n"
                    "1. Login do usuario - seu nome de acesso ao sistema\n"
                    "2. Senha atual - a senha que voce usa hoje\n"
                    "3. Nova senha - a senha que deseja usar\n\n"
                    "Se nao lembra seu login, peca ajuda ao administrador.",
                    parent=dialog)
                return
            try:
                db = DatabaseHelper.get_instance()
                rows = db.execute_query(
                    "SELECT id FROM usuarios WHERE login = %s AND senha = %s AND ativo = 1",
                    (lg, atual)
                )
                if rows:
                    db.execute_update(
                        "UPDATE usuarios SET senha = %s WHERE id = %s",
                        (nova, rows[0]["id"])
                    )
                    messagebox.showinfo(
                        "Senha Alterada",
                        "Sua senha foi alterada com sucesso!\n\n"
                        "A partir de agora, use a nova senha para fazer login.\n"
                        "Guarde sua nova senha em um local seguro.",
                        parent=dialog)
                    dialog.destroy()
                else:
                    messagebox.showerror(
                        "Dados Incorretos",
                        "O login ou a senha atual estao incorretos.\n\n"
                        "COMO RESOLVER:\n"
                        "1. Verifique se o login esta correto\n"
                        "2. Verifique se a senha atual esta correta\n"
                        "3. Cuidado com Caps Lock e espacos extras\n"
                        "4. Se esqueceu a senha, peca ao administrador para redefinir\n\n"
                        "O administrador pode trocar sua senha pelo menu de usuarios.",
                        parent=dialog)
            except Exception as e:
                ErroAmigavel.mostrar_erro(e, "trocar_senha", parent=dialog)

        StyledButton(card, text=f"{Icons.SAVE} Trocar Senha", command=trocar).pack(pady=5)

    # ========================================================================
    # CONFIGURACAO DO BANCO DE DADOS
    # ========================================================================
    def show_config_banco(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Configuracao do Banco de Dados")
        dialog.geometry("480x440")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        tk.Label(dialog, text=f"{Icons.CONFIG} Configuracao MySQL", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=15)

        card = GlassCard(dialog)
        card.pack(padx=20, pady=10, fill="x")

        db = DatabaseHelper.get_instance()
        fields = [
            ("Host:", db.host),
            ("Banco:", db.database),
            ("Usuario:", db.username),
            ("Senha:", db.password),
            ("Porta:", str(db.port))
        ]
        entries = []
        for label, value in fields:
            tk.Label(card, text=label, bg=COR_GLASS, fg=COR_TEXTO,
                     font=("Segoe UI", 10)).pack(anchor="w")
            e = StyledEntry(card)
            e.insert(0, value)
            if label == "Senha:":
                e.config(show="\u2022")
            e.pack(fill="x", pady=(0, 8))
            entries.append(e)

        btn_frame = tk.Frame(card, bg=COR_GLASS)
        btn_frame.pack(fill="x", pady=10)

        def testar():
            try:
                ok = db.test_connection(
                    entries[0].get(), entries[1].get(),
                    entries[2].get(), entries[3].get(),
                    int(entries[4].get())
                )
                if ok:
                    messagebox.showinfo(
                        "Conexao OK",
                        "Conexao com o banco de dados realizada com sucesso!\n\n"
                        "O sistema conseguiu se comunicar com o MySQL.\n"
                        "Clique em 'Salvar' para gravar estas configuracoes.",
                        parent=dialog)
                else:
                    messagebox.showerror(
                        "Falha na Conexao",
                        "Nao foi possivel conectar ao banco de dados.\n\n"
                        "VERIFIQUE:\n"
                        "1. O MySQL esta instalado e rodando?\n"
                        "2. O endereco (Host) esta correto?\n"
                        "3. O usuario e senha do banco estao corretos?\n"
                        "4. A porta esta correta? (padrao: 3306)\n"
                        "5. O firewall nao esta bloqueando?\n\n"
                        "DICA: Se o banco esta neste computador,\n"
                        "use 'localhost' no campo Host.",
                        parent=dialog)
            except Exception as e:
                ErroAmigavel.mostrar_erro(e, "operacao_dialog", parent=dialog)

        def salvar():
            try:
                db.save_config(
                    entries[0].get(), entries[1].get(),
                    entries[2].get(), entries[3].get(),
                    int(entries[4].get())
                )
                messagebox.showinfo(
                    "Configuracao Salva",
                    "As configuracoes do banco de dados foram salvas com sucesso!\n\n"
                    "O sistema ira se reconectar usando as novas configuracoes.",
                    parent=dialog)
                dialog.destroy()
                self.carregar_usuarios_login()
            except Exception as e:
                ErroAmigavel.mostrar_erro(e, "operacao_dialog", parent=dialog)

        StyledButton(btn_frame, text=f"{Icons.REFRESH} Testar", command=testar,
                     color=COR_BOTAO_AZUL, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text=f"{Icons.SAVE} Salvar", command=salvar,
                     color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=5)

    def do_logoff(self):
        """Realiza a troca de usuario, desconectando o atual e retornando a tela de login."""
        if messagebox.askyesno("Trocar Usuario",
                f"Deseja desconectar o usuario '{Session.user_nome}'?\n\n"
                "Voce sera redirecionado para a tela de login."):
            AuditLogger.log("LOGOFF", usuario=Session.user_login)
            self.show_login()

    # ========================================================================
    # SISTEMA DE LICENCA - VERIFICACAO E BLOQUEIO
    # ========================================================================

    def _verificar_licenca_pos_login(self):
        """Verifica a licenca apos login bem-sucedido.
        Equivalente ao fluxo do LoginActivity.java do Android:
        - Se licenca valida: vai para o menu principal
        - Se licenca expirada: mostra tela de bloqueio com info de vencimento
        - Se licenca faltante/invalida: mostra tela de bloqueio"""
        def check():
            try:
                # Forcar recarga do cache do disco (garante que nao usa cache stale em memoria)
                # Isso e essencial apos reiniciar o app, quando _cache e None
                if LicencaManager._cache is None:
                    print("[LICENCA] Cache em memoria vazio - forcando leitura do disco...")
                    LicencaManager._carregar_cache_local()

                valida = LicencaManager.verificar_licenca()
                expirada = False
                data_exp = None
                if not valida:
                    expirada = LicencaManager.is_licenca_expirada()
                    if expirada:
                        data_exp = LicencaManager.get_data_expiracao()
                return {"valida": valida, "expirada": expirada, "data_exp": data_exp}
            except Exception as e:
                print(f"[LICENCA] Erro ao verificar licenca pos-login: {e}")
                import traceback
                traceback.print_exc()
                # Em caso de erro, tentar verificar apenas o cache local
                try:
                    cache_ok = LicencaManager._verificar_cache_local()
                    if cache_ok:
                        print("[LICENCA] Fallback: cache local valido apos erro")
                        return {"valida": True, "expirada": False, "data_exp": None}
                except Exception:
                    pass
                return {"valida": False, "expirada": False, "data_exp": None}

        def on_result(result):
            if result["valida"]:
                # Verificar se houve fraude de data mesmo com licenca "valida"
                if LicencaManager._date_fraud_detected:
                    AuditLogger.log("LICENCA_BLOQUEIO",
                                    "Sistema bloqueado - fraude de data detectada",
                                    usuario=Session.user_login)
                    self._show_tela_bloqueio_licenca_fraude()
                    return
                # Setar flag para pular re-verificacao no show_main_menu
                # (ja verificamos agora, nao precisa verificar de novo)
                self._licenca_recem_ativada = True
                AuditLogger.log("LICENCA_OK", "Licenca valida - sistema habilitado",
                                usuario=Session.user_login)
                # Iniciar monitor periodico de licenca (verifica a cada 5 min)
                self._start_licenca_monitor()
                self.show_main_menu()
            else:
                motivo = "expirada" if result["expirada"] else "invalida/faltante"
                AuditLogger.log("LICENCA_BLOQUEIO",
                                f"Sistema bloqueado - licenca {motivo}",
                                usuario=Session.user_login)
                self._show_tela_bloqueio_licenca(
                    expirada=result["expirada"],
                    data_exp=result["data_exp"]
                )

        self.run_async(check, on_result)

    def _sincronizar_status_caixa(self):
        """Sincroniza o status do caixa com o banco de dados ao entrar no menu principal.
        Garante que Session.caixa_id esteja sempre atualizado, evitando inconsistencias
        caso o caixa tenha sido fechado por outro terminal ou sessao."""
        def check():
            try:
                db = DatabaseHelper.get_instance()
                rows = db.execute_query(
                    "SELECT id FROM caixa WHERE status = 'aberto' ORDER BY id DESC LIMIT 1"
                )
                return rows
            except Exception:
                return None

        def on_result(rows):
            try:
                if rows:
                    Session.caixa_id = rows[0]["id"]
                    self.status_bar.set_caixa(True, Session.caixa_id)
                else:
                    Session.caixa_id = 0
                    self.caixa_aberto = None
                    self.status_bar.set_caixa(False)
            except Exception:
                pass

        self.run_async(check, on_result)

    def _verificar_licenca_menu(self):
        """Verifica a licenca ao acessar o menu principal (equivalente ao onResume do Android).
        Se invalida, bloqueia o sistema.
        Se a licenca foi recem-ativada, pula a re-verificacao para evitar race condition."""
        # Se a licenca acabou de ser ativada, pular a verificacao
        # e resetar o flag para que proximas chamadas verifiquem normalmente
        if self._licenca_recem_ativada:
            self._licenca_recem_ativada = False
            return

        def check():
            try:
                return LicencaManager.verificar_licenca()
            except Exception as e:
                print(f"[LICENCA] Erro em verificar_licenca_menu: {e}")
                # Fallback: se cache local e valido, nao bloquear
                try:
                    if LicencaManager._verificar_cache_local():
                        print("[LICENCA] Fallback menu: cache local valido")
                        return True
                except Exception:
                    pass
                return False

        def on_result(valida):
            if not valida or LicencaManager._date_fraud_detected:
                if LicencaManager._date_fraud_detected:
                    AuditLogger.log("LICENCA_BLOQUEIO",
                                    "Sistema bloqueado durante uso - fraude de data",
                                    usuario=Session.user_login)
                    self._show_tela_bloqueio_licenca_fraude()
                else:
                    expirada = LicencaManager.is_licenca_expirada()
                    data_exp = LicencaManager.get_data_expiracao() if expirada else None
                    AuditLogger.log("LICENCA_BLOQUEIO",
                                    "Sistema bloqueado durante uso - licenca invalida",
                                    usuario=Session.user_login)
                    self._show_tela_bloqueio_licenca(
                        expirada=expirada, data_exp=data_exp)

        self.run_async(check, on_result)

    def _show_tela_bloqueio_licenca(self, expirada=False, data_exp=None):
        """Exibe a tela de bloqueio por licenca invalida/faltante/expirada.
        O usuario NAO pode usar o sistema ate ativar uma licenca valida.
        Equivalente ao comportamento do LicencaActivity + bloqueio do Android."""
        self.clear_container()

        # Fundo com particulas (visual mantido)
        self._create_bg_particles(self.main_container)

        # Container central com scroll
        outer = tk.Frame(self.main_container, bg=COR_FUNDO)
        outer.place(relx=0.5, rely=0.5, anchor="center")

        # ---- Icone de bloqueio ----
        icon_frame = tk.Frame(outer, bg=COR_FUNDO)
        icon_frame.pack(pady=(0, 5))

        block_canvas = tk.Canvas(icon_frame, width=90, height=90, bg=COR_FUNDO,
                                  highlightthickness=0)
        block_canvas.pack()
        # Circulo vermelho
        block_canvas.create_oval(5, 5, 85, 85, outline=COR_ERRO, fill="", width=3)
        block_canvas.create_text(45, 45, text=Icons.BLOCKED, fill=COR_ERRO,
                                  font=("Segoe UI", 32, "bold"))

        # ---- Titulo de bloqueio ----
        tk.Label(outer, text="SISTEMA BLOQUEADO", bg=COR_FUNDO, fg=COR_ERRO,
                 font=("Segoe UI", 28, "bold")).pack(pady=(10, 5))

        # ---- Mensagem principal ----
        if expirada and data_exp:
            # Formatar data para DD/MM/AAAA
            try:
                dt = datetime.datetime.strptime(data_exp, "%Y-%m-%d")
                data_fmt = dt.strftime("%d/%m/%Y")
            except Exception:
                data_fmt = data_exp
            dias = LicencaManager.get_dias_para_vencimento()
            msg_principal = (
                f"Sua licenca esta VENCIDA desde {data_fmt}\n"
                f"({abs(dias)} dia(s) apos o vencimento)\n\n"
                "O sistema esta bloqueado por licenca expirada.\n"
                "Procure o suporte para renovar sua licenca."
            )
        elif expirada:
            msg_principal = (
                "Sua licenca esta VENCIDA.\n\n"
                "O sistema esta bloqueado por licenca expirada.\n"
                "Procure o suporte para renovar sua licenca."
            )
        else:
            msg_principal = (
                "Licenca invalida ou nao encontrada.\n\n"
                "O sistema esta bloqueado por licenca invalida.\n"
                "Procure o suporte para validar sua licenca."
            )

        tk.Label(outer, text=msg_principal, bg=COR_FUNDO, fg=COR_TEXTO,
                 font=("Segoe UI", 12), justify="center").pack(pady=(5, 15))

        # ---- Card de ativacao ----
        card = GlassCard(outer, glow_color=COR_ERRO)
        card.pack(padx=30, pady=5, ipadx=25, ipady=15)

        # Contra-chave
        contra_chave = LicencaManager.gerar_contra_chave()
        ck_frame = tk.Frame(card, bg=COR_GLASS)
        ck_frame.pack(fill="x", pady=(5, 12))

        tk.Label(ck_frame, text=f"{Icons.KEY} Contra-Chave:", bg=COR_GLASS,
                 fg=COR_TEXTO2, font=("Segoe UI", 10)).pack(anchor="w")

        ck_display_frame = tk.Frame(ck_frame, bg=COR_GLASS)
        ck_display_frame.pack(fill="x", pady=(3, 0))

        ck_entry = StyledEntry(ck_display_frame, width=22)
        ck_entry.insert(0, contra_chave)
        ck_entry.config(state="readonly")
        ck_entry.pack(side="left", fill="x", expand=True)

        def copiar_contra_chave():
            try:
                self.root.clipboard_clear()
                self.root.clipboard_append(contra_chave)
                ToastManager.success("Contra-chave copiada!")
            except Exception:
                pass

        btn_copiar = tk.Button(ck_display_frame, text=Icons.COPY, bg=COR_ENTRADA,
                                fg=COR_PRIMARIA, relief="flat", font=("Segoe UI", 12),
                                cursor="hand2", activebackground=COR_ENTRADA,
                                activeforeground=COR_ACCENT, bd=0,
                                command=copiar_contra_chave)
        btn_copiar.pack(side="right", padx=(5, 0))
        add_tooltip(btn_copiar, "Copiar contra-chave para a area de transferencia")

        tk.Label(card, text="Informe esta contra-chave ao suporte para obter a chave de ativacao.",
                 bg=COR_GLASS, fg=COR_ALERTA,
                 font=("Segoe UI", 9, "italic"), wraplength=380).pack(pady=(0, 10))

        NeonDivider(card, color=COR_ERRO, width_pct=0.8).pack(fill="x", padx=10, pady=8)

        # Chave de ativacao
        tk.Label(card, text=f"{Icons.LOCK} Chave de Ativacao:", bg=COR_GLASS,
                 fg=COR_TEXTO2, font=("Segoe UI", 10)).pack(anchor="w", pady=(5, 3))
        et_chave = StyledEntry(card, width=40)
        et_chave.pack(fill="x", pady=(0, 10))
        add_tooltip(et_chave, "Cole aqui a chave de ativacao fornecida pelo suporte")

        # Data de expiracao (DatePicker com calendario)
        tk.Label(card, text=f"{Icons.CALENDAR} Data de Expiracao:",
                 bg=COR_GLASS, fg=COR_TEXTO2,
                 font=("Segoe UI", 10)).pack(anchor="w", pady=(0, 3))
        et_data = DatePickerEntry(card, width=15)
        et_data.pack(anchor="w", pady=(0, 12))
        add_tooltip(et_data, "Clique para selecionar a data de expiracao da licenca")

        # ---- Status da licenca atual ----
        status_frame = tk.Frame(card, bg=COR_GLASS)
        status_frame.pack(fill="x", pady=(0, 5))

        if expirada and data_exp:
            try:
                dt = datetime.datetime.strptime(data_exp, "%Y-%m-%d")
                data_fmt = dt.strftime("%d/%m/%Y")
            except Exception:
                data_fmt = data_exp
            status_text = f"Status: Licenca VENCIDA em {data_fmt}"
            status_color = COR_ERRO
        elif data_exp:
            status_text = "Status: Licenca INVALIDA"
            status_color = COR_ERRO
        else:
            status_text = "Status: Sem licenca cadastrada"
            status_color = COR_ALERTA

        StatusIndicator(status_frame, color=status_color, size=8).pack(side="left", padx=(0, 5))
        tk.Label(status_frame, text=status_text, bg=COR_GLASS, fg=status_color,
                 font=("Segoe UI", 10, "bold")).pack(side="left")

        # ---- Botao Ativar ----
        def ativar_licenca():
            chave = et_chave.get().strip()
            data_str = et_data.get().strip()

            if not chave or not data_str:
                messagebox.showwarning(
                    "Campos Obrigatorios",
                    "Para ativar a licenca, preencha todos os campos.\n\n"
                    "1. Cole a CHAVE DE ATIVACAO fornecida pelo suporte\n"
                    "2. Selecione a DATA DE EXPIRACAO no calendario\n\n"
                    "Se nao tem uma chave, entre em contato com o suporte\n"
                    "para adquirir uma licenca.")
                return

            # Converter DD/MM/AAAA para AAAA-MM-DD
            try:
                dt = datetime.datetime.strptime(data_str, "%d/%m/%Y")
                data_interno = dt.strftime("%Y-%m-%d")
                try:
                    hoje_conf, _ = LicencaManager._obter_data_confiavel()
                except Exception:
                    hoje_conf = datetime.date.today()
                if dt.date() < hoje_conf:
                    hoje_fmt = hoje_conf.strftime("%d/%m/%Y")
                    messagebox.showerror(
                        "Data de Expiracao Invalida",
                        f"A data selecionada ja passou!\n\n"
                        f"Data selecionada: {data_str}\n"
                        f"Data de hoje: {hoje_fmt}\n\n"
                        f"COMO RESOLVER:\n"
                        f"1. Selecione uma data FUTURA no calendario\n"
                        f"2. A data deve ser a mesma informada pelo suporte\n"
                        f"3. Se a data do suporte ja passou, solicite uma nova chave")
                    return
            except ValueError:
                messagebox.showerror(
                    "Data Invalida",
                    "A data de expiracao informada nao e valida.\n\n"
                    "COMO RESOLVER:\n"
                    "1. Use o calendario para selecionar a data\n"
                    "2. O formato correto e DD/MM/AAAA\n"
                    "3. Exemplo: 31/12/2026")
                return

            def do_ativar():
                return LicencaManager.ativar_licenca(contra_chave, chave, data_interno)

            def on_ativado(success):
                if success:
                    # Setar flag para pular re-verificacao no show_main_menu
                    self._licenca_recem_ativada = True
                    # Resetar flag de fraude apos ativacao bem-sucedida
                    LicencaManager._date_fraud_detected = False
                    # Exibir mensagem de sucesso clara ao usuario
                    messagebox.showinfo(
                        "Licenca Ativada",
                        f"Licenca ativada com sucesso!\n\n"
                        f"Sua licenca e valida ate {data_str}.\n\n"
                        f"O sistema sera habilitado agora.")
                    ToastManager.success("Licenca ativada com sucesso! Sistema habilitado.")
                    AuditLogger.log("LICENCA_ATIVADA",
                                    f"Licenca ativada ate {data_str} - sistema habilitado",
                                    usuario=Session.user_login)
                    # Reiniciar monitor periodico de licenca
                    self._start_licenca_monitor()
                    # Ir para a tela principal
                    self.show_main_menu()
                else:
                    messagebox.showerror(
                        "Chave de Ativacao Invalida",
                        "A chave de ativacao informada nao foi aceita.\n\n"
                        "POSSIVEIS CAUSAS:\n"
                        "1. A chave foi digitada ou colada incorretamente\n"
                        "2. A data de expiracao nao corresponde a chave\n"
                        "3. A chave pode ter sido gerada para outro computador\n\n"
                        "COMO RESOLVER:\n"
                        "1. Copie a chave COMPLETA (Ctrl+C) e cole aqui (Ctrl+V)\n"
                        "2. Verifique se a data de expiracao esta correta\n"
                        "3. Confira os dados com o suporte que forneceu a chave\n"
                        "4. Se necessario, solicite uma nova chave ao suporte")

            self.run_async(do_ativar, on_ativado)

        btn_frame = tk.Frame(card, bg=COR_GLASS)
        btn_frame.pack(fill="x", pady=(5, 5))

        StyledButton(btn_frame, text=f"{Icons.CHECK}  ATIVAR LICENCA",
                     command=ativar_licenca,
                     color=COR_BOTAO_VERDE, width=28).pack(pady=(5, 3))

        # ---- Rodape com info de suporte ----
        tk.Label(outer, text="Entre em contato com o suporte tecnico para obter sua licenca.",
                 bg=COR_FUNDO, fg=COR_TEXTO2,
                 font=("Segoe UI", 9)).pack(pady=(15, 3))
        tk.Label(outer, text="Powered by PDV Pro Technology",
                 bg=COR_FUNDO, fg="#2a3a5c",
                 font=("Segoe UI", 8)).pack(pady=(0, 0))

