        vsb = ttk.Scrollbar(content, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=vsb.set)
        tree.pack(side="left", fill="both", expand=True)
        vsb.pack(side="right", fill="y")

        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=10, pady=8)

        def _ver_cupom():
            sel = tree.selection()
            if not sel:
                ToastManager.warning("Selecione uma venda.")
                return
            venda_id = tree.item(sel[0])["values"][0]
            dialog.destroy()
            self.show_historico()

        def _ir_historico():
            dialog.destroy()
            self.show_historico()

        StyledButton(btn_frame, text=f"{Icons.HISTORICO} Abrir Historico",
                     command=_ir_historico,
                     color=COR_BOTAO_AZUL, width=16).pack(side="left", padx=5)
        StyledButton(btn_frame, text="Fechar", command=dialog.destroy,
                     color=COR_FUNDO3, width=10).pack(side="right", padx=5)

        def _carregar():
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT v.id, COALESCE(NULLIF(v.cliente_nome,''), NULLIF(u.cliente_nome,''), c.nome,'N/A') as cliente_nome, "
                    "v.total_liquido, v.data_venda, v.status, "
                    "GROUP_CONCAT(fp.descricao SEPARATOR ' + ') as formas "
                    "FROM vendas v "
                    "LEFT JOIN clientes c ON v.cliente_id = c.id "
                    "LEFT JOIN uso_armario_sauna u ON v.uso_armario_id = u.id "
                    "LEFT JOIN pagamentos_venda pv ON pv.venda_id = v.id "
                    "LEFT JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                    "WHERE v.status='finalizada' AND DATE(v.data_venda) = CURDATE() "
                    "GROUP BY v.id ORDER BY v.id DESC"
                )
            def on_loaded(rows):
                tree.delete(*tree.get_children())
                total_valor = 0.0
                for i, r in enumerate(rows):
                    tag = "even" if i % 2 == 0 else "odd"
                    tree.insert("", "end", values=(
                        r["id"],
                        r.get("cliente_nome") or "N/A",
                        f"R$ {FormatUtils.format_money(r['total_liquido'])}",
                        FormatUtils.format_date(r["data_venda"]),
                        r["status"],
                        r.get("formas") or ""
                    ), tags=(tag,))
                    total_valor += float(r.get("total_liquido", 0))
                tree.tag_configure("even", background=COR_GLASS)
                tree.tag_configure("odd", background=COR_CARD)
                lbl_resumo.config(
                    text=f"{len(rows)} vendas  |  Total: R$ {FormatUtils.format_money(total_valor)}")
            self.run_async(load, on_loaded)
        _carregar()

