        cols_v = ("id", "cliente", "total", "hora", "formas")
        tree_v = ttk.Treeview(content, columns=cols_v, show="headings", height=10)
        tree_v.heading("id", text="ID")
        tree_v.heading("cliente", text="Cliente")
        tree_v.heading("total", text="Total")
        tree_v.heading("hora", text="Hora")
        tree_v.heading("formas", text="Pagamento")
        tree_v.column("id", width=55, anchor="center")
        tree_v.column("cliente", width=200)
        tree_v.column("total", width=110, anchor="e")
        tree_v.column("hora", width=80, anchor="center")
        tree_v.column("formas", width=180)

        vsb = ttk.Scrollbar(content, orient="vertical", command=tree_v.yview)
        tree_v.configure(yscrollcommand=vsb.set)
        tree_frame = tk.Frame(content, bg=COR_FUNDO)
        tree_frame.pack(fill="both", expand=True)
        tree_v.pack(in_=tree_frame, side="left", fill="both", expand=True)
        vsb.pack(in_=tree_frame, side="right", fill="y")

