    # ========================================================================
    # VERIFICACAO DE CAIXA ABERTO PARA VENDAS (TRAVA DE SEGURANCA)
    # ========================================================================
    def _verificar_caixa_aberto_para_venda(self, callback_sucesso, origem="venda"):
        """Verifica em tempo real no banco de dados se existe um caixa aberto.
        Se existir, atualiza Session.caixa_id e executa callback_sucesso.
        Se nao existir, bloqueia a operacao e exibe mensagem ao usuario.
        Parametros:
            callback_sucesso: funcao a ser chamada se o caixa estiver aberto.
            origem: string identificando a origem da verificacao (para log)."""
        def check_caixa_db():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT id FROM caixa WHERE status = 'aberto' ORDER BY id DESC LIMIT 1"
            )
            return rows

        def on_check_result(rows):
            if rows:
                # Caixa aberto encontrado - atualizar Session e prosseguir
                Session.caixa_id = rows[0]["id"]
                self.status_bar.set_caixa(True, Session.caixa_id)
                callback_sucesso()
            else:
                # Nenhum caixa aberto - bloquear operacao
                Session.caixa_id = 0
                self.caixa_aberto = None
                self.status_bar.set_caixa(False)
                AuditLogger.log("VENDA_BLOQUEADA_CAIXA_FECHADO",
                                f"Tentativa de {origem} bloqueada - caixa fechado",
                                usuario=Session.user_login)
                ToastManager.error(
                    "Venda bloqueada! Abra o caixa antes de vender.", duration=5000)
                messagebox.showwarning(
                    "Caixa Fechado - Venda Bloqueada",
                    f"{Icons.BLOCKED} Nao e possivel realizar vendas com o caixa fechado.\n\n"
                    "Para continuar, abra o caixa primeiro:\n"
                    "  1. Acesse o menu 'Caixa' (F3)\n"
                    "  2. Clique em 'Abrir Caixa'\n"
                    "  3. Informe o valor de abertura\n\n"
                    "Apos abrir o caixa, tente novamente.")

        self.run_async(check_caixa_db, on_check_result)

    # ========================================================================
    # TELA DE VENDAS
    # ========================================================================
    def show_venda(self):
        # === TRAVA DE CAIXA: Verificar se o caixa esta aberto antes de abrir a tela de vendas ===
        self._verificar_caixa_aberto_para_venda(
            callback_sucesso=self._show_venda_ui,
            origem="abrir tela de venda"
        )

