    def selecionar_cliente_venda(self):
        self._selecionar_registro(
            "clientes", "Selecionar Cliente",
            "SELECT id, nome, celular FROM clientes WHERE ativo = 1 ORDER BY nome",
            ["ID", "Nome", "Celular"],
            lambda row: self._set_cliente_venda(row)
        )

    def _set_cliente_venda(self, row):
        if row:
            self.venda_cliente_id = row[0]
            self.venda_cliente_nome = row[1]
            self.lbl_cliente_venda.config(text=self.venda_cliente_nome)
            # Preencher automaticamente os dados de entrega a partir do cadastro
            self._preencher_entrega_do_cliente(row[0])

    def _preencher_entrega_do_cliente(self, cliente_id):
        """Ao selecionar um cliente, puxa endereco, bairro (com a taxa) e
        WhatsApp do cadastro e preenche a secao de entrega automaticamente."""
        if not cliente_id:
            return

        def load():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT nome, celular, endereco, numero, bairro, cidade, uf "
                "FROM clientes WHERE id = %s LIMIT 1", (cliente_id,))
            taxas = db.execute_query(
                "SELECT bairro, taxa FROM taxa_entrega_bairro WHERE ativo = 1")
            return {"cli": rows[0] if rows else None, "taxas": taxas or []}

        def done(data):
            cli = (data or {}).get("cli")
            if not cli:
                return

            # Montar o endereco completo
            partes = []
            if cli.get("endereco"):
                partes.append(str(cli["endereco"]))
            if cli.get("numero"):
                partes.append(f"n {cli['numero']}")
            if cli.get("bairro"):
                partes.append(str(cli["bairro"]))
            if cli.get("cidade"):
                cid = str(cli["cidade"])
                if cli.get("uf"):
                    cid += f"/{cli['uf']}"
                partes.append(cid)
            endereco = ", ".join(partes)
            celular = (cli.get("celular") or "").strip()
            bairro_cli = (cli.get("bairro") or "").strip()

            # So ativa a entrega se o cliente tiver algum dado de entrega
            if not (endereco or celular or bairro_cli):
                return

            # Mostrar a secao de entrega (se ainda nao estiver marcada)
            if not getattr(self, "venda_para_entrega", False):
                try:
                    self._var_entrega.set(1)
                    self._toggle_entrega()
                except Exception:
                    pass

            # Preencher endereco e WhatsApp
            try:
                self.et_endereco_entrega.delete(0, tk.END)
                self.et_endereco_entrega.insert(0, endereco)
            except Exception:
                pass
            try:
                self.et_whatsapp_entrega.delete(0, tk.END)
                self.et_whatsapp_entrega.insert(0, celular)
            except Exception:
                pass

            # Casar o bairro do cliente com a taxa cadastrada (se existir)
            if bairro_cli:
                taxa = 0.0
                bairro_final = bairro_cli
                for t in data.get("taxas", []):
                    if str(t.get("bairro", "")).strip().lower() == bairro_cli.lower():
                        try:
                            taxa = float(t.get("taxa") or 0)
                        except Exception:
                            taxa = 0.0
                        bairro_final = t.get("bairro") or bairro_cli
                        break
                self.venda_bairro_entrega = bairro_final
                self.venda_taxa_entrega = taxa
                try:
                    if taxa > 0:
                        self.lbl_bairro_entrega.config(
                            text=f"{bairro_final}  (R$ {FormatUtils.format_money(taxa)})")
                    else:
                        self.lbl_bairro_entrega.config(
                            text=f"{bairro_final}  (taxa nao cadastrada)")
                except Exception:
                    pass

            self.atualizar_totais_venda()
            ToastManager.info("Dados de entrega preenchidos pelo cadastro do cliente.")

        self.run_async(load, done)

    # ------------------------------------------------------------------
    # MODULO DE ENTREGA  -  captura de dados na tela de venda
    # ------------------------------------------------------------------
    def _toggle_entrega(self):
        """Mostra/oculta a secao de entrega e recalcula o total."""
        self.venda_para_entrega = bool(self._var_entrega.get())
        if self.venda_para_entrega:
            self._entrega_frame.pack(fill="x", padx=15, pady=2,
                                     after=self._entrega_card)
        else:
            self._entrega_frame.pack_forget()
            # Limpar dados de entrega ao desmarcar
            self.venda_taxa_entrega = 0.0
            self.venda_bairro_entrega = ""
            self.venda_entregador_id = 0
            self.venda_entregador_nome = ""
            try:
                self.lbl_bairro_entrega.config(text="(nenhum)")
                self.lbl_entregador_venda.config(text="(a definir)")
            except Exception:
                pass
        self.atualizar_totais_venda()

    def _selecionar_bairro_entrega(self):
        """Seleciona o bairro de entrega (define a taxa automaticamente)."""
        def _on_bairro(row):
            if not row:
                return
            self.venda_bairro_entrega = row[1]
            try:
                self.venda_taxa_entrega = float(row[2])
            except Exception:
                self.venda_taxa_entrega = 0.0
            self.lbl_bairro_entrega.config(
                text=f"{row[1]}  (R$ {FormatUtils.format_money(self.venda_taxa_entrega)})")
            self.atualizar_totais_venda()

        self._selecionar_registro(
            "taxa_entrega_bairro", "Selecionar Bairro / Taxa",
            "SELECT id, bairro, taxa FROM taxa_entrega_bairro WHERE ativo = 1 ORDER BY bairro",
            ["ID", "Bairro", "Taxa (R$)"],
            _on_bairro
        )

    def _selecionar_entregador_venda(self):
        """Seleciona o entregador responsavel pela entrega."""
        def _on_entregador(row):
            if not row:
                return
            self.venda_entregador_id = row[0]
            self.venda_entregador_nome = row[1]
            self.lbl_entregador_venda.config(text=row[1])

        self._selecionar_registro(
            "entregadores", "Selecionar Entregador",
            "SELECT id, nome, celular FROM entregadores WHERE ativo = 1 ORDER BY nome",
            ["ID", "Nome", "Celular"],
            _on_entregador
        )

    def buscar_por_codigo(self):
        codigo = self.et_codigo_barras.get().strip()
        if not codigo:
            return
        def buscar():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT id, descricao, preco_venda, estoque, codigo_barras "
                "FROM produtos WHERE ativo = 1 AND (codigo = %s OR codigo_barras = %s) LIMIT 1",
                (codigo, codigo)
            )
            return rows
        def on_found(rows):
            self.et_codigo_barras.delete(0, tk.END)
            if rows:
                p = rows[0]
                self.adicionar_ao_carrinho(p["id"], p["descricao"], p["preco_venda"], 1)
            else:
                self.show_error("Produto nao encontrado com este codigo.")
        self.run_async(buscar, on_found)

    def buscar_produto_dialog(self):
        self._selecionar_registro(
            "produtos", "Buscar Produto",
            "SELECT id, descricao, preco_venda, estoque FROM produtos WHERE ativo = 1 ORDER BY descricao",
            ["ID", "Descricao", "Preco", "Estoque"],
            lambda row: self.adicionar_ao_carrinho(row[0], row[1], float(row[2]), 1) if row else None
        )

    def adicionar_ao_carrinho(self, produto_id, descricao, preco, qtd,
                               tipo_produto_id=None, tipo_produto_desc=""):
        # Verificar se ja existe no carrinho
        for item in self.carrinho:
            if item.produto_id == produto_id:
                item.quantidade += qtd
                item.total = item.quantidade * item.preco_unitario
                self.atualizar_tree_carrinho()
                return
        item = ItemVenda()
        item.produto_id = produto_id
        item.descricao_produto = descricao
        item.preco_unitario = float(preco)
        item.quantidade = qtd
        item.total = item.quantidade * item.preco_unitario
        item.tipo_produto_id = tipo_produto_id
        item.tipo_produto_desc = tipo_produto_desc
        self.carrinho.append(item)
        self.atualizar_tree_carrinho()
        # Buscar tipo_produto_id do banco se nao foi informado
        if tipo_produto_id is None:
            def _buscar_tipo():
                try:
                    db = DatabaseHelper.get_instance()
                    rows = db.execute_query(
                        "SELECT p.tipo_produto_id, COALESCE(tp.descricao, '') as tipo_desc "
                        "FROM produtos p LEFT JOIN tipos_produto tp ON p.tipo_produto_id = tp.id "
                        "WHERE p.id = %s LIMIT 1",
                        (produto_id,)
                    )
                    return rows
                except Exception:
                    return []
            def _on_tipo(rows):
                if rows and rows[0].get("tipo_produto_id"):
                    item.tipo_produto_id = rows[0]["tipo_produto_id"]
                    item.tipo_produto_desc = rows[0].get("tipo_desc", "")
            self.run_async(_buscar_tipo, _on_tipo)

    def atualizar_tree_carrinho(self):
        self.tree_carrinho.delete(*self.tree_carrinho.get_children())
        for i, item in enumerate(self.carrinho, 1):
            qtd_str = (f"{item.quantidade:.0f}"
                       if item.quantidade == int(item.quantidade)
                       else f"{item.quantidade:.3f}")
            tag = "even" if i % 2 == 0 else "odd"
            self.tree_carrinho.insert("", "end", values=(
                i, item.descricao_produto, qtd_str,
                FormatUtils.format_money(item.preco_unitario),
                FormatUtils.format_money(item.total)
            ), tags=(tag,))
        self.tree_carrinho.tag_configure("even", background=COR_GLASS)
        self.tree_carrinho.tag_configure("odd", background=COR_CARD)
        self.atualizar_totais_venda()
        # Atualizar contador de itens se existir
        try:
            n = len(self.carrinho)
            total_qtd = sum(i.quantidade for i in self.carrinho)
            self._lbl_itens_carrinho.config(
                text=f"{n} produto(s)  |  {total_qtd:.0f} un."
                     if total_qtd == int(total_qtd)
                     else f"{n} produto(s)  |  {total_qtd:.3f} un.")
        except Exception:
            pass

    def atualizar_totais_venda(self):
        subtotal = sum(item.total for item in self.carrinho)
        try:
            desc_val = FormatUtils.parse_money(self.et_desconto.get())
        except Exception:
            desc_val = 0
        try:
            acre_val = FormatUtils.parse_money(self.et_acrescimo.get())
        except Exception:
            acre_val = 0

        desc_tipo = self.combo_desc_tipo.get()
        acre_tipo = self.combo_acre_tipo.get()

        desconto = desc_val if "R$" in desc_tipo else (subtotal * desc_val / 100)
        acrescimo = acre_val if "R$" in acre_tipo else (subtotal * acre_val / 100)

        taxa_entrega = (self.venda_taxa_entrega or 0) if getattr(self, "venda_para_entrega", False) else 0
        total = subtotal - desconto + acrescimo + taxa_entrega
        if total < 0:
            total = 0

        # Atualizar rotulo da taxa de entrega (se a secao existir)
        try:
            self.lbl_taxa_entrega.config(
                text=f"Taxa de entrega: R$ {FormatUtils.format_money(taxa_entrega)}")
        except Exception:
            pass

        self.lbl_subtotal.config(
            text=f"Subtotal: R$ {FormatUtils.format_money(subtotal)}")
        self.lbl_total_venda.config(
            text=f"TOTAL: R$ {FormatUtils.format_money(total)}")

        # Feedback visual: total muda de cor conforme valor
        if total > 0:
            self.lbl_total_venda.config(fg=COR_SUCESSO)
        else:
            self.lbl_total_venda.config(fg=COR_TEXTO2)

    def editar_qtd_carrinho(self):
        sel = self.tree_carrinho.selection()
        if not sel:
            ToastManager.warning("Selecione um item do carrinho.")
            return
        idx = self.tree_carrinho.index(sel[0])
        item = self.carrinho[idx]
        nova_qtd = simpledialog.askfloat(
            "Editar Quantidade",
            f"Nova quantidade para:\n{item.descricao_produto}",
            initialvalue=item.quantidade,
            minvalue=0.001, parent=self.root)
        if nova_qtd:
            self.carrinho[idx].quantidade = nova_qtd
            self.carrinho[idx].total = nova_qtd * self.carrinho[idx].preco_unitario
            self.atualizar_tree_carrinho()
            ToastManager.info(f"Qtd atualizada: {nova_qtd:.3f}")

    def remover_item_carrinho(self):
        sel = self.tree_carrinho.selection()
        if not sel:
            ToastManager.warning("Selecione um item para remover.")
            return
        idx = self.tree_carrinho.index(sel[0])
        nome = self.carrinho[idx].descricao_produto
        del self.carrinho[idx]
        self.atualizar_tree_carrinho()
        ToastManager.info(f"Removido: {nome}")

    # ========================================================================
    # ASSISTENTE "MONTE SEU PRATO"  (DELICIAS FOOD)
    # Fluxo: 1) Tamanho  ->  2) Proteinas (limitado pelo tamanho)
    #        3) Acompanhamentos  ->  4) Revisao/adicionar ao carrinho
    #        5) Extras (sucos, refrigerantes, aguas, sobremesas)
    # ========================================================================
    def montar_prato_dialog(self):
        """Abre o assistente guiado para montar um prato do cardapio."""
        db = DatabaseHelper.get_instance()

        def carregar():
            tamanhos = db.execute_query(
                "SELECT p.id, p.descricao, p.codigo, p.preco_venda, p.tipo_produto_id "
                "FROM produtos p JOIN tipos_produto t ON p.tipo_produto_id = t.id "
                "WHERE t.descricao = %s AND p.ativo = 1 ORDER BY p.id",
                (DatabaseHelper.CAT_MONTE_PRATO,)
            )
            proteinas = db.execute_query(
                "SELECT p.id, p.descricao FROM produtos p "
                "JOIN tipos_produto t ON p.tipo_produto_id = t.id "
                "WHERE t.descricao = %s AND p.ativo = 1 ORDER BY p.descricao",
                (DatabaseHelper.CAT_PROTEINAS,)
            )
            acomp = db.execute_query(
                "SELECT p.id, p.descricao, COALESCE(p.codigo,'') AS codigo FROM produtos p "
                "JOIN tipos_produto t ON p.tipo_produto_id = t.id "
                "WHERE t.descricao = %s AND p.ativo = 1 ORDER BY p.codigo, p.descricao",
                (DatabaseHelper.CAT_ACOMPANHAMENTOS,)
            )
            return {"tamanhos": tamanhos, "proteinas": proteinas, "acomp": acomp}

        def on_loaded(data):
            if not data or not data.get("tamanhos"):
                ErroAmigavel.mostrar_aviso(
                    "O cardapio ainda nao foi cadastrado.\n\n"
                    "Reinicie o sistema uma vez para que o cardapio do "
                    "Delicias Food seja criado automaticamente.",
                    titulo="Monte Seu Prato", parent=self.root)
                return
            self._abrir_wizard_prato(data)

        self.run_async(carregar, on_loaded)

    def _abrir_wizard_prato(self, data):
        tamanhos = data["tamanhos"]
        proteinas = data["proteinas"]
        acomp = data["acomp"]

        # Estado da montagem
        st = {"tam": None, "n_prot": 1, "proteinas": [], "acomp": []}

        dialog = tk.Toplevel(self.root)
        dialog.title("Monte Seu Prato - Delicias Food")
        dialog.geometry("760x620")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        # Cabecalho
        header = tk.Frame(dialog, bg=COR_FUNDO2, height=58)
        header.pack(fill="x")
        header.pack_propagate(False)
        tk.Label(header, text="🍽  MONTE SEU PRATO", bg=COR_FUNDO2,
                 fg=COR_BOTAO_LARANJA, font=("Segoe UI", 16, "bold")).pack(
                     side="left", padx=18, pady=10)
        self._lbl_passo_prato = tk.Label(header, text="", bg=COR_FUNDO2,
                                         fg=COR_TEXTO2, font=("Segoe UI", 10))
        self._lbl_passo_prato.pack(side="right", padx=18)

        # Corpo (re-renderizado a cada etapa)
        body = tk.Frame(dialog, bg=COR_FUNDO)
        body.pack(fill="both", expand=True, padx=12, pady=8)

        # Rodape (botoes de navegacao)
        footer = tk.Frame(dialog, bg=COR_FUNDO2, height=56)
        footer.pack(fill="x")
        footer.pack_propagate(False)

        def _limpar(frame):
            for w in frame.winfo_children():
                w.destroy()

        def _scroll_area(parent):
            """Cria uma area com rolagem e retorna o frame interno."""
            wrap = tk.Frame(parent, bg=COR_FUNDO)
            wrap.pack(fill="both", expand=True)
            canvas = tk.Canvas(wrap, bg=COR_FUNDO, highlightthickness=0)
            sb = ttk.Scrollbar(wrap, orient="vertical", command=canvas.yview)
            inner = tk.Frame(canvas, bg=COR_FUNDO)
            inner.bind("<Configure>",
                       lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
            win = canvas.create_window((0, 0), window=inner, anchor="nw")
            canvas.bind("<Configure>", lambda e: canvas.itemconfig(win, width=e.width))
            canvas.configure(yscrollcommand=sb.set)
            canvas.pack(side="left", fill="both", expand=True)
            sb.pack(side="right", fill="y")

            def _on_wheel(e):
                try:
                    canvas.yview_scroll(int(-1 * (e.delta / 120)), "units")
                except Exception:
                    pass
            canvas.bind_all("<MouseWheel>", _on_wheel)
            dialog.bind("<Destroy>",
                        lambda e: canvas.unbind_all("<MouseWheel>"), add="+")
            return inner

        def _parse_n_prot(tam):
            """Numero de proteinas que o tamanho permite."""
            cod = (tam.get("codigo") or "").strip()
            if cod and cod[-1].isdigit():
                return int(cod[-1])
            m = re.search(r"(\d+)\s*Prote", tam.get("descricao", ""))
            return int(m.group(1)) if m else 1

        # -------------------- ETAPA 1: TAMANHO --------------------
        def render_tamanho():
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text="Etapa 1 de 4  -  Tamanho")
            tk.Label(body, text="Escolha o tamanho do prato:", bg=COR_FUNDO,
                     fg=COR_TEXTO, font=("Segoe UI", 13, "bold")).pack(
                         anchor="w", pady=(4, 12))

            grid = tk.Frame(body, bg=COR_FUNDO)
            grid.pack(fill="x")

            def escolher(tam):
                st["tam"] = tam
                st["n_prot"] = _parse_n_prot(tam)
                st["proteinas"] = []
                render_proteinas()

            for i, tam in enumerate(tamanhos):
                n = _parse_n_prot(tam)
                card = tk.Frame(grid, bg=COR_CARD, highlightthickness=1,
                                highlightbackground=COR_GLASS_BORDER)
                card.grid(row=i // 2, column=i % 2, padx=8, pady=8,
                          sticky="nsew", ipadx=10, ipady=10)
                grid.grid_columnconfigure(i % 2, weight=1)
                tk.Label(card, text=tam["descricao"], bg=COR_CARD, fg=COR_BOTAO_LARANJA,
                         font=("Segoe UI", 13, "bold")).pack(anchor="w", padx=10, pady=(6, 2))
                tk.Label(card, text=f"Escolha {n} proteina(s)", bg=COR_CARD,
                         fg=COR_TEXTO2, font=("Segoe UI", 10)).pack(anchor="w", padx=10)
                StyledButton(card, text="Selecionar",
                             command=lambda t=tam: escolher(t),
                             color=COR_BOTAO_VERDE, width=14).pack(
                                 anchor="e", padx=10, pady=(8, 4))

            StyledButton(footer, text="✖ Cancelar", command=dialog.destroy,
                         color=COR_ERRO, width=12).pack(side="right", padx=12, pady=8)

        # -------------------- ETAPA 2: PROTEINAS --------------------
        def render_proteinas():
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text="Etapa 2 de 4  -  Proteinas")
            n = st["n_prot"]
            tk.Label(body,
                     text=f"{st['tam']['descricao']}  -  escolha {n} proteina(s):",
                     bg=COR_FUNDO, fg=COR_TEXTO,
                     font=("Segoe UI", 13, "bold")).pack(anchor="w", pady=(4, 2))
            lbl_cont = tk.Label(body, text=f"Selecionadas: 0 / {n}", bg=COR_FUNDO,
                                fg=COR_ALERTA, font=("Segoe UI", 10, "bold"))
            lbl_cont.pack(anchor="w", pady=(0, 8))

            inner = _scroll_area(body)
            prot_vars = {}

            def _atualizar_contador():
                sel = [pid for pid, (v, _d) in prot_vars.items() if v.get()]
                lbl_cont.config(text=f"Selecionadas: {len(sel)} / {n}")

            def _on_toggle(pid):
                sel = [p for p, (v, _d) in prot_vars.items() if v.get()]
                if len(sel) > n:
                    prot_vars[pid][0].set(0)
                    ToastManager.warning(
                        f"Este tamanho permite apenas {n} proteina(s).")
                _atualizar_contador()

            cols = 2
            for i, p in enumerate(proteinas):
                var = tk.IntVar(value=0)
                prot_vars[p["id"]] = (var, p["descricao"])
                cb = tk.Checkbutton(
                    inner, text=p["descricao"], variable=var,
                    command=lambda pid=p["id"]: _on_toggle(pid),
                    bg=COR_FUNDO, fg=COR_TEXTO, selectcolor=COR_CARD,
                    activebackground=COR_FUNDO, activeforeground=COR_PRIMARIA,
                    font=("Segoe UI", 10), anchor="w")
                cb.grid(row=i // cols, column=i % cols, sticky="w", padx=8, pady=2)
            for c in range(cols):
                inner.grid_columnconfigure(c, weight=1)

            def avancar():
                sel = [(pid, d) for pid, (v, d) in prot_vars.items() if v.get()]
                if len(sel) != n:
                    ToastManager.warning(
                        f"Selecione exatamente {n} proteina(s).")
                    return
                st["proteinas"] = sel
                render_acompanhamentos()

            StyledButton(footer, text="◀ Voltar", command=render_tamanho,
                         color=COR_FUNDO3, width=10).pack(side="left", padx=12, pady=8)
            StyledButton(footer, text="Avancar ▶", command=avancar,
                         color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=12, pady=8)

        # -------------------- ETAPA 3: ACOMPANHAMENTOS --------------------
        def render_acompanhamentos():
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text="Etapa 3 de 4  -  Acompanhamentos")
            tk.Label(body, text="Escolha os acompanhamentos:", bg=COR_FUNDO,
                     fg=COR_TEXTO, font=("Segoe UI", 13, "bold")).pack(
                         anchor="w", pady=(4, 8))

            inner = _scroll_area(body)
            ac_vars = {}
            grupos = {
                "ARROZ": "Arroz / Massas",
                "FEIJAO": "Feijoes",
                "SALADA": "Saladas",
                "": "Outros",
            }
            # Agrupar por prefixo do codigo (ACOMP-XXX)
            por_grupo = {}
            for a in acomp:
                cod = a.get("codigo") or ""
                g = cod.replace("ACOMP-", "") if cod.startswith("ACOMP-") else ""
                por_grupo.setdefault(g, []).append(a)

            row = 0
            for gkey in ["ARROZ", "FEIJAO", "SALADA", ""]:
                itens = por_grupo.get(gkey)
                if not itens:
                    continue
                tk.Label(inner, text=grupos.get(gkey, "Outros"), bg=COR_FUNDO,
                         fg=COR_PRIMARIA, font=("Segoe UI", 11, "bold")).grid(
                             row=row, column=0, columnspan=2, sticky="w",
                             padx=4, pady=(10, 2))
                row += 1
                for j, a in enumerate(itens):
                    var = tk.IntVar(value=0)
                    ac_vars[a["id"]] = (var, a["descricao"])
                    cb = tk.Checkbutton(
                        inner, text=a["descricao"], variable=var,
                        bg=COR_FUNDO, fg=COR_TEXTO, selectcolor=COR_CARD,
                        activebackground=COR_FUNDO, activeforeground=COR_PRIMARIA,
                        font=("Segoe UI", 10), anchor="w")
                    cb.grid(row=row + j // 2, column=j % 2, sticky="w", padx=8, pady=2)
                row += (len(itens) + 1) // 2
            for c in range(2):
                inner.grid_columnconfigure(c, weight=1)

            def avancar():
                sel = [(aid, d) for aid, (v, d) in ac_vars.items() if v.get()]
                if not sel:
                    ToastManager.warning("Selecione ao menos 1 acompanhamento.")
                    return
                st["acomp"] = sel
                render_revisao()

            StyledButton(footer, text="◀ Voltar", command=render_proteinas,
                         color=COR_FUNDO3, width=10).pack(side="left", padx=12, pady=8)
            StyledButton(footer, text="Avancar ▶", command=avancar,
                         color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=12, pady=8)

        # -------------------- ETAPA 4: REVISAO --------------------
        def render_revisao():
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text="Etapa 4 de 4  -  Revisao")
            tk.Label(body, text="Confira o prato montado:", bg=COR_FUNDO,
                     fg=COR_TEXTO, font=("Segoe UI", 13, "bold")).pack(
                         anchor="w", pady=(4, 8))

            card = tk.Frame(body, bg=COR_CARD, highlightthickness=1,
                            highlightbackground=COR_GLASS_BORDER)
            card.pack(fill="both", expand=True, padx=4, pady=4)

            tk.Label(card, text=st["tam"]["descricao"], bg=COR_CARD,
                     fg=COR_BOTAO_LARANJA, font=("Segoe UI", 14, "bold")).pack(
                         anchor="w", padx=14, pady=(12, 6))

            prot_txt = ", ".join(d for _i, d in st["proteinas"])
            ac_txt = ", ".join(d for _i, d in st["acomp"])
            tk.Label(card, text="Proteinas:", bg=COR_CARD, fg=COR_PRIMARIA,
                     font=("Segoe UI", 11, "bold")).pack(anchor="w", padx=14)
            tk.Label(card, text=prot_txt, bg=COR_CARD, fg=COR_TEXTO,
                     font=("Segoe UI", 11), wraplength=680, justify="left").pack(
                         anchor="w", padx=24, pady=(0, 8))
            tk.Label(card, text="Acompanhamentos:", bg=COR_CARD, fg=COR_PRIMARIA,
                     font=("Segoe UI", 11, "bold")).pack(anchor="w", padx=14)
            tk.Label(card, text=ac_txt, bg=COR_CARD, fg=COR_TEXTO,
                     font=("Segoe UI", 11), wraplength=680, justify="left").pack(
                         anchor="w", padx=24, pady=(0, 8))

            StyledButton(footer, text="◀ Voltar", command=render_acompanhamentos,
                         color=COR_FUNDO3, width=10).pack(side="left", padx=12, pady=8)
            StyledButton(footer, text="✔ Adicionar ao carrinho",
                         command=adicionar_prato, color=COR_BOTAO_VERDE,
                         width=22).pack(side="right", padx=12, pady=8)

        def adicionar_prato():
            tam = st["tam"]
            prot_nomes = [d for _i, d in st["proteinas"]]
            ac_nomes = [d for _i, d in st["acomp"]]

            item = ItemVenda()
            item.produto_id = tam["id"]
            descricao_full = (
                f"{tam['descricao']} | Proteinas: {', '.join(prot_nomes)} "
                f"| Acomp: {', '.join(ac_nomes)}"
            )
            # itens_venda.descricao_produto e VARCHAR(200): limita com seguranca.
            item.descricao_produto = descricao_full[:195]
            item.preco_unitario = float(tam.get("preco_venda") or 0)
            item.quantidade = 1
            item.total = item.preco_unitario
            item.tipo_produto_id = tam.get("tipo_produto_id")
            item.tipo_produto_desc = DatabaseHelper.CAT_MONTE_PRATO
            # adicionais (impressos no cupom de producao/cozinha como "+ ...")
            item.adicionais = (
                [f"Proteina: {p}" for p in prot_nomes]
                + [f"Acomp.: {a}" for a in ac_nomes]
            )
            self.carrinho.append(item)
            self.atualizar_tree_carrinho()
            ToastManager.success("Prato adicionado ao carrinho!")
            render_extras_categorias()

        # -------------------- ETAPA 5: EXTRAS --------------------
        def render_extras_categorias():
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text="Extras (opcional)")
            tk.Label(body, text="Deseja adicionar bebidas ou sobremesas?",
                     bg=COR_FUNDO, fg=COR_TEXTO,
                     font=("Segoe UI", 13, "bold")).pack(anchor="w", pady=(4, 4))
            tk.Label(body, text="Itens que nao fazem parte do prato.",
                     bg=COR_FUNDO, fg=COR_TEXTO2,
                     font=("Segoe UI", 10)).pack(anchor="w", pady=(0, 12))

            grid = tk.Frame(body, bg=COR_FUNDO)
            grid.pack(fill="x")
            categorias = [
                (DatabaseHelper.CAT_SUCOS, "Sucos", COR_BOTAO_LARANJA),
                (DatabaseHelper.CAT_REFRI_200, "Refrigerantes 200ml", COR_BOTAO_AZUL),
                (DatabaseHelper.CAT_REFRI_350, "Refrigerantes Lata 350ml", COR_BOTAO_AZUL),
                (DatabaseHelper.CAT_AGUAS, "Aguas", COR_PRIMARIA),
                (DatabaseHelper.CAT_SOBREMESAS, "Sobremesas", COR_ACCENT),
            ]
            for i, (tipo_desc, rotulo, cor) in enumerate(categorias):
                StyledButton(grid, text=rotulo,
                             command=lambda t=tipo_desc, r=rotulo: render_extras_lista(t, r),
                             color=cor, width=22).grid(
                                 row=i // 2, column=i % 2, padx=8, pady=8, sticky="w")

            StyledButton(footer, text="+ Montar outro prato",
                         command=render_tamanho, color=COR_BOTAO_LARANJA,
                         width=20).pack(side="left", padx=12, pady=8)
            StyledButton(footer, text="✔ Concluir", command=dialog.destroy,
                         color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=12, pady=8)

        def render_extras_lista(tipo_desc, rotulo):
            _limpar(body)
            _limpar(footer)
            self._lbl_passo_prato.config(text=f"Extras  -  {rotulo}")
            tk.Label(body, text=f"{rotulo} - toque para adicionar:", bg=COR_FUNDO,
                     fg=COR_TEXTO, font=("Segoe UI", 13, "bold")).pack(
                         anchor="w", pady=(4, 8))
            inner = _scroll_area(body)

            def carregar_lista():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT p.id, p.descricao, p.preco_venda, p.tipo_produto_id "
                    "FROM produtos p JOIN tipos_produto t ON p.tipo_produto_id = t.id "
                    "WHERE t.descricao = %s AND p.ativo = 1 ORDER BY p.descricao",
                    (tipo_desc,)
                )

            def on_lista(rows):
                for w in inner.winfo_children():
                    w.destroy()
                for i, p in enumerate(rows or []):
                    linha = tk.Frame(inner, bg=COR_CARD if i % 2 else COR_GLASS)
                    linha.pack(fill="x", padx=4, pady=1)
                    tk.Label(linha, text=p["descricao"],
                             bg=linha.cget("bg"), fg=COR_TEXTO,
                             font=("Segoe UI", 10), anchor="w").pack(
                                 side="left", padx=8, pady=4, fill="x", expand=True)
                    StyledButton(
                        linha, text="+ Adicionar",
                        command=lambda pr=p: (
                            self.adicionar_ao_carrinho(
                                pr["id"], pr["descricao"],
                                float(pr.get("preco_venda") or 0), 1,
                                pr.get("tipo_produto_id"), rotulo),
                            ToastManager.info(f"Adicionado: {pr['descricao']}")),
                        color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=6, pady=3)

            self.run_async(carregar_lista, on_lista)

            StyledButton(footer, text="◀ Voltar", command=render_extras_categorias,
                         color=COR_FUNDO3, width=10).pack(side="left", padx=12, pady=8)
            StyledButton(footer, text="✔ Concluir", command=dialog.destroy,
                         color=COR_BOTAO_VERDE, width=12).pack(side="right", padx=12, pady=8)

        render_tamanho()

    def limpar_carrinho(self):
        if self.carrinho:
            if messagebox.askyesno("Confirmar",
                    f"Limpar todo o carrinho?\n({len(self.carrinho)} item(s))"):
                self.carrinho.clear()
                self.atualizar_tree_carrinho()
                ToastManager.info("Carrinho limpo.")

    def finalizar_venda(self):
        if not self.carrinho:
            ToastManager.warning("Adicione itens ao carrinho antes de finalizar.")
            return
        # === TRAVA DE CAIXA: Verificar em tempo real se o caixa esta aberto ===
        self._verificar_caixa_aberto_para_venda(
            callback_sucesso=self.show_pagamento,
            origem="finalizar venda"
        )


    # ========================================================================
    # TELA DE PAGAMENTO
    # ========================================================================
    def show_pagamento(self):
        subtotal = sum(item.total for item in self.carrinho)
        try:
            desc_val = FormatUtils.parse_money(self.et_desconto.get())
        except Exception:
            desc_val = 0
        try:
            acre_val = FormatUtils.parse_money(self.et_acrescimo.get())
        except Exception:
            acre_val = 0

        desc_tipo = self.combo_desc_tipo.get()
        acre_tipo = self.combo_acre_tipo.get()
        desconto = desc_val if "R$" in desc_tipo else (subtotal * desc_val / 100)
        acrescimo = acre_val if "R$" in acre_tipo else (subtotal * acre_val / 100)
        taxa_entrega = (self.venda_taxa_entrega or 0) if getattr(self, "venda_para_entrega", False) else 0
        total = subtotal - desconto + acrescimo + taxa_entrega
        if total < 0:
            total = 0

        self.venda_total_bruto = subtotal
        self.venda_desconto_valor = desconto
        self.venda_desconto_tipo = "valor" if "R$" in desc_tipo else "percentual"
        self.venda_acrescimo_valor = acrescimo
        self.venda_acrescimo_tipo = "valor" if "R$" in acre_tipo else "percentual"
        self.venda_total_liquido = total
        self.venda_observacao = self.et_obs_venda.get("1.0", "end").strip()
        # Capturar dados de entrega (endereco/whatsapp) digitados no painel
        if getattr(self, "venda_para_entrega", False):
            try:
                self.venda_endereco_entrega = self.et_endereco_entrega.get().strip()
            except Exception:
                self.venda_endereco_entrega = ""
            try:
                self.venda_celular_whatsapp = self.et_whatsapp_entrega.get().strip()
            except Exception:
                self.venda_celular_whatsapp = ""
        else:
            self.venda_endereco_entrega = ""
            self.venda_celular_whatsapp = ""
        self.pagamentos_venda = []

        # Carregar formas de pagamento
        def load_formas():
            db = DatabaseHelper.get_instance()
            return db.execute_query(
                "SELECT id, descricao, tipo, permite_parcelamento FROM formas_pagamento WHERE ativo = 1"
            )

        def on_formas(formas):
            self.formas_pagamento_list = formas
            self._show_pagamento_ui()

        self.run_async(load_formas, on_formas)

    def _show_pagamento_ui(self):
        dialog = tk.Toplevel(self.root)
        dialog.title("Pagamento")
        dialog.geometry("600x550")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()
        self._pag_dialog = dialog

        tk.Label(dialog, text="Pagamento", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=10)

        # Total
        tk.Label(dialog, text=f"Total da Venda: R$ {FormatUtils.format_money(self.venda_total_liquido)}",
                 bg=COR_FUNDO, fg=COR_SUCESSO, font=("Segoe UI", 14, "bold")).pack(pady=5)

        self.lbl_saldo = tk.Label(dialog,
            text=f"Saldo Devedor: R$ {FormatUtils.format_money(self.venda_total_liquido)}",
            bg=COR_FUNDO, fg=COR_ALERTA, font=("Segoe UI", 12))
        self.lbl_saldo.pack(pady=3)

        # Adicionar pagamento
        add_frame = CardFrame(dialog)
        add_frame.pack(fill="x", padx=20, pady=10)

        tk.Label(add_frame, text="Forma:", bg=COR_CARD, fg=COR_TEXTO).pack(side="left")
        self.combo_forma_pag = ttk.Combobox(add_frame, width=20, state="readonly")
        formas_nomes = [f.get("descricao", "") for f in self.formas_pagamento_list]
        self.combo_forma_pag["values"] = formas_nomes
        if formas_nomes:
            self.combo_forma_pag.current(0)
        self.combo_forma_pag.pack(side="left", padx=5)

        tk.Label(add_frame, text="Valor:", bg=COR_CARD, fg=COR_TEXTO).pack(side="left", padx=(10, 0))
        self.et_valor_pag = StyledEntry(add_frame, width=12)
        saldo = self.venda_total_liquido - sum(p.valor for p in self.pagamentos_venda)
        self.et_valor_pag.insert(0, FormatUtils.format_money(saldo))
        self.et_valor_pag.pack(side="left", padx=5)

        StyledButton(add_frame, text="Add", command=lambda: self._add_pagamento(dialog),
                     color=COR_BOTAO_VERDE, width=6).pack(side="right", padx=5)

        # Lista de pagamentos
        cols_pag = ("forma", "valor")
        self.tree_pagamentos = ttk.Treeview(dialog, columns=cols_pag, show="headings", height=6)
        self.tree_pagamentos.heading("forma", text="Forma de Pagamento")
        self.tree_pagamentos.heading("valor", text="Valor")
        self.tree_pagamentos.column("forma", width=300)
        self.tree_pagamentos.column("valor", width=150, anchor="e")
        self.tree_pagamentos.pack(fill="x", padx=20, pady=5)

        # Valor recebido e troco
        troco_frame = tk.Frame(dialog, bg=COR_FUNDO)
        troco_frame.pack(fill="x", padx=20, pady=5)
        self.lbl_troco = tk.Label(troco_frame, text="Troco: R$ 0,00",
                                   bg=COR_FUNDO, fg=COR_TEXTO, font=("Segoe UI", 12))
        self.lbl_troco.pack()

        # Botoes
        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=20, pady=10)
        StyledButton(btn_frame, text="Remover Pagamento",
                     command=self._remover_pagamento,
                     color=COR_ERRO, width=18).pack(side="left", padx=5)
        StyledButton(btn_frame, text="CONFIRMAR VENDA",
                     command=lambda: self._confirmar_venda(dialog),
                     color=COR_BOTAO_VERDE, width=18).pack(side="right", padx=5)

    def _add_pagamento(self, dialog):
        idx = self.combo_forma_pag.current()
        if idx < 0:
            messagebox.showwarning(
                "Selecione a Forma de Pagamento",
                "Nenhuma forma de pagamento foi selecionada.\n\n"
                "COMO FAZER:\n"
                "1. Escolha a forma de pagamento na lista\n"
                "   (Dinheiro, Cartao, Pix, etc.)\n"
                "2. Digite o valor pago pelo cliente\n"
                "3. Clique em 'Adicionar Pagamento'\n\n"
                "Voce pode usar mais de uma forma de pagamento.",
                parent=dialog)
            return
        valor = FormatUtils.parse_money(self.et_valor_pag.get())
        if valor <= 0:
            messagebox.showwarning(
                "Valor Invalido",
                "O valor informado para o pagamento nao e valido.\n\n"
                "COMO CORRIGIR:\n"
                "1. O valor deve ser maior que zero\n"
                "2. Use virgula para centavos (ex: 10,50)\n"
                "3. Nao use letras ou simbolos (R$, etc.)\n"
                "4. Exemplos validos: 10  /  10,50  /  100,00",
                parent=dialog)
            return

        forma = self.formas_pagamento_list[idx]
        pag = PagamentoVenda()
        pag.forma_pagamento_id = forma["id"]
        pag.forma_descricao = forma["descricao"]
        pag.valor = valor
        self.pagamentos_venda.append(pag)
        self._atualizar_pagamentos_ui()

    def _remover_pagamento(self):
        sel = self.tree_pagamentos.selection()
        if sel:
            idx = self.tree_pagamentos.index(sel[0])
            del self.pagamentos_venda[idx]
            self._atualizar_pagamentos_ui()

    def _atualizar_pagamentos_ui(self):
        self.tree_pagamentos.delete(*self.tree_pagamentos.get_children())
        total_pago = 0
        for pag in self.pagamentos_venda:
            self.tree_pagamentos.insert("", "end", values=(
                pag.forma_descricao, f"R$ {FormatUtils.format_money(pag.valor)}"
            ))
            total_pago += pag.valor

        saldo = self.venda_total_liquido - total_pago
        troco = max(0, -saldo)
        saldo_display = max(0, saldo)

        self.lbl_saldo.config(
            text=f"Saldo Devedor: R$ {FormatUtils.format_money(saldo_display)}",
            fg=COR_SUCESSO if saldo_display == 0 else COR_ALERTA
        )
        self.lbl_troco.config(text=f"Troco: R$ {FormatUtils.format_money(troco)}")

        # Atualizar valor sugerido
        self.et_valor_pag.delete(0, tk.END)
        self.et_valor_pag.insert(0, FormatUtils.format_money(max(0, saldo)))

    def _confirmar_venda(self, dialog):
        total_pago = sum(p.valor for p in self.pagamentos_venda)
        if total_pago < self.venda_total_liquido:
            faltante = self.venda_total_liquido - total_pago
            messagebox.showwarning(
                "Pagamento Incompleto",
                f"O valor pago ainda nao cobre o total da venda.\n\n"
                f"Total da venda: R$ {FormatUtils.format_money(self.venda_total_liquido)}\n"
                f"Total pago: R$ {FormatUtils.format_money(total_pago)}\n"
                f"Faltam: R$ {FormatUtils.format_money(faltante)}\n\n"
                f"COMO RESOLVER:\n"
                f"1. Adicione mais uma forma de pagamento\n"
                f"2. Ou aumente o valor do pagamento atual\n"
                f"3. O cliente pode pagar com formas diferentes\n"
                f"   (ex: parte em dinheiro, parte no cartao)",
                parent=dialog)
            return

        # === TRAVA DE CAIXA (verificacao final de seguranca antes de gravar) ===
        if not Session.caixa_id:
            AuditLogger.log("VENDA_BLOQUEADA_CAIXA_FECHADO",
                            "Tentativa de confirmar venda bloqueada - caixa fechado (verificacao final)",
                            usuario=Session.user_login)
            ToastManager.error("Venda bloqueada! Caixa fechado.", duration=5000)
            messagebox.showerror(
                "Caixa Fechado - Venda Bloqueada",
                f"{Icons.BLOCKED} Nao e possivel confirmar a venda com o caixa fechado.\n\n"
                "O caixa foi fechado durante o processo de pagamento.\n"
                "Abra o caixa (F3) e tente novamente.",
                parent=dialog)
            return

        troco = total_pago - self.venda_total_liquido

        def salvar():
            db = DatabaseHelper.get_instance()
            uso_armario_id_venda = int(((self._armario_pendente or {}).get("uso_id")) or 0)
            nome_cliente_venda = (self.venda_cliente_nome or "").strip() or None
            if nome_cliente_venda and nome_cliente_venda.lower() == "cliente nao informado" and not self.venda_cliente_id:
                nome_cliente_venda = None
            if uso_armario_id_venda > 0 and not nome_cliente_venda:
                try:
                    uso_row = db.execute_query(
                        "SELECT cliente_nome FROM uso_armario_sauna WHERE id = %s",
                        (uso_armario_id_venda,)
                    )
                    if uso_row:
                        nome_armario = (uso_row[0].get("cliente_nome") or "").strip()
                        if nome_armario:
                            nome_cliente_venda = nome_armario
                except Exception:
                    pass
            venda_id = db.execute_update(
                "INSERT INTO vendas (cliente_id, cliente_nome, vendedor_id, entregador_id, caixa_id, "
                "total_bruto, desconto_tipo, desconto_valor, acrescimo_tipo, acrescimo_valor, "
                "total_liquido, valor_recebido, troco, observacao, status, uso_armario_id, "
                "para_entrega, taxa_entrega, bairro_entrega, endereco_entrega, celular_whatsapp, status_entrega) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'finalizada',%s,%s,%s,%s,%s,%s,%s)",
                (self.venda_cliente_id, nome_cliente_venda, self.venda_vendedor_id, self.venda_entregador_id,
                 Session.caixa_id, self.venda_total_bruto, self.venda_desconto_tipo,
                 self.venda_desconto_valor, self.venda_acrescimo_tipo, self.venda_acrescimo_valor,
                 self.venda_total_liquido, total_pago, troco, self.venda_observacao, uso_armario_id_venda,
                 1 if getattr(self, "venda_para_entrega", False) else 0,
                 (self.venda_taxa_entrega or 0) if getattr(self, "venda_para_entrega", False) else 0,
                 getattr(self, "venda_bairro_entrega", "") or None,
                 getattr(self, "venda_endereco_entrega", "") or None,
                 getattr(self, "venda_celular_whatsapp", "") or None,
                 "pendente" if getattr(self, "venda_para_entrega", False) else None)
            )

            for item in self.carrinho:
                db.execute_update(
                    "INSERT INTO itens_venda (venda_id, produto_id, descricao_produto, "
                    "quantidade, preco_unitario, desconto, total) VALUES (%s,%s,%s,%s,%s,%s,%s)",
                    (venda_id, item.produto_id, item.descricao_produto,
                     item.quantidade, item.preco_unitario, item.desconto, item.total)
                )
                # Baixar estoque
                db.execute_update(
                    "UPDATE produtos SET estoque = estoque - %s WHERE id = %s",
                    (item.quantidade, item.produto_id)
                )

            for pag in self.pagamentos_venda:
                db.execute_update(
                    "INSERT INTO pagamentos_venda (venda_id, forma_pagamento_id, valor, parcelas) "
                    "VALUES (%s,%s,%s,%s)",
                    (venda_id, pag.forma_pagamento_id, pag.valor, pag.parcelas)
                )

                # Contas a receber
                forma_info = None
                for f in self.formas_pagamento_list:
                    if f["id"] == pag.forma_pagamento_id:
                        forma_info = f
                        break
                if forma_info and forma_info.get("tipo") == "conta_receber" and self.venda_cliente_id > 0:
                    db.execute_update(
                        "INSERT INTO contas_receber (cliente_id, venda_id, valor_original, "
                        "valor_pago, valor_pendente, status) VALUES (%s,%s,%s,0,%s,'pendente')",
                        (self.venda_cliente_id, venda_id, pag.valor, pag.valor)
                    )

            return venda_id

        def on_saved(venda_id):
            dialog.destroy()
            # Gerar cupom
            venda = Venda()
            venda.id = venda_id
            venda.cliente_nome = self.venda_cliente_nome
            venda.total_bruto = self.venda_total_bruto
            venda.desconto_valor = self.venda_desconto_valor
            venda.acrescimo_valor = self.venda_acrescimo_valor
            venda.total_liquido = self.venda_total_liquido
            venda.valor_recebido = total_pago
            venda.troco = troco
            venda.observacao = self.venda_observacao
            # Dados de entrega (para o cupom exibir taxa/endereco)
            venda.para_entrega = bool(getattr(self, "venda_para_entrega", False))
            venda.taxa_entrega = (self.venda_taxa_entrega or 0) if venda.para_entrega else 0.0
            venda.bairro_entrega = getattr(self, "venda_bairro_entrega", "") or ""
            venda.endereco_entrega = getattr(self, "venda_endereco_entrega", "") or ""
            venda.celular_whatsapp = getattr(self, "venda_celular_whatsapp", "") or ""
            venda.entregador_nome = getattr(self, "venda_entregador_nome", "") or ""
            venda.data_venda = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")

            # Carregar dados da empresa para o cupom
            empresa = None
            try:
                db = DatabaseHelper.get_instance()
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass

            # Carregar config da impressora para layout e impressao automatica
            printer_cfg = self._load_printer_config()
            cupom = CupomGenerator.gerar_cupom(
                venda, self.carrinho, self.pagamentos_venda,
                empresa=empresa,
                colunas=printer_cfg.get("largura_papel", 48),
                margem_esq=printer_cfg.get("margem_esquerda", 0),
                margem_dir=printer_cfg.get("margem_direita", 0),
                espacamento=printer_cfg.get("espacamento_linhas", 1)
            )

            auto_imp = printer_cfg.get("imprimir_automatico", False)

            # === MULTI-IMPRESSORA: Imprimir cupons parciais por categoria ===
            try:
                multi_cfg = self._load_multi_printer_config()
                if multi_cfg.get("ativo", False):
                    # Se configurado para NAO imprimir cupom completo, desativar auto_imp
                    if not multi_cfg.get("imprimir_cupom_completo", True):
                        auto_imp = False
                    # Despachar impressao por categoria em thread separada
                    self._imprimir_por_categoria(venda, self.carrinho, empresa=empresa)
            except Exception as e:
                _logger.error(f"Erro ao despachar multi-impressora: {e}")

            # Se a venda veio de um armario, liberar o armario e voltar ao menu ao fechar o cupom
            if self._armario_pendente:
                arm_id = self._armario_pendente["arm_id"]
                arm_numero = self._armario_pendente["numero"]
                arm_uso_id = self._armario_pendente.get("uso_id", 0)
                self._armario_pendente = None

                def ao_fechar_cupom_armario():
                    def liberar_armario():
                        db = DatabaseHelper.get_instance()
                        # Limpar usando tabelas do APK (uso_armario_sauna + itens_armario_sauna)
                        if arm_uso_id and arm_uso_id > 0:
                            try:
                                db.execute_update(
                                    "DELETE FROM itens_armario_sauna_adicionais "
                                    "WHERE item_armario_id IN (SELECT id FROM itens_armario_sauna WHERE uso_armario_id = %s)",
                                    (arm_uso_id,))
                            except Exception:
                                pass
                            db.execute_update(
                                "DELETE FROM itens_armario_sauna WHERE uso_armario_id = %s",
                                (arm_uso_id,))
                            db.execute_update(
                                "UPDATE uso_armario_sauna SET status = 'encerrado', data_saida = NOW() WHERE id = %s",
                                (arm_uso_id,))
                    def on_armario_liberado(_):
                        self.show_success(f"Armario {arm_numero} liberado com sucesso! Chave devolvida.")
                        self.show_main_menu()
                    self.run_async(liberar_armario, on_armario_liberado)

                self._mostrar_cupom(cupom, auto_imprimir=auto_imp, on_close=ao_fechar_cupom_armario)
            else:
                self._mostrar_cupom(cupom, auto_imprimir=auto_imp, on_close=self.show_main_menu)

        self.run_async(salvar, on_saved)

    def _mostrar_cupom(self, cupom_text, auto_imprimir=False, on_close=None):
        """Exibe o cupom na tela com opcoes de Copiar, Salvar, Imprimir e Fechar.
        Se auto_imprimir=True, envia automaticamente para a impressora.
        Se on_close for fornecido, sera executado ao fechar o dialog do cupom."""
        # Guardar ultimo cupom para impressao rapida Ctrl+P
        self._ultimo_cupom = cupom_text

        dialog = tk.Toplevel(self.root)
        dialog.title("Cupom da Venda")
        dialog.geometry("500x650")
        dialog.configure(bg=COR_FUNDO)

        tk.Label(dialog, text="Cupom Nao Fiscal", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(pady=10)

        text_widget = scrolledtext.ScrolledText(dialog, bg=COR_ENTRADA, fg=COR_TEXTO,
                                                 font=("Courier New", 10), wrap="word")
        text_widget.pack(fill="both", expand=True, padx=15, pady=5)
        text_widget.insert("1.0", cupom_text)
        text_widget.config(state="disabled")

        # Label de status da impressao
        lbl_status_imp = tk.Label(dialog, text="", bg=COR_FUNDO, fg=COR_TEXTO2,
                                   font=("Segoe UI", 9, "italic"))
        lbl_status_imp.pack(pady=(0, 5))

        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=15, pady=10)

        def copiar():
            self.root.clipboard_clear()
            self.root.clipboard_append(cupom_text)
            ToastManager.success("Cupom copiado para a area de transferencia!")

        def salvar_arquivo():
            DataExporter.export_text(cupom_text, "cupom", parent=dialog)

        def imprimir_cupom():
            lbl_status_imp.config(text="Enviando para impressora...", fg=COR_ALERTA)
            dialog.update_idletasks()

            def _do_print():
                return self._imprimir_texto(cupom_text, parent_window=dialog)

            def _on_result(resultado):
                sucesso, msg = resultado
                if sucesso:
                    lbl_status_imp.config(text=msg, fg=COR_SUCESSO)
                    messagebox.showinfo(
                        "Impressao Enviada",
                        f"{msg}\n\n"
                        "O documento foi enviado para a impressora com sucesso.",
                        parent=dialog)
                else:
                    lbl_status_imp.config(text=f"Falha: {msg}", fg=COR_ERRO)
                    messagebox.showerror(
                        "Erro na Impressao",
                        f"{msg}\n\n"
                        "COMO RESOLVER:\n"
                        "1. Verifique se a impressora esta LIGADA\n"
                        "2. Verifique se o cabo esta conectado\n"
                        "3. Verifique se ha papel na impressora\n"
                        "4. Abra 'Dispositivos e Impressoras' no Windows\n"
                        "5. Verifique se nao ha documentos travados na fila",
                        parent=dialog)

            def _on_error(e):
                lbl_status_imp.config(text=f"Erro: {e}", fg=COR_ERRO)
                ErroAmigavel.mostrar_erro(e, "impressao_cupom", parent=dialog)

            self.run_async(_do_print, _on_result, _on_error)

        StyledButton(btn_frame, text="⎙ Imprimir", command=imprimir_cupom,
                     color=COR_PRIMARIA, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text="◎ Copiar", command=copiar,
                     color=COR_BOTAO_AZUL, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text="Salvar TXT", command=salvar_arquivo,
                     color=COR_BOTAO_VERDE, width=12).pack(side="left", padx=5)
        def fechar_cupom():
            dialog.destroy()
            if on_close:
                on_close()

        StyledButton(btn_frame, text="Fechar", command=fechar_cupom,
                     color="#2a3a5c", width=12).pack(side="right", padx=5)

        # Garantir que on_close seja chamado ao fechar pela barra de titulo (X)
        dialog.protocol("WM_DELETE_WINDOW", fechar_cupom)

        # Impressao automatica se configurado
        if auto_imprimir:
            dialog.after(500, imprimir_cupom)

    def _mostrar_cupom_caixa(self, cupom_text, titulo="Cupom do Caixa", auto_imprimir=False):
        """Exibe o cupom de abertura ou fechamento de caixa na tela
        com opcoes de Copiar, Salvar, Imprimir e Fechar.
        Se auto_imprimir=True, envia automaticamente para a impressora."""
        dialog = tk.Toplevel(self.root)
        dialog.title(titulo)
        dialog.geometry("500x650")
        dialog.configure(bg=COR_FUNDO)

        tk.Label(dialog, text=titulo, bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(pady=10)

        text_widget = scrolledtext.ScrolledText(dialog, bg=COR_ENTRADA, fg=COR_TEXTO,
                                                 font=("Courier New", 10), wrap="word")
        text_widget.pack(fill="both", expand=True, padx=15, pady=5)
        text_widget.insert("1.0", cupom_text)
        text_widget.config(state="disabled")

        # Label de status da impressao
        lbl_status_imp = tk.Label(dialog, text="", bg=COR_FUNDO, fg=COR_TEXTO2,
                                   font=("Segoe UI", 9, "italic"))
        lbl_status_imp.pack(pady=(0, 5))

        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=15, pady=10)

        def copiar():
            self.root.clipboard_clear()
            self.root.clipboard_append(cupom_text)
            ToastManager.success("Cupom copiado para a area de transferencia!")

        def salvar_arquivo():
            path = filedialog.asksaveasfilename(defaultextension=".txt",
                filetypes=[("Arquivo de Texto", "*.txt")], parent=dialog)
            if path:
                with open(path, "w", encoding="utf-8") as f:
                    f.write(cupom_text)
                ToastManager.success("Cupom salvo com sucesso!")
                messagebox.showinfo(
                    "Arquivo Salvo",
                    f"O cupom foi salvo com sucesso!\n\n"
                    f"Local: {path}\n\n"
                    f"Voce pode abrir este arquivo com o Bloco de Notas.",
                    parent=dialog)

        def imprimir_cupom():
            lbl_status_imp.config(text="Enviando para impressora...", fg=COR_ALERTA)
            dialog.update_idletasks()

            def _do_print():
                return self._imprimir_texto(cupom_text, parent_window=dialog)

            def _on_result(resultado):
                sucesso, msg = resultado
                if sucesso:
                    lbl_status_imp.config(text=msg, fg=COR_SUCESSO)
                    messagebox.showinfo(
                        "Impressao Enviada",
                        f"{msg}\n\n"
                        "O documento foi enviado para a impressora com sucesso.",
                        parent=dialog)
                else:
                    lbl_status_imp.config(text=f"Falha: {msg}", fg=COR_ERRO)
                    messagebox.showerror(
                        "Erro na Impressao",
                        f"{msg}\n\n"
                        "COMO RESOLVER:\n"
                        "1. Verifique se a impressora esta LIGADA\n"
                        "2. Verifique se o cabo esta conectado\n"
                        "3. Verifique se ha papel na impressora\n"
                        "4. Abra 'Dispositivos e Impressoras' no Windows\n"
                        "5. Verifique se nao ha documentos travados na fila",
                        parent=dialog)

            def _on_error(e):
                lbl_status_imp.config(text=f"Erro: {e}", fg=COR_ERRO)
                ErroAmigavel.mostrar_erro(e, "impressao_cupom", parent=dialog)

            self.run_async(_do_print, _on_result, _on_error)

        StyledButton(btn_frame, text="⎙ Imprimir", command=imprimir_cupom,
                     color=COR_PRIMARIA, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text="◎ Copiar", command=copiar,
                     color=COR_BOTAO_AZUL, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text="Salvar TXT", command=salvar_arquivo,
                     color=COR_BOTAO_VERDE, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame, text="Fechar", command=dialog.destroy,
                     color="#2a3a5c", width=12).pack(side="right", padx=5)

        dialog.protocol("WM_DELETE_WINDOW", dialog.destroy)

        # Impressao automatica se configurado
        if auto_imprimir:
            dialog.after(500, imprimir_cupom)

