    def _mini_kpi(self, parent, label, valor, color, col):
        """Cria um mini card KPI para a tela de caixa."""
        card = tk.Frame(parent, bg=COR_GLASS, highlightthickness=1,
                        highlightbackground=COR_GLASS_BORDER,
                        padx=8, pady=6)
        card.grid(row=0, column=col, padx=3, pady=2, sticky="nsew")
        lbl_v = tk.Label(card, text=valor, bg=COR_GLASS, fg=color,
                         font=("Consolas", 13, "bold"))
        lbl_v.pack()
        tk.Label(card, text=label, bg=COR_GLASS, fg=COR_TEXTO2,
                 font=("Segoe UI", 8)).pack()
        return lbl_v

    def carregar_status_caixa(self):
        def load():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT c.*, u.nome as usuario_nome FROM caixa c "
                "LEFT JOIN usuarios u ON c.usuario_id = u.id "
                "WHERE c.status = 'aberto' ORDER BY c.id DESC LIMIT 1"
            )
            return rows

        def on_loaded(rows):
            if rows:
                cx = rows[0]
                Session.caixa_id = cx["id"]
                self.caixa_aberto = cx
                self.lbl_caixa_status.config(text="CAIXA ABERTO", fg=COR_SUCESSO)
                try:
                    self._caixa_dot.master.itemconfig(
                        self._caixa_dot, fill=COR_SUCESSO)
                except Exception:
                    pass
                info = (f"Caixa #{cx['id']}  |  Operador: {cx.get('usuario_nome','N/A')}  |  "
                        f"Abertura: {FormatUtils.format_date(cx.get('data_abertura'))}  |  "
                        f"Valor Abertura: R$ {FormatUtils.format_money(cx.get('valor_abertura',0))}")
                self.lbl_caixa_info.config(text=info)
                self.btn_abrir_caixa.config(state="disabled")
                self.btn_fechar_caixa.config(state="normal")
                self.status_bar.set_caixa(True, cx["id"])
                self.carregar_resumo_caixa(cx["id"])
            else:
                Session.caixa_id = 0
                self.caixa_aberto = None
                self.lbl_caixa_status.config(text="CAIXA FECHADO", fg=COR_ERRO)
                try:
                    self._caixa_dot.master.itemconfig(
                        self._caixa_dot, fill=COR_ERRO)
                except Exception:
                    pass
                self.lbl_caixa_info.config(
                    text="Nenhum caixa aberto no momento. Clique em 'Abrir Caixa' para iniciar.")
                self.btn_abrir_caixa.config(state="normal")
                self.btn_fechar_caixa.config(state="disabled")
                self.status_bar.set_caixa(False)

        self.run_async(load, on_loaded)

    def carregar_resumo_caixa(self, caixa_id):
        def load():
            db = DatabaseHelper.get_instance()
            resumo = []
            sep = "-" * 52

            # Vendas do caixa
            rows = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(total_liquido),0) as total "
                "FROM vendas WHERE caixa_id = %s AND status = 'finalizada'",
                (caixa_id,)
            )
            qtd_v = int(rows[0]["qtd"]) if rows else 0
            tot_v = float(rows[0]["total"]) if rows else 0.0
            resumo.append(sep)
            resumo.append(f"  VENDAS FINALIZADAS: {qtd_v:>4}  |  "
                          f"TOTAL: R$ {FormatUtils.format_money(tot_v)}")
            resumo.append(sep)

            # Por forma de pagamento
            rows = db.execute_query(
                "SELECT fp.descricao, COALESCE(SUM(pv.valor),0) as total "
                "FROM pagamentos_venda pv "
                "JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                "JOIN vendas v ON pv.venda_id = v.id "
                "WHERE v.caixa_id = %s AND v.status = 'finalizada' "
                "GROUP BY fp.id, fp.descricao ORDER BY total DESC", (caixa_id,)
            )
            if rows:
                resumo.append("  Por Forma de Pagamento:")
                for r in rows:
                    resumo.append(
                        f"    {r['descricao']:<22} R$ "
                        f"{FormatUtils.format_money(r['total']):>10}")
                resumo.append(sep)

            # Vales
            rows = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total "
                "FROM vales_debito WHERE caixa_id = %s", (caixa_id,)
            )
            qtd_vales = int(rows[0]["qtd"]) if rows else 0
            tot_vales = float(rows[0]["total"]) if rows else 0.0
            if qtd_vales > 0:
                resumo.append(
                    f"  Vales/Debitos: {qtd_vales}  |  "
                    f"Total: R$ {FormatUtils.format_money(tot_vales)}")

            # Sangrias
            rows_s = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total "
                "FROM sangrias WHERE caixa_id = %s", (caixa_id,)
            )
            qtd_sang = int(rows_s[0]["qtd"]) if rows_s else 0
            tot_sang = float(rows_s[0]["total"]) if rows_s else 0.0
            if qtd_sang > 0:
                resumo.append(
                    f"  Sangrias: {qtd_sang}  |  "
                    f"Total: R$ {FormatUtils.format_money(tot_sang)}")

            if qtd_vales > 0 or qtd_sang > 0:
                resumo.append(sep)

            # Ultimas 10 vendas
            ultimas = db.execute_query(
                "SELECT v.id, COALESCE(NULLIF(v.cliente_nome,''), NULLIF(u.cliente_nome,''), c.nome,'N/A') as cli, "
                "v.total_liquido, v.data_venda "
                "FROM vendas v "
                "LEFT JOIN clientes c ON v.cliente_id = c.id "
                "LEFT JOIN uso_armario_sauna u ON v.uso_armario_id = u.id "
                "WHERE v.caixa_id = %s AND v.status='finalizada' "
                "ORDER BY v.id DESC LIMIT 10",
                (caixa_id,)
            )
            if ultimas:
                resumo.append("  Ultimas Vendas:")
                for u in ultimas:
                    resumo.append(
                        f"    #{u['id']:<5} {str(u.get('cli',''))[:18]:<18} "
                        f"R$ {FormatUtils.format_money(u['total_liquido']):>9}  "
                        f"{FormatUtils.format_date(u['data_venda'])}")
                resumo.append(sep)

            return {
                "texto": "\n".join(resumo) if resumo else "Nenhuma movimentacao.",
                "qtd_v": qtd_v, "tot_v": tot_v,
                "qtd_vales": qtd_vales, "qtd_sang": qtd_sang,
            }

        def on_loaded(result):
            try:
                self.text_resumo_caixa.config(state="normal")
                self.text_resumo_caixa.delete("1.0", "end")
                self.text_resumo_caixa.insert("1.0", result["texto"])
                self.text_resumo_caixa.config(state="disabled")
                # Atualizar mini KPIs
                self._lbl_kpi_vendas.config(text=str(result["qtd_v"]))
                self._lbl_kpi_total.config(
                    text=f"R$ {FormatUtils.format_money(result['tot_v'])}")
                self._lbl_kpi_vales.config(text=str(result["qtd_vales"]))
                self._lbl_kpi_sangrias.config(text=str(result["qtd_sang"]))
            except Exception:
                pass

        self.run_async(load, on_loaded)


    def abrir_caixa(self):
        valor = simpledialog.askfloat("Abrir Caixa", "Valor de abertura (R$):",
                                       initialvalue=0, minvalue=0, parent=self.root)
        if valor is None:
            return
        def abrir():
            db = DatabaseHelper.get_instance()
            caixa_id = db.execute_update(
                "INSERT INTO caixa (usuario_id, valor_abertura, status) VALUES (%s, %s, 'aberto')",
                (Session.user_id, valor)
            )
            # Carregar dados da empresa para o cupom
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass
            return {"caixa_id": caixa_id, "empresa": empresa}
        def on_aberto(result):
            caixa_id = result["caixa_id"]
            empresa = result["empresa"]
            Session.caixa_id = caixa_id
            data_abertura = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")

            # Gerar cupom de abertura de caixa
            printer_cfg = self._load_printer_config()
            cupom = CupomGenerator.gerar_cupom_abertura_caixa(
                caixa_id=caixa_id,
                usuario_nome=Session.user_nome,
                valor_abertura=valor,
                data_abertura=data_abertura,
                empresa=empresa,
                colunas=printer_cfg.get("largura_papel", 48),
                margem_esq=printer_cfg.get("margem_esquerda", 0),
                margem_dir=printer_cfg.get("margem_direita", 0),
                espacamento=printer_cfg.get("espacamento_linhas", 1)
            )
            auto_imp = printer_cfg.get("imprimir_automatico", False)
            self._mostrar_cupom_caixa(cupom, "Abertura de Caixa",
                                       auto_imprimir=auto_imp)
            self.status_bar.set_caixa(True, caixa_id)
            ToastManager.success(
                f"Caixa #{caixa_id} aberto com R$ {FormatUtils.format_money(valor)}")
            AuditLogger.log("CAIXA_ABERTO",
                            f"Caixa #{caixa_id} | Valor: R$ {FormatUtils.format_money(valor)}",
                            usuario=Session.user_login)
            self.carregar_status_caixa()
        self.run_async(abrir, on_aberto)

    def fechar_caixa(self):
        if not self.caixa_aberto:
            return
        if not messagebox.askyesno("Confirmar", "Deseja fechar o caixa?"):
            return
        caixa_id_fechando = Session.caixa_id
        caixa_data = self.caixa_aberto
        def fechar():
            db = DatabaseHelper.get_instance()
            # Calcular total de vendas
            rows = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(total_liquido),0) as total FROM vendas "
                "WHERE caixa_id = %s AND status = 'finalizada'", (caixa_id_fechando,)
            )
            total_vendas = float(rows[0]["total"]) if rows else 0
            qtd_vendas = int(rows[0]["qtd"]) if rows else 0
            valor_abertura = float(caixa_data.get("valor_abertura", 0))

            # Vales
            rows_v = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total FROM vales_debito WHERE caixa_id = %s",
                (caixa_id_fechando,)
            )
            total_vales = float(rows_v[0]["total"]) if rows_v else 0
            qtd_vales = int(rows_v[0]["qtd"]) if rows_v else 0

            # Sangrias
            rows_s = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total FROM sangrias WHERE caixa_id = %s",
                (caixa_id_fechando,)
            )
            total_sangrias = float(rows_s[0]["total"]) if rows_s else 0
            qtd_sangrias = int(rows_s[0]["qtd"]) if rows_s else 0

            valor_fechamento = valor_abertura + total_vendas - total_vales - total_sangrias

            # Resumo por forma de pagamento
            pag_rows = db.execute_query(
                "SELECT fp.descricao, COALESCE(SUM(pv.valor),0) as total "
                "FROM pagamentos_venda pv "
                "JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                "JOIN vendas v ON pv.venda_id = v.id "
                "WHERE v.caixa_id = %s AND v.status = 'finalizada' "
                "GROUP BY fp.id, fp.descricao ORDER BY total DESC", (caixa_id_fechando,)
            )
            pagamentos_resumo = []
            if pag_rows:
                for pr in pag_rows:
                    pagamentos_resumo.append({
                        "descricao": pr.get("descricao", "N/A"),
                        "total": float(pr.get("total", 0))
                    })

            # Carregar dados da empresa para o cupom
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass

            db.execute_update(
                "UPDATE caixa SET data_fechamento = NOW(), valor_fechamento = %s, "
                "status = 'fechado' WHERE id = %s",
                (valor_fechamento, caixa_id_fechando)
            )

            return {
                "valor_fechamento": valor_fechamento,
                "valor_abertura": valor_abertura,
                "total_vendas": total_vendas,
                "qtd_vendas": qtd_vendas,
                "total_vales": total_vales,
                "qtd_vales": qtd_vales,
                "total_sangrias": total_sangrias,
                "qtd_sangrias": qtd_sangrias,
                "pagamentos_resumo": pagamentos_resumo,
                "empresa": empresa,
                "data_abertura": caixa_data.get("data_abertura", ""),
            }

        def on_fechado(result):
            valor_fechamento = result["valor_fechamento"]
            data_fechamento = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            caixa_id_tmp = caixa_id_fechando
            Session.caixa_id = 0

            # Gerar cupom de fechamento de caixa
            printer_cfg = self._load_printer_config()
            cupom = CupomGenerator.gerar_cupom_fechamento_caixa(
                caixa_id=caixa_id_tmp,
                usuario_nome=Session.user_nome,
                valor_abertura=result["valor_abertura"],
                valor_fechamento=valor_fechamento,
                data_abertura=result["data_abertura"],
                data_fechamento=data_fechamento,
                total_vendas=result["total_vendas"],
                qtd_vendas=result["qtd_vendas"],
                total_vales=result["total_vales"],
                qtd_vales=result["qtd_vales"],
                total_sangrias=result.get("total_sangrias", 0),
                qtd_sangrias=result.get("qtd_sangrias", 0),
                pagamentos_resumo=result["pagamentos_resumo"],
                empresa=result["empresa"],
                colunas=printer_cfg.get("largura_papel", 48),
                margem_esq=printer_cfg.get("margem_esquerda", 0),
                margem_dir=printer_cfg.get("margem_direita", 0),
                espacamento=printer_cfg.get("espacamento_linhas", 1)
            )
            auto_imp = printer_cfg.get("imprimir_automatico", False)
            self._mostrar_cupom_caixa(cupom, "Fechamento de Caixa",
                                       auto_imprimir=auto_imp)
            self.status_bar.set_caixa(False)
            ToastManager.info(
                f"Caixa #{caixa_id_tmp} fechado. "
                f"Total: R$ {FormatUtils.format_money(valor_fechamento)}")
            AuditLogger.log(
                "CAIXA_FECHADO",
                f"Caixa #{caixa_id_tmp} | "
                f"Total Vendas: R$ {FormatUtils.format_money(result['total_vendas'])} | "
                f"Fechamento: R$ {FormatUtils.format_money(valor_fechamento)}",
                usuario=Session.user_login)
            self.carregar_status_caixa()

        self.run_async(fechar, on_fechado)

    def add_vale_debito(self):
        if not Session.caixa_id:
            self.show_error("Abra o caixa antes de registrar vales.")
            return
        dialog = tk.Toplevel(self.root)
        dialog.title("Vale/Debito")
        dialog.geometry("400x250")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        card = CardFrame(dialog)
        card.pack(padx=20, pady=20, fill="x")

        tk.Label(card, text="Descricao:", bg=COR_CARD, fg=COR_TEXTO).pack(anchor="w")
        et_desc = StyledEntry(card)
        et_desc.pack(fill="x", pady=(0, 8))

        tk.Label(card, text="Valor (R$):", bg=COR_CARD, fg=COR_TEXTO).pack(anchor="w")
        et_valor = StyledEntry(card)
        et_valor.pack(fill="x", pady=(0, 10))

        def salvar():
            desc = et_desc.get().strip()
            valor = FormatUtils.parse_money(et_valor.get())
            if not desc or valor <= 0:
                messagebox.showwarning(
                    "Campos Obrigatorios",
                    "Preencha todos os campos para registrar o vale/debito.\n\n"
                    "1. Descricao - motivo do vale (ex: 'Vale funcionario Joao')\n"
                    "2. Valor - valor em reais (ex: 50,00)\n\n"
                    "O valor deve ser maior que zero.",
                    parent=dialog)
                return
            try:
                db = DatabaseHelper.get_instance()
                db.execute_update(
                    "INSERT INTO vales_debito (caixa_id, descricao, valor) VALUES (%s,%s,%s)",
                    (Session.caixa_id, desc, valor)
                )
                messagebox.showinfo(
                    "Vale Registrado",
                    "O vale/debito foi registrado com sucesso no caixa!\n\n"
                    "O valor sera descontado no fechamento do caixa.",
                    parent=dialog)
                dialog.destroy()
                self.carregar_status_caixa()
            except Exception as e:
                ErroAmigavel.mostrar_erro(e, "operacao_dialog", parent=dialog)

        StyledButton(card, text="✔ Salvar", command=salvar, color=COR_BOTAO_VERDE).pack(pady=5)


    def add_sangria(self):
        """Registra uma sangria no caixa. Exige senha de administrador."""
        if not Session.caixa_id:
            self.show_error("Abra o caixa antes de registrar sangrias.")
            return

        def _abrir_dialog_sangria():
            dialog = tk.Toplevel(self.root)
            dialog.title("Sangria de Caixa")
            dialog.configure(bg=COR_FUNDO)
            dialog.transient(self.root)
            dialog.grab_set()
            dialog.resizable(False, False)

            # Posicionar o dialog a direita da tela
            dlg_w = 450
            dlg_h = 320
            screen_w = dialog.winfo_screenwidth()
            screen_h = dialog.winfo_screenheight()
            pos_x = screen_w - dlg_w - 30
            pos_y = (screen_h - dlg_h) // 2
            dialog.geometry(f"{dlg_w}x{dlg_h}+{pos_x}+{pos_y}")

            tk.Label(dialog, text="Sangria de Caixa", bg=COR_FUNDO, fg=COR_PRIMARIA,
                     font=("Segoe UI", 16, "bold")).pack(pady=(15, 5))
            tk.Label(dialog, text="Informe os dados da sangria.",
                     bg=COR_FUNDO, fg=COR_TEXTO2, font=("Segoe UI", 10),
                     justify="center").pack(pady=(0, 10))

            card = CardFrame(dialog)
            card.pack(padx=25, pady=5, fill="x")

            tk.Label(card, text="Descricao/Motivo:", bg=COR_CARD, fg=COR_TEXTO,
                     font=("Segoe UI", 11)).pack(anchor="w", pady=(8, 2))
            et_desc = StyledEntry(card)
            et_desc.pack(fill="x", pady=(0, 8))
            et_desc.focus_set()

            tk.Label(card, text="Valor (R$):", bg=COR_CARD, fg=COR_TEXTO,
                     font=("Segoe UI", 11)).pack(anchor="w", pady=(0, 2))
            et_valor = StyledEntry(card)
            et_valor.pack(fill="x", pady=(0, 10))

            lbl_erro = tk.Label(dialog, text="", bg=COR_FUNDO, fg=COR_ERRO,
                                 font=("Segoe UI", 9, "italic"))
            lbl_erro.pack(pady=(0, 5))

            def salvar_sangria():
                desc = et_desc.get().strip()
                valor = FormatUtils.parse_money(et_valor.get())
                if not desc:
                    lbl_erro.config(text="Informe a descricao/motivo da sangria.")
                    return
                if valor <= 0:
                    lbl_erro.config(text="Informe um valor valido para a sangria.")
                    return

                def _registrar():
                    db = DatabaseHelper.get_instance()
                    # Buscar nome do admin que autorizou (usuario logado se for admin,
                    # ou o admin que autorizou via _solicitar_senha_admin)
                    sangria_id = db.execute_update(
                        "INSERT INTO sangrias (caixa_id, descricao, valor, operador_nome) "
                        "VALUES (%s, %s, %s, %s)",
                        (Session.caixa_id, desc, valor, Session.user_nome)
                    )
                    # Carregar dados da empresa para o cupom
                    empresa = None
                    try:
                        emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                        if emp_rows:
                            empresa = emp_rows[0]
                    except Exception:
                        pass
                    return {"sangria_id": sangria_id, "empresa": empresa,
                            "desc": desc, "valor": valor}

                def _on_registrado(result):
                    dialog.destroy()
                    data_sangria = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")

                    # Gerar cupom de sangria
                    printer_cfg = self._load_printer_config()
                    cupom = CupomGenerator.gerar_cupom_sangria(
                        sangria_id=result["sangria_id"],
                        caixa_id=Session.caixa_id,
                        operador_nome=Session.user_nome,
                        descricao=result["desc"],
                        valor=result["valor"],
                        data_sangria=data_sangria,
                        empresa=result["empresa"],
                        colunas=printer_cfg.get("largura_papel", 48),
                        margem_esq=printer_cfg.get("margem_esquerda", 0),
                        margem_dir=printer_cfg.get("margem_direita", 0),
                        espacamento=printer_cfg.get("espacamento_linhas", 1)
                    )
                    auto_imp = printer_cfg.get("imprimir_automatico", False)
                    self._mostrar_cupom_caixa(cupom, "Comprovante de Sangria", auto_imprimir=auto_imp)
                    self.carregar_status_caixa()

                self.run_async(_registrar, _on_registrado)

            btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
            btn_frame.pack(fill="x", padx=25, pady=(0, 15))
            StyledButton(btn_frame, text="Registrar Sangria", command=salvar_sangria,
                         color="#9C27B0", width=15).pack(side="left", padx=5)
            StyledButton(btn_frame, text="✘ Cancelar", command=dialog.destroy,
                         color="#2a3a5c", width=12).pack(side="right", padx=5)

        # Solicitar senha de administrador antes de abrir o dialog
        self._solicitar_senha_admin(_abrir_dialog_sangria, parent_window=self.root)

    # ========================================================================
    # DIALOG GENERICO DE SELECAO DE REGISTROS
    # ========================================================================
    def _selecionar_registro(self, tabela, titulo, sql, colunas, callback, params=None):
        dialog = tk.Toplevel(self.root)
        dialog.title(titulo)
        dialog.geometry("650x450")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        tk.Label(dialog, text=titulo, bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(pady=10)

        # Busca
        busca_frame = tk.Frame(dialog, bg=COR_FUNDO)
        busca_frame.pack(fill="x", padx=15, pady=5)
        et_busca = StyledEntry(busca_frame, width=40)
        et_busca.pack(side="left", fill="x", expand=True)

        tree = ttk.Treeview(dialog, columns=[f"c{i}" for i in range(len(colunas))],
                            show="headings", height=12)
        for i, col in enumerate(colunas):
            tree.heading(f"c{i}", text=col)
            tree.column(f"c{i}", width=120)
        tree.pack(fill="both", expand=True, padx=15, pady=5)

        vsb = ttk.Scrollbar(dialog, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=vsb.set)

        def carregar(filtro=""):
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(sql, params)
            def on_loaded(rows):
                tree.delete(*tree.get_children())
                for row in rows:
                    values = list(row.values())
                    if filtro:
                        match = any(filtro.lower() in str(v).lower() for v in values)
                        if not match:
                            continue
                    tree.insert("", "end", values=values)
            self.run_async(load, on_loaded)

        et_busca.bind("<KeyRelease>", lambda e: carregar(et_busca.get()))

        def selecionar():
            sel = tree.selection()
            if sel:
                values = tree.item(sel[0])["values"]
                dialog.destroy()
                callback(values)

        tree.bind("<Double-1>", lambda e: selecionar())
        StyledButton(dialog, text="▶ Selecionar", command=selecionar,
                     color=COR_BOTAO_VERDE, width=15).pack(pady=5)

        carregar()

    # ========================================================================
    # TELA GENERICA DE CADASTRO (CRUD)
    # ========================================================================
    def _show_cadastro_generico(self, titulo, table_name, campos, sql_list, sql_insert,
                                 sql_update, sql_delete=None, extra_buttons=None,
                                 on_after_save=None):
        self.clear_container()

        top = tk.Frame(self.main_container, bg=COR_FUNDO2, height=52)
        top.pack(fill="x")
        top.pack_propagate(False)
        # Linha neon superior
        _neon = tk.Canvas(top, height=2, bg=COR_FUNDO2, highlightthickness=0)
        _neon.pack(fill="x", side="top")
        _neon.bind("<Configure>", lambda e: (
            _neon.delete("all"),
            _neon.create_line(0, 1, e.width, 1, fill=COR_PRIMARIA, width=1)))
        StyledButton(top, text="◀ Voltar", command=self.show_main_menu,
                     color=COR_FUNDO3, width=10).pack(side="left", padx=10, pady=5)
        tk.Label(top, text=titulo, bg=COR_FUNDO2, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(side="left", padx=10)
        # Botoes Sair e Trocar de Usuario
        _btn_sair = StyledButton(top, text=f"{Icons.SAIR} Sair",
                     command=self._on_close,
                     color=COR_ERRO, width=8)
        _btn_sair.pack(side="right", padx=5, pady=5)
        add_tooltip(_btn_sair, "Fechar o PDV Pro (Alt+F4)")

        _btn_trocar = StyledButton(top, text=f"{Icons.TROCAR} Trocar",
                     command=self.do_logoff,
                     color=COR_BOTAO_LARANJA, width=10)
        _btn_trocar.pack(side="right", padx=5, pady=5)
        add_tooltip(_btn_trocar, "Trocar de usuario (Ctrl+L)")


        content = tk.Frame(self.main_container, bg=COR_FUNDO)
        content.pack(fill="both", expand=True, padx=10, pady=5)

        # Formulario
        form_card = CardFrame(content)
        form_card.pack(fill="x", pady=5)

        entries = {}
        row_idx = 0
        for campo in campos:
            nome = campo["nome"]
            label = campo.get("label", nome.replace("_", " ").title())
            tipo = campo.get("tipo", "text")

            tk.Label(form_card, text=f"{label}:", bg=COR_CARD, fg=COR_TEXTO,
                     font=("Segoe UI", 10)).grid(row=row_idx, column=0, sticky="w", padx=5, pady=3)

            if tipo == "combo":
                widget = ttk.Combobox(form_card, values=campo.get("values", []),
                                       width=30, state="readonly")
                if campo.get("values"):
                    widget.current(0)
            elif tipo == "check":
                var = tk.BooleanVar(value=campo.get("default", False))
                widget = tk.Checkbutton(form_card, variable=var, bg=COR_CARD,
                                         fg=COR_TEXTO, selectcolor=COR_ENTRADA,
                                         activebackground=COR_CARD)
                widget._var = var
            else:
                widget = StyledEntry(form_card, width=35)
                if campo.get("default"):
                    widget.insert(0, str(campo["default"]))

            widget.grid(row=row_idx, column=1, sticky="w", padx=5, pady=3)
            entries[nome] = widget
            row_idx += 1

        # Botoes do formulario
        btn_form = tk.Frame(form_card, bg=COR_CARD)
        btn_form.grid(row=row_idx, column=0, columnspan=2, pady=10)

        selected_id = [None]

        def limpar_form():
            selected_id[0] = None
            for campo in campos:
                w = entries[campo["nome"]]
                tipo = campo.get("tipo", "text")
                if tipo == "combo":
                    if w["values"]:
                        w.current(0)
                elif tipo == "check":
                    w._var.set(campo.get("default", False))
                else:
                    w.delete(0, tk.END)
                    if campo.get("default"):
                        w.insert(0, str(campo["default"]))

        def get_values():
            vals = []
            for campo in campos:
                w = entries[campo["nome"]]
                tipo = campo.get("tipo", "text")
                if tipo == "combo":
                    vals.append(w.get())
                elif tipo == "check":
                    vals.append(1 if w._var.get() else 0)
                elif tipo == "money":
                    vals.append(FormatUtils.parse_money(w.get()))
                elif tipo == "int":
                    try:
                        vals.append(int(w.get()))
                    except ValueError:
                        vals.append(0)
                elif tipo == "float":
                    try:
                        vals.append(float(w.get().replace(",", ".")))
                    except ValueError:
                        vals.append(0.0)
                else:
                    vals.append(w.get().strip())
            return vals

        def salvar():
            vals = get_values()
            # Validar campo obrigatorio (primeiro campo geralmente)
            if campos[0].get("required", True) and not vals[0]:
                self.show_error(f"Preencha o campo {campos[0].get('label', campos[0]['nome'])}.")
                return
            def do_save():
                db = DatabaseHelper.get_instance()
                last_id = None
                if selected_id[0]:
                    db.execute_update(sql_update, tuple(vals) + (selected_id[0],))
                    last_id = selected_id[0]
                else:
                    last_id = db.execute_update(sql_insert, tuple(vals))
                return last_id
            def on_saved(last_id):
                if on_after_save and last_id:
                    try:
                        on_after_save(last_id, vals, campos)
                    except Exception as e:
                        print(f"Aviso on_after_save: {e}")
                limpar_form()
                carregar_lista()
                self.show_success("Registro salvo com sucesso!")
            self.run_async(do_save, on_saved)

        def excluir():
            if not selected_id[0]:
                self.show_error("Por favor, selecione um registro na lista antes de excluir.\n\nClique sobre o registro desejado e tente novamente.")
                return
            if not messagebox.askyesno("Confirmar", "Deseja excluir este registro?"):
                return
            def do_del():
                db = DatabaseHelper.get_instance()
                if sql_delete:
                    db.execute_update(sql_delete, (selected_id[0],))
                else:
                    db.execute_update(f"DELETE FROM {table_name} WHERE id = %s", (selected_id[0],))
            def on_deleted(_):
                limpar_form()
                carregar_lista()
            self.run_async(do_del, on_deleted)

        StyledButton(btn_form, text="✔ Salvar", command=salvar,
                     color=COR_BOTAO_VERDE, width=10).pack(side="left", padx=5)
        StyledButton(btn_form, text="✚ Novo", command=limpar_form,
                     color=COR_BOTAO_AZUL, width=10).pack(side="left", padx=5)
        StyledButton(btn_form, text="✖ Excluir", command=excluir,
                     color=COR_ERRO, width=10).pack(side="left", padx=5)

        if extra_buttons:
            for btn_text, btn_cmd in extra_buttons:
                StyledButton(btn_form, text=btn_text, command=lambda c=btn_cmd: c(selected_id[0]),
                             color=COR_BOTAO_LARANJA, width=12).pack(side="left", padx=5)

        # Lista
        col_names = [c.get("label", c["nome"].replace("_", " ").title()) for c in campos]
        col_ids = [f"c{i}" for i in range(len(campos) + 1)]  # +1 para ID

        tree = ttk.Treeview(content, columns=col_ids, show="headings", height=15)
        tree.heading("c0", text="ID")
        tree.column("c0", width=50, anchor="center")
        for i, col in enumerate(col_names):
            tree.heading(f"c{i+1}", text=col)
            tree.column(f"c{i+1}", width=120)

        vsb = ttk.Scrollbar(content, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=vsb.set)
        tree.pack(side="left", fill="both", expand=True, pady=5)
        vsb.pack(side="right", fill="y", pady=5)

        def on_select(event):
            sel = tree.selection()
            if sel:
                values = tree.item(sel[0])["values"]
                selected_id[0] = values[0]
                for i, campo in enumerate(campos):
                    w = entries[campo["nome"]]
                    tipo = campo.get("tipo", "text")
                    val = values[i + 1] if i + 1 < len(values) else ""
                    if tipo == "combo":
                        try:
                            w.set(str(val))
                        except Exception:
                            pass
                    elif tipo == "check":
                        w._var.set(bool(val))
                    else:
                        w.delete(0, tk.END)
                        w.insert(0, str(val) if val else "")

        tree.bind("<<TreeviewSelect>>", on_select)

        def carregar_lista():
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(sql_list)
            def on_loaded(rows):
                # Preservar selecao atual
                sel = tree.selection()
                sel_id = None
                if sel:
                    try:
                        sel_id = tree.item(sel[0])["values"][0]
                    except Exception:
                        pass
                tree.delete(*tree.get_children())
                new_sel_iid = None
                for row in rows:
                    vals = list(row.values())
                    iid = tree.insert("", "end", values=vals)
                    if sel_id is not None and vals and vals[0] == sel_id:
                        new_sel_iid = iid
                # Restaurar selecao
                if new_sel_iid:
                    tree.selection_set(new_sel_iid)
                    tree.see(new_sel_iid)
            self.run_async(load, on_loaded)

        carregar_lista()

        # Auto-refresh em tempo real (a cada 10 segundos)
        self._start_auto_refresh(f"cadastro_{table_name}", carregar_lista, 10000)

