        # ---- Variaveis de estado ----
        selected_id = [None]
        tipos_produto_cache = [[]]

        # ---- Funcoes auxiliares ----

        def _load_foto_into_label(b64_data):
            """Carrega imagem base64 no label iv_foto (igual ao Android ImageUtils.loadBase64IntoImageView)."""
            if not b64_data:
                iv_foto.config(image="", text="Sem Foto", fg=COR_TEXTO2)
                self._produto_foto_tk = None
                return
            try:
                if HAS_PIL:
                    img_data = base64.b64decode(b64_data)
                    img = Image.open(io.BytesIO(img_data))
                    img = img.resize((120, 120), Image.LANCZOS)
                    photo = ImageTk.PhotoImage(img)
                    iv_foto.config(image=photo, text="")
                    self._produto_foto_tk = photo  # Manter referencia
                else:
                    iv_foto.config(image="", text="[Foto OK]", fg=COR_SUCESSO)
            except Exception:
                iv_foto.config(image="", text="[Erro foto]", fg=COR_ERRO)

        def _escolher_foto():
            """Abre dialog para selecionar imagem (igual ao Android imagePickerLauncher)."""
            filepath = filedialog.askopenfilename(
                title="Selecionar Foto do Produto",
                filetypes=[("Imagens", "*.png *.jpg *.jpeg *.gif *.bmp *.webp"), ("Todos", "*.*")]
            )
            if filepath:
                try:
                    if HAS_PIL:
                        img = Image.open(filepath)
                        # Redimensionar para max 400x400 para nao sobrecarregar o banco
                        img.thumbnail((400, 400), Image.LANCZOS)
                        buffer = io.BytesIO()
                        img.save(buffer, format="PNG")
                        b64 = base64.b64encode(buffer.getvalue()).decode("utf-8")
                    else:
                        with open(filepath, "rb") as f:
                            b64 = base64.b64encode(f.read()).decode("utf-8")
                    self._produto_foto_base64_temp = b64
                    _load_foto_into_label(b64)
                except Exception as e:
                    self.show_error(f"Erro ao carregar imagem: {e}")

        def _remover_foto():
            """Remove a foto do produto."""
            self._produto_foto_base64_temp = None
            _load_foto_into_label(None)

        def _carregar_tipos_produto():
            """Carrega tipos de produto do banco para o combobox (igual ao Android carregarTiposProduto)."""
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query("SELECT id, descricao FROM tipos_produto WHERE ativo = 1 ORDER BY descricao")
            def on_loaded(rows):
                tipos = [{"id": 0, "descricao": "-- Selecione o Tipo --"}]
                for r in rows:
                    tipos.append({"id": r["id"], "descricao": r["descricao"]})
                tipos_produto_cache[0] = tipos
                combo_tipo_produto["values"] = [t["descricao"] for t in tipos]
                combo_tipo_produto.current(0)
            self.run_async(load, on_loaded)

        def _get_tipo_produto_id_selecionado():
            """Retorna o ID do tipo de produto selecionado no combobox."""
            idx = combo_tipo_produto.current()
            if idx >= 0 and idx < len(tipos_produto_cache[0]):
                return tipos_produto_cache[0][idx]["id"]
            return 0

        def _set_tipo_produto_por_id(tipo_id):
            """Seleciona o tipo de produto no combobox pelo ID."""
            if not tipo_id:
                combo_tipo_produto.current(0)
                return
            for i, t in enumerate(tipos_produto_cache[0]):
                if t["id"] == tipo_id:
                    combo_tipo_produto.current(i)
                    return
            combo_tipo_produto.current(0)

        def _gerar_proximo_codigo():
            """Gera o proximo codigo sequencial (igual ao Android gerarProximoCodigo)."""
            def load():
                db = DatabaseHelper.get_instance()
                rows = db.execute_query(
                    "SELECT MAX(CAST(codigo AS UNSIGNED)) AS max_codigo FROM produtos WHERE codigo REGEXP '^[0-9]+$'")
                max_codigo = 0
                if rows and rows[0].get("max_codigo"):
                    max_codigo = int(rows[0]["max_codigo"])
                proximo = max_codigo + 1
                return f"{proximo:03d}" if proximo < 1000 else str(proximo)
            def on_loaded(codigo):
                et_codigo.delete(0, tk.END)
                et_codigo.insert(0, codigo)
            self.run_async(load, on_loaded)

        def _gerar_ean13_unico():
            """Gera EAN-13 unico verificando no banco (igual ao Android gerarEan13Unico)."""
            btn_gerar_ean.config(state="disabled", text="...")
            def load():
                db = DatabaseHelper.get_instance()
                for _ in range(50):
                    ean = EanUtils.gerar_ean13()
                    rows = db.execute_query("SELECT COUNT(*) as cnt FROM produtos WHERE codigo_barras = %s", (ean,))
                    if rows and rows[0].get("cnt", 0) == 0:
                        return ean
                return EanUtils.gerar_ean13()
            def on_loaded(ean):
                et_codigo_barras.delete(0, tk.END)
                et_codigo_barras.insert(0, ean)
                btn_gerar_ean.config(state="normal", text="Gerar")
                self.show_success(f"EAN-13 gerado: {ean}")
            def on_error(e):
                ean = EanUtils.gerar_ean13()
                et_codigo_barras.delete(0, tk.END)
                et_codigo_barras.insert(0, ean)
                btn_gerar_ean.config(state="normal", text="Gerar")
                self.show_success(f"EAN-13 gerado: {ean}")
            self.run_async(load, on_loaded, on_error)

        def limpar_form():
            """Limpa o formulario e prepara para novo produto (igual ao Android showEditDialog(null))."""
            selected_id[0] = None
            self._produto_foto_base64_temp = None
            _load_foto_into_label(None)
            et_codigo.delete(0, tk.END)
            et_codigo_barras.delete(0, tk.END)
            et_descricao.delete(0, tk.END)
            combo_tipo_produto.current(0)
            et_unidade.delete(0, tk.END)
            et_unidade.insert(0, "UN")
            et_preco_custo.delete(0, tk.END)
            et_preco_venda.delete(0, tk.END)
            et_estoque.delete(0, tk.END)
            et_estoque_min.delete(0, tk.END)
            # Gerar codigo automatico (igual ao Android)
            _gerar_proximo_codigo()

        def preencher_form(produto_dict):
            """Preenche o formulario com dados do produto selecionado (igual ao Android showEditDialog(produto))."""
            selected_id[0] = produto_dict.get("id")
            et_codigo.delete(0, tk.END)
            et_codigo.insert(0, FormatUtils.safe_string(str(produto_dict.get("codigo", ""))))
            et_codigo_barras.delete(0, tk.END)
            et_codigo_barras.insert(0, FormatUtils.safe_string(str(produto_dict.get("codigo_barras", ""))))
            et_descricao.delete(0, tk.END)
            et_descricao.insert(0, FormatUtils.safe_string(str(produto_dict.get("descricao", ""))))
            _set_tipo_produto_por_id(produto_dict.get("tipo_produto_id"))
            et_unidade.delete(0, tk.END)
            et_unidade.insert(0, FormatUtils.safe_string(str(produto_dict.get("unidade", "UN"))))
            et_preco_custo.delete(0, tk.END)
            et_preco_custo.insert(0, FormatUtils.format_money(produto_dict.get("preco_custo", 0)))
            et_preco_venda.delete(0, tk.END)
            et_preco_venda.insert(0, FormatUtils.format_money(produto_dict.get("preco_venda", 0)))
            et_estoque.delete(0, tk.END)
            et_estoque.insert(0, FormatUtils.format_quantidade(produto_dict.get("estoque", 0)))
            et_estoque_min.delete(0, tk.END)
            et_estoque_min.insert(0, FormatUtils.format_quantidade(produto_dict.get("estoque_minimo", 0)))
            # Foto
            foto_b64 = produto_dict.get("foto_base64")
            self._produto_foto_base64_temp = foto_b64
            _load_foto_into_label(foto_b64)

        def salvar_produto():
            """Salva o produto (igual ao Android saveProduto)."""
            descricao = et_descricao.get().strip()
            if not descricao:
                self.show_error("Por favor, preencha o campo Descricao antes de salvar.")
                return

            # Verificar permissao
            if selected_id[0]:
                if not Session.has_permission(PermissionConstants.PRODUTOS_EDITAR):
                    self.show_error("Voce nao tem permissao para editar produtos.")
                    return
            else:
                if not Session.has_permission(PermissionConstants.PRODUTOS_CRIAR):
                    self.show_error("Voce nao tem permissao para criar produtos.")
                    return

            codigo = et_codigo.get().strip()
            codigo_barras = et_codigo_barras.get().strip()
            unidade = et_unidade.get().strip() or "UN"
            preco_custo = FormatUtils.parse_money(et_preco_custo.get())
            preco_venda = FormatUtils.parse_money(et_preco_venda.get())
            estoque_val = et_estoque.get().strip().replace(",", ".")
            estoque_min_val = et_estoque_min.get().strip().replace(",", ".")
            try:
                estoque = float(estoque_val) if estoque_val else 0.0
            except ValueError:
                estoque = 0.0
            try:
                estoque_min = float(estoque_min_val) if estoque_min_val else 0.0
            except ValueError:
                estoque_min = 0.0
            tipo_produto_id = _get_tipo_produto_id_selecionado()
            foto_b64 = self._produto_foto_base64_temp

            def do_save():
                db = DatabaseHelper.get_instance()
                codigo_final = codigo
                if not codigo_final or codigo_final == "...":
                    rows = db.execute_query(
                        "SELECT MAX(CAST(codigo AS UNSIGNED)) AS max_codigo FROM produtos WHERE codigo REGEXP '^[0-9]+$'")
                    max_c = 0
                    if rows and rows[0].get("max_codigo"):
                        max_c = int(rows[0]["max_codigo"])
                    prox = max_c + 1
                    codigo_final = f"{prox:03d}" if prox < 1000 else str(prox)

                if selected_id[0]:
                    # UPDATE (igual ao Android)
                    db.execute_update(
                        "UPDATE produtos SET codigo=%s, codigo_barras=%s, descricao=%s, unidade=%s, "
                        "tipo_produto_id=%s, preco_custo=%s, preco_venda=%s, estoque=%s, "
                        "estoque_minimo=%s, foto_base64=%s WHERE id=%s",
                        (codigo_final, codigo_barras if codigo_barras else None, descricao, unidade,
                         tipo_produto_id if tipo_produto_id > 0 else None,
                         preco_custo, preco_venda, estoque, estoque_min, foto_b64,
                         selected_id[0])
                    )
                else:
                    # INSERT (igual ao Android)
                    db.execute_update(
                        "INSERT INTO produtos (codigo, codigo_barras, descricao, unidade, tipo_produto_id, "
                        "preco_custo, preco_venda, estoque, estoque_minimo, foto_base64, ativo) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,1)",
                        (codigo_final, codigo_barras if codigo_barras else None, descricao, unidade,
                         tipo_produto_id if tipo_produto_id > 0 else None,
                         preco_custo, preco_venda, estoque, estoque_min, foto_b64)
                    )
            def on_saved(_):
                limpar_form()
                carregar_lista()
                self.show_success("Produto salvo!")
            self.run_async(do_save, on_saved)

        def inativar_produto():
            """Inativa o produto selecionado (igual ao Android inativarProduto, NAO exclui)."""
            if not selected_id[0]:
                self.show_error("Selecione um produto para inativar.")
                return
            if not Session.has_permission(PermissionConstants.PRODUTOS_EXCLUIR):
                self.show_error("Voce nao tem permissao para inativar produtos.")
                return
            if not messagebox.askyesno("Inativar", "Deseja inativar este produto?\n\nO produto nao aparecera mais nas vendas, mas podera ser reativado depois."):
                return
            def do_inativar():
                db = DatabaseHelper.get_instance()
                db.execute_update("UPDATE produtos SET ativo = 0 WHERE id = %s", (selected_id[0],))
            def on_inativado(_):
                limpar_form()
                carregar_lista()
                self.show_success("Produto inativado!")
            self.run_async(do_inativar, on_inativado)

        def on_select(event):
            """Ao selecionar um item na lista, preenche o formulario."""
            sel = tree.selection()
            if sel:
                item_id = tree.item(sel[0])["values"][0]
                # Carregar dados completos do banco (incluindo foto_base64)
                def load():
                    db = DatabaseHelper.get_instance()
                    rows = db.execute_query(
                        "SELECT p.*, tp.descricao AS tipo_desc FROM produtos p "
                        "LEFT JOIN tipos_produto tp ON p.tipo_produto_id = tp.id "
                        "WHERE p.id = %s", (item_id,))
                    return rows[0] if rows else None
                def on_loaded(row):
                    if row:
                        preencher_form(row)
                self.run_async(load, on_loaded)

        def carregar_lista():
            """Carrega a lista de produtos (igual ao Android loadData)."""
            busca = et_busca.get().strip()
            def load():
                db = DatabaseHelper.get_instance()
                sql = ("SELECT p.id, p.descricao, p.codigo, p.preco_venda, p.estoque, "
                       "p.codigo_barras, tp.descricao AS tipo_desc, p.ativo "
                       "FROM produtos p LEFT JOIN tipos_produto tp ON p.tipo_produto_id = tp.id "
                       "WHERE p.ativo = 1")
                params = []
                if busca:
                    sql += " AND (p.descricao LIKE %s OR p.codigo LIKE %s OR p.codigo_barras LIKE %s)"
                    params = [f"%{busca}%", f"%{busca}%", f"%{busca}%"]
                sql += " ORDER BY p.descricao"
                return db.execute_query(sql, tuple(params) if params else None)
            def on_loaded(rows):
                # Preservar selecao
                sel = tree.selection()
                sel_id = None
                if sel:
                    try:
                        sel_id = tree.item(sel[0])["values"][0]
                    except Exception:
                        pass
                tree.delete(*tree.get_children())
                new_sel_iid = None
                for row in rows:
                    preco_fmt = FormatUtils.format_money(row.get("preco_venda", 0))
                    estoque_fmt = FormatUtils.format_quantidade(row.get("estoque", 0))
                    tipo_desc = FormatUtils.safe_string(str(row.get("tipo_desc", "") or ""))
                    cod_barras = FormatUtils.safe_string(str(row.get("codigo_barras", "") or ""))
                    ativo_txt = "Sim" if row.get("ativo", 1) else "Nao"
                    iid = tree.insert("", "end", values=(
                        row["id"], row.get("descricao", ""), row.get("codigo", ""),
                        preco_fmt, estoque_fmt, cod_barras, tipo_desc, ativo_txt
                    ))
                    if sel_id is not None and row["id"] == sel_id:
                        new_sel_iid = iid
                if new_sel_iid:
                    tree.selection_set(new_sel_iid)
                    tree.see(new_sel_iid)
            self.run_async(load, on_loaded)

        # ---- Conectar eventos ----
        btn_foto.config(command=_escolher_foto)
        btn_remover_foto.config(command=_remover_foto)
        btn_gerar_ean.config(command=_gerar_ean13_unico)
        btn_salvar.config(command=salvar_produto)
        btn_limpar.config(command=limpar_form)
        btn_inativar.config(command=inativar_produto)
        btn_novo.config(command=limpar_form)
        btn_buscar.config(command=carregar_lista)
        et_busca.bind("<Return>", lambda e: carregar_lista())
        tree.bind("<<TreeviewSelect>>", on_select)

        # ---- Carregar dados iniciais ----
        _carregar_tipos_produto()
        carregar_lista()
        _gerar_proximo_codigo()
        _load_foto_into_label(None)

        # Auto-refresh em tempo real (a cada 10 segundos)
        self._start_auto_refresh("cadastro_produto", carregar_lista, 10000)

