    def show_cadastro_tipo_produto(self):
        """Tela de Cadastro de Tipos de Produto (Categorias) - Alinhada com
        CadastroTipoProdutoActivity.java do Android.
        Campos: Descricao + Secao de Adicionais vinculados.
        Funcionalidades: Listar, Novo, Editar, Inativar, Vincular/Desvincular Adicionais.
        """
        if not Session.has_permission(PermissionConstants.TIPOS_PRODUTO_ACESSAR):
            self.show_error("Voce nao tem permissao para acessar Tipos de Produto.")
            return

        self.clear_container()

