        _neon.pack(fill="x", side="top")
        _neon.bind("<Configure>", lambda e: (
            _neon.delete("all"),
            _neon.create_line(0, 1, e.width, 1, fill=COR_PRIMARIA, width=1)))
        StyledButton(top, text="◀ Voltar", command=self.show_main_menu,
                     color=COR_FUNDO3, width=10).pack(side="left", padx=10, pady=5)
        tk.Label(top, text="Tipos de Produto (Categorias)", bg=COR_FUNDO2, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(side="left", padx=10)
        # Botoes Sair e Trocar de Usuario
        _btn_sair = StyledButton(top, text=f"{Icons.SAIR} Sair",
                     command=self._on_close,
                     color=COR_ERRO, width=8)
        _btn_sair.pack(side="right", padx=5, pady=5)
        add_tooltip(_btn_sair, "Fechar o PDV Pro (Alt+F4)")

        _btn_trocar = StyledButton(top, text=f"{Icons.TROCAR} Trocar",
                     command=self.do_logoff,
                     color=COR_BOTAO_LARANJA, width=10)
        _btn_trocar.pack(side="right", padx=5, pady=5)
        add_tooltip(_btn_trocar, "Trocar de usuario (Ctrl+L)")


        # --- Conteudo principal ---
        content = tk.Frame(self.main_container, bg=COR_FUNDO)
        content.pack(fill="both", expand=True, padx=10, pady=5)

        # === FORMULARIO ===
        form_card = CardFrame(content)
        form_card.pack(fill="x", pady=5)

        # Campo Descricao
        tk.Label(form_card, text="Descricao:", bg=COR_GLASS, fg=COR_TEXTO,
                 font=("Segoe UI", 10)).grid(row=0, column=0, sticky="w", padx=5, pady=3)
        et_descricao = StyledEntry(form_card, width=40)
        et_descricao.grid(row=0, column=1, sticky="w", padx=5, pady=3)

        # === SECAO DE ADICIONAIS VINCULADOS ===
        tk.Label(form_card, text="Adicionais vinculados:", bg=COR_CARD, fg="#00BCD4",
                 font=("Segoe UI", 10, "bold")).grid(row=1, column=0, columnspan=2,
                                                       sticky="w", padx=5, pady=(10, 3))

        # Frame para lista de adicionais vinculados
        adicionais_frame = tk.Frame(form_card, bg=COR_CARD)
        adicionais_frame.grid(row=2, column=0, columnspan=2, sticky="ew", padx=5, pady=3)

        # Combobox para selecionar adicional + botao Adicionar
        add_frame = tk.Frame(form_card, bg=COR_CARD)
        add_frame.grid(row=3, column=0, columnspan=2, sticky="ew", padx=5, pady=3)

        tk.Label(add_frame, text="Adicionar adicional:", bg=COR_CARD, fg=COR_TEXTO2,
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 5))
        combo_adicionais = ttk.Combobox(add_frame, width=35, state="readonly")
        combo_adicionais.pack(side="left", padx=5)
        btn_add_adicional = StyledButton(add_frame, text="+ Adicionar",
                                          color=COR_BOTAO_VERDE, width=12)
        btn_add_adicional.pack(side="left", padx=5)

        # === BOTOES DO FORMULARIO ===
        btn_form = tk.Frame(form_card, bg=COR_CARD)
        btn_form.grid(row=4, column=0, columnspan=2, pady=10)

        # --- Estado interno ---
        selected_id = [None]
        adicionais_selecionados = []  # lista de dicts {"id": int, "descricao": str, "preco": float}
        todos_adicionais_cache = []   # todos os adicionais ativos do banco

        def _carregar_todos_adicionais():
            """Carrega todos os adicionais ativos do banco para o combobox."""
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT id, descricao, preco FROM adicionais WHERE ativo = 1 ORDER BY descricao")
            def on_loaded(rows):
                todos_adicionais_cache.clear()
                for r in rows:
                    todos_adicionais_cache.append({
                        "id": r["id"],
                        "descricao": r["descricao"],
                        "preco": float(r.get("preco", 0) or 0)
                    })
                _atualizar_combo_adicionais()
            self.run_async(load, on_loaded)

        def _atualizar_combo_adicionais():
            """Atualiza o combobox de adicionais removendo os ja vinculados."""
            ids_vinculados = {a["id"] for a in adicionais_selecionados}
            disponiveis = [a for a in todos_adicionais_cache if a["id"] not in ids_vinculados]
            nomes = ["-- Selecione um adicional --"]
            for a in disponiveis:
                nome = a["descricao"]
                if a["preco"] > 0:
                    nome += f" (R$ {FormatUtils.format_money(a['preco'])})"
                nomes.append(nome)
            combo_adicionais["values"] = nomes
            combo_adicionais.current(0)

        def _atualizar_lista_adicionais_ui():
            """Atualiza a exibicao visual dos adicionais vinculados."""
            for w in adicionais_frame.winfo_children():
                w.destroy()

            if not adicionais_selecionados:
                tk.Label(adicionais_frame, text="Nenhum adicional vinculado",
                         bg=COR_CARD, fg=COR_TEXTO2,
                         font=("Segoe UI", 9)).pack(anchor="w", padx=5, pady=2)
                return

            for ad in list(adicionais_selecionados):
                row_f = tk.Frame(adicionais_frame, bg="#1a237e",
                                 highlightthickness=1, highlightbackground="#37474F")
                row_f.pack(fill="x", padx=2, pady=1)

                texto = ad["descricao"]
                if ad["preco"] > 0:
                    texto += f" - R$ {FormatUtils.format_money(ad['preco'])}"
                tk.Label(row_f, text=texto, bg="#1a237e", fg=COR_TEXTO,
                         font=("Segoe UI", 10)).pack(side="left", padx=8, pady=4)

                ad_id_ref = ad["id"]
                btn_rem = tk.Button(row_f, text="X", bg=COR_ERRO, fg=COR_TEXTO,
                                    font=("Segoe UI", 9, "bold"), relief="flat",
                                    cursor="hand2", padx=6, pady=1,
                                    command=lambda aid=ad_id_ref: _remover_adicional(aid))
                btn_rem.pack(side="right", padx=5, pady=2)

        def _adicionar_adicional():
            """Adiciona um adicional a lista de vinculados."""
            idx = combo_adicionais.current()
            if idx <= 0:
                self.show_error("Selecione um adicional para vincular.")
                return
            # Mapear indice do combo para o adicional correto (descontando os ja vinculados)
            ids_vinculados = {a["id"] for a in adicionais_selecionados}
            disponiveis = [a for a in todos_adicionais_cache if a["id"] not in ids_vinculados]
            if idx - 1 < len(disponiveis):
                ad = disponiveis[idx - 1]
                # Verificar duplicata
                if any(s["id"] == ad["id"] for s in adicionais_selecionados):
                    self.show_error("Este adicional ja foi adicionado.")
                    return
                adicionais_selecionados.append(dict(ad))
                _atualizar_lista_adicionais_ui()
                _atualizar_combo_adicionais()

        def _remover_adicional(ad_id):
            """Remove um adicional da lista de vinculados."""
            for i, a in enumerate(adicionais_selecionados):
                if a["id"] == ad_id:
                    adicionais_selecionados.pop(i)
                    break
            _atualizar_lista_adicionais_ui()
            _atualizar_combo_adicionais()

        btn_add_adicional.configure(command=_adicionar_adicional)

        def _carregar_adicionais_do_tipo(tipo_id):
            """Carrega os adicionais vinculados a um tipo de produto especifico."""
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT a.id, a.descricao, a.preco FROM tipo_produto_adicionais tpa "
                    "INNER JOIN adicionais a ON tpa.adicional_id = a.id "
                    "WHERE tpa.tipo_produto_id = %s AND a.ativo = 1 ORDER BY a.descricao",
                    (tipo_id,))
            def on_loaded(rows):
                adicionais_selecionados.clear()
                for r in rows:
                    adicionais_selecionados.append({
                        "id": r["id"],
                        "descricao": r["descricao"],
                        "preco": float(r.get("preco", 0) or 0)
                    })
                _atualizar_lista_adicionais_ui()
                _atualizar_combo_adicionais()
            self.run_async(load, on_loaded)

        def limpar_form():
            selected_id[0] = None
            et_descricao.delete(0, tk.END)
            adicionais_selecionados.clear()
            _atualizar_lista_adicionais_ui()
            _atualizar_combo_adicionais()

        def salvar():
            descricao = et_descricao.get().strip()
            if not descricao:
                self.show_error("Por favor, preencha o campo Descricao antes de salvar.")
                return
            ad_ids = [a["id"] for a in adicionais_selecionados]
            tipo_id_ref = selected_id[0]

            def do_save():
                db = DatabaseHelper.get_instance()
                if tipo_id_ref:
                    # UPDATE
                    db.execute_update(
                        "UPDATE tipos_produto SET descricao=%s WHERE id=%s",
                        (descricao, tipo_id_ref))
                    new_id = tipo_id_ref
                else:
                    # INSERT
                    new_id = db.execute_update(
                        "INSERT INTO tipos_produto (descricao, ativo) VALUES (%s, 1)",
                        (descricao,))
                # Atualizar adicionais vinculados: remove todos e reinsere
                db.execute_update(
                    "DELETE FROM tipo_produto_adicionais WHERE tipo_produto_id = %s",
                    (new_id,))
                for ad_id in ad_ids:
                    db.execute_update(
                        "INSERT INTO tipo_produto_adicionais (tipo_produto_id, adicional_id) VALUES (%s, %s)",
                        (new_id, ad_id))
                return new_id

            def on_saved(result):
                limpar_form()
                carregar_lista()
                self.show_success("Tipo de produto salvo com sucesso!")

            self.run_async(do_save, on_saved)

        def inativar():
            if not selected_id[0]:
                self.show_error("Selecione um tipo de produto para inativar.")
                return
            if not messagebox.askyesno("Confirmar", "Deseja inativar este tipo de produto?"):
                return
            ref_id = selected_id[0]

            def do_inativar():
                db = DatabaseHelper.get_instance()
                db.execute_update(
                    "UPDATE tipos_produto SET ativo = 0 WHERE id = %s", (ref_id,))

            def on_inativado(_):
                limpar_form()
                carregar_lista()
                self.show_success("Tipo de produto inativado com sucesso!")

            self.run_async(do_inativar, on_inativado)

        StyledButton(btn_form, text="✔ Salvar", command=salvar,
                     color=COR_BOTAO_VERDE, width=10).pack(side="left", padx=5)
        StyledButton(btn_form, text="✚ Novo", command=limpar_form,
                     color=COR_BOTAO_AZUL, width=10).pack(side="left", padx=5)
        StyledButton(btn_form, text="Inativar", command=inativar,
                     color=COR_ERRO, width=10).pack(side="left", padx=5)

        # === LISTA (TREEVIEW) ===
        list_frame = tk.Frame(content, bg=COR_FUNDO)
        list_frame.pack(fill="both", expand=True, pady=5)

        cols = ("c0", "c1", "c2")
        tree = ttk.Treeview(list_frame, columns=cols, show="headings", height=15)
        tree.heading("c0", text="ID")
        tree.column("c0", width=50, anchor="center")
        tree.heading("c1", text="Descricao")
        tree.column("c1", width=250)
        tree.heading("c2", text="Adicionais")
        tree.column("c2", width=400)

        vsb = ttk.Scrollbar(list_frame, orient="vertical", command=tree.yview)
        tree.configure(yscrollcommand=vsb.set)
        tree.pack(side="left", fill="both", expand=True)
        vsb.pack(side="right", fill="y")

        def on_select(event):
            sel = tree.selection()
            if sel:
                values = tree.item(sel[0])["values"]
                selected_id[0] = values[0]
                et_descricao.delete(0, tk.END)
                et_descricao.insert(0, str(values[1]) if values[1] else "")
                # Carregar adicionais vinculados a este tipo
                _carregar_adicionais_do_tipo(values[0])

        tree.bind("<<TreeviewSelect>>", on_select)

        def _carregar_adicionais_str(conn_db, tipo_id):
            """Retorna string descritiva dos adicionais vinculados a um tipo."""
            rows = conn_db.execute_query(
                "SELECT a.descricao, a.preco FROM tipo_produto_adicionais tpa "
                "INNER JOIN adicionais a ON tpa.adicional_id = a.id "
                "WHERE tpa.tipo_produto_id = %s AND a.ativo = 1 ORDER BY a.descricao",
                (tipo_id,))
            if not rows:
                return "Sem adicionais"
            partes = []
            for r in rows:
                nome = r["descricao"]
                preco = float(r.get("preco", 0) or 0)
                if preco > 0:
                    nome += f" (R$ {FormatUtils.format_money(preco)})"
                partes.append(nome)
            return "Adicionais: " + ", ".join(partes)

        def carregar_lista():
            def load():
                db = DatabaseHelper.get_instance()
                tipos = db.execute_query(
                    "SELECT id, descricao FROM tipos_produto WHERE ativo = 1 ORDER BY id DESC")
                result = []
                for t in tipos:
                    ad_str = _carregar_adicionais_str(db, t["id"])
                    result.append((t["id"], t["descricao"], ad_str))
                return result

            def on_loaded(rows):
                # Preservar selecao
                sel = tree.selection()
                sel_id = None
                if sel:
                    try:
                        sel_id = tree.item(sel[0])["values"][0]
                    except Exception:
                        pass
                tree.delete(*tree.get_children())
                new_sel_iid = None
                for r in rows:
                    iid = tree.insert("", "end", values=r)
                    if sel_id is not None and r[0] == sel_id:
                        new_sel_iid = iid
                if new_sel_iid:
                    tree.selection_set(new_sel_iid)
                    tree.see(new_sel_iid)

            self.run_async(load, on_loaded)

        # --- Inicializacao ---
        _carregar_todos_adicionais()
        carregar_lista()

        # Auto-refresh em tempo real (a cada 10 segundos)
        self._start_auto_refresh("cadastro_tipo_produto", carregar_lista, 10000)

