    def carregar_comandas(self):
        def load():
            db = DatabaseHelper.get_instance()
            return db.execute_query(
                "SELECT id, numero, status, total_itens, data_abertura FROM comandas ORDER BY id DESC"
            )
        def on_loaded(rows):
            # Preservar selecao
            sel = self.tree_comandas.selection()
            sel_id = None
            if sel:
                try:
                    sel_id = self.tree_comandas.item(sel[0])["values"][0]
                except Exception:
                    pass
            self.tree_comandas.delete(*self.tree_comandas.get_children())
            new_sel_iid = None
            for r in rows:
                iid = self.tree_comandas.insert("", "end", values=(
                    r["id"], r["numero"], r["status"],
                    f"R$ {FormatUtils.format_money(r['total_itens'])}",
                    FormatUtils.format_date(r["data_abertura"])
                ))
                if sel_id is not None and r["id"] == sel_id:
                    new_sel_iid = iid
            if new_sel_iid:
                self.tree_comandas.selection_set(new_sel_iid)
                self.tree_comandas.see(new_sel_iid)
        self.run_async(load, on_loaded)

    def _solicitar_intervalo_criacao_lote(self, titulo, item_plural):
        quantidade = simpledialog.askinteger(
            titulo,
            f"Quantas {item_plural} deseja adicionar?",
            minvalue=1,
            parent=self.root
        )
        if quantidade is None:
            return None, None, None

        numero_inicial = simpledialog.askinteger(
            titulo,
            f"A partir de qual numero deseja adicionar as {item_plural}?",
            minvalue=1,
            parent=self.root
        )
        if numero_inicial is None:
            return None, None, None

        numero_final = numero_inicial + quantidade - 1
        confirmar = messagebox.askyesno(
            titulo,
            f"Deseja adicionar {quantidade} {item_plural} do numero {numero_inicial} ao numero {numero_final}?",
            parent=self.root
        )
        if not confirmar:
            return None, None, None

        return quantidade, numero_inicial, numero_final

    def _formatar_resumo_numeros(self, numeros, limite=15):
        if not numeros:
            return ""
        if len(numeros) <= limite:
            return ", ".join(str(n) for n in numeros)
        return ", ".join(str(n) for n in numeros[:limite]) + f" ... (+{len(numeros) - limite})"

    def _executar_assistente_criacao_lote(self, titulo, item_singular, item_plural,
                                          criar_callback, refresh_callback=None):
        quantidade, numero_inicial, numero_final = self._solicitar_intervalo_criacao_lote(
            titulo, item_plural
        )
        if quantidade is None:
            return

        def criar_lote():
            return criar_callback(numero_inicial, numero_final)

        def on_criado(resultado):
            resultado = resultado or {}
            criados = resultado.get("criados", []) or []
            ignorados = resultado.get("ignorados", []) or []

            if refresh_callback:
                try:
                    refresh_callback()
                except Exception:
                    pass

            total_criados = len(criados)
            linhas = [
                f"{total_criados} {item_plural if total_criados != 1 else item_singular} criada(s) com sucesso."
            ]
            if criados:
                if len(criados) == 1:
                    linhas.append(f"Numero criado: {criados[0]}")
                else:
                    linhas.append(f"Intervalo criado: {criados[0]} ao {criados[-1]}")
            if ignorados:
                linhas.append(
                    "Ja existentes/ignorados: " + self._formatar_resumo_numeros(ignorados)
                )
            self.show_success("\n".join(linhas))

        self.run_async(criar_lote, on_criado)

    def assistente_criar_comandas(self, *_):
        def criar_comandas(numero_inicial, numero_final):
            db = DatabaseHelper.get_instance()
            criados = []
            for numero in range(numero_inicial, numero_final + 1):
                db.execute_update(
                    "INSERT INTO comandas (numero, status) VALUES (%s, 'aberta')",
                    (numero,)
                )
                criados.append(numero)
            return {"criados": criados, "ignorados": []}

        self._executar_assistente_criacao_lote(
            "Assistente de Criacao de Comandas",
            "comanda",
            "comandas",
            criar_comandas,
            refresh_callback=self.carregar_comandas
        )

    def assistente_criar_mesas(self, *_):
        def criar_mesas(numero_inicial, numero_final):
            db = DatabaseHelper.get_instance()
            existentes = db.execute_query(
                "SELECT numero FROM mesas WHERE numero BETWEEN %s AND %s",
                (numero_inicial, numero_final)
            )
            numeros_existentes = {int(r["numero"]) for r in (existentes or [])}
            criados = []
            ignorados = []
            for numero in range(numero_inicial, numero_final + 1):
                if numero in numeros_existentes:
                    ignorados.append(numero)
                    continue
                db.execute_update(
                    "INSERT INTO mesas (numero, ativa) VALUES (%s, 1)",
                    (numero,)
                )
                criados.append(numero)
            return {"criados": criados, "ignorados": ignorados}

        self._executar_assistente_criacao_lote(
            "Assistente de Criacao de Mesas",
            "mesa",
            "mesas",
            criar_mesas,
            refresh_callback=lambda: (
                self.carregar_mesas() if hasattr(self, "mesas_frame") and self.mesas_frame.winfo_exists()
                else self.show_cadastro_mesa()
            )
        )

    def assistente_criar_armarios(self, *_):
        def criar_armarios(numero_inicial, numero_final):
            db = DatabaseHelper.get_instance()
            existentes = db.execute_query(
                "SELECT numero FROM armarios_sauna WHERE numero BETWEEN %s AND %s",
                (numero_inicial, numero_final)
            )
            numeros_existentes = {int(r["numero"]) for r in (existentes or [])}
            criados = []
            ignorados = []
            for numero in range(numero_inicial, numero_final + 1):
                if numero in numeros_existentes:
                    ignorados.append(numero)
                    continue
                db.execute_update(
                    "INSERT INTO armarios_sauna (numero, descricao, localizacao, ativo) VALUES (%s, NULL, NULL, 1)",
                    (numero,)
                )
                criados.append(numero)
            return {"criados": criados, "ignorados": ignorados}

        self._executar_assistente_criacao_lote(
            "Assistente de Criacao de Armarios",
            "armario",
            "armarios",
            criar_armarios,
            refresh_callback=lambda: (
                self.carregar_armarios() if hasattr(self, "armarios_frame") and self.armarios_frame.winfo_exists()
                else self.show_cadastro_armario_sauna()
            )
        )

    def nova_comanda(self):
        num = simpledialog.askinteger("Nova Comanda", "Numero da comanda:",
                                       minvalue=1, parent=self.root)
        if num is None:
            return
        def criar():
            db = DatabaseHelper.get_instance()
            return db.execute_update(
                "INSERT INTO comandas (numero, status) VALUES (%s, 'aberta')", (num,)
            )
        def on_criada(cid):
            self.show_success(f"Comanda #{num} criada!")
            self.carregar_comandas()
        self.run_async(criar, on_criada)

    def abrir_comanda_detalhe(self):
        sel = self.tree_comandas.selection()
        if not sel:
            self.show_error("Por favor, selecione uma comanda na lista.\n\nClique sobre a comanda desejada e tente novamente.")
            return
        comanda_id = self.tree_comandas.item(sel[0])["values"][0]
        self._show_comanda_detalhe(comanda_id)

    def _show_comanda_detalhe(self, comanda_id):
        dialog = tk.Toplevel(self.root)
        dialog.title(f"Comanda #{comanda_id}")
        dialog.geometry("700x500")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        tk.Label(dialog, text=f"Comanda #{comanda_id}", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 14, "bold")).pack(pady=10)

        # Itens da comanda
        cols = ("id", "produto", "qtd", "preco", "total")
        tree = ttk.Treeview(dialog, columns=cols, show="headings", height=12)
        tree.heading("id", text="ID")
        tree.heading("produto", text="Produto")
        tree.heading("qtd", text="Qtd")
        tree.heading("preco", text="Preco")
        tree.heading("total", text="Total")
        tree.column("id", width=50, anchor="center")
        tree.column("produto", width=250)
        tree.column("qtd", width=60, anchor="center")
        tree.column("preco", width=80, anchor="e")
        tree.column("total", width=80, anchor="e")
        tree.pack(fill="both", expand=True, padx=15, pady=5)

        lbl_total = tk.Label(dialog, text="Total: R$ 0,00", bg=COR_FUNDO, fg=COR_SUCESSO,
                              font=("Segoe UI", 14, "bold"))
        lbl_total.pack(pady=5)

        def carregar_itens():
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT id, descricao_produto, quantidade, preco_unitario, total "
                    "FROM itens_comanda WHERE comanda_id = %s ORDER BY id", (comanda_id,)
                )
            def on_loaded(rows):
                tree.delete(*tree.get_children())
                total = 0
                for r in rows:
                    tree.insert("", "end", values=(
                        r["id"], r["descricao_produto"], r["quantidade"],
                        FormatUtils.format_money(r["preco_unitario"]),
                        FormatUtils.format_money(r["total"])
                    ))
                    total += float(r["total"])
                lbl_total.config(text=f"Total: R$ {FormatUtils.format_money(total)}")
            self.run_async(load, on_loaded)

        def add_item():
            self._selecionar_registro(
                "produtos", "Adicionar Produto",
                "SELECT id, descricao, preco_venda FROM produtos WHERE ativo = 1 ORDER BY descricao",
                ["ID", "Descricao", "Preco"],
                lambda row: self._add_item_comanda(comanda_id, row, carregar_itens) if row else None
            )

        def remover_item():
            sel_item = tree.selection()
            if not sel_item:
                messagebox.showwarning(
                    "Selecione um Item",
                    "Nenhum item foi selecionado.\n\n"
                    "Clique sobre o item desejado na lista\n"
                    "e tente novamente.",
                    parent=dialog)
                return
            item_id = tree.item(sel_item[0])["values"][0]
            def do_remove():
                db = DatabaseHelper.get_instance()
                db.execute_update("DELETE FROM itens_comanda WHERE id = %s", (item_id,))
                self._atualizar_total_comanda(comanda_id)
            self.run_async(do_remove, lambda _: carregar_itens())

        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=15, pady=10)
        StyledButton(btn_frame, text="Adicionar Item", command=add_item,
                     color=COR_BOTAO_VERDE, width=15).pack(side="left", padx=5)
        StyledButton(btn_frame, text="Remover Item", command=remover_item,
                     color=COR_ERRO, width=15).pack(side="left", padx=5)

        carregar_itens()

    def _add_item_comanda(self, comanda_id, row, refresh_callback):
        produto_id = row[0]
        descricao = row[1]
        preco = float(row[2])
        qtd = simpledialog.askfloat("Quantidade", f"Quantidade de {descricao}:",
                                     initialvalue=1, minvalue=0.001, parent=self.root)
        if not qtd:
            return
        total = qtd * preco
        def salvar():
            db = DatabaseHelper.get_instance()
            db.execute_update(
                "INSERT INTO itens_comanda (comanda_id, produto_id, descricao_produto, "
                "quantidade, preco_unitario, total) VALUES (%s,%s,%s,%s,%s,%s)",
                (comanda_id, produto_id, descricao, qtd, preco, total)
            )
            self._atualizar_total_comanda(comanda_id)
        self.run_async(salvar, lambda _: refresh_callback())

    def _atualizar_total_comanda(self, comanda_id):
        db = DatabaseHelper.get_instance()
        total = db.execute_scalar(
            "SELECT COALESCE(SUM(total),0) FROM itens_comanda WHERE comanda_id = %s",
            (comanda_id,)
        )
        db.execute_update(
            "UPDATE comandas SET total_itens = %s WHERE id = %s", (total, comanda_id)
        )

    def fechar_comanda(self):
        sel = self.tree_comandas.selection()
        if not sel:
            self.show_error("Por favor, selecione uma comanda na lista.\n\nClique sobre a comanda desejada e tente novamente.")
            return
        comanda_id = self.tree_comandas.item(sel[0])["values"][0]
        status = self.tree_comandas.item(sel[0])["values"][2]
        if status != "aberta":
            self.show_error("Esta comanda ja esta fechada.")
            return
        if not messagebox.askyesno("Confirmar", f"Fechar comanda #{comanda_id}?"):
            return
        def fechar():
            db = DatabaseHelper.get_instance()
            db.execute_update(
                "UPDATE comandas SET status = 'fechada', data_fechamento = NOW() WHERE id = %s",
                (comanda_id,)
            )
        self.run_async(fechar, lambda _: self.carregar_comandas())

