        def _on_historico_mousewheel(event):
            try:
                if not self.tree_historico.winfo_exists():
                    return "break"
                if getattr(event, "num", None) == 4:
                    self.tree_historico.yview_scroll(-3, "units")
                elif getattr(event, "num", None) == 5:
                    self.tree_historico.yview_scroll(3, "units")
                else:
                    delta = getattr(event, "delta", 0)
                    if delta:
                        self.tree_historico.yview_scroll(int(-1 * (delta / 120)), "units")
                return "break"
            except Exception:
                return "break"

        def _bind_historico_mousewheel(event=None):
            try:
                if self.tree_historico.winfo_exists():
                    self.tree_historico.bind_all("<MouseWheel>", _on_historico_mousewheel)
                    self.tree_historico.bind_all("<Button-4>", _on_historico_mousewheel)
                    self.tree_historico.bind_all("<Button-5>", _on_historico_mousewheel)
            except Exception:
                pass

        def _unbind_historico_mousewheel(event=None):
            try:
                if hasattr(self, "tree_historico") and self.tree_historico.winfo_exists():
                    self.tree_historico.unbind_all("<MouseWheel>")
                    self.tree_historico.unbind_all("<Button-4>")
                    self.tree_historico.unbind_all("<Button-5>")
            except Exception:
                pass

        self.tree_historico.bind("<Enter>", _bind_historico_mousewheel)
        self.tree_historico.bind("<Leave>", _unbind_historico_mousewheel)

