    def carregar_mesas(self):
        """Carrega mesas usando ocupacao_mesa para status (alinhado com Android)."""
        def load():
            db = DatabaseHelper.get_instance()
            return db.execute_query(
                "SELECT m.id, m.numero, m.descricao, m.capacidade, "
                "COALESCE(om.garcom_id, 0) as garcom_id, "
                "COALESCE(g.nome, '') as garcom_nome, "
                "COALESCE(om.qtd_pessoas, 0) as qtd_pessoas, "
                "COALESCE(om.status, 'livre') as status, "
                "COALESCE(om.id, 0) as ocupacao_id, "
                "COALESCE(om.reservado_por_usuario_id, 0) as reservado_por_usuario_id, "
                "COALESCE(om.reservado_por_usuario_nome, '') as reservado_por_usuario_nome "
                "FROM mesas m "
                "LEFT JOIN ocupacao_mesa om ON m.id = om.mesa_id AND om.status != 'encerrada' "
                "LEFT JOIN garcons g ON om.garcom_id = g.id "
                "WHERE m.ativa = 1 "
                "ORDER BY m.numero ASC"
            )

        def on_loaded(mesas):
            try:
                for w in self.mesas_frame.winfo_children():
                    w.destroy()
            except Exception:
                return

            # Calcular totais por ocupacao
            for mesa in mesas:
                ocupacao_id = int(mesa.get("ocupacao_id", 0))
                if ocupacao_id > 0:
                    try:
                        db = DatabaseHelper.get_instance()
                        res = db.execute_query(
                            "SELECT COUNT(*) as qtd, COALESCE(SUM(total + COALESCE(adicionais_total, 0)), 0) as total_val "
                            "FROM itens_mesa WHERE ocupacao_id = %s", (ocupacao_id,))
                        if res:
                            mesa["qtd_itens"] = int(res[0].get("qtd", 0))
                            mesa["total"] = float(res[0].get("total_val", 0))
                        else:
                            mesa["qtd_itens"] = 0
                            mesa["total"] = 0.0
                    except Exception:
                        mesa["qtd_itens"] = 0
                        mesa["total"] = 0.0
                else:
                    mesa["qtd_itens"] = 0
                    mesa["total"] = 0.0

            livres = sum(1 for m in mesas if m.get("status") == "livre")
            ocupadas = sum(1 for m in mesas if m.get("status") == "ocupada")
            reservadas = sum(1 for m in mesas if m.get("status") == "reservada")
            prontas = sum(1 for m in mesas if m.get("status") == "pronta")
            try:
                self._lbl_mesas_info.config(
                    text=f"{Icons.PIN} {len(mesas)} mesas  |  "
                         f"{Icons.ONLINE} {livres} livres  |  "
                         f"{Icons.OFFLINE} {ocupadas} ocupadas"
                         + (f"  |  {reservadas} reservadas" if reservadas else "")
                         + (f"  |  {prontas} prontas" if prontas else ""))
            except Exception:
                pass

            col = 0
            row = 0
            max_cols = 7
            for mesa in mesas:
                status = mesa.get("status", "livre")
                total = float(mesa.get("total", 0))
                qtd_itens = int(mesa.get("qtd_itens", 0))
                garcom_nome = mesa.get("garcom_nome", "")
                qtd_pessoas = int(mesa.get("qtd_pessoas", 0))
                reservado_por = mesa.get("reservado_por_usuario_nome", "")

                # Cores por status (alinhado com Android MesaAdapter)
                if status == "livre":
                    bg_cor = "#0a1f0a"
                    borda_cor = COR_BOTAO_VERDE
                    status_cor = COR_BOTAO_VERDE
                elif status == "ocupada":
                    bg_cor = "#1f0a0a"
                    borda_cor = COR_ERRO
                    status_cor = COR_ERRO
                elif status == "reservada":
                    bg_cor = "#1a1500"
                    borda_cor = COR_ALERTA
                    status_cor = COR_ALERTA
                elif status == "pronta":
                    bg_cor = "#0a0a2f"
                    borda_cor = "#42A5F5"
                    status_cor = "#42A5F5"
                else:
                    bg_cor = "#1a1500"
                    borda_cor = COR_ALERTA
                    status_cor = COR_ALERTA

                # Card visual da mesa
                card = tk.Frame(self.mesas_frame, bg=bg_cor,
                                highlightthickness=2,
                                highlightbackground=borda_cor,
                                cursor="hand2")
                card.grid(row=row, column=col, padx=7, pady=7,
                          sticky="nsew")

                # Numero da mesa grande
                tk.Label(card, text=str(mesa["numero"]),
                         bg=bg_cor, fg=borda_cor,
                         font=("Segoe UI", 22, "bold"),
                         width=5, height=2).pack(pady=(6, 0))

                # Status label (alinhado com Android)
                status_text = status.upper()
                if status == "pronta":
                    status_text = "PRONTA P/ COBRANCA"
                tk.Label(card, text=status_text,
                         bg=bg_cor, fg=status_cor,
                         font=("Segoe UI", 8, "bold")).pack()

                # Reservado por (alinhado com Android)
                if status == "reservada" and reservado_por:
                    tk.Label(card, text=f"Reservado: {reservado_por}",
                             bg=bg_cor, fg=COR_ALERTA,
                             font=("Segoe UI", 7)).pack()

                # Garcom
                if garcom_nome:
                    tk.Label(card, text=f"Garcom: {garcom_nome}",
                             bg=bg_cor, fg=COR_TEXTO2,
                             font=("Segoe UI", 7)).pack()

                # Pessoas
                if qtd_pessoas > 0:
                    tk.Label(card, text=f"{qtd_pessoas} pessoa(s)",
                             bg=bg_cor, fg=COR_TEXTO2,
                             font=("Segoe UI", 7)).pack()

                # Total e itens
                if total > 0:
                    tk.Label(card,
                             text=f"R$ {FormatUtils.format_money(total)}",
                             bg=bg_cor, fg=COR_ALERTA,
                             font=("Consolas", 9, "bold")).pack(pady=(0, 2))
                if qtd_itens > 0:
                    tk.Label(card, text=f"{qtd_itens} item(ns)",
                             bg=bg_cor, fg=COR_TEXTO2,
                             font=("Segoe UI", 7)).pack(pady=(0, 4))
                elif total <= 0:
                    tk.Label(card, text="", bg=bg_cor,
                             font=("Segoe UI", 9)).pack(pady=(0, 4))

                # Hover effect
                def _hover_on(e, c=card, b=borda_cor):
                    c.configure(bg=COR_CARD_HOVER)
                    for w in c.winfo_children():
                        try:
                            w.configure(bg=COR_CARD_HOVER)
                        except Exception:
                            pass

                def _hover_off(e, c=card, bg=bg_cor):
                    c.configure(bg=bg)
                    for w in c.winfo_children():
                        try:
                            w.configure(bg=bg)
                        except Exception:
                            pass

                card.bind("<Enter>", _hover_on)
                card.bind("<Leave>", _hover_off)
                for child in card.winfo_children():
                    child.bind("<Enter>", _hover_on)
                    child.bind("<Leave>", _hover_off)
                    child.bind("<Button-1>",
                               lambda e, m=mesa: self._acao_mesa(m))

                card.bind("<Button-1>", lambda e, m=mesa: self._acao_mesa(m))

                tooltip_text = f"Mesa {mesa['numero']} — {status.upper()}"
                if garcom_nome:
                    tooltip_text += f" — Garcom: {garcom_nome}"
                if total > 0:
                    tooltip_text += f" — R$ {FormatUtils.format_money(total)}"
                if status == "reservada" and reservado_por:
                    tooltip_text += f" — Reservado por: {reservado_por}"
                add_tooltip(card, tooltip_text)

                col += 1
                if col >= max_cols:
                    col = 0
                    row += 1

            for c in range(max_cols):
                self.mesas_frame.columnconfigure(c, weight=1)

        self.run_async(load, on_loaded)

    def nova_mesa(self):
        num = simpledialog.askinteger(
            "Nova Mesa", "Numero da nova mesa:", minvalue=1, parent=self.root)
        if not num:
            return
        def criar():
            db = DatabaseHelper.get_instance()
            # Verificar se ja existe
            existe = db.execute_query(
                "SELECT id FROM mesas WHERE numero = %s", (num,))
            if existe:
                return False
            db.execute_update(
                "INSERT INTO mesas (numero, ativa) VALUES (%s, 1)", (num,))
            return True
        def on_criado(ok):
            if ok:
                ToastManager.success(f"Mesa {num} criada com sucesso!")
                AuditLogger.log("MESA_CRIADA", f"Mesa #{num}",
                                usuario=Session.user_login)
                self.carregar_mesas()
            else:
                ToastManager.warning(f"Mesa {num} ja existe!")
        self.run_async(criar, on_criado)

    def _acao_mesa(self, mesa):
        """Acao ao clicar em uma mesa - abre detalhe (alinhado com Android)."""
        status = mesa.get("status", "livre")
        mesa_id = mesa["id"]
        ocupacao_id = int(mesa.get("ocupacao_id", 0))
        self._show_mesa_detalhe(mesa_id, mesa["numero"], ocupacao_id, status, mesa)

    def _show_mesa_detalhe(self, mesa_id, numero, ocupacao_id, status_atual, mesa_data):
        """Dialog de detalhe da mesa - alinhado com Android GerenciarMesasActivity."""
        dialog = tk.Toplevel(self.root)
        dialog.title(f"Mesa {numero}")
        dialog.geometry("700x600")
        dialog.configure(bg=COR_FUNDO)
        dialog.transient(self.root)
        dialog.grab_set()

        # Dados de reserva
        reservado_por_id = int(mesa_data.get("reservado_por_usuario_id", 0))
        reservado_por_nome = mesa_data.get("reservado_por_usuario_nome", "")
        mesa_reservada = status_atual == "reservada" and reservado_por_id > 0
        usuario_eh_dono = (reservado_por_id == Session.user_id) if hasattr(Session, 'user_id') else True
        pode_editar = not mesa_reservada or usuario_eh_dono

        # Header
        tk.Label(dialog, text=f"Mesa {numero}", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=5)

        # Info de reserva/pronta (alinhado com Android)
        if mesa_reservada:
            info_frame = tk.Frame(dialog, bg="#1a1500")
            info_frame.pack(fill="x", padx=15, pady=3)
            tk.Label(info_frame, text="MESA RESERVADA" + (" (BLOQUEADA)" if not pode_editar else ""),
                     bg="#1a1500", fg=COR_ALERTA if pode_editar else COR_ERRO,
                     font=("Segoe UI", 10, "bold")).pack(pady=2)
            tk.Label(info_frame, text=f"Reservado por: {reservado_por_nome}",
                     bg="#1a1500", fg=COR_TEXTO2, font=("Segoe UI", 9)).pack(pady=2)
        elif status_atual == "pronta":
            info_frame = tk.Frame(dialog, bg="#0a0a2f")
            info_frame.pack(fill="x", padx=15, pady=3)
            tk.Label(info_frame, text="PRONTA PARA COBRANCA",
                     bg="#0a0a2f", fg="#42A5F5",
                     font=("Segoe UI", 10, "bold")).pack(pady=2)
            tk.Label(info_frame, text="Esta mesa esta pronta para ser cobrada e fechada.",
                     bg="#0a0a2f", fg="#90CAF9", font=("Segoe UI", 9)).pack(pady=2)

        # Garcom selector (alinhado com Android)
        garcom_frame = tk.Frame(dialog, bg=COR_FUNDO)
        garcom_frame.pack(fill="x", padx=15, pady=3)
        tk.Label(garcom_frame, text="Garcom:", bg=COR_FUNDO, fg=COR_TEXTO2,
                 font=("Segoe UI", 9)).pack(side="left")
        self._mesa_garcom_var = tk.StringVar(value="-- Selecione Garcom --")
        self._mesa_garcons_list = []
        garcom_combo = ttk.Combobox(garcom_frame, textvariable=self._mesa_garcom_var,
                                    state="readonly", width=30)
        garcom_combo.pack(side="left", padx=5)

        # Qtd pessoas
        tk.Label(garcom_frame, text="Pessoas:", bg=COR_FUNDO, fg=COR_TEXTO2,
                 font=("Segoe UI", 9)).pack(side="left", padx=(15, 0))
        self._mesa_pessoas_var = tk.StringVar(value=str(int(mesa_data.get("qtd_pessoas", 0))))
        pessoas_entry = tk.Entry(garcom_frame, textvariable=self._mesa_pessoas_var,
                                  width=5, bg=COR_FUNDO2, fg=COR_TEXTO, insertbackground=COR_TEXTO)
        pessoas_entry.pack(side="left", padx=5)

        # Carregar garcons
        def load_garcons():
            db = DatabaseHelper.get_instance()
            return db.execute_query("SELECT id, nome FROM garcons WHERE ativo = 1 ORDER BY nome")
        def on_garcons(garcons):
            self._mesa_garcons_list = garcons or []
            nomes = ["-- Selecione Garcom --"] + [g["nome"] for g in self._mesa_garcons_list]
            garcom_combo["values"] = nomes
            garcom_id_atual = int(mesa_data.get("garcom_id", 0))
            if garcom_id_atual > 0:
                for i, g in enumerate(self._mesa_garcons_list):
                    if g["id"] == garcom_id_atual:
                        garcom_combo.current(i + 1)
                        break
        self.run_async(load_garcons, on_garcons)

        # Tabela de itens
        cols = ("id", "produto", "qtd", "preco", "total", "adicionais")
        tree = ttk.Treeview(dialog, columns=cols, show="headings", height=10)
        for c, h, w in [("id","ID",50),("produto","Produto",220),("qtd","Qtd",60),
                         ("preco","Preco",80),("total","Total",80),("adicionais","Adicionais",120)]:
            tree.heading(c, text=h)
            tree.column(c, width=w, anchor="center" if c in ("id","qtd") else "e" if c in ("preco","total") else "w")
        tree.pack(fill="both", expand=True, padx=15, pady=5)

        lbl_total = tk.Label(dialog, text="Total: R$ 0,00", bg=COR_FUNDO, fg=COR_SUCESSO,
                              font=("Segoe UI", 14, "bold"))
        lbl_total.pack(pady=5)

        # Estado local da ocupacao
        _ocupacao = {"id": ocupacao_id}

        def carregar():
            """Carrega itens da mesa via ocupacao_id (alinhado com Android)."""
            def load():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]
                if oc_id > 0:
                    return db.execute_query(
                        "SELECT id, descricao_produto, quantidade, preco_unitario, total, "
                        "adicionais_descricao, COALESCE(adicionais_total, 0) as adicionais_total "
                        "FROM itens_mesa WHERE ocupacao_id = %s ORDER BY id ASC", (oc_id,)
                    )
                return []
            def on_loaded(rows):
                tree.delete(*tree.get_children())
                total = 0
                for r in rows:
                    ad_desc = r.get("adicionais_descricao", "") or ""
                    ad_total = float(r.get("adicionais_total", 0))
                    tree.insert("", "end", values=(
                        r["id"], r["descricao_produto"], r["quantidade"],
                        FormatUtils.format_money(r["preco_unitario"]),
                        FormatUtils.format_money(r["total"]),
                        ad_desc if ad_desc else "-"
                    ))
                    total += float(r["total"]) + ad_total
                lbl_total.config(text=f"Total: R$ {FormatUtils.format_money(total)}")
            self.run_async(load, on_loaded)

        def add_item():
            if not pode_editar:
                ToastManager.warning("Mesa reservada por outro usuario. Nao e possivel editar.")
                return
            self._selecionar_registro(
                "produtos", "Adicionar Produto",
                "SELECT id, descricao, preco_venda FROM produtos WHERE ativo = 1 ORDER BY descricao",
                ["ID", "Descricao", "Preco"],
                lambda row: self._add_item_mesa(_ocupacao, mesa_id, row, carregar, dialog) if row else None
            )

        def remover_item():
            if not pode_editar:
                ToastManager.warning("Mesa reservada por outro usuario. Nao e possivel editar.")
                return
            sel = tree.selection()
            if not sel:
                ToastManager.warning("Selecione um item para remover.")
                return
            item_id = tree.item(sel[0])["values"][0]
            if messagebox.askyesno("Confirmar", "Remover este item?", parent=dialog):
                def do_remover():
                    db = DatabaseHelper.get_instance()
                    try:
                        db.execute_update("DELETE FROM itens_mesa_adicionais WHERE item_mesa_id = %s", (item_id,))
                    except Exception:
                        pass
                    db.execute_update("DELETE FROM itens_mesa WHERE id = %s", (item_id,))
                self.run_async(do_remover, lambda _: carregar())

        def salvar_mesa():
            """Salva garcom, pessoas e status via ocupacao_mesa (alinhado com Android)."""
            garcom_idx = garcom_combo.current()
            garcom_id = 0
            if garcom_idx > 0 and garcom_idx <= len(self._mesa_garcons_list):
                garcom_id = self._mesa_garcons_list[garcom_idx - 1]["id"]
            try:
                qtd_pessoas = int(self._mesa_pessoas_var.get())
            except (ValueError, TypeError):
                qtd_pessoas = 0

            def do_salvar():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]

                # Contar itens para determinar status
                itens_count = 0
                if oc_id > 0:
                    res = db.execute_query(
                        "SELECT COUNT(*) as qtd FROM itens_mesa WHERE ocupacao_id = %s", (oc_id,))
                    if res:
                        itens_count = int(res[0].get("qtd", 0))

                # Determinar novo status (alinhado com Android)
                if itens_count > 0:
                    # Preservar status 'pronta' se ja estiver marcada
                    if oc_id > 0:
                        res_status = db.execute_query(
                            "SELECT status FROM ocupacao_mesa WHERE id = %s", (oc_id,))
                        if res_status and res_status[0].get("status") == "pronta":
                            novo_status = "pronta"
                        else:
                            novo_status = "ocupada"
                    else:
                        novo_status = "ocupada"
                else:
                    # Preservar reserva se existir
                    if oc_id > 0:
                        res_status = db.execute_query(
                            "SELECT status, reservado_por_usuario_id FROM ocupacao_mesa WHERE id = %s", (oc_id,))
                        if res_status:
                            st = res_status[0].get("status", "livre")
                            rpid = int(res_status[0].get("reservado_por_usuario_id", 0))
                            if st == "reservada" and rpid > 0:
                                novo_status = "reservada"
                            else:
                                novo_status = "livre"
                        else:
                            novo_status = "livre"
                    else:
                        novo_status = "livre"

                if oc_id == 0:
                    # Criar nova ocupacao se necessario
                    if itens_count > 0 or garcom_id > 0 or qtd_pessoas > 0:
                        db.execute_update(
                            "INSERT INTO ocupacao_mesa (mesa_id, garcom_id, qtd_pessoas, status, data_abertura) "
                            "VALUES (%s, %s, %s, %s, NOW())",
                            (mesa_id, garcom_id, qtd_pessoas, novo_status))
                        res = db.execute_query("SELECT LAST_INSERT_ID() as lid")
                        if res:
                            _ocupacao["id"] = int(res[0].get("lid", 0))
                else:
                    # Atualizar ocupacao existente
                    db.execute_update(
                        "UPDATE ocupacao_mesa SET garcom_id=%s, qtd_pessoas=%s, status=%s WHERE id=%s",
                        (garcom_id, qtd_pessoas, novo_status, oc_id))

            def on_salvo(_):
                ToastManager.success("Mesa salva com sucesso!")
                dialog.destroy()
                self.carregar_mesas()
            self.run_async(do_salvar, on_salvo)

        def limpar_mesa():
            """Limpa mesa encerrando ocupacao (alinhado com Android)."""
            if messagebox.askyesno("Confirmar", f"Limpar mesa {numero}? Todos os itens serao removidos.", parent=dialog):
                def do_limpar():
                    db = DatabaseHelper.get_instance()
                    oc_id = _ocupacao["id"]
                    if oc_id > 0:
                        # Remover adicionais dos itens
                        try:
                            db.execute_update(
                                "DELETE FROM itens_mesa_adicionais WHERE item_mesa_id IN "
                                "(SELECT id FROM itens_mesa WHERE ocupacao_id = %s)", (oc_id,))
                        except Exception:
                            pass
                        # Remover itens
                        db.execute_update("DELETE FROM itens_mesa WHERE ocupacao_id = %s", (oc_id,))
                        # Encerrar ocupacao e limpar reserva
                        db.execute_update(
                            "UPDATE ocupacao_mesa SET status = 'encerrada', data_fechamento = NOW(), "
                            "reservado_por_usuario_id = 0, reservado_por_usuario_nome = NULL WHERE id = %s",
                            (oc_id,))
                def on_limpa(_):
                    ToastManager.success(f"Mesa {numero} limpa com sucesso!")
                    dialog.destroy()
                    self.carregar_mesas()
                self.run_async(do_limpar, on_limpa)

        def reservar_mesa():
            """Reserva a mesa para o usuario logado (alinhado com Android)."""
            def do_reservar():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]
                user_id = Session.user_id if hasattr(Session, 'user_id') else 0
                user_nome = Session.user_nome if hasattr(Session, 'user_nome') else ""
                if oc_id == 0:
                    db.execute_update(
                        "INSERT INTO ocupacao_mesa (mesa_id, garcom_id, qtd_pessoas, status, data_abertura, "
                        "reservado_por_usuario_id, reservado_por_usuario_nome) VALUES (%s, 0, 0, 'reservada', NOW(), %s, %s)",
                        (mesa_id, user_id, user_nome))
                else:
                    db.execute_update(
                        "UPDATE ocupacao_mesa SET status = 'reservada', reservado_por_usuario_id = %s, "
                        "reservado_por_usuario_nome = %s WHERE id = %s",
                        (user_id, user_nome, oc_id))
            def on_reservada(_):
                ToastManager.success(f"Mesa {numero} reservada!")
                dialog.destroy()
                self.carregar_mesas()
            self.run_async(do_reservar, on_reservada)

        def cancelar_reserva():
            """Cancela reserva da mesa (alinhado com Android)."""
            def do_cancelar():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]
                if oc_id > 0:
                    res = db.execute_query(
                        "SELECT COUNT(*) as qtd FROM itens_mesa WHERE ocupacao_id = %s", (oc_id,))
                    qtd_itens = int(res[0].get("qtd", 0)) if res else 0
                    if qtd_itens > 0:
                        db.execute_update(
                            "UPDATE ocupacao_mesa SET status = 'ocupada', reservado_por_usuario_id = 0, "
                            "reservado_por_usuario_nome = NULL WHERE id = %s", (oc_id,))
                    else:
                        db.execute_update(
                            "UPDATE ocupacao_mesa SET status = 'encerrada', data_fechamento = NOW(), "
                            "reservado_por_usuario_id = 0, reservado_por_usuario_nome = NULL WHERE id = %s",
                            (oc_id,))
            def on_cancelada(_):
                ToastManager.success("Reserva cancelada!")
                dialog.destroy()
                self.carregar_mesas()
            self.run_async(do_cancelar, on_cancelada)

        def marcar_pronta():
            """Marca mesa como pronta para cobranca (alinhado com Android)."""
            def do_marcar():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]
                if oc_id > 0:
                    db.execute_update(
                        "UPDATE ocupacao_mesa SET status = 'pronta' WHERE id = %s", (oc_id,))
            def on_marcada(_):
                ToastManager.success(f"Mesa {numero} marcada como pronta para cobranca!")
                dialog.destroy()
                self.carregar_mesas()
            self.run_async(do_marcar, on_marcada)

        def cancelar_pronta():
            """Cancela status pronta (alinhado com Android)."""
            def do_cancelar():
                db = DatabaseHelper.get_instance()
                oc_id = _ocupacao["id"]
                if oc_id > 0:
                    db.execute_update(
                        "UPDATE ocupacao_mesa SET status = 'ocupada' WHERE id = %s", (oc_id,))
            def on_cancelada(_):
                ToastManager.success("Status pronta cancelado. Mesa voltou para ocupada.")
                dialog.destroy()
                self.carregar_mesas()
            self.run_async(do_cancelar, on_cancelada)

        # Botoes de acao (alinhado com Android)
        btn_frame = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame.pack(fill="x", padx=15, pady=5)

        if pode_editar:
            StyledButton(btn_frame, text=f"{Icons.ADD} Add Item", command=add_item,
                         color=COR_BOTAO_VERDE, width=12).pack(side="left", padx=3)
            StyledButton(btn_frame, text=f"{Icons.REMOVE} Remover", command=remover_item,
                         color=COR_ERRO, width=12).pack(side="left", padx=3)

        btn_frame2 = tk.Frame(dialog, bg=COR_FUNDO)
        btn_frame2.pack(fill="x", padx=15, pady=5)

        if pode_editar:
            StyledButton(btn_frame2, text=f"{Icons.SAVE} Salvar", command=salvar_mesa,
                         color=COR_BOTAO_VERDE, width=12).pack(side="left", padx=3)

        # Botao Reservar/Cancelar Reserva
        if status_atual == "livre":
            StyledButton(btn_frame2, text="Reservar Mesa", command=reservar_mesa,
                         color=COR_ALERTA, width=14).pack(side="left", padx=3)
        elif mesa_reservada and usuario_eh_dono:
            StyledButton(btn_frame2, text="Cancelar Reserva", command=cancelar_reserva,
                         color=COR_ALERTA, width=14).pack(side="left", padx=3)

        # Botao Pronta p/ Cobranca
        if status_atual in ("ocupada", "reservada") and pode_editar:
            StyledButton(btn_frame2, text="Pronta p/ Cobranca", command=marcar_pronta,
                         color="#42A5F5", width=16).pack(side="left", padx=3)
        elif status_atual == "pronta":
            StyledButton(btn_frame2, text="Cancelar Pronta", command=cancelar_pronta,
                         color="#42A5F5", width=14).pack(side="left", padx=3)

        # Botao Limpar Mesa
        if status_atual != "livre" and pode_editar:
            StyledButton(btn_frame2, text="Limpar Mesa", command=limpar_mesa,
                         color=COR_ERRO, width=12).pack(side="right", padx=3)

        carregar()

    def _add_item_mesa(self, ocupacao_ref, mesa_id, row, refresh, dialog):
        """Adiciona item a mesa via ocupacao_id (alinhado com Android)."""
        produto_id, descricao, preco = row[0], row[1], float(row[2])
        qtd = simpledialog.askfloat("Quantidade", f"Qtd de {descricao}:",
                                     initialvalue=1, minvalue=0.001, parent=dialog)
        if not qtd:
            return
        def salvar():
            db = DatabaseHelper.get_instance()
            oc_id = ocupacao_ref["id"]
            # Se nao tem ocupacao, criar uma
            if oc_id == 0:
                db.execute_update(
                    "INSERT INTO ocupacao_mesa (mesa_id, garcom_id, qtd_pessoas, status, data_abertura) "
                    "VALUES (%s, 0, 0, 'ocupada', NOW())",
                    (mesa_id,))
                res = db.execute_query("SELECT LAST_INSERT_ID() as lid")
                if res:
                    oc_id = int(res[0].get("lid", 0))
                    ocupacao_ref["id"] = oc_id
            # Inserir item vinculado a ocupacao (sem mesa_id, alinhado com Android)
            db.execute_update(
                "INSERT INTO itens_mesa (ocupacao_id, produto_id, descricao_produto, "
                "quantidade, preco_unitario, total) VALUES (%s,%s,%s,%s,%s,%s)",
                (oc_id, produto_id, descricao, qtd, preco, qtd * preco)
            )
            # Atualizar status da ocupacao para ocupada se estava livre
            if oc_id > 0:
                res_st = db.execute_query(
                    "SELECT status FROM ocupacao_mesa WHERE id = %s", (oc_id,))
                if res_st and res_st[0].get("status") in ("livre", None):
                    db.execute_update(
                        "UPDATE ocupacao_mesa SET status = 'ocupada' WHERE id = %s", (oc_id,))
        self.run_async(salvar, lambda _: refresh())

    # ========================================================================
    # GERENCIAR ARMARIOS (SAUNA) - Compativel com APK
    # Usa as mesmas tabelas do APK: armarios_sauna, uso_armario_sauna,
    # itens_armario_sauna, itens_armario_sauna_adicionais
    # ========================================================================
    def _iniciar_auto_refresh_armarios(self):
        """Inicia o auto-refresh periodico da tela de armarios (a cada 5 segundos).
        Agora usa o sistema centralizado de auto-refresh."""
        self._parar_auto_refresh_armarios()  # Garante que nao haja duplicidade
        # Usar sistema centralizado
        self._start_auto_refresh("gerenciar_armarios", self.carregar_armarios, 5000)
        # Manter compatibilidade com o _armario_auto_refresh_id
        self._armario_auto_refresh_id = True  # Flag para indicar que esta ativo

    def _parar_auto_refresh_armarios(self):
        """Para o auto-refresh periodico da tela de armarios."""
        if self._armario_auto_refresh_id is not None:
            # O sistema centralizado cuida do cancelamento via _stop_all_auto_refresh
            # Apenas resetar a flag de compatibilidade
            self._armario_auto_refresh_id = None

