        # Atualizar scrollregion quando o frame interno muda de tamanho
        def _on_armarios_frame_configure(event):
            self._armarios_canvas.configure(scrollregion=self._armarios_canvas.bbox("all"))
        self.armarios_frame.bind("<Configure>", _on_armarios_frame_configure)

        # Ajustar largura do frame interno para acompanhar a largura do canvas
        def _on_armarios_canvas_configure(event):
            self._armarios_canvas.itemconfig(self._armarios_canvas_window, width=event.width)
        self._armarios_canvas.bind("<Configure>", _on_armarios_canvas_configure)

        # Scroll com roda do mouse (Windows/Mac e Linux)
        def _on_armarios_mousewheel(event):
            try:
                if not self._armarios_canvas.winfo_exists():
                    return
                bbox = self._armarios_canvas.bbox("all")
                if bbox is None:
                    return
                canvas_height = self._armarios_canvas.winfo_height()
                content_height = bbox[3] - bbox[1]
                if content_height <= canvas_height:
                    return
                if event.num == 4:
                    self._armarios_canvas.yview_scroll(-3, "units")
                elif event.num == 5:
                    self._armarios_canvas.yview_scroll(3, "units")
                else:
                    self._armarios_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
            except Exception:
                pass

        def _bind_armarios_mousewheel(event):
            self._armarios_canvas.bind_all("<MouseWheel>", _on_armarios_mousewheel)
            self._armarios_canvas.bind_all("<Button-4>", _on_armarios_mousewheel)
            self._armarios_canvas.bind_all("<Button-5>", _on_armarios_mousewheel)

        def _unbind_armarios_mousewheel(event):
            self._armarios_canvas.unbind_all("<MouseWheel>")
            self._armarios_canvas.unbind_all("<Button-4>")
            self._armarios_canvas.unbind_all("<Button-5>")

        self._armarios_canvas.bind("<Enter>", _bind_armarios_mousewheel)
        self._armarios_canvas.bind("<Leave>", _unbind_armarios_mousewheel)

