    def _ir_para_armario(self):
        """Busca o armario pelo numero digitado e abre a acao correspondente."""
        try:
            texto = self._entry_busca_armario.get().strip()
            if not texto:
                messagebox.showwarning(
                    "Numero do Armario",
                    "Por favor, digite o numero do armario no campo de busca.\n\n"
                    "Digite apenas o numero (ex: 1, 2, 3...) e pressione Enter.",
                    parent=self.root)
                return
            try:
                numero = int(texto)
            except ValueError:
                messagebox.showwarning(
                    "Numero Invalido",
                    "O valor digitado nao e um numero valido.\n\n"
                    "Digite apenas numeros inteiros (ex: 1, 2, 3...).\n"
                    "Nao use letras, espacos ou simbolos.",
                    parent=self.root)
                self._entry_busca_armario.delete(0, tk.END)
                self._entry_busca_armario.focus_set()
                return

            def buscar():
                db = DatabaseHelper.get_instance()
                armario = db.execute_query(
                    "SELECT a.id, a.numero, a.descricao, a.localizacao, "
                    "u.id as uso_id, u.cliente_nome, u.observacao, u.status as uso_status, "
                    "u.data_entrada, u.data_saida, "
                    "COALESCE(("
                    "  SELECT SUM(COALESCE(i.total,0) + COALESCE(i.adicionais_total,0)) "
                    "  FROM itens_armario_sauna i WHERE i.uso_armario_id = u.id"
                    "), 0) as total_consumo "
                    "FROM armarios_sauna a "
                    "LEFT JOIN uso_armario_sauna u ON u.armario_id = a.id "
                    "  AND u.status IN ('ocupado','manutencao') "
                    "WHERE a.ativo = 1 AND a.numero = %s "
                    "ORDER BY a.numero LIMIT 1",
                    (numero,)
                )
                return armario

            def on_found(armario):
                self._entry_busca_armario.delete(0, tk.END)
                if not armario:
                    messagebox.showwarning(
                        "Armario Nao Encontrado",
                        f"O armario numero {numero} nao foi encontrado no sistema.\n\n"
                        f"VERIFIQUE:\n"
                        f"1. O numero digitado esta correto?\n"
                        f"2. O armario esta cadastrado no sistema?\n"
                        f"3. O armario esta ativo?",
                        parent=self.root)
                    self._entry_busca_armario.focus_set()
                    return
                arm = armario[0]
                uso_status = arm.get("uso_status") or ""
                if uso_status == "ocupado":
                    status = "ocupado"
                elif uso_status == "manutencao":
                    status = "manutencao"
                else:
                    status = "livre"
                self._acao_armario(arm, status)

            self.run_async(buscar, on_found)
        except Exception as e:
            self.show_error(str(e))

    def _atualizar_visual_filtro(self, filtro_ativo):
        """Atualiza o visual dos botoes de filtro, destacando o ativo."""
        try:
            if not hasattr(self, '_filtro_buttons'):
                return
            for key, (btn, cor) in self._filtro_buttons.items():
                if key == filtro_ativo:
                    btn.configure(bg=cor, fg=COR_TEXTO, highlightbackground=cor)
                else:
                    btn.configure(bg=COR_FUNDO3, fg=cor, highlightbackground=COR_FUNDO3)
        except Exception:
            pass

    def _aplicar_filtro_armarios(self, filtro):
        """Aplica o filtro selecionado e re-renderiza os armarios."""
        self._armario_filtro_atual = filtro
        self._atualizar_visual_filtro(filtro)
        self._renderizar_armarios_filtrados()

    def _renderizar_armarios_filtrados(self):
        """Renderiza os armarios no grid aplicando o filtro atual."""
        try:
            if not hasattr(self, 'armarios_frame') or not self.armarios_frame.winfo_exists():
                return
        except Exception:
            return

        for w in self.armarios_frame.winfo_children():
            w.destroy()

        armarios = getattr(self, '_armarios_dados_cache', [])
        if not armarios:
            tk.Label(self.armarios_frame,
                     text="Nenhum armario cadastrado.\nCadastre armarios pelo app APK ou clique em 'Novo Armario'.",
                     bg=COR_FUNDO, fg=COR_TEXTO2, font=("Segoe UI", 12),
                     justify="center").pack(pady=40)
            return

        filtro = getattr(self, '_armario_filtro_atual', 'todos')

        col = 0
        row = 0
        exibidos = 0

        for arm in armarios:
            uso_status = arm.get("uso_status") or ""
            if uso_status == "ocupado":
                status = "ocupado"
            elif uso_status == "manutencao":
                status = "manutencao"
            else:
                status = "livre"

            # Aplicar filtro
            if filtro != "todos" and status != filtro:
                continue

            if status == "livre":
                cor = COR_BOTAO_VERDE
            elif status == "manutencao":
                cor = COR_ALERTA
            else:
                cor = "#9C27B0"

            total = float(arm.get("total_consumo", 0))
            desc = arm.get("descricao") or ""
            loc = arm.get("localizacao") or ""
            text = f"Armario {arm['numero']}\n{status.upper()}"
            if loc:
                loc_short = loc[:18] + ".." if len(loc) > 18 else loc
                text += f"\n{loc_short}"
            elif desc:
                desc_short = desc[:18] + ".." if len(desc) > 18 else desc
                text += f"\n{desc_short}"
            if status == "ocupado":
                text += f"\nR$ {FormatUtils.format_money(total)}"
                cliente = arm.get("cliente_nome") or ""
                if cliente:
                    cli_short = cliente[:15] + ".." if len(cliente) > 15 else cliente
                    text += f"\n{cli_short}"
                if arm.get("data_entrada"):
                    abertura_str = FormatUtils.format_date(arm["data_entrada"])
                    text += f"\n{abertura_str}"
            elif status == "manutencao":
                obs = arm.get("observacao") or ""
                if obs:
                    obs_short = obs[:18] + ".." if len(obs) > 18 else obs
                    text += f"\n{obs_short}"

            btn = tk.Button(self.armarios_frame, text=text, bg=cor, fg=COR_TEXTO,
                           font=("Segoe UI", 10, "bold"), width=14, height=6,
                           relief="flat", cursor="hand2",
                           command=lambda a=arm, s=status: self._acao_armario(a, s))
            btn.grid(row=row, column=col, padx=8, pady=8)

            # Tooltip rico com todos os dados do armario
            RichTooltipArmario(btn, arm, status)

            exibidos += 1
            col += 1
            if col >= 4:
                col = 0
                row += 1

        if exibidos == 0:
            filtro_nome = {"todos": "Todos", "ocupado": "Ocupados", "livre": "Livres", "manutencao": "Manutencao"}.get(filtro, filtro)
            tk.Label(self.armarios_frame,
                     text=f"Nenhum armario com status '{filtro_nome}'.",
                     bg=COR_FUNDO, fg=COR_TEXTO2, font=("Segoe UI", 12),
                     justify="center").pack(pady=40)

        # Atualizar label de contagem do filtro
        try:
            filtro_nome = {"todos": "Todos", "ocupado": "Ocupados", "livre": "Livres", "manutencao": "Manutencao"}.get(filtro, filtro)
            self._filtro_count_label.config(
                text=f"Exibindo: {exibidos} armario(s) [{filtro_nome}]")
        except Exception:
            pass

    def carregar_armarios(self):
        """Carrega armarios diretamente da tabela armarios_sauna (mesma do APK).
        O status e derivado de uso_armario_sauna (como o APK faz).
        Tambem carrega itens de cada armario ocupado para exibir no tooltip."""
        def load():
            db = DatabaseHelper.get_instance()
            armarios = db.execute_query(
                "SELECT a.id, a.numero, a.descricao, a.localizacao, "
                "u.id as uso_id, u.cliente_nome, u.observacao, u.status as uso_status, "
                "u.data_entrada, u.data_saida, "
                "COALESCE(("
                "  SELECT SUM(COALESCE(i.total,0) + COALESCE(i.adicionais_total,0)) "
                "  FROM itens_armario_sauna i WHERE i.uso_armario_id = u.id"
                "), 0) as total_consumo "
                "FROM armarios_sauna a "
                "LEFT JOIN uso_armario_sauna u ON u.armario_id = a.id "
                "  AND u.status IN ('ocupado','manutencao') "
                "WHERE a.ativo = 1 "
                "ORDER BY a.numero"
            )
            # Carregar itens de cada armario ocupado para tooltip
            for arm in (armarios or []):
                uso_id = arm.get("uso_id") or 0
                uso_status = arm.get("uso_status") or ""
                if uso_status == "ocupado" and uso_id > 0:
                    try:
                        itens = db.execute_query(
                            "SELECT descricao_produto, quantidade, preco_unitario, total, "
                            "adicionais_descricao, adicionais_total "
                            "FROM itens_armario_sauna WHERE uso_armario_id = %s ORDER BY id",
                            (uso_id,)
                        )
                        arm["_itens_tooltip"] = itens or []
                    except Exception:
                        arm["_itens_tooltip"] = []
                else:
                    arm["_itens_tooltip"] = []
            return armarios

        def on_loaded(armarios):
            try:
                if not hasattr(self, 'armarios_frame') or not self.armarios_frame.winfo_exists():
                    return
            except Exception:
                return

            # Guardar dados no cache
            self._armarios_dados_cache = armarios or []

            # Calcular contagens totais (independente do filtro)
            livres = 0
            ocupados = 0
            manutencao_count = 0
            for arm in (armarios or []):
                uso_status = arm.get("uso_status") or ""
                if uso_status == "ocupado":
                    ocupados += 1
                elif uso_status == "manutencao":
                    manutencao_count += 1
                else:
                    livres += 1

            # Atualizar resumo e indicador grande
            try:
                self.lbl_resumo_armarios.config(
                    text=f"Livres: {livres} | Ocupados: {ocupados} | Manutencao: {manutencao_count} | Total: {len(armarios or [])}"
                )
            except Exception:
                pass
            try:
                self.lbl_livres_grande.config(text=f"LIVRES: {livres}")
            except Exception:
                pass

            # Atualizar contagens nos botoes de filtro
            try:
                contagens = {"todos": len(armarios or []), "ocupado": ocupados,
                             "livre": livres, "manutencao": manutencao_count}
                for key, (btn, cor) in self._filtro_buttons.items():
                    nome = {"todos": "Todos", "ocupado": "Ocupados", "livre": "Livres", "manutencao": "Manutencao"}[key]
                    btn.config(text=f"  {nome} ({contagens[key]})  ")
            except Exception:
                pass

            # Renderizar com filtro atual
            self._renderizar_armarios_filtrados()

        self.run_async(load, on_loaded)

    def novo_armario(self):
        """Cria novo armario na tabela armarios_sauna (mesma do APK)."""
        num = simpledialog.askinteger("Novo Armario", "Numero:", minvalue=1, parent=self.root)
        if not num:
            return
        desc = simpledialog.askstring("Novo Armario", "Descricao (opcional):",
                                       parent=self.root) or ""
        loc = simpledialog.askstring("Novo Armario", "Localizacao (opcional, ex: Ala A, Andar 1):",
                                      parent=self.root) or ""
        def criar():
            db = DatabaseHelper.get_instance()
            existente = db.execute_query(
                "SELECT id FROM armarios_sauna WHERE numero = %s AND ativo = 1", (num,)
            )
            if existente:
                raise Exception(f"Ja existe um armario ativo com o numero {num}.")
            db.execute_update(
                "INSERT INTO armarios_sauna (numero, descricao, localizacao, ativo) VALUES (%s, %s, %s, 1)",
                (num, desc or None, loc or None)
            )
        self.run_async(criar, lambda _: self.carregar_armarios())

    def _acao_armario(self, arm, status):
        """Acao ao clicar em um armario. Exibe no painel direito em vez de popup."""
        arm_id = arm["id"]
        numero = arm["numero"]
        uso_id = arm.get("uso_id") or 0

        if status == "livre":
            # Exibir opcoes de Entregar Chave / Manutencao no painel direito
            self._limpar_painel_direito_armarios()
            panel = self._armario_right_panel

            tk.Label(panel, text=f"Armario {numero}", bg=COR_FUNDO, fg=COR_PRIMARIA,
                     font=("Segoe UI", 18, "bold")).pack(pady=(20, 5))
            tk.Label(panel, text="LIVRE", bg=COR_FUNDO, fg=COR_BOTAO_VERDE,
                     font=("Segoe UI", 14, "bold")).pack(pady=(0, 10))

            sep = tk.Frame(panel, bg="#37474F", height=1)
            sep.pack(fill="x", padx=20, pady=5)

            tk.Label(panel, text="O que deseja fazer?", bg=COR_FUNDO, fg=COR_TEXTO,
                     font=("Segoe UI", 12)).pack(pady=10)

            # Campo para nome do cliente
            cli_frame = tk.Frame(panel, bg=COR_FUNDO)
            cli_frame.pack(fill="x", padx=30, pady=5)
            tk.Label(cli_frame, text="Cliente (opcional):", bg=COR_FUNDO, fg=COR_TEXTO,
                     font=("Segoe UI", 10)).pack(anchor="w")
            et_cliente = StyledEntry(cli_frame)
            et_cliente.pack(fill="x", pady=(2, 0))
            et_cliente.focus_set()

            btn_frame = tk.Frame(panel, bg=COR_FUNDO)
            btn_frame.pack(fill="x", padx=30, pady=20)

            def entregar_chave():
                cliente = et_cliente.get().strip()
                def abrir():
                    db = DatabaseHelper.get_instance()
                    db.execute_update(
                        "INSERT INTO uso_armario_sauna (armario_id, cliente_nome, status, data_entrada) "
                        "VALUES (%s, %s, 'ocupado', NOW())",
                        (arm_id, cliente or None)
                    )
                def on_aberto(_):
                    self._mostrar_placeholder_direito()
                    self.carregar_armarios()
                self.run_async(abrir, on_aberto)

            def colocar_manutencao():
                """Coloca armario em manutencao.
                SEMPRE exige senha de administrador, independente de permissoes."""
                obs = et_cliente.get().strip()
                def executar_manutencao():
                    def manutencao():
                        db = DatabaseHelper.get_instance()
                        db.execute_update(
                            "INSERT INTO uso_armario_sauna (armario_id, observacao, status, data_entrada) "
                            "VALUES (%s, %s, 'manutencao', NOW())",
                            (arm_id, obs or "Em manutencao")
                        )
                    def on_manutencao(_):
                        self._mostrar_placeholder_direito()
                        self.carregar_armarios()
                    self.run_async(manutencao, on_manutencao)
                self._solicitar_senha_admin_obrigatoria(executar_manutencao, parent_window=self.root)

            StyledButton(btn_frame, text="Entregar Chave", command=entregar_chave,
                         color=COR_BOTAO_VERDE, width=18).pack(side="left", padx=5, pady=5)
            StyledButton(btn_frame, text="Manutencao", command=colocar_manutencao,
                         color=COR_ALERTA, width=18).pack(side="right", padx=5, pady=5)

            # Botao fechar painel
            StyledButton(panel, text="Fechar", command=self._mostrar_placeholder_direito,
                         color="#2a3a5c", width=10).pack(side="bottom", pady=10)

        elif status == "manutencao":
            # Exibir opcao de liberar manutencao no painel direito
            self._limpar_painel_direito_armarios()
            panel = self._armario_right_panel

            tk.Label(panel, text=f"Armario {numero}", bg=COR_FUNDO, fg=COR_PRIMARIA,
                     font=("Segoe UI", 18, "bold")).pack(pady=(20, 5))
            tk.Label(panel, text="MANUTENCAO", bg=COR_FUNDO, fg=COR_ALERTA,
                     font=("Segoe UI", 14, "bold")).pack(pady=(0, 10))

            obs = arm.get("observacao") or ""
            if obs:
                tk.Label(panel, text=f"Obs: {obs}", bg=COR_FUNDO, fg=COR_TEXTO2,
                         font=("Segoe UI", 10)).pack(pady=5)

            sep = tk.Frame(panel, bg="#37474F", height=1)
            sep.pack(fill="x", padx=20, pady=10)

            def liberar():
                if messagebox.askyesno("Manutencao",
                        f"Liberar armario {numero} da manutencao?",
                        parent=self.root):
                    def lib():
                        db = DatabaseHelper.get_instance()
                        db.execute_update(
                            "UPDATE uso_armario_sauna SET status = 'encerrado', data_saida = NOW() "
                            "WHERE armario_id = %s AND status = 'manutencao'",
                            (arm_id,)
                        )
                    def on_lib(_):
                        self._mostrar_placeholder_direito()
                        self.carregar_armarios()
                    self.run_async(lib, on_lib)

            StyledButton(panel, text="Liberar da Manutencao", command=liberar,
                         color=COR_BOTAO_VERDE, width=22).pack(pady=20)

            StyledButton(panel, text="Fechar", command=self._mostrar_placeholder_direito,
                         color="#2a3a5c", width=10).pack(side="bottom", pady=10)

        else:
            # Armario ocupado - mostrar detalhe no painel direito
            self._show_armario_detalhe(arm_id, numero, uso_id,
                                       arm.get("data_entrada"),
                                       arm.get("descricao"),
                                       arm.get("localizacao"),
                                       arm.get("cliente_nome"),
                                       arm.get("observacao"))

    def _show_armario_detalhe(self, arm_id, numero, uso_id, data_entrada=None,
                               descricao=None, localizacao=None, cliente_nome=None,
                               observacao=None):
        """Mostra detalhe do armario ocupado no painel direito (sem popup)."""
        self._limpar_painel_direito_armarios()
        panel = self._armario_right_panel

        titulo_text = f"Armario {numero}"
        if descricao:
            titulo_text += f" - {descricao}"
        if localizacao:
            titulo_text += f" ({localizacao})"
        tk.Label(panel, text=titulo_text, bg=COR_FUNDO, fg="#9C27B0",
                 font=("Segoe UI", 16, "bold")).pack(side="top", pady=(10, 2))

        # Info do uso
        info_text = ""
        if cliente_nome:
            info_text += f"Cliente: {cliente_nome}"
        if data_entrada:
            abertura_str = FormatUtils.format_date(data_entrada)
            if info_text:
                info_text += f"  |  "
            info_text += f"Entrada: {abertura_str}"
        if observacao:
            if info_text:
                info_text += f"  |  "
            info_text += f"Obs: {observacao}"
        if info_text:
            tk.Label(panel, text=info_text, bg=COR_FUNDO, fg=COR_ALERTA,
                     font=("Segoe UI", 10), wraplength=450).pack(side="top", pady=(0, 5))

        # Frame de botoes fixo na parte inferior (pack side=bottom primeiro)
        btn_frame = tk.Frame(panel, bg=COR_FUNDO)
        btn_frame.pack(side="bottom", fill="x", padx=10, pady=(5, 10))

        # Label de total fixo acima dos botoes
        lbl_total = tk.Label(panel, text="Total: R$ 0,00", bg=COR_FUNDO, fg=COR_SUCESSO,
                              font=("Segoe UI", 14, "bold"))
        lbl_total.pack(side="bottom", pady=(5, 5))

        # Frame da treeview com scrollbar (expande no espaco restante)
        tree_frame = tk.Frame(panel, bg=COR_FUNDO)
        tree_frame.pack(side="top", fill="both", expand=True, padx=10, pady=5)

        cols = ("id", "produto", "qtd", "preco", "total", "adicionais")
        tree_scroll = ttk.Scrollbar(tree_frame, orient="vertical")
        tree = ttk.Treeview(tree_frame, columns=cols, show="headings", height=10,
                            yscrollcommand=tree_scroll.set)
        tree_scroll.config(command=tree.yview)
        for c, h, w in [("id","ID",40),("produto","Produto",180),("qtd","Qtd",50),
                         ("preco","Preco",70),("total","Total",70),("adicionais","Adicionais",100)]:
            tree.heading(c, text=h)
            tree.column(c, width=w)
        tree_scroll.pack(side="right", fill="y")
        tree.pack(side="left", fill="both", expand=True)

        def carregar():
            """Carrega itens de itens_armario_sauna (mesma tabela do APK)."""
            def load():
                db = DatabaseHelper.get_instance()
                if not uso_id or uso_id <= 0:
                    return []
                return db.execute_query(
                    "SELECT id, descricao_produto, quantidade, preco_unitario, total, "
                    "adicionais_descricao, adicionais_total, impresso "
                    "FROM itens_armario_sauna WHERE uso_armario_id = %s ORDER BY id",
                    (uso_id,)
                )
            def on_loaded(rows):
                try:
                    if not tree.winfo_exists():
                        return
                except Exception:
                    return
                tree.delete(*tree.get_children())
                total = 0
                for r in rows:
                    item_total = float(r.get("total", 0)) + float(r.get("adicionais_total", 0))
                    total += item_total
                    ad_desc = r.get("adicionais_descricao") or ""
                    tree.insert("", "end", values=(
                        r["id"], r["descricao_produto"], r["quantidade"],
                        FormatUtils.format_money(r["preco_unitario"]),
                        FormatUtils.format_money(item_total),
                        ad_desc
                    ))
                lbl_total.config(text=f"Total: R$ {FormatUtils.format_money(total)}")
            self.run_async(load, on_loaded)

        def add_item():
            self._selecionar_produto_armario_inline(
                uso_id, arm_id, numero, data_entrada, descricao,
                localizacao, cliente_nome, observacao, carregar
            )

        def remover_item():
            sel = tree.selection()
            if not sel:
                messagebox.showwarning(
                    "Selecione um Item",
                    "Nenhum item foi selecionado para remover.\n\n"
                    "Clique sobre o item que deseja remover na lista\n"
                    "e tente novamente.",
                    parent=self.root)
                return
            values = tree.item(sel[0])["values"]
            item_id = values[0]
            item_desc = values[1] if len(values) > 1 else "item"
            if not messagebox.askyesno("Confirmar", f"Remover '{item_desc}'?", parent=self.root):
                return

            def executar_remocao():
                def remover():
                    db = DatabaseHelper.get_instance()
                    try:
                        db.execute_update(
                            "DELETE FROM itens_armario_sauna_adicionais WHERE item_armario_id = %s",
                            (item_id,))
                    except Exception:
                        pass
                    db.execute_update(
                        "DELETE FROM itens_armario_sauna WHERE id = %s", (item_id,))
                self.run_async(remover, lambda _: carregar())

            self._solicitar_senha_admin_obrigatoria(executar_remocao, parent_window=self.root)

        def fechar_armario():
            if messagebox.askyesno("Confirmar",
                    f"Fechar armario {numero}?\nOs itens serao enviados para a tela de vendas para pagamento.",
                    parent=self.root):
                self._fechar_armario_via_venda(arm_id, numero, uso_id, None)

        def devolver_chave_sem_consumo():
            """Devolve a chave sem pagamento (armario sem itens ou cancelamento).
            SEMPRE exige senha de administrador, independente de permissoes."""
            if messagebox.askyesno("Confirmar",
                    f"Devolver chave do armario {numero} sem pagamento?\nTodos os itens serao removidos.",
                    parent=self.root):
                def executar_devolucao():
                    def devolver():
                        db = DatabaseHelper.get_instance()
                        if uso_id and uso_id > 0:
                            try:
                                db.execute_update(
                                    "DELETE FROM itens_armario_sauna_adicionais "
                                    "WHERE item_armario_id IN (SELECT id FROM itens_armario_sauna WHERE uso_armario_id = %s)",
                                    (uso_id,))
                            except Exception:
                                pass
                            db.execute_update(
                                "DELETE FROM itens_armario_sauna WHERE uso_armario_id = %s", (uso_id,))
                            db.execute_update(
                                "UPDATE uso_armario_sauna SET status = 'encerrado', data_saida = NOW() WHERE id = %s",
                                (uso_id,))
                    def on_devolvido(_):
                        self._mostrar_placeholder_direito()
                        self.show_success(f"Armario {numero} liberado!")
                        self.carregar_armarios()
                    self.run_async(devolver, on_devolvido)
                self._solicitar_senha_admin_obrigatoria(executar_devolucao, parent_window=self.root)

        StyledButton(btn_frame, text="Add Item", command=add_item,
                     color=COR_BOTAO_VERDE, width=10).pack(side="left", padx=3)
        StyledButton(btn_frame, text="Remover Item", command=remover_item,
                     color=COR_ALERTA, width=11).pack(side="left", padx=3)
        StyledButton(btn_frame, text="Devolver Chave", command=devolver_chave_sem_consumo,
                     color=COR_BOTAO_AZUL, width=12).pack(side="left", padx=3)
        StyledButton(btn_frame, text="Fechar e Pagar", command=fechar_armario,
                     color=COR_ERRO, width=12).pack(side="right", padx=3)

        carregar()

    def _selecionar_produto_armario_inline(self, uso_id, arm_id, numero, data_entrada,
                                              descricao, localizacao, cliente_nome,
                                              observacao, refresh_callback):
        """Exibe a tela de selecao de produto no painel direito (sem popup).
        Ao selecionar, pede quantidade e adiciona o item, depois volta ao detalhe."""
        self._limpar_painel_direito_armarios()
        panel = self._armario_right_panel

        tk.Label(panel, text="Adicionar Produto", bg=COR_FUNDO, fg=COR_PRIMARIA,
                 font=("Segoe UI", 16, "bold")).pack(pady=(10, 5))
        tk.Label(panel, text=f"Armario {numero}", bg=COR_FUNDO, fg="#9C27B0",
                 font=("Segoe UI", 11)).pack(pady=(0, 5))

        # Busca
        busca_frame = tk.Frame(panel, bg=COR_FUNDO)
        busca_frame.pack(fill="x", padx=15, pady=5)
        tk.Label(busca_frame, text="Buscar:", bg=COR_FUNDO, fg=COR_TEXTO,
                 font=("Segoe UI", 10)).pack(side="left", padx=(0, 5))
        et_busca = StyledEntry(busca_frame, width=30)
        et_busca.pack(side="left", fill="x", expand=True)
        et_busca.focus_set()

        # Treeview de produtos
        tree_frame = tk.Frame(panel, bg=COR_FUNDO)
        tree_frame.pack(fill="both", expand=True, padx=15, pady=5)

        prod_cols = ("c0", "c1", "c2")
        prod_scroll = ttk.Scrollbar(tree_frame, orient="vertical")
        prod_tree = ttk.Treeview(tree_frame, columns=prod_cols, show="headings", height=12,
                                  yscrollcommand=prod_scroll.set)
        prod_scroll.config(command=prod_tree.yview)
        for c, h, w in [("c0", "ID", 50), ("c1", "Descricao", 250), ("c2", "Preco", 80)]:
            prod_tree.heading(c, text=h)
            prod_tree.column(c, width=w)
        prod_scroll.pack(side="right", fill="y")
        prod_tree.pack(side="left", fill="both", expand=True)

        # Botoes na parte inferior
        btn_frame_sel = tk.Frame(panel, bg=COR_FUNDO)
        btn_frame_sel.pack(fill="x", padx=15, pady=(5, 10))

        def carregar_produtos(filtro=""):
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT id, descricao, preco_venda FROM produtos WHERE ativo = 1 ORDER BY descricao"
                )
            def on_loaded(rows):
                try:
                    if not prod_tree.winfo_exists():
                        return
                except Exception:
                    return
                prod_tree.delete(*prod_tree.get_children())
                for row in rows:
                    values = list(row.values())
                    if filtro:
                        match = any(filtro.lower() in str(v).lower() for v in values)
                        if not match:
                            continue
                    prod_tree.insert("", "end", values=values)
            self.run_async(load, on_loaded)

        et_busca.bind("<KeyRelease>", lambda e: carregar_produtos(et_busca.get()))

        def selecionar_produto():
            sel = prod_tree.selection()
            if not sel:
                messagebox.showwarning(
                    "Selecione um Produto",
                    "Nenhum produto foi selecionado.\n\n"
                    "COMO SELECIONAR:\n"
                    "1. Use o campo de busca para encontrar o produto\n"
                    "2. Digite o nome, codigo ou codigo de barras\n"
                    "3. Clique sobre o produto desejado na lista\n"
                    "4. Ou de um duplo-clique para selecionar rapidamente",
                    parent=self.root)
                return
            values = prod_tree.item(sel[0])["values"]
            # Pedir quantidade
            produto_id, desc_prod, preco = values[0], values[1], float(values[2])
            qtd = simpledialog.askfloat("Quantidade", f"Qtd de {desc_prod}:",
                                         initialvalue=1, minvalue=0.001, parent=self.root)
            if not qtd:
                return
            # Salvar item
            def salvar():
                db = DatabaseHelper.get_instance()
                db.execute_update(
                    "INSERT INTO itens_armario_sauna (uso_armario_id, produto_id, descricao_produto, "
                    "quantidade, preco_unitario, total, adicionais_descricao, adicionais_total, impresso) "
                    "VALUES (%s,%s,%s,%s,%s,%s,NULL,0,0)",
                    (uso_id, produto_id, desc_prod, qtd, preco, qtd * preco)
                )
            def on_salvo(_):
                # Voltar para a tela de detalhe do armario (atualizada)
                self._show_armario_detalhe(arm_id, numero, uso_id, data_entrada,
                                           descricao, localizacao, cliente_nome, observacao)
            self.run_async(salvar, on_salvo)

        prod_tree.bind("<Double-1>", lambda e: selecionar_produto())

        StyledButton(btn_frame_sel, text="▶ Selecionar", command=selecionar_produto,
                     color=COR_BOTAO_VERDE, width=12).pack(side="left", padx=5)
        StyledButton(btn_frame_sel, text="Voltar", command=lambda: self._show_armario_detalhe(
                         arm_id, numero, uso_id, data_entrada, descricao,
                         localizacao, cliente_nome, observacao),
                     color="#2a3a5c", width=10).pack(side="right", padx=5)

        carregar_produtos()

    def _add_item_armario_sauna(self, uso_id, row, refresh):
        """Adiciona item em itens_armario_sauna (mesma tabela do APK)."""
        if not uso_id or uso_id <= 0:
            self.show_error("Erro: uso do armario nao encontrado.")
            return
        produto_id, descricao, preco = row[0], row[1], float(row[2])
        qtd = simpledialog.askfloat("Quantidade", f"Qtd de {descricao}:",
                                     initialvalue=1, minvalue=0.001, parent=self.root)
        if not qtd:
            return
        def salvar():
            db = DatabaseHelper.get_instance()
            db.execute_update(
                "INSERT INTO itens_armario_sauna (uso_armario_id, produto_id, descricao_produto, "
                "quantidade, preco_unitario, total, adicionais_descricao, adicionais_total, impresso) "
                "VALUES (%s,%s,%s,%s,%s,%s,NULL,0,0)",
                (uso_id, produto_id, descricao, qtd, preco, qtd * preco)
            )
        self.run_async(salvar, lambda _: refresh())

    def _fechar_armario_via_venda(self, arm_id, numero, uso_id, dialog):
        """Envia os itens do armario para a tela de vendas para pagamento.
        Usa itens_armario_sauna (mesma tabela do APK).
        O armario so sera liberado apos a venda ser confirmada."""
        # === TRAVA DE CAIXA: Verificar se o caixa esta aberto antes de enviar para venda ===
        if not Session.caixa_id:
            AuditLogger.log("VENDA_BLOQUEADA_CAIXA_FECHADO",
                            f"Tentativa de fechar armario {numero} via venda bloqueada - caixa fechado",
                            usuario=Session.user_login)
            ToastManager.error("Venda bloqueada! Abra o caixa antes.", duration=5000)
            messagebox.showwarning(
                "Caixa Fechado - Venda Bloqueada",
                "Nao e possivel faturar o armario com o caixa fechado.\n\n"
                "COMO RESOLVER:\n"
                "1. Acesse o menu 'Caixa' (pressione F3)\n"
                "2. Clique em 'Abrir Caixa'\n"
                "3. Informe o valor de abertura\n"
                "4. Depois volte e tente novamente",
                parent=dialog if dialog else self.root)
            return

        def load_dados():
            db = DatabaseHelper.get_instance()
            if not uso_id or uso_id <= 0:
                return {"itens": [], "data_entrada": None}
            itens = db.execute_query(
                "SELECT produto_id, descricao_produto, quantidade, preco_unitario, "
                "total, adicionais_descricao, adicionais_total "
                "FROM itens_armario_sauna WHERE uso_armario_id = %s ORDER BY id",
                (uso_id,)
            )
            uso_data = db.execute_query(
                "SELECT data_entrada, cliente_nome FROM uso_armario_sauna WHERE id = %s",
                (uso_id,)
            )
            data_entrada = None
            cliente = ""
            if uso_data:
                data_entrada = uso_data[0].get("data_entrada")
                cliente = uso_data[0].get("cliente_nome") or ""
            return {"itens": itens, "data_entrada": data_entrada, "cliente": cliente}

        def on_dados_loaded(dados):
            itens = dados["itens"]
            data_entrada = dados["data_entrada"]
            cliente = dados.get("cliente", "")

            if not itens:
                messagebox.showwarning(
                    "Armario Sem Itens",
                    f"O armario {numero} nao possui itens para faturar.\n\n"
                    f"Adicione produtos ao armario antes de fechar a conta\n"
                    f"ou use 'Devolver Chave' para liberar sem cobranca.",
                    parent=self.root)
                return

            # Fechar o dialog do armario (se existir - compatibilidade)
            if dialog:
                try:
                    dialog.destroy()
                except Exception:
                    pass

            # Abrir a tela de vendas DIRETAMENTE (sem passar pela verificacao
            # assincrona de caixa, pois ja foi verificado no inicio desta funcao).
            # Isso garante que a UI e renderizada de forma SINCRONA antes de
            # popular o carrinho, evitando que _show_venda_ui() limpe os dados.
            self._show_venda_ui()

            try:
                self.venda_cliente_id = 0
                self.venda_cliente_nome = cliente.strip() if cliente else "Cliente nao informado"
                if hasattr(self, "lbl_cliente_venda") and self.lbl_cliente_venda.winfo_exists():
                    self.lbl_cliente_venda.config(text=self.venda_cliente_nome)
            except Exception:
                pass

            # Salvar referencia do armario pendente APOS _show_venda_ui
            self._armario_pendente = {
                "arm_id": arm_id,
                "numero": numero,
                "uso_id": uso_id
            }

            # Popular o carrinho com os itens do armario
            for item_data in itens:
                item = ItemVenda()
                item.produto_id = item_data["produto_id"]
                item.descricao_produto = item_data["descricao_produto"]
                item.quantidade = float(item_data["quantidade"])
                item.preco_unitario = float(item_data["preco_unitario"])
                item_total = float(item_data["total"])
                ad_total = float(item_data.get("adicionais_total", 0) or 0)
                item.total = item_total + ad_total
                if ad_total > 0 and item.quantidade > 0:
                    item.preco_unitario = item.total / item.quantidade
                self.carrinho.append(item)

            # Atualizar a treeview do carrinho e totais
            self.atualizar_tree_carrinho()

            # Colocar observacao indicando origem com data de abertura
            try:
                self.et_obs_venda.delete("1.0", tk.END)
                obs_text = f"Armario Sauna {numero}"
                if cliente:
                    obs_text += f" | Cliente: {cliente}"
                if data_entrada:
                    abertura_str = FormatUtils.format_date(data_entrada)
                    obs_text += f" | Entrada: {abertura_str}"
                self.et_obs_venda.insert("1.0", obs_text)
            except Exception:
                pass

        self.run_async(load_dados, on_dados_loaded)

