    def show_contas_receber(self):
        self.clear_container()

        top = self._create_top_bar(f"{Icons.MONEY} Contas a Receber")

        content = tk.Frame(self.main_container, bg=COR_FUNDO)
        content.pack(fill="both", expand=True, padx=10, pady=5)

        # Filtros
        filtro_card = tk.Frame(content, bg=COR_GLASS,
                               highlightthickness=1,
                               highlightbackground=COR_GLASS_BORDER)
        filtro_card.pack(fill="x", pady=(0, 6))

        tk.Label(filtro_card, text="Status:", bg=COR_GLASS,
                 fg=COR_TEXTO2, font=("Segoe UI", 9)).pack(side="left", padx=(10, 4), pady=6)
        combo_status_c = ttk.Combobox(filtro_card,
                                       values=["Todos", "pendente", "parcial", "quitada"],
                                       width=10, state="readonly",
                                       font=("Segoe UI", 9))
        combo_status_c.current(0)
        combo_status_c.pack(side="left", padx=4)

        tk.Label(filtro_card, text="Buscar:", bg=COR_GLASS,
                 fg=COR_TEXTO2, font=("Segoe UI", 9)).pack(side="left", padx=(8, 4))
        et_busca_c = StyledEntry(filtro_card, width=20)
        et_busca_c.pack(side="left", padx=4)

        lbl_total_c = tk.Label(filtro_card, text="", bg=COR_GLASS,
                                fg=COR_ERRO, font=("Segoe UI", 9, "bold"))
        lbl_total_c.pack(side="right", padx=12)

        # Treeview
        tree_frame = tk.Frame(content, bg=COR_FUNDO)
        tree_frame.pack(fill="both", expand=True)

        cols = ("id", "cliente", "valor_original", "valor_pago", "valor_pendente", "status", "vencimento")
        self.tree_contas = ttk.Treeview(tree_frame, columns=cols,
                                         show="headings", height=17)
        for c, h, w in [
            ("id",             "ID",             50),
            ("cliente",        "Cliente",        190),
            ("valor_original", "Valor Original", 115),
            ("valor_pago",     "Valor Pago",     110),
            ("valor_pendente", "Pendente",        110),
            ("status",         "Status",          90),
            ("vencimento",     "Vencimento",      110),
        ]:
            self.tree_contas.heading(c, text=h,
                command=lambda col=c: self._sort_tree(self.tree_contas, col, False))
            self.tree_contas.column(c, width=w,
                anchor="center" if c in ("id", "status", "vencimento") else "e")

        vsb_c = ttk.Scrollbar(tree_frame, orient="vertical",
                               command=self.tree_contas.yview)
        self.tree_contas.configure(yscrollcommand=vsb_c.set)
        self.tree_contas.pack(side="left", fill="both", expand=True)
        vsb_c.pack(side="right", fill="y")

        btn_frame = tk.Frame(content, bg=COR_FUNDO)
        btn_frame.pack(fill="x", pady=5)

        StyledButton(btn_frame, text=f"{Icons.MONEY} Receber Pagamento",
                     command=self.receber_conta,
                     color=COR_BOTAO_VERDE, width=20).pack(side="left", padx=5)
        add_tooltip(btn_frame.winfo_children()[-1],
                    "Registrar pagamento da conta selecionada")

        StyledButton(btn_frame, text=f"{Icons.REFRESH} Atualizar",
                     command=lambda: _carregar(),
                     color=COR_FUNDO3, width=10).pack(side="left", padx=5)

        StyledButton(btn_frame, text=f"{Icons.EXPORT} Exportar CSV",
                     command=lambda: DataExporter.export_treeview_csv(
                         self.tree_contas, "contas_receber", parent=self.root),
                     color=COR_BOTAO_AZUL, width=14).pack(side="left", padx=5)

        _cache_c = [None]

        def _preencher_contas(rows, filtro="", status_f="Todos"):
            # Preservar selecao
            sel = self.tree_contas.selection()
            sel_id = None
            if sel:
                try:
                    sel_id = self.tree_contas.item(sel[0])["values"][0]
                except Exception:
                    pass
            self.tree_contas.delete(*self.tree_contas.get_children())
            tot_pend = 0.0
            new_sel_iid = None
            for i, r in enumerate(rows):
                st = r.get("status", "")
                cli = r.get("cliente_nome", "N/A") or "N/A"
                pend = float(r.get("valor_pendente", 0))
                venc = str(r.get("data_vencimento", "")) or ""
                if venc and len(venc) >= 10:
                    try:
                        venc = datetime.datetime.strptime(
                            venc[:10], "%Y-%m-%d").strftime("%d/%m/%Y")
                    except Exception:
                        pass

                if status_f != "Todos" and st != status_f:
                    continue
                if filtro and filtro.lower() not in cli.lower():
                    continue

                tag = "quitada" if st == "quitada" else (
                    "even" if i % 2 == 0 else "odd")
                iid = self.tree_contas.insert("", "end", values=(
                    r["id"], cli,
                    FormatUtils.format_money(r["valor_original"]),
                    FormatUtils.format_money(r["valor_pago"]),
                    FormatUtils.format_money(pend),
                    st, venc
                ), tags=(tag,))
                if sel_id is not None and r["id"] == sel_id:
                    new_sel_iid = iid
                if st in ("pendente", "parcial"):
                    tot_pend += pend
            if new_sel_iid:
                self.tree_contas.selection_set(new_sel_iid)
                self.tree_contas.see(new_sel_iid)

            self.tree_contas.tag_configure("even", background=COR_GLASS)
            self.tree_contas.tag_configure("odd",  background=COR_CARD)
            self.tree_contas.tag_configure(
                "quitada", background="#0a1a0a", foreground="#44bb44")
            lbl_total_c.config(
                text=f"Pendente Total: R$ {FormatUtils.format_money(tot_pend)}")

        def _carregar():
            def load():
                db = DatabaseHelper.get_instance()
                return db.execute_query(
                    "SELECT cr.id, c.nome as cliente_nome, cr.valor_original, "
                    "cr.valor_pago, cr.valor_pendente, cr.status, "
                    "cr.data_vencimento "
                    "FROM contas_receber cr "
                    "LEFT JOIN clientes c ON cr.cliente_id = c.id "
                    "ORDER BY cr.id DESC"
                )
            def on_loaded(rows):
                _cache_c[0] = rows
                _preencher_contas(rows,
                                  et_busca_c.get().strip(),
                                  combo_status_c.get())
            self.run_async(load, on_loaded)

        combo_status_c.bind("<<ComboboxSelected>>",
            lambda e: _preencher_contas(
                _cache_c[0] or [],
                et_busca_c.get().strip(),
                combo_status_c.get()))
        et_busca_c.bind("<KeyRelease>",
            lambda e: _preencher_contas(
                _cache_c[0] or [],
                et_busca_c.get().strip(),
                combo_status_c.get()))

        StyledButton(filtro_card, text=f"{Icons.SEARCH} Buscar",
                     command=_carregar,
                     color=COR_BOTAO_AZUL, width=8).pack(side="left", padx=6, pady=6)

        _carregar()

        # Auto-refresh em tempo real (a cada 12 segundos)
        self._start_auto_refresh("contas_receber", _carregar, 12000)



    def receber_conta(self):
        sel = self.tree_contas.selection()
        if not sel:
            ToastManager.warning("Selecione uma conta.")
            return
        conta_id = self.tree_contas.item(sel[0])["values"][0]
        cliente_nome = self.tree_contas.item(sel[0])["values"][1]
        pendente = FormatUtils.parse_money(
            str(self.tree_contas.item(sel[0])["values"][4]))
        if pendente <= 0:
            ToastManager.info("Esta conta ja esta quitada.")
            return
        valor = simpledialog.askfloat(
            "Receber Pagamento",
            f"Cliente: {cliente_nome}\n"
            f"Valor pendente: R$ {FormatUtils.format_money(pendente)}\n\n"
            f"Valor a receber (R$):",
            initialvalue=pendente, minvalue=0.01, parent=self.root)
        if not valor:
            return

        def receber():
            db = DatabaseHelper.get_instance()
            novo_pendente = pendente - valor
            status = "quitada" if novo_pendente <= 0.009 else "parcial"
            db.execute_update(
                "UPDATE contas_receber SET "
                "valor_pago = valor_pago + %s, "
                "valor_pendente = GREATEST(0, valor_pendente - %s), "
                "status = %s "
                "WHERE id = %s",
                (valor, valor, status, conta_id)
            )
            return status

        def on_recebido(status):
            msg = (f"Pagamento de R$ {FormatUtils.format_money(valor)} registrado!"
                   + (" Conta QUITADA!" if status == "quitada" else ""))
            ToastManager.success(msg)
            AuditLogger.log("CONTA_RECEBIDA",
                            f"Conta #{conta_id} | Cliente: {cliente_nome} | "
                            f"Valor: R$ {FormatUtils.format_money(valor)} | Status: {status}",
                            usuario=Session.user_login)
            self.show_contas_receber()

        self.run_async(receber, on_recebido)



