            ("Vendas por Vendedor",  self._rel_vendas_vendedor,       COR_BOTAO_AZUL),
            ("Vendas por Cliente",   self._rel_vendas_cliente,        COR_BOTAO_AZUL),
            ("Mais Vendidos",        self._rel_produtos_mais_vendidos, "#7c3aed"),
            ("Estoque Atual",        self._rel_estoque,               COR_BOTAO_VERDE),
            ("Estoque Critico",      self._rel_estoque_minimo,        COR_ALERTA),
            ("Lucro por Produto",    self._rel_lucro_produto,         COR_SUCESSO),
