    def _rel_lucro_produto(self):
        di, df = self._get_datas_filtro()
        if not di:
            return
        def load():
            db = DatabaseHelper.get_instance()
            return db.execute_query(
                "SELECT iv.descricao_produto, SUM(iv.quantidade) as qtd, "
                "SUM(iv.total) as receita, "
                "SUM(iv.quantidade * p.preco_custo) as custo "
                "FROM itens_venda iv JOIN vendas v ON iv.venda_id = v.id "
                "LEFT JOIN produtos p ON iv.produto_id = p.id "
                "WHERE v.data_venda BETWEEN %s AND %s AND v.status = 'finalizada' "
                "GROUP BY iv.produto_id, iv.descricao_produto, p.preco_custo ORDER BY (SUM(iv.total) - SUM(iv.quantidade * COALESCE(p.preco_custo,0))) DESC",
                (di, df)
            )
        def on_loaded(rows):
            linhas = [f"{'Produto':<25} {'Receita':>10} {'Custo':>10} {'Lucro':>10} {'Margem':>8}"]
            linhas.append("-" * 65)
            for r in rows:
                receita = float(r["receita"])
                custo = float(r["custo"]) if r["custo"] else 0
                lucro = receita - custo
                margem = (lucro / receita * 100) if receita > 0 else 0
                linhas.append(
                    f"{r['descricao_produto']:<25} R${FormatUtils.format_money(receita):>8} "
                    f"R${FormatUtils.format_money(custo):>8} R${FormatUtils.format_money(lucro):>8} "
                    f"{margem:>6.1f}%"
                )
            self._exibir_relatorio("LUCRO POR PRODUTO", linhas)
        self.run_async(load, on_loaded)

