    def _imprimir_relatorio_exibido(self):
        """Imprime o conteudo do relatorio atualmente exibido na area de texto."""
        texto = self.text_relatorio.get("1.0", "end").strip()
        if not texto:
            self.show_error("Nenhum relatorio para imprimir. Gere um relatorio primeiro.")
            return
        self._mostrar_cupom_caixa(texto, titulo="Imprimir Relatorio")

    def _rel_reimprimir_cupom(self):
        """Permite selecionar uma venda pelo ID e reimprimir o cupom."""
        venda_id = simpledialog.askinteger(
            "Reimprimir Cupom",
            "Digite o numero (ID) da venda para reimprimir o cupom:",
            parent=self.root, minvalue=1
        )
        if not venda_id:
            return

        def load():
            db = DatabaseHelper.get_instance()
            venda_rows = db.execute_query("SELECT * FROM vendas WHERE id = %s", (venda_id,))
            if not venda_rows:
                return None
            vr = venda_rows[0]
            venda = Venda()
            venda.id = vr["id"]
            venda.total_bruto = float(vr.get("total_bruto", 0))
            venda.desconto_valor = float(vr.get("desconto_valor", 0))
            venda.acrescimo_valor = float(vr.get("acrescimo_valor", 0))
            venda.total_liquido = float(vr.get("total_liquido", 0))
            venda.valor_recebido = float(vr.get("valor_recebido", 0))
            venda.troco = float(vr.get("troco", 0))
            venda.observacao = vr.get("observacao", "")
            venda.data_venda = str(vr.get("data_venda", ""))
            venda.para_entrega = bool(vr.get("para_entrega", 0))
            venda.taxa_entrega = float(vr.get("taxa_entrega", 0))

            # Cliente
            venda.cliente_nome = (vr.get("cliente_nome") or "").strip()
            if (not venda.cliente_nome) and vr.get("uso_armario_id"):
                uso = db.execute_query("SELECT cliente_nome FROM uso_armario_sauna WHERE id = %s", (vr["uso_armario_id"],))
                venda.cliente_nome = (uso[0]["cliente_nome"] or "").strip() if uso else ""
            if (not venda.cliente_nome) and vr.get("cliente_id"):
                cli = db.execute_query("SELECT nome FROM clientes WHERE id = %s", (vr["cliente_id"],))
                venda.cliente_nome = cli[0]["nome"] if cli else ""

            # Vendedor
            if vr.get("vendedor_id"):
                vend = db.execute_query("SELECT nome FROM vendedores WHERE id = %s", (vr["vendedor_id"],))
                venda.vendedor_nome = vend[0]["nome"] if vend else ""

            # Itens
            itens_rows = db.execute_query(
                "SELECT * FROM itens_venda WHERE venda_id = %s", (venda_id,)
            )
            itens = []
            for ir in itens_rows:
                item = ItemVenda()
                item.descricao_produto = ir.get("descricao_produto", "")
                item.quantidade = float(ir.get("quantidade", 1))
                item.preco_unitario = float(ir.get("preco_unitario", 0))
                item.total = float(ir.get("total", 0))
                itens.append(item)

            # Pagamentos
            pag_rows = db.execute_query(
                "SELECT pv.*, fp.descricao as forma_descricao FROM pagamentos_venda pv "
                "LEFT JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                "WHERE pv.venda_id = %s", (venda_id,)
            )
            pags = []
            for pr in pag_rows:
                pag = PagamentoVenda()
                pag.forma_descricao = pr.get("forma_descricao", "")
                pag.valor = float(pr.get("valor", 0))
                pag.parcelas = int(pr.get("parcelas", 1))
                pags.append(pag)

            # Empresa
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass

            return venda, itens, pags, empresa

        def on_loaded(result):
            if result:
                venda, itens, pags, empresa = result
                printer_cfg = self._load_printer_config()
                cupom = CupomGenerator.gerar_cupom(
                    venda, itens, pags,
                    empresa=empresa,
                    colunas=printer_cfg.get("largura_papel", 48),
                    margem_esq=printer_cfg.get("margem_esquerda", 0),
                    margem_dir=printer_cfg.get("margem_direita", 0),
                    espacamento=printer_cfg.get("espacamento_linhas", 1)
                )
                # Exibir no text_relatorio tambem
                self._exibir_relatorio(f"REIMPRESSAO - CUPOM VENDA #{venda_id}",
                                       cupom.split("\n"))
                # Abrir dialog de impressao
                self._mostrar_cupom(cupom)
            else:
                self.show_error(f"Venda #{venda_id} nao encontrada.")

        self.run_async(load, on_loaded)

    def _rel_reimprimir_fechamento(self):
        """Permite selecionar um caixa pelo ID e reimprimir o cupom de fechamento."""
        caixa_id = simpledialog.askinteger(
            "Reimprimir Fechamento de Caixa",
            "Digite o numero (ID) do caixa para reimprimir o fechamento:\n\n"
            "(Dica: o ID do caixa aparece na tela de Caixa)",
            parent=self.root, minvalue=1
        )
        if not caixa_id:
            return

        def load():
            db = DatabaseHelper.get_instance()
            caixa_rows = db.execute_query("SELECT * FROM caixa WHERE id = %s", (caixa_id,))
            if not caixa_rows:
                return None
            cx = caixa_rows[0]

            if cx.get("status") != "fechado":
                return "NAO_FECHADO"

            # Dados do operador
            usuario_nome = "N/A"
            if cx.get("usuario_id"):
                user_rows = db.execute_query("SELECT nome FROM usuarios WHERE id = %s", (cx["usuario_id"],))
                if user_rows:
                    usuario_nome = user_rows[0]["nome"]

            valor_abertura = float(cx.get("valor_abertura", 0))
            valor_fechamento = float(cx.get("valor_fechamento", 0))
            data_abertura = str(cx.get("data_abertura", ""))
            data_fechamento = str(cx.get("data_fechamento", ""))

            # Total de vendas
            rows = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(total_liquido),0) as total "
                "FROM vendas WHERE caixa_id = %s AND status = 'finalizada'", (caixa_id,)
            )
            total_vendas = float(rows[0]["total"]) if rows else 0
            qtd_vendas = int(rows[0]["qtd"]) if rows else 0

            # Vales
            rows_v = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total FROM vales_debito WHERE caixa_id = %s",
                (caixa_id,)
            )
            total_vales = float(rows_v[0]["total"]) if rows_v else 0
            qtd_vales = int(rows_v[0]["qtd"]) if rows_v else 0

            # Sangrias
            rows_s = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(valor),0) as total FROM sangrias WHERE caixa_id = %s",
                (caixa_id,)
            )
            total_sangrias = float(rows_s[0]["total"]) if rows_s else 0
            qtd_sangrias = int(rows_s[0]["qtd"]) if rows_s else 0

            # Resumo por forma de pagamento
            pag_rows = db.execute_query(
                "SELECT fp.descricao, COALESCE(SUM(pv.valor),0) as total "
                "FROM pagamentos_venda pv "
                "JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                "JOIN vendas v ON pv.venda_id = v.id "
                "WHERE v.caixa_id = %s AND v.status = 'finalizada' "
                "GROUP BY fp.id, fp.descricao ORDER BY total DESC", (caixa_id,)
            )
            pagamentos_resumo = []
            if pag_rows:
                for pr in pag_rows:
                    pagamentos_resumo.append({
                        "descricao": pr.get("descricao", "N/A"),
                        "total": float(pr.get("total", 0))
                    })

            # Empresa
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass

            return {
                "caixa_id": caixa_id,
                "usuario_nome": usuario_nome,
                "valor_abertura": valor_abertura,
                "valor_fechamento": valor_fechamento,
                "data_abertura": data_abertura,
                "data_fechamento": data_fechamento,
                "total_vendas": total_vendas,
                "qtd_vendas": qtd_vendas,
                "total_vales": total_vales,
                "qtd_vales": qtd_vales,
                "total_sangrias": total_sangrias,
                "qtd_sangrias": qtd_sangrias,
                "pagamentos_resumo": pagamentos_resumo,
                "empresa": empresa,
            }

        def on_loaded(result):
            if result is None:
                self.show_error(f"Caixa #{caixa_id} nao encontrado.")
                return
            if result == "NAO_FECHADO":
                self.show_error(f"Caixa #{caixa_id} ainda nao foi fechado.\n"
                                "Somente caixas fechados podem ser reimpressos.")
                return

            printer_cfg = self._load_printer_config()
            cupom = CupomGenerator.gerar_cupom_fechamento_caixa(
                caixa_id=result["caixa_id"],
                usuario_nome=result["usuario_nome"],
                valor_abertura=result["valor_abertura"],
                valor_fechamento=result["valor_fechamento"],
                data_abertura=result["data_abertura"],
                data_fechamento=result["data_fechamento"],
                total_vendas=result["total_vendas"],
                qtd_vendas=result["qtd_vendas"],
                total_vales=result["total_vales"],
                qtd_vales=result["qtd_vales"],
                total_sangrias=result["total_sangrias"],
                qtd_sangrias=result["qtd_sangrias"],
                pagamentos_resumo=result["pagamentos_resumo"],
                empresa=result["empresa"],
                colunas=printer_cfg.get("largura_papel", 48),
                margem_esq=printer_cfg.get("margem_esquerda", 0),
                margem_dir=printer_cfg.get("margem_direita", 0),
                espacamento=printer_cfg.get("espacamento_linhas", 1)
            )
            # Exibir no text_relatorio tambem
            self._exibir_relatorio(f"REIMPRESSAO - FECHAMENTO CAIXA #{caixa_id}",
                                   cupom.split("\n"))
            # Abrir dialog de impressao
            self._mostrar_cupom_caixa(cupom, titulo=f"Reimpr. Fechamento Caixa #{caixa_id}")

        self.run_async(load, on_loaded)

    def _rel_impressao_produtos_vendidos(self):
        """Gera relatorio de produtos vendidos no periodo com opcao de impressao.
        Lista todos os produtos vendidos com quantidade e valor total."""
        di, df = self._get_datas_filtro()
        if not di:
            return

        def load():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT iv.descricao_produto, SUM(iv.quantidade) as qtd, "
                "SUM(iv.total) as total, "
                "ROUND(SUM(iv.total)/SUM(iv.quantidade),2) as preco_medio "
                "FROM itens_venda iv JOIN vendas v ON iv.venda_id = v.id "
                "WHERE v.data_venda BETWEEN %s AND %s AND v.status = 'finalizada' "
                "GROUP BY iv.descricao_produto ORDER BY total DESC", (di, df)
            )
            # Empresa para cabecalho
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass
            return rows, empresa

        def on_loaded(result):
            rows, empresa = result
            if not rows:
                self._exibir_relatorio("PRODUTOS VENDIDOS",
                                       ["Nenhum produto vendido no periodo selecionado."])
                return

            # Formatar datas para exibicao
            try:
                di_fmt = datetime.datetime.strptime(di[:10], "%Y-%m-%d").strftime("%d/%m/%Y")
                df_fmt = datetime.datetime.strptime(df[:10], "%Y-%m-%d").strftime("%d/%m/%Y")
            except Exception:
                di_fmt, df_fmt = di, df

            linhas = []
            linhas.append(f"Periodo: {di_fmt} a {df_fmt}")
            linhas.append("")
            linhas.append(f"{'#':>3} {'Produto':<28} {'Qtd':>8} {'Preco Med':>10} {'Total':>12}")
            linhas.append("-" * 63)

            total_geral = 0
            qtd_geral = 0
            for i, r in enumerate(rows, 1):
                qtd = float(r['qtd'])
                total = float(r['total'])
                preco_medio = float(r.get('preco_medio', 0))
                linhas.append(
                    f"{i:>3} {r['descricao_produto']:<28} {qtd:>8.0f} "
                    f"R${FormatUtils.format_money(preco_medio):>8} "
                    f"R${FormatUtils.format_money(total):>10}"
                )
                total_geral += total
                qtd_geral += qtd

            linhas.append("-" * 63)
            linhas.append(
                f"{'':>3} {'TOTAL GERAL':<28} {qtd_geral:>8.0f} "
                f"{'':>10} R${FormatUtils.format_money(total_geral):>10}"
            )
            linhas.append(f"\nTotal de produtos distintos: {len(rows)}")

            self._exibir_relatorio("PRODUTOS VENDIDOS", linhas)

            # Gerar cupom formatado para impressao
            printer_cfg = self._load_printer_config()
            largura = printer_cfg.get("largura_papel", 48)
            cupom_linhas = []
            cupom_linhas.append("=" * largura)
            if empresa:
                nome_emp = empresa.get("nome_fantasia") or empresa.get("razao_social") or ""
                if nome_emp:
                    cupom_linhas.append(nome_emp.center(largura))
                cnpj = empresa.get("cnpj", "")
                if cnpj:
                    cupom_linhas.append(f"CNPJ: {cnpj}".center(largura))
            cupom_linhas.append("-" * largura)
            cupom_linhas.append("RELATORIO: PRODUTOS VENDIDOS".center(largura))
            cupom_linhas.append(f"Periodo: {di_fmt} a {df_fmt}".center(largura))
            cupom_linhas.append("-" * largura)
            for i, r in enumerate(rows, 1):
                desc = (r['descricao_produto'] or "")[:largura - 20]
                qtd = float(r['qtd'])
                total = float(r['total'])
                cupom_linhas.append(f"{i:>3}. {desc}")
                cupom_linhas.append(f"     Qtd: {qtd:.0f}  Total: R$ {FormatUtils.format_money(total)}".rjust(largura))
            cupom_linhas.append("-" * largura)
            cupom_linhas.append(f"TOTAL GERAL: R$ {FormatUtils.format_money(total_geral)}".rjust(largura))
            cupom_linhas.append(f"Produtos distintos: {len(rows)}")
            cupom_linhas.append("=" * largura)

            self._ultimo_relatorio_cupom = "\n".join(cupom_linhas)

        self.run_async(load, on_loaded)

    def _rel_impressao_faturamento_pgto(self):
        """Gera relatorio de faturamento por forma de pagamento no periodo com opcao de impressao.
        Mostra o total faturado em cada forma de pagamento."""
        di, df = self._get_datas_filtro()
        if not di:
            return

        def load():
            db = DatabaseHelper.get_instance()
            rows = db.execute_query(
                "SELECT fp.descricao, COUNT(*) as qtd_transacoes, "
                "SUM(pv.valor) as total, "
                "ROUND(AVG(pv.valor),2) as ticket_medio "
                "FROM pagamentos_venda pv "
                "JOIN formas_pagamento fp ON pv.forma_pagamento_id = fp.id "
                "JOIN vendas v ON pv.venda_id = v.id "
                "WHERE v.data_venda BETWEEN %s AND %s AND v.status = 'finalizada' "
                "GROUP BY fp.id, fp.descricao ORDER BY total DESC", (di, df)
            )
            # Total geral de vendas no periodo
            total_row = db.execute_query(
                "SELECT COUNT(*) as qtd, COALESCE(SUM(total_liquido),0) as total "
                "FROM vendas WHERE data_venda BETWEEN %s AND %s AND status = 'finalizada'",
                (di, df)
            )
            # Empresa para cabecalho
            empresa = None
            try:
                emp_rows = db.execute_query("SELECT * FROM empresa LIMIT 1")
                if emp_rows:
                    empresa = emp_rows[0]
            except Exception:
                pass
            return rows, total_row, empresa

        def on_loaded(result):
            rows, total_row, empresa = result
            if not rows:
                self._exibir_relatorio("FATURAMENTO POR FORMA DE PAGAMENTO",
                                       ["Nenhum faturamento no periodo selecionado."])
                return

            # Formatar datas para exibicao
            try:
                di_fmt = datetime.datetime.strptime(di[:10], "%Y-%m-%d").strftime("%d/%m/%Y")
                df_fmt = datetime.datetime.strptime(df[:10], "%Y-%m-%d").strftime("%d/%m/%Y")
            except Exception:
                di_fmt, df_fmt = di, df

            total_vendas = float(total_row[0]["total"]) if total_row else 0
            qtd_vendas = int(total_row[0]["qtd"]) if total_row else 0

            linhas = []
            linhas.append(f"Periodo: {di_fmt} a {df_fmt}")
            linhas.append(f"Total de vendas finalizadas: {qtd_vendas}")
            linhas.append(f"Faturamento total: R$ {FormatUtils.format_money(total_vendas)}")
            linhas.append("")
            linhas.append(f"{'Forma de Pagamento':<25} {'Transacoes':>10} {'Ticket Med':>12} {'Total':>14} {'%':>6}")
            linhas.append("-" * 69)

            total_pgto = 0
            for r in rows:
                total = float(r['total'])
                qtd = int(r['qtd_transacoes'])
                ticket = float(r.get('ticket_medio', 0))
                pct = (total / total_vendas * 100) if total_vendas > 0 else 0
                linhas.append(
                    f"{r['descricao']:<25} {qtd:>10} "
                    f"R${FormatUtils.format_money(ticket):>10} "
                    f"R${FormatUtils.format_money(total):>12} "
                    f"{pct:>5.1f}%"
                )
                total_pgto += total

            linhas.append("-" * 69)
            linhas.append(
                f"{'TOTAL':<25} {'':>10} {'':>12} "
                f"R${FormatUtils.format_money(total_pgto):>12} {'100.0%':>6}"
            )

            self._exibir_relatorio("FATURAMENTO POR FORMA DE PAGAMENTO", linhas)

            # Gerar cupom formatado para impressao
            printer_cfg = self._load_printer_config()
            largura = printer_cfg.get("largura_papel", 48)
            cupom_linhas = []
            cupom_linhas.append("=" * largura)
            if empresa:
                nome_emp = empresa.get("nome_fantasia") or empresa.get("razao_social") or ""
                if nome_emp:
                    cupom_linhas.append(nome_emp.center(largura))
                cnpj = empresa.get("cnpj", "")
                if cnpj:
                    cupom_linhas.append(f"CNPJ: {cnpj}".center(largura))
            cupom_linhas.append("-" * largura)
            cupom_linhas.append("FATURAMENTO POR FORMA PGTO".center(largura))
            cupom_linhas.append(f"Periodo: {di_fmt} a {df_fmt}".center(largura))
            cupom_linhas.append(f"Vendas: {qtd_vendas}  Total: R$ {FormatUtils.format_money(total_vendas)}".center(largura))
            cupom_linhas.append("-" * largura)
            for r in rows:
                total = float(r['total'])
                qtd = int(r['qtd_transacoes'])
                pct = (total / total_vendas * 100) if total_vendas > 0 else 0
                desc = (r['descricao'] or "")[:largura - 25]
                cupom_linhas.append(f"{desc}")
                cupom_linhas.append(f"  {qtd} transacoes  R$ {FormatUtils.format_money(total)}  ({pct:.1f}%)".rjust(largura))
            cupom_linhas.append("-" * largura)
            cupom_linhas.append(f"TOTAL: R$ {FormatUtils.format_money(total_pgto)}".rjust(largura))
            cupom_linhas.append("=" * largura)

            self._ultimo_relatorio_cupom = "\n".join(cupom_linhas)

        self.run_async(load, on_loaded)

    # ========================================================================
    # PERFIS E PERMISSOES GRANULARES (alinhado com PermissionManager.java)
