        self._lbl_users_count = tk.Label(users_header, text="(0)", bg=COR_GLASS, fg=COR_TEXTO2,
                                          font=("Segoe UI", 9))
        self._lbl_users_count.pack(side="right")

        # Busca de usuario
        busca_user_frame = tk.Frame(users_card, bg=COR_GLASS)
        busca_user_frame.pack(fill="x", pady=(5, 3))
