        def coletar_config():
            """Coleta todos os valores dos campos e retorna um dict."""
            try:
                largura = int(et_largura.get().strip())
            except (ValueError, TypeError):
                largura = 48
            try:
                fonte = int(et_fonte.get().strip())
            except (ValueError, TypeError):
                fonte = 10
            try:
                copias = int(et_copias.get().strip())
            except (ValueError, TypeError):
                copias = 1
            try:
                m_esq = int(et_margem_esq.get().strip())
            except (ValueError, TypeError):
                m_esq = 0
            try:
                m_dir = int(et_margem_dir.get().strip())
            except (ValueError, TypeError):
                m_dir = 0
            try:
                espac = int(et_espacamento.get().strip())
            except (ValueError, TypeError):
                espac = 1

            if largura < 20:
                largura = 20
            if largura > 120:
                largura = 120
            if fonte < 6:
                fonte = 6
            if fonte > 30:
                fonte = 30
            if copias < 1:
                copias = 1
            if copias > 10:
                copias = 10

            return {
                "tipo_impressora": combo_tipo.get(),
                "nome_impressora": et_nome.get().strip(),
                "porta_impressora": et_porta.get().strip(),
                "codepage": combo_codepage.get(),
                "tamanho_papel": combo_tamanho_papel.get(),
                "largura_papel": largura,
                "modo_fonte": combo_modo_fonte.get(),
                "tamanho_fonte": fonte,
                "margem_esquerda": m_esq,
                "margem_direita": m_dir,
                "espacamento_linhas": espac,
                "num_copias": copias,
                "velocidade_impressao": combo_velocidade.get(),
                "corte_automatico": var_corte.get(),
                "abrir_gaveta": var_gaveta.get(),
                "imprimir_logo": var_logo.get(),
                "caminho_logo": et_logo.get().strip(),
                "imprimir_automatico": var_auto.get()
            }

        def salvar_config():
            cfg = coletar_config()
            if self._save_printer_config(cfg):
                self.show_success("Configuracoes de impressora salvas com sucesso!")
            else:
                self.show_error("Erro ao salvar configuracoes de impressora.")

        def testar_impressao():
            cfg = coletar_config()
            largura = cfg["largura_papel"]
            m_esq = cfg.get("margem_esquerda", 0)
            m_dir = cfg.get("margem_direita", 0)
            largura_util = max(20, largura - m_esq - m_dir)
            prefixo = " " * m_esq

            line = prefixo + "-" * largura_util
            line_eq = prefixo + "=" * largura_util

            def _t(texto):
                """Texto alinhado a esquerda, truncado na largura util."""
                return prefixo + texto[:largura_util]

            def _tc(texto):
                """Texto centralizado na largura util."""
                return prefixo + CupomGenerator._center(texto, largura_util)

            def _tw(texto):
                """Texto com word-wrap automatico."""
                lines = []
                for ln in CupomGenerator._wrap_text(texto, largura_util):
                    lines.append(prefixo + ln)
                return lines

            cupom = []
            cupom.append(line_eq)
            cupom.append(_tc("TESTE DE IMPRESSAO"))
            cupom.append(_tc(f"PDV Pro v{APP_VERSION}"))
            cupom.append(line)
            # Informacoes da impressora - cada campo em sua propria linha
            cupom.append(_t(f"Tipo: {cfg['tipo_impressora']}"))
            cupom.extend(_tw(f"Impressora: {cfg['nome_impressora'] or '(padrao)'}"))
            cupom.append(_t(f"Porta: {cfg['porta_impressora'] or '(auto)'}"))
            cupom.append(_t(f"Papel: {cfg.get('tamanho_papel', '80mm')}"))
            cupom.append(_t(f"Colunas: {largura} (util: {largura_util})"))
            cupom.append(_t(f"Fonte: {cfg.get('modo_fonte', 'Normal')}"))
            cupom.append(_t(f"Margens: E={m_esq} D={m_dir}"))
            cupom.append(_t(f"Codepage: {cfg['codepage']}"))
            cupom.append(_t(f"Copias: {cfg['num_copias']}"))
            cupom.append(_t(f"Velocidade: {cfg['velocidade_impressao']}"))
            cupom.append(line)
            corte_s = "Sim" if cfg['corte_automatico'] else "Nao"
            gaveta_s = "Sim" if cfg['abrir_gaveta'] else "Nao"
            logo_s = "Sim" if cfg['imprimir_logo'] else "Nao"
            auto_s = "Sim" if cfg['imprimir_automatico'] else "Nao"
            cupom.append(_t(f"Corte: {corte_s}  Gaveta: {gaveta_s}"))
            cupom.append(_t(f"Logo: {logo_s}  Auto: {auto_s}"))
            cupom.append(line)
            # Teste de caracteres (respeitando largura util)
            abc_upper = "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
            abc_lower = "abcdefghijklmnopqrstuvwxyz"
            nums = "0123456789"
            symbols = "!@#$%&*()-+=[]{}|;:',.<>?/"
            cupom.append(_t(abc_upper[:largura_util]))
            cupom.append(_t(abc_lower[:largura_util]))
            cupom.append(_t(nums[:largura_util]))
            cupom.append(_t(symbols[:largura_util]))
            cupom.append(line)
            cupom.append(_tc("Teste de acentuacao:"))
            cupom.append(_tc("aeiou AEIOU cC"))
            cupom.append(line)
            # Teste de regua de largura
            regua = "".join([str(i % 10) for i in range(1, largura_util + 1)])
            cupom.append(_t(regua))
            cupom.append(line)
            data_hora = datetime.datetime.now().strftime("%d/%m/%Y %H:%M:%S")
            cupom.append(_tc(f"Data/Hora: {data_hora}"))
            cupom.append(line_eq)
            cupom.append(_tc("FIM DO TESTE"))
            cupom.append(line_eq)

            texto_cupom = "\n".join(cupom)

            # Exibir preview do teste
            preview = tk.Toplevel(self.root)
            preview.title("Teste de Impressao - Preview")
            preview.geometry("550x650")
            preview.configure(bg=COR_FUNDO)
            preview.transient(self.root)
            preview.grab_set()

            tk.Label(preview, text="Preview do Teste de Impressao", bg=COR_FUNDO,
                     fg=COR_PRIMARIA, font=("Segoe UI", 14, "bold")).pack(pady=10)

            text_area = scrolledtext.ScrolledText(preview, width=60, height=25,
                                                   bg=COR_ENTRADA, fg=COR_TEXTO,
                                                   font=("Courier New", cfg["tamanho_fonte"]),
                                                   relief="flat", bd=0)
            text_area.pack(fill="both", expand=True, padx=15, pady=5)
            text_area.insert("1.0", texto_cupom)
            text_area.config(state="disabled")

            # Label de status
            lbl_status_teste = tk.Label(preview, text="", bg=COR_FUNDO, fg=COR_TEXTO2,
                                         font=("Segoe UI", 9, "italic"))
            lbl_status_teste.pack(pady=(5, 0))

            def enviar_para_impressora():
                """Envia teste para a impressora usando o metodo centralizado."""
                lbl_status_teste.config(text="Enviando para impressora...", fg=COR_ALERTA)
                preview.update_idletasks()

                def _do_print():
                    return self._imprimir_texto(texto_cupom, config=cfg, parent_window=preview)

                def _on_result(resultado):
                    sucesso, msg = resultado
                    if sucesso:
                        lbl_status_teste.config(text=msg, fg=COR_SUCESSO)
                        messagebox.showinfo(
                            "Teste de Impressao OK",
                            f"{msg}\n\n"
                            "A pagina de teste foi enviada para a impressora.\n"
                            "Verifique se saiu corretamente na impressora.",
                            parent=preview)
                    else:
                        lbl_status_teste.config(text=f"Falha: {msg}", fg=COR_ERRO)
                        messagebox.showerror(
                            "Erro no Teste de Impressao",
                            f"{msg}\n\n"
                            "COMO RESOLVER:\n"
                            "1. Verifique se a impressora esta LIGADA e conectada\n"
                            "2. Verifique se o nome da impressora esta correto\n"
                            "3. Teste imprimir algo pelo Bloco de Notas do Windows\n"
                            "4. Se funcionar no Bloco de Notas, revise as configuracoes",
                            parent=preview)

                def _on_error(e):
                    lbl_status_teste.config(text=f"Erro: {e}", fg=COR_ERRO)
                    ErroAmigavel.mostrar_erro(e, "teste_impressao", parent=preview)

                self.run_async(_do_print, _on_result, _on_error)

            btn_preview_frame = tk.Frame(preview, bg=COR_FUNDO)
            btn_preview_frame.pack(fill="x", padx=15, pady=10)

            StyledButton(btn_preview_frame, text="Enviar para Impressora",
                         command=enviar_para_impressora,
                         color=COR_BOTAO_VERDE, width=20).pack(side="left", padx=5)
            StyledButton(btn_preview_frame, text="Fechar",
                         command=preview.destroy,
                         color="#2a3a5c", width=10).pack(side="right", padx=5)

        def restaurar_padroes():
            if messagebox.askyesno("Confirmar",
                "Deseja restaurar todas as configuracoes de impressora para os valores padrao?"):
                combo_tipo.set("Termica")
                combo_impressora.set("")
                lbl_status_busca.config(text="")
                lbl_impressora_padrao.config(text="")
                lbl_driver_info.config(text="")
                et_porta.delete(0, tk.END)
                combo_codepage.set("UTF-8")
                combo_tamanho_papel.set("80mm")
                combo_modo_fonte.set("Condensada")
                lbl_fonte_info.config(text="")
                et_largura.delete(0, tk.END)
                et_largura.insert(0, "48")
                et_fonte.delete(0, tk.END)
                et_fonte.insert(0, "8")
                et_margem_esq.delete(0, tk.END)
                et_margem_esq.insert(0, "0")
                et_margem_dir.delete(0, tk.END)
                et_margem_dir.insert(0, "0")
                et_espacamento.delete(0, tk.END)
                et_espacamento.insert(0, "1")
                et_copias.delete(0, tk.END)
                et_copias.insert(0, "1")
                combo_velocidade.set("Normal")
                var_corte.set(True)
                var_gaveta.set(False)
                var_logo.set(False)
                et_logo.delete(0, tk.END)
                var_auto.set(False)
                self.show_success("Configuracoes restauradas para os valores padrao.")

        StyledButton(btn_frame, text="Salvar Configuracoes",
                     command=salvar_config,
                     color=COR_BOTAO_VERDE, width=20).pack(side="left", padx=8)
        StyledButton(btn_frame, text="⎙ Testar Impressao",
                     command=testar_impressao,
                     color=COR_BOTAO_AZUL, width=18).pack(side="left", padx=8)
        StyledButton(btn_frame, text="Restaurar Padroes",
                     command=restaurar_padroes,
                     color=COR_BOTAO_LARANJA, width=18).pack(side="left", padx=8)
