# ============================================================================
# PONTO DE ENTRADA
# ============================================================================

def main():
    """Ponto de entrada principal com tratamento global de erros robusto.
    Inclui diagnostico automatico, mensagens claras e recuperacao inteligente."""
    try:
        root = tk.Tk()

        try:
            root.iconname("PDV Pro")
        except Exception:
            pass

        # Handler global para excecoes nao tratadas no Tkinter
        def _tk_exception_handler(exc_type, exc_value, exc_tb):
            """Captura excecoes nao tratadas e exibe mensagem amigavel.
            O sistema continua funcionando apos o erro."""
            try:
                ErroAmigavel.log_erro(exc_value, "excecao_global_tkinter")
                msg, cod, det = ErroAmigavel.traduzir(exc_value)
                severidade = ErroAmigavel.obter_severidade(exc_value)

                if severidade == Severidade.CRITICO:
                    titulo = "Erro Critico no Sistema"
                    complemento = (
                        "\n\nATENCAO: Este e um erro grave.\n"
                        "Salve seu trabalho e reinicie o sistema o mais rapido possivel.")
                else:
                    titulo = "Ops! Algo deu errado"
                    complemento = (
                        "\n\nO sistema continuara funcionando normalmente.\n"
                        "Se o problema persistir, reinicie o sistema.")

                messagebox.showerror(
                    titulo,
                    f"{msg}\n\n"
                    f"{'='*40}\n"
                    f"Codigo do erro: {cod}\n"
                    f"Anote este codigo caso precise de suporte.{complemento}")
            except Exception:
                pass

        # Registrar handler global
        root.report_callback_exception = _tk_exception_handler

        # Handler global para excecoes nao tratadas em threads
        def _thread_exception_handler(args):
            """Captura excecoes em threads daemon."""
            try:
                ErroAmigavel.log_erro(args.exc_value, f"excecao_thread_{args.thread.name}")
            except Exception:
                pass

        try:
            import threading
            threading.excepthook = _thread_exception_handler
        except (AttributeError, ImportError):
            pass  # Python < 3.8

        app = PDVApp(root)
        root.mainloop()

    except mysql.connector.Error as e:
        ErroAmigavel.log_erro(e, "inicializacao_mysql")
        msg, cod, det = ErroAmigavel.traduzir(e)

        # Diagnostico automatico
        diagnostico = ""
        try:
            db = DatabaseHelper.get_instance()
            ok, diag = ErroAmigavel.diagnosticar_conexao(db.host, db.port)
            diagnostico = f"\n\nDIAGNOSTICO AUTOMATICO:\n{diag}"
        except Exception:
            diagnostico = ""

        try:
            messagebox.showerror(
                "Erro ao Iniciar - Banco de Dados",
                f"O PDV Pro nao conseguiu conectar ao banco de dados.\n\n"
                f"{msg}\n\n"
                f"{'='*40}\n"
                f"Codigo: {cod}\n\n"
                f"PASSO A PASSO PARA RESOLVER:\n"
                f"1. Verifique se o MySQL esta instalado neste computador\n"
                f"2. Abra 'Servicos' do Windows (services.msc)\n"
                f"3. Procure 'MySQL' na lista e clique em 'Iniciar'\n"
                f"4. Tente abrir o PDV Pro novamente\n"
                f"5. Se nao funcionar, reinicie o computador\n"
                f"6. Se nada resolver, entre em contato com o suporte"
                f"{diagnostico}")
        except Exception:
            print(f"\n{'='*50}")
            print(f"ERRO CRITICO - PDV Pro nao pode iniciar")
            print(f"{'='*50}")
            print(f"Problema: {msg}")
            print(f"Codigo: {cod}")
            print(f"\nVerifique se o MySQL esta instalado e rodando.")
            print(f"{'='*50}")

    except Exception as e:
        try:
            ErroAmigavel.log_erro(e, "inicializacao_geral")
        except Exception:
            pass

        try:
            msg, cod, det = ErroAmigavel.traduzir(e)
        except Exception:
            msg = "Erro desconhecido ao iniciar o sistema."
            cod = "ERRO-INIT-999"
            det = str(e)

        try:
            messagebox.showerror(
                "Erro ao Iniciar o Sistema",
                f"Ocorreu um erro ao iniciar o PDV Pro.\n\n"
                f"{msg}\n\n"
                f"{'='*40}\n"
                f"Codigo: {cod}\n\n"
                f"COMO RESOLVER:\n"
                f"1. Feche todos os programas e tente novamente\n"
                f"2. Reinicie o computador\n"
                f"3. Verifique se o antivirus nao esta bloqueando\n"
                f"4. Execute como Administrador (clique direito > Executar como admin)\n"
                f"5. Se nada funcionar, entre em contato com o suporte\n"
                f"   e informe o codigo: {cod}")
        except Exception:
            print(f"\n{'='*50}")
            print(f"ERRO CRITICO - PDV Pro nao pode iniciar")
            print(f"{'='*50}")
            print(f"Erro: {det}")
            print(f"Codigo: {cod}")
            print(f"\nTente reiniciar o programa ou entre em contato com o suporte.")
            print(f"{'='*50}")
            traceback.print_exc()


if __name__ == "__main__":
    main()


